/* Capsule world helpers use a vertical +Y, bottom-origin convention. origin is
   the bottom of the capsule, radius is the capsule radius, and height is the
   full bottom-to-top height for normal capsules where height >= 2 * radius.
   Internally this maps to local endpoints (0, radius, 0) and
   (0, height - radius, 0); if height is less than 2 * radius, the endpoints
   collapse to height * 0.5.
   Default helpers query all non-sensor fixtures unless ignoredBody excludes
   them; use ByType or WithFilter for narrower body sets. The AABB variants
   test/sweep only the enclosing box. */
bool b3World_TestCapsuleAABB(const b3World *world, b3Vec3 origin,
                             scalar radius, scalar height,
                             const b3Body *ignoredBody);
bool b3World_TestCapsuleAABBByType(const b3World *world, b3Vec3 origin,
                                   scalar radius, scalar height,
                                   b3BodyType bodyType,
                                   const b3Body *ignoredBody);
