#include <stdarg.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

struct b3BlockPool {
  uint32 blockSize;
  uint32 chunkSize;
  b3Chunk *chunks;
  uint32 chunkCount;
};

struct b3BlockAllocator {
  b3BlockPool *pools[B3_BLOCK_ALLOCATOR_SIZE_COUNT];
};

typedef struct b3StackBlock {
  uint32 size;
  unsigned char *data;
  bool parent;
} b3StackBlock;

struct b3StackAllocator {
  uint32 blockCapacity;
  b3StackBlock *blocks;
  uint32 blockCount;
  uint32 allocatedSize;
  unsigned char memory[B3_MAX_STACK_SIZE];
};

typedef struct b3FrameBlock {
  uint32 size;
  void *ptr;
  bool parent;
} b3FrameBlock;

struct b3FrameAllocator {
  unsigned char memory[B3_MAX_FRAME_SIZE];
  unsigned char *ptr;
  uint32 allocatedSize;
};

static const uint32 b3_memory_block_sizes[B3_BLOCK_ALLOCATOR_SIZE_COUNT] = {
    16u, 32u, 64u, 96u, 128u, 160u, 192u,
    224u, 256u, 320u, 384u, 448u, 512u, 640u,
};

b3Version b3_version = {0u, 1u, 0u};
uint32 b3_allocCalls = 0u;
uint32 b3_maxAllocCalls = 0u;

void *b3Alloc_Default(uint32 size) {
  ++b3_allocCalls;
  if (b3_allocCalls > b3_maxAllocCalls) {
    b3_maxAllocCalls = b3_allocCalls;
  }
  return malloc((size_t)size);
}

void b3Free_Default(void *block) { free(block); }

void *b3Alloc(uint32 size) { return b3Alloc_Default(size); }

void b3Free(void *block) { b3Free_Default(block); }

void b3Log_Default(const char *text, va_list args) { vprintf(text, args); }

void b3Log(const char *text, ...) {
  va_list args;
  va_start(args, text);
  b3Log_Default(text, args);
  va_end(args);
}

static bool block_pool_add_chunk(b3BlockPool *pool) {
  if (pool == NULL || pool->blockSize == 0u || pool->chunkSize == 0u) {
    return false;
  }

  size_t totalSize = sizeof(b3Chunk) + (size_t)pool->chunkSize;
  b3Chunk *chunk = (b3Chunk *)malloc(totalSize);
  if (chunk == NULL) {
    return false;
  }

  chunk->freeBlocks =
      (b3Block *)((unsigned char *)chunk + sizeof(*chunk));
  for (uint32 i = 0u; i < B3_BLOCK_POOL_BLOCK_COUNT - 1u; ++i) {
    b3Block *current =
        (b3Block *)((unsigned char *)chunk->freeBlocks +
                    (size_t)i * pool->blockSize);
    current->next =
        (b3Block *)((unsigned char *)chunk->freeBlocks +
                    (size_t)(i + 1u) * pool->blockSize);
  }
  b3Block *last =
      (b3Block *)((unsigned char *)chunk->freeBlocks +
                  (size_t)(B3_BLOCK_POOL_BLOCK_COUNT - 1u) * pool->blockSize);
  last->next = NULL;

  chunk->next = pool->chunks;
  pool->chunks = chunk;
  ++pool->chunkCount;
  return true;
}

b3BlockPool *b3BlockPool_Create(uint32 blockSize) {
  if (blockSize < sizeof(b3Block)) {
    blockSize = (uint32)sizeof(b3Block);
  }

  b3BlockPool *pool = (b3BlockPool *)calloc(1u, sizeof(*pool));
  if (pool == NULL) {
    return NULL;
  }

  pool->blockSize = blockSize;
  if (blockSize > UINT32_MAX / B3_BLOCK_POOL_BLOCK_COUNT) {
    free(pool);
    return NULL;
  }
  pool->chunkSize = B3_BLOCK_POOL_BLOCK_COUNT * blockSize;
  if (!block_pool_add_chunk(pool)) {
    free(pool);
    return NULL;
  }
  return pool;
}

void b3BlockPool_Destroy(b3BlockPool *pool) {
  if (pool == NULL) {
    return;
  }

  b3Chunk *chunk = pool->chunks;
  while (chunk != NULL) {
    b3Chunk *next = chunk->next;
    free(chunk);
    chunk = next;
  }
  free(pool);
}

void *b3BlockPool_Allocate(b3BlockPool *pool) {
  if (pool == NULL) {
    return NULL;
  }

  if (pool->chunks == NULL || pool->chunks->freeBlocks == NULL) {
    if (!block_pool_add_chunk(pool)) {
      return NULL;
    }
  }

  b3Block *block = pool->chunks->freeBlocks;
  pool->chunks->freeBlocks = block->next;
  return block;
}

void b3BlockPool_Free(b3BlockPool *pool, void *ptr) {
  if (pool == NULL || ptr == NULL || pool->chunks == NULL) {
    return;
  }

  b3Block *block = (b3Block *)ptr;
  block->next = pool->chunks->freeBlocks;
  pool->chunks->freeBlocks = block;
}

static uint32 block_allocator_slot(uint32 size) {
  for (uint32 i = 0u; i < B3_BLOCK_ALLOCATOR_SIZE_COUNT; ++i) {
    if (size <= b3_memory_block_sizes[i]) {
      return i;
    }
  }
  return B3_BLOCK_ALLOCATOR_SIZE_COUNT;
}

b3BlockAllocator *b3BlockAllocator_Create(void) {
  b3BlockAllocator *allocator =
      (b3BlockAllocator *)calloc(1u, sizeof(*allocator));
  if (allocator == NULL) {
    return NULL;
  }

  for (uint32 i = 0u; i < B3_BLOCK_ALLOCATOR_SIZE_COUNT; ++i) {
    allocator->pools[i] = b3BlockPool_Create(b3_memory_block_sizes[i]);
    if (allocator->pools[i] == NULL) {
      b3BlockAllocator_Destroy(allocator);
      return NULL;
    }
  }
  return allocator;
}

void b3BlockAllocator_Destroy(b3BlockAllocator *allocator) {
  if (allocator == NULL) {
    return;
  }
  for (uint32 i = 0u; i < B3_BLOCK_ALLOCATOR_SIZE_COUNT; ++i) {
    b3BlockPool_Destroy(allocator->pools[i]);
  }
  free(allocator);
}

void *b3BlockAllocator_Allocate(b3BlockAllocator *allocator, uint32 size) {
  if (allocator == NULL || size == 0u) {
    return NULL;
  }
  if (size > B3_MAX_BLOCK_SIZE) {
    return malloc(size);
  }
  uint32 slot = block_allocator_slot(size);
  if (slot >= B3_BLOCK_ALLOCATOR_SIZE_COUNT) {
    return NULL;
  }
  return b3BlockPool_Allocate(allocator->pools[slot]);
}

void b3BlockAllocator_Free(b3BlockAllocator *allocator, void *ptr,
                           uint32 size) {
  if (allocator == NULL || ptr == NULL || size == 0u) {
    return;
  }
  if (size > B3_MAX_BLOCK_SIZE) {
    free(ptr);
    return;
  }
  uint32 slot = block_allocator_slot(size);
  if (slot < B3_BLOCK_ALLOCATOR_SIZE_COUNT) {
    b3BlockPool_Free(allocator->pools[slot], ptr);
  }
}

b3StackAllocator *b3StackAllocator_Create(void) {
  b3StackAllocator *allocator =
      (b3StackAllocator *)calloc(1u, sizeof(*allocator));
  if (allocator == NULL) {
    return NULL;
  }

  allocator->blockCapacity = 256u;
  allocator->blocks =
      (b3StackBlock *)calloc(allocator->blockCapacity, sizeof(*allocator->blocks));
  if (allocator->blocks == NULL) {
    free(allocator);
    return NULL;
  }
  return allocator;
}

void b3StackAllocator_Destroy(b3StackAllocator *allocator) {
  if (allocator == NULL) {
    return;
  }
  for (uint32 i = 0u; i < allocator->blockCount; ++i) {
    if (allocator->blocks[i].parent) {
      free(allocator->blocks[i].data);
    }
  }
  free(allocator->blocks);
  free(allocator);
}

void *b3StackAllocator_Allocate(b3StackAllocator *allocator, uint32 size) {
  if (allocator == NULL) {
    return NULL;
  }
  if (allocator->blockCount == allocator->blockCapacity) {
    uint32 newCapacity = allocator->blockCapacity * 2u;
    b3StackBlock *newBlocks =
        (b3StackBlock *)realloc(allocator->blocks,
                                (size_t)newCapacity * sizeof(*newBlocks));
    if (newBlocks == NULL) {
      return NULL;
    }
    memset(newBlocks + allocator->blockCapacity, 0,
           (size_t)(newCapacity - allocator->blockCapacity) *
               sizeof(*newBlocks));
    allocator->blocks = newBlocks;
    allocator->blockCapacity = newCapacity;
  }

  b3StackBlock *block = allocator->blocks + allocator->blockCount;
  block->size = size;
  if (size > B3_MAX_STACK_SIZE - allocator->allocatedSize) {
    block->data = (unsigned char *)malloc(size);
    block->parent = true;
    if (block->data == NULL) {
      return NULL;
    }
  } else {
    block->data = allocator->memory + allocator->allocatedSize;
    block->parent = false;
    allocator->allocatedSize += size;
  }
  ++allocator->blockCount;
  return block->data;
}

void b3StackAllocator_Free(b3StackAllocator *allocator, void *ptr) {
  if (allocator == NULL || ptr == NULL || allocator->blockCount == 0u) {
    return;
  }

  b3StackBlock *block = allocator->blocks + allocator->blockCount - 1u;
  if (block->data != ptr) {
    return;
  }

  if (block->parent) {
    free(block->data);
  } else {
    allocator->allocatedSize -= block->size;
  }
  memset(block, 0, sizeof(*block));
  --allocator->blockCount;
}

b3FrameAllocator *b3FrameAllocator_Create(void) {
  b3FrameAllocator *allocator =
      (b3FrameAllocator *)calloc(1u, sizeof(*allocator));
  if (allocator == NULL) {
    return NULL;
  }
  allocator->ptr = allocator->memory;
  return allocator;
}

void b3FrameAllocator_Destroy(b3FrameAllocator *allocator) {
  free(allocator);
}

void *b3FrameAllocator_Allocate(b3FrameAllocator *allocator, uint32 size) {
  if (allocator == NULL) {
    return NULL;
  }

  uint32 totalSize = (uint32)sizeof(b3FrameBlock) + size;
  if (totalSize < size) {
    return NULL;
  }
  if (totalSize > B3_MAX_FRAME_SIZE - allocator->allocatedSize) {
    unsigned char *ptr = (unsigned char *)malloc(totalSize);
    if (ptr == NULL) {
      return NULL;
    }
    b3FrameBlock *block = (b3FrameBlock *)ptr;
    block->size = size;
    block->ptr = ptr;
    block->parent = true;
    return ptr + sizeof(*block);
  }

  unsigned char *ptr = allocator->ptr;
  allocator->ptr += totalSize;
  allocator->allocatedSize += totalSize;

  b3FrameBlock *block = (b3FrameBlock *)ptr;
  block->size = size;
  block->ptr = ptr;
  block->parent = false;
  return ptr + sizeof(*block);
}

void b3FrameAllocator_Free(b3FrameAllocator *allocator, void *ptr) {
  (void)allocator;
  if (ptr == NULL) {
    return;
  }

  unsigned char *blockPtr = (unsigned char *)ptr - sizeof(b3FrameBlock);
  b3FrameBlock *block = (b3FrameBlock *)blockPtr;
  if (block->ptr == blockPtr && block->parent) {
    free(blockPtr);
  }
}

void b3FrameAllocator_Reset(b3FrameAllocator *allocator) {
  if (allocator == NULL) {
    return;
  }
  allocator->ptr = allocator->memory;
  allocator->allocatedSize = 0u;
}
