#include <float.h>
#include <math.h>
#include <stddef.h>
#include <string.h>

typedef enum b3SeparationType {
  e_separationPoints = 0,
  e_separationEdgeA = 1,
  e_separationFaceA = 2,
  e_separationEdgeB = 3,
  e_separationFaceB = 4,
  e_separationEdges = 5,
} b3SeparationType;

typedef struct b3SeparationFunction {
  const b3GJKProxy *proxyA;
  const b3GJKProxy *proxyB;
  b3Sweep sweepA;
  b3Sweep sweepB;
  b3SeparationType type;
  b3Vec3 localPoint;
  b3Vec3 axis;
  bool edgesParallel;
} b3SeparationFunction;

static b3Vec3 vec3_add(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x + b.x, a.y + b.y, a.z + b.z);
}

static b3Vec3 vec3_sub(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x - b.x, a.y - b.y, a.z - b.z);
}

static b3Vec3 vec3_mul(b3Vec3 v, scalar s) {
  return b3Vec3_Make(v.x * s, v.y * s, v.z * s);
}

static b3Vec3 vec3_neg(b3Vec3 v) { return vec3_mul(v, -1.0f); }

static scalar vec3_dot(b3Vec3 a, b3Vec3 b) {
  return a.x * b.x + a.y * b.y + a.z * b.z;
}

static b3Vec3 vec3_cross(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.y * b.z - a.z * b.y, a.z * b.x - a.x * b.z,
                     a.x * b.y - a.y * b.x);
}

static scalar vec3_length_sq(b3Vec3 v) { return vec3_dot(v, v); }

static scalar vec3_length(b3Vec3 v) { return sqrtf(vec3_length_sq(v)); }

static scalar scalar_abs(scalar value) { return value < 0.0f ? -value : value; }

static scalar scalar_max(scalar a, scalar b) { return a > b ? a : b; }

static b3Vec3 vec3_normalize_or_zero(b3Vec3 v) {
  scalar length = vec3_length(v);
  if (length <= B3_EPSILON) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  return vec3_mul(v, 1.0f / length);
}

static b3Vec3 vec3_normalize_or_x(b3Vec3 v) {
  scalar length = vec3_length(v);
  if (length <= B3_EPSILON) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  return vec3_mul(v, 1.0f / length);
}

static scalar vec3_distance(b3Vec3 a, b3Vec3 b) {
  return vec3_length(vec3_sub(a, b));
}

static scalar vec3_det(b3Vec3 a, b3Vec3 b, b3Vec3 c) {
  return vec3_dot(a, vec3_cross(b, c));
}

static scalar scalar_sign(scalar x) {
  return (scalar)((0.0f < x) - (x < 0.0f));
}

static b3Vec3 quat_rotate(b3Quat q, b3Vec3 v) {
  b3Vec3 t = vec3_mul(vec3_cross(q.v, v), 2.0f);
  return vec3_add(v, vec3_add(vec3_mul(t, q.s), vec3_cross(q.v, t)));
}

static scalar quat_dot(b3Quat a, b3Quat b) {
  return vec3_dot(a.v, b.v) + a.s * b.s;
}

static b3Quat quat_neg(b3Quat q) {
  return b3Quat_Make(-q.v.x, -q.v.y, -q.v.z, -q.s);
}

static b3Quat quat_lerp(b3Quat a, b3Quat b, scalar t) {
  scalar oneMinusT = 1.0f - t;
  return b3Quat_Make(oneMinusT * a.v.x + t * b.v.x,
                     oneMinusT * a.v.y + t * b.v.y,
                     oneMinusT * a.v.z + t * b.v.z,
                     oneMinusT * a.s + t * b.s);
}

static b3Quat quat_normalize_or_identity(b3Quat q) {
  scalar length = sqrtf(quat_dot(q, q));
  if (length <= B3_EPSILON) {
    return b3Quat_Identity();
  }
  scalar inv = 1.0f / length;
  return b3Quat_Make(q.v.x * inv, q.v.y * inv, q.v.z * inv, q.s * inv);
}

static b3Vec3 quat_rotate_t(b3Quat q, b3Vec3 v) {
  q.v = vec3_neg(q.v);
  return quat_rotate(q, v);
}

static b3Vec3 transform_mul_t_vector(b3Transform xf, b3Vec3 v) {
  return quat_rotate_t(xf.rotation, v);
}

b3Transform b3Sweep_GetTransform(const b3Sweep *sweep, scalar t) {
  if (sweep == NULL) {
    return b3Transform_Identity();
  }

  b3Vec3 c = vec3_add(vec3_mul(sweep->worldCenter0, 1.0f - t),
                      vec3_mul(sweep->worldCenter, t));
  b3Quat q0 = sweep->orientation0;
  b3Quat q1 = sweep->orientation;
  if (quat_dot(q0, q1) < 0.0f) {
    q0 = quat_neg(q0);
  }
  b3Quat q = quat_normalize_or_identity(quat_lerp(q0, q1, t));

  b3Transform xf;
  xf.rotation = q;
  xf.translation = vec3_sub(c, quat_rotate(q, sweep->localCenter));
  return xf;
}

static uint32 proxy_support_index(const b3GJKProxy *proxy, b3Vec3 direction) {
  uint32 maxIndex = 0u;
  scalar maxProjection = vec3_dot(direction, proxy->vertices[0]);
  for (uint32 i = 1u; i < proxy->vertexCount; ++i) {
    scalar projection = vec3_dot(direction, proxy->vertices[i]);
    if (projection > maxProjection) {
      maxIndex = i;
      maxProjection = projection;
    }
  }
  return maxIndex;
}

static b3Vec3 proxy_vertex(const b3GJKProxy *proxy, uint32 index) {
  if (index >= proxy->vertexCount) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  return proxy->vertices[index];
}

static b3Vec3 closest_point_on_segment(b3Vec3 q, b3Vec3 a, b3Vec3 b) {
  b3Vec3 ab = vec3_sub(b, a);
  scalar u = vec3_dot(vec3_sub(b, q), ab);
  scalar v = vec3_dot(vec3_sub(q, a), ab);

  if (v <= 0.0f) {
    return a;
  }
  if (u <= 0.0f) {
    return b;
  }

  scalar w = vec3_dot(ab, ab);
  if (w <= B3_LINEAR_SLOP * B3_LINEAR_SLOP) {
    return a;
  }

  scalar inv = 1.0f / w;
  return vec3_mul(vec3_add(vec3_mul(a, u), vec3_mul(b, v)), inv);
}

static void closest_points_between_segments(b3Vec3 *c1, b3Vec3 *c2,
                                            b3Vec3 p1, b3Vec3 q1, b3Vec3 e1,
                                            scalar l1, b3Vec3 p2, b3Vec3 q2,
                                            b3Vec3 e2, scalar l2) {
  if (l1 < B3_LINEAR_SLOP && l2 < B3_LINEAR_SLOP) {
    *c1 = p1;
    *c2 = p2;
    return;
  }

  if (l1 < B3_LINEAR_SLOP) {
    *c1 = p1;
    *c2 = closest_point_on_segment(p1, p2, q2);
    return;
  }

  if (l2 < B3_LINEAR_SLOP) {
    *c1 = closest_point_on_segment(p2, p1, q1);
    *c2 = p2;
    return;
  }

  b3Vec3 n1 = vec3_mul(e1, 1.0f / l1);
  b3Vec3 n2 = vec3_mul(e2, 1.0f / l2);
  scalar b = vec3_dot(n1, n2);
  scalar den = 1.0f - b * b;

  if (den != 0.0f) {
    scalar invDen = 1.0f / den;
    b3Vec3 e3 = vec3_sub(p1, p2);
    scalar d = vec3_dot(n1, e3);
    scalar e = vec3_dot(n2, e3);
    scalar s = invDen * (b * e - d);
    scalar t = invDen * (e - b * d);
    *c1 = vec3_add(p1, vec3_mul(n1, s));
    *c2 = vec3_add(p2, vec3_mul(n2, t));
  } else {
    *c1 = p1;
    *c2 = p2;
  }

  *c1 = closest_point_on_segment(*c1, p1, q1);
  *c2 = closest_point_on_segment(*c1, p2, q2);
  *c1 = closest_point_on_segment(*c2, p1, q1);
}

static bool separation_initialize(b3SeparationFunction *fcn,
                                  const b3SimplexCache *cache,
                                  const b3GJKProxy *proxyA,
                                  const b3Sweep *sweepA,
                                  const b3GJKProxy *proxyB,
                                  const b3Sweep *sweepB, scalar t1) {
  if (fcn == NULL || cache == NULL || cache->count == 0u ||
      cache->count >= 4u) {
    return false;
  }

  memset(fcn, 0, sizeof(*fcn));
  fcn->proxyA = proxyA;
  fcn->proxyB = proxyB;
  fcn->sweepA = *sweepA;
  fcn->sweepB = *sweepB;

  b3Transform xfA = b3Sweep_GetTransform(&fcn->sweepA, t1);
  b3Transform xfB = b3Sweep_GetTransform(&fcn->sweepB, t1);
  b3GJKFeaturePair fp = b3GJK_GetFeaturePair(cache);

  uint32 countA = fp.count1;
  uint32 countB = fp.count2;

  if (countA == 1u && countB == 1u) {
    fcn->type = e_separationPoints;
    b3Vec3 localA = proxy_vertex(proxyA, fp.index1[0]);
    b3Vec3 localB = proxy_vertex(proxyB, fp.index2[0]);
    b3Vec3 a = b3Transform_MulPoint(xfA, localA);
    b3Vec3 b = b3Transform_MulPoint(xfB, localB);
    fcn->axis = vec3_normalize_or_x(vec3_sub(b, a));
    return true;
  }

  if (countA == 2u && countB == 1u) {
    fcn->type = e_separationEdgeA;
    b3Vec3 a = proxy_vertex(proxyA, fp.index1[0]);
    b3Vec3 b = proxy_vertex(proxyA, fp.index1[1]);
    b3Vec3 c = b3Transform_MulTPoint(
        xfA, b3Transform_MulPoint(xfB, proxy_vertex(proxyB, fp.index2[0])));
    b3Vec3 ab = vec3_sub(b, a);
    b3Vec3 ac = vec3_sub(c, a);
    fcn->axis = quat_rotate(xfA.rotation,
                            vec3_cross(vec3_cross(ab, ac), ab));
    fcn->axis = vec3_normalize_or_x(fcn->axis);
    return true;
  }

  if (countA == 3u) {
    fcn->type = e_separationFaceA;
    b3Vec3 a = proxy_vertex(proxyA, fp.index1[0]);
    b3Vec3 b = proxy_vertex(proxyA, fp.index1[1]);
    b3Vec3 c = proxy_vertex(proxyA, fp.index1[2]);
    b3Vec3 d = b3Transform_MulTPoint(
        xfA, b3Transform_MulPoint(xfB, proxy_vertex(proxyB, fp.index2[0])));
    b3Vec3 n = vec3_neg(vec3_cross(vec3_sub(b, a), vec3_sub(c, a)));
    if (vec3_dot(vec3_sub(d, a), n) < 0.0f) {
      n = vec3_neg(n);
    }
    fcn->axis = vec3_normalize_or_x(n);
    fcn->localPoint = a;
    return true;
  }

  if (countB == 2u && countA == 1u) {
    fcn->type = e_separationEdgeB;
    b3Vec3 a = proxy_vertex(proxyB, fp.index2[0]);
    b3Vec3 b = proxy_vertex(proxyB, fp.index2[1]);
    b3Vec3 c = b3Transform_MulTPoint(
        xfB, b3Transform_MulPoint(xfA, proxy_vertex(proxyA, fp.index1[0])));
    b3Vec3 ab = vec3_sub(b, a);
    b3Vec3 ac = vec3_sub(c, a);
    fcn->axis = quat_rotate(xfB.rotation,
                            vec3_cross(vec3_cross(ab, ac), ab));
    fcn->axis = vec3_normalize_or_x(fcn->axis);
    return true;
  }

  if (countB == 3u) {
    fcn->type = e_separationFaceB;
    b3Vec3 a = proxy_vertex(proxyB, fp.index2[0]);
    b3Vec3 b = proxy_vertex(proxyB, fp.index2[1]);
    b3Vec3 c = proxy_vertex(proxyB, fp.index2[2]);
    b3Vec3 d = b3Transform_MulTPoint(
        xfB, b3Transform_MulPoint(xfA, proxy_vertex(proxyA, fp.index1[0])));
    b3Vec3 n = vec3_neg(vec3_cross(vec3_sub(b, a), vec3_sub(c, a)));
    if (vec3_dot(vec3_sub(d, a), n) < 0.0f) {
      n = vec3_neg(n);
    }
    fcn->axis = vec3_normalize_or_x(n);
    fcn->localPoint = a;
    return true;
  }

  if (countA == 2u && countB == 2u) {
    fcn->type = e_separationEdges;
    b3Vec3 a = proxy_vertex(proxyA, fp.index1[0]);
    b3Vec3 b = proxy_vertex(proxyA, fp.index1[1]);
    b3Vec3 c = b3Transform_MulTPoint(
        xfA, b3Transform_MulPoint(xfB, proxy_vertex(proxyB, fp.index2[0])));
    b3Vec3 d = b3Transform_MulTPoint(
        xfA, b3Transform_MulPoint(xfB, proxy_vertex(proxyB, fp.index2[1])));

    b3Vec3 e1 = vec3_sub(b, a);
    b3Vec3 e2 = vec3_sub(d, c);
    scalar l1 = vec3_length(e1);
    scalar l2 = vec3_length(e2);
    if (l1 <= B3_EPSILON || l2 <= B3_EPSILON) {
      return false;
    }

    const scalar kTol = 0.005f;
    b3Vec3 e1xe2 = vec3_cross(e1, e2);
    scalar l = vec3_length(e1xe2);
    if (l < kTol * l1 * l2) {
      b3Vec3 c1;
      b3Vec3 c2;
      closest_points_between_segments(&c1, &c2, a, b, e1, l1, c, d, e2,
                                      l2);
      c1 = b3Transform_MulPoint(xfA, c1);
      c2 = b3Transform_MulPoint(xfA, c2);
      fcn->axis = vec3_normalize_or_x(vec3_sub(c2, c1));
      fcn->edgesParallel = true;
      return true;
    }

    fcn->edgesParallel = false;
    b3Vec3 c1 = vec3_mul(vec3_add(a, b), 0.5f);
    b3Vec3 c2 = vec3_mul(vec3_add(c, d), 0.5f);
    b3Vec3 n = vec3_mul(e1xe2, 1.0f / l);
    if (vec3_dot(n, vec3_sub(c2, c1)) < 0.0f) {
      n = vec3_neg(n);
    }
    fcn->axis = n;
    fcn->localPoint = c1;
    return true;
  }

  return false;
}

static scalar separation_find_min(const b3SeparationFunction *fcn,
                                  uint32 *indexA, uint32 *indexB, scalar t) {
  b3Transform xfA = b3Sweep_GetTransform(&fcn->sweepA, t);
  b3Transform xfB = b3Sweep_GetTransform(&fcn->sweepB, t);
  b3Quat qA = xfA.rotation;
  b3Quat qB = xfB.rotation;

  switch (fcn->type) {
  case e_separationPoints:
  case e_separationEdgeA: {
    b3Vec3 axisA = quat_rotate_t(qA, fcn->axis);
    b3Vec3 axisB = quat_rotate_t(qB, vec3_neg(fcn->axis));
    *indexA = proxy_support_index(fcn->proxyA, axisA);
    *indexB = proxy_support_index(fcn->proxyB, axisB);
    b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, *indexA));
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, *indexB));
    return vec3_dot(vec3_sub(b, a), fcn->axis);
  }

  case e_separationFaceA: {
    b3Vec3 n = quat_rotate(qA, fcn->axis);
    b3Vec3 a = b3Transform_MulPoint(xfA, fcn->localPoint);
    b3Vec3 axisB = quat_rotate_t(qB, vec3_neg(n));
    *indexA = B3_MAX_U32;
    *indexB = proxy_support_index(fcn->proxyB, axisB);
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, *indexB));
    return vec3_dot(vec3_sub(b, a), n);
  }

  case e_separationEdgeB: {
    b3Vec3 axisB = quat_rotate_t(qB, fcn->axis);
    b3Vec3 axisA = quat_rotate_t(qA, vec3_neg(fcn->axis));
    *indexA = proxy_support_index(fcn->proxyA, axisA);
    *indexB = proxy_support_index(fcn->proxyB, axisB);
    b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, *indexA));
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, *indexB));
    return vec3_dot(vec3_sub(a, b), fcn->axis);
  }

  case e_separationFaceB: {
    b3Vec3 n = quat_rotate(qB, fcn->axis);
    b3Vec3 b = b3Transform_MulPoint(xfB, fcn->localPoint);
    b3Vec3 axisA = quat_rotate_t(qA, vec3_neg(n));
    *indexA = proxy_support_index(fcn->proxyA, axisA);
    *indexB = B3_MAX_U32;
    b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, *indexA));
    return vec3_dot(vec3_sub(a, b), n);
  }

  case e_separationEdges: {
    if (fcn->edgesParallel) {
      b3Vec3 axisA = quat_rotate_t(qA, fcn->axis);
      b3Vec3 axisB = quat_rotate_t(qB, vec3_neg(fcn->axis));
      *indexA = proxy_support_index(fcn->proxyA, axisA);
      *indexB = proxy_support_index(fcn->proxyB, axisB);
      b3Vec3 a =
          b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, *indexA));
      b3Vec3 b =
          b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, *indexB));
      return vec3_dot(vec3_sub(b, a), fcn->axis);
    }

    b3Vec3 n = quat_rotate(qA, fcn->axis);
    b3Vec3 a = b3Transform_MulPoint(xfA, fcn->localPoint);
    b3Vec3 axisB = quat_rotate_t(qB, vec3_neg(n));
    *indexA = B3_MAX_U32;
    *indexB = proxy_support_index(fcn->proxyB, axisB);
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, *indexB));
    return vec3_dot(vec3_sub(b, a), n);
  }
  }

  *indexA = B3_MAX_U32;
  *indexB = B3_MAX_U32;
  return -FLT_MAX;
}

static scalar separation_evaluate(const b3SeparationFunction *fcn,
                                  uint32 indexA, uint32 indexB, scalar t) {
  b3Transform xfA = b3Sweep_GetTransform(&fcn->sweepA, t);
  b3Transform xfB = b3Sweep_GetTransform(&fcn->sweepB, t);

  switch (fcn->type) {
  case e_separationPoints:
  case e_separationEdgeA: {
    b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, indexA));
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, indexB));
    return vec3_dot(vec3_sub(b, a), fcn->axis);
  }

  case e_separationFaceA: {
    b3Vec3 n = quat_rotate(xfA.rotation, fcn->axis);
    b3Vec3 a = b3Transform_MulPoint(xfA, fcn->localPoint);
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, indexB));
    return vec3_dot(vec3_sub(b, a), n);
  }

  case e_separationEdgeB: {
    b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, indexA));
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, indexB));
    return vec3_dot(vec3_sub(a, b), fcn->axis);
  }

  case e_separationFaceB: {
    b3Vec3 n = quat_rotate(xfB.rotation, fcn->axis);
    b3Vec3 b = b3Transform_MulPoint(xfB, fcn->localPoint);
    b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, indexA));
    return vec3_dot(vec3_sub(a, b), n);
  }

  case e_separationEdges: {
    if (fcn->edgesParallel) {
      b3Vec3 a = b3Transform_MulPoint(xfA, proxy_vertex(fcn->proxyA, indexA));
      b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, indexB));
      return vec3_dot(vec3_sub(b, a), fcn->axis);
    }

    b3Vec3 n = quat_rotate(xfA.rotation, fcn->axis);
    b3Vec3 a = b3Transform_MulPoint(xfA, fcn->localPoint);
    b3Vec3 b = b3Transform_MulPoint(xfB, proxy_vertex(fcn->proxyB, indexB));
    return vec3_dot(vec3_sub(b, a), n);
  }
  }

  return 0.0f;
}

static void barycentric_segment(scalar out[3], b3Vec3 a, b3Vec3 b,
                                b3Vec3 q) {
  b3Vec3 ab = vec3_sub(b, a);
  b3Vec3 qa = vec3_sub(a, q);
  b3Vec3 qb = vec3_sub(b, q);

  out[0] = vec3_dot(qb, ab);
  out[1] = -vec3_dot(qa, ab);
  out[2] = out[0] + out[1];
}

static void barycentric_triangle(scalar out[4], b3Vec3 a, b3Vec3 b,
                                 b3Vec3 c, b3Vec3 q) {
  b3Vec3 ab = vec3_sub(b, a);
  b3Vec3 ac = vec3_sub(c, a);
  b3Vec3 qa = vec3_sub(a, q);
  b3Vec3 qb = vec3_sub(b, q);
  b3Vec3 qc = vec3_sub(c, q);

  b3Vec3 qb_x_qc = vec3_cross(qb, qc);
  b3Vec3 qc_x_qa = vec3_cross(qc, qa);
  b3Vec3 qa_x_qb = vec3_cross(qa, qb);
  b3Vec3 ab_x_ac = vec3_cross(ab, ac);

  out[0] = vec3_dot(qb_x_qc, ab_x_ac);
  out[1] = vec3_dot(qc_x_qa, ab_x_ac);
  out[2] = vec3_dot(qa_x_qb, ab_x_ac);
  out[3] = out[0] + out[1] + out[2];
}

static void barycentric_tetrahedron(scalar out[5], b3Vec3 a, b3Vec3 b,
                                    b3Vec3 c, b3Vec3 d, b3Vec3 q) {
  b3Vec3 ab = vec3_sub(b, a);
  b3Vec3 ac = vec3_sub(c, a);
  b3Vec3 ad = vec3_sub(d, a);
  b3Vec3 qa = vec3_sub(a, q);
  b3Vec3 qb = vec3_sub(b, q);
  b3Vec3 qc = vec3_sub(c, q);
  b3Vec3 qd = vec3_sub(d, q);

  scalar divisor = vec3_det(ab, ac, ad);
  scalar sign = scalar_sign(divisor);
  out[0] = sign * vec3_det(qb, qc, qd);
  out[1] = sign * vec3_det(qa, qd, qc);
  out[2] = sign * vec3_det(qa, qb, qd);
  out[3] = sign * vec3_det(qa, qc, qb);
  out[4] = sign * divisor;
}

static b3Vec3 simplex_get_search_direction(const b3Simplex *simplex,
                                           b3Vec3 q) {
  switch (simplex->count) {
  case 1u:
    return vec3_sub(q, simplex->vertices[0].point);
  case 2u: {
    b3Vec3 a = simplex->vertices[0].point;
    b3Vec3 b = simplex->vertices[1].point;
    b3Vec3 ab = vec3_sub(b, a);
    b3Vec3 aq = vec3_sub(q, a);
    return vec3_cross(vec3_cross(ab, aq), ab);
  }
  case 3u: {
    b3Vec3 a = simplex->vertices[0].point;
    b3Vec3 b = simplex->vertices[1].point;
    b3Vec3 c = simplex->vertices[2].point;
    b3Vec3 ab = vec3_sub(b, a);
    b3Vec3 ac = vec3_sub(c, a);
    b3Vec3 aq = vec3_sub(q, a);
    b3Vec3 normal = vec3_cross(ab, ac);
    return vec3_dot(normal, aq) > 0.0f ? normal : vec3_neg(normal);
  }
  default:
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
}

static b3Vec3 simplex_get_closest_point(const b3Simplex *simplex) {
  switch (simplex->count) {
  case 1u:
    return simplex->vertices[0].point;
  case 2u:
    return vec3_add(vec3_mul(simplex->vertices[0].point,
                             simplex->vertices[0].weight),
                    vec3_mul(simplex->vertices[1].point,
                             simplex->vertices[1].weight));
  case 3u:
    return vec3_add(
        vec3_add(vec3_mul(simplex->vertices[0].point,
                          simplex->vertices[0].weight),
                 vec3_mul(simplex->vertices[1].point,
                          simplex->vertices[1].weight)),
        vec3_mul(simplex->vertices[2].point, simplex->vertices[2].weight));
  default:
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
}

static void simplex_get_closest_points(const b3Simplex *simplex, b3Vec3 *p1,
                                       b3Vec3 *p2) {
  switch (simplex->count) {
  case 1u:
    *p1 = simplex->vertices[0].point1;
    *p2 = simplex->vertices[0].point2;
    break;
  case 2u:
    *p1 = vec3_add(vec3_mul(simplex->vertices[0].point1,
                            simplex->vertices[0].weight),
                   vec3_mul(simplex->vertices[1].point1,
                            simplex->vertices[1].weight));
    *p2 = vec3_add(vec3_mul(simplex->vertices[0].point2,
                            simplex->vertices[0].weight),
                   vec3_mul(simplex->vertices[1].point2,
                            simplex->vertices[1].weight));
    break;
  case 3u:
    *p1 = vec3_add(
        vec3_add(vec3_mul(simplex->vertices[0].point1,
                          simplex->vertices[0].weight),
                 vec3_mul(simplex->vertices[1].point1,
                          simplex->vertices[1].weight)),
        vec3_mul(simplex->vertices[2].point1, simplex->vertices[2].weight));
    *p2 = vec3_add(
        vec3_add(vec3_mul(simplex->vertices[0].point2,
                          simplex->vertices[0].weight),
                 vec3_mul(simplex->vertices[1].point2,
                          simplex->vertices[1].weight)),
        vec3_mul(simplex->vertices[2].point2, simplex->vertices[2].weight));
    break;
  case 4u:
    *p1 = vec3_add(
        vec3_add(vec3_mul(simplex->vertices[0].point1,
                          simplex->vertices[0].weight),
                 vec3_mul(simplex->vertices[1].point1,
                          simplex->vertices[1].weight)),
        vec3_add(vec3_mul(simplex->vertices[2].point1,
                          simplex->vertices[2].weight),
                 vec3_mul(simplex->vertices[3].point1,
                          simplex->vertices[3].weight)));
    *p2 = *p1;
    break;
  default:
    *p1 = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    *p2 = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    break;
  }
}

static scalar simplex_get_metric(const b3Simplex *simplex) {
  switch (simplex->count) {
  case 1u:
    return 0.0f;
  case 2u:
    return vec3_distance(simplex->vertices[0].point,
                         simplex->vertices[1].point);
  case 3u: {
    b3Vec3 e1 = vec3_sub(simplex->vertices[1].point,
                         simplex->vertices[0].point);
    b3Vec3 e2 = vec3_sub(simplex->vertices[2].point,
                         simplex->vertices[0].point);
    return vec3_length(vec3_cross(e1, e2));
  }
  case 4u: {
    b3Vec3 e1 = vec3_sub(simplex->vertices[1].point,
                         simplex->vertices[0].point);
    b3Vec3 e2 = vec3_sub(simplex->vertices[2].point,
                         simplex->vertices[0].point);
    b3Vec3 e3 = vec3_sub(simplex->vertices[3].point,
                         simplex->vertices[0].point);
    scalar det = vec3_det(e1, e2, e3);
    return scalar_sign(det) * det;
  }
  default:
    return 0.0f;
  }
}

static void simplex_solve2(b3Simplex *simplex, b3Vec3 q) {
  b3SimplexVertex a = simplex->vertices[0];
  b3SimplexVertex b = simplex->vertices[1];
  scalar wAB[3];
  barycentric_segment(wAB, a.point, b.point, q);

  if (wAB[1] <= 0.0f) {
    simplex->count = 1u;
    simplex->vertices[0] = a;
    simplex->vertices[0].weight = 1.0f;
    return;
  }

  if (wAB[0] <= 0.0f) {
    simplex->count = 1u;
    simplex->vertices[0] = b;
    simplex->vertices[0].weight = 1.0f;
    return;
  }

  scalar s = 1.0f / wAB[2];
  simplex->count = 2u;
  simplex->vertices[0] = a;
  simplex->vertices[0].weight = s * wAB[0];
  simplex->vertices[1] = b;
  simplex->vertices[1].weight = s * wAB[1];
}

static void simplex_solve3(b3Simplex *simplex, b3Vec3 q) {
  b3SimplexVertex a = simplex->vertices[0];
  b3SimplexVertex b = simplex->vertices[1];
  b3SimplexVertex c = simplex->vertices[2];
  scalar wAB[3], wBC[3], wCA[3];
  barycentric_segment(wAB, a.point, b.point, q);
  barycentric_segment(wBC, b.point, c.point, q);
  barycentric_segment(wCA, c.point, a.point, q);

  if (wAB[1] <= 0.0f && wCA[0] <= 0.0f) {
    simplex->count = 1u;
    simplex->vertices[0] = a;
    simplex->vertices[0].weight = 1.0f;
    return;
  }
  if (wAB[0] <= 0.0f && wBC[1] <= 0.0f) {
    simplex->count = 1u;
    simplex->vertices[0] = b;
    simplex->vertices[0].weight = 1.0f;
    return;
  }
  if (wBC[0] <= 0.0f && wCA[1] <= 0.0f) {
    simplex->count = 1u;
    simplex->vertices[0] = c;
    simplex->vertices[0].weight = 1.0f;
    return;
  }

  scalar wABC[4];
  barycentric_triangle(wABC, a.point, b.point, c.point, q);
  scalar area = wABC[3];

  if (wAB[0] > 0.0f && wAB[1] > 0.0f && area * wABC[2] <= 0.0f) {
    scalar s = 1.0f / wAB[2];
    simplex->count = 2u;
    simplex->vertices[0] = a;
    simplex->vertices[0].weight = s * wAB[0];
    simplex->vertices[1] = b;
    simplex->vertices[1].weight = s * wAB[1];
    return;
  }
  if (wBC[0] > 0.0f && wBC[1] > 0.0f && area * wABC[0] <= 0.0f) {
    scalar s = 1.0f / wBC[2];
    simplex->count = 2u;
    simplex->vertices[0] = b;
    simplex->vertices[0].weight = s * wBC[0];
    simplex->vertices[1] = c;
    simplex->vertices[1].weight = s * wBC[1];
    return;
  }
  if (wCA[0] > 0.0f && wCA[1] > 0.0f && area * wABC[1] <= 0.0f) {
    scalar s = 1.0f / wCA[2];
    simplex->count = 2u;
    simplex->vertices[0] = c;
    simplex->vertices[0].weight = s * wCA[0];
    simplex->vertices[1] = a;
    simplex->vertices[1].weight = s * wCA[1];
    return;
  }

  if (wABC[3] <= 0.0f) {
    return;
  }
  scalar s = 1.0f / wABC[3];
  simplex->count = 3u;
  simplex->vertices[0] = a;
  simplex->vertices[0].weight = s * wABC[0];
  simplex->vertices[1] = b;
  simplex->vertices[1].weight = s * wABC[1];
  simplex->vertices[2] = c;
  simplex->vertices[2].weight = s * wABC[2];
}

static void simplex_set1(b3Simplex *simplex, b3SimplexVertex a) {
  simplex->count = 1u;
  simplex->vertices[0] = a;
  simplex->vertices[0].weight = 1.0f;
}

static void simplex_set2(b3Simplex *simplex, b3SimplexVertex a,
                         b3SimplexVertex b, scalar wa, scalar wb) {
  simplex->count = 2u;
  simplex->vertices[0] = a;
  simplex->vertices[0].weight = wa;
  simplex->vertices[1] = b;
  simplex->vertices[1].weight = wb;
}

static void simplex_set3(b3Simplex *simplex, b3SimplexVertex a,
                         b3SimplexVertex b, b3SimplexVertex c, scalar wa,
                         scalar wb, scalar wc) {
  simplex->count = 3u;
  simplex->vertices[0] = a;
  simplex->vertices[0].weight = wa;
  simplex->vertices[1] = b;
  simplex->vertices[1].weight = wb;
  simplex->vertices[2] = c;
  simplex->vertices[2].weight = wc;
}

static void simplex_solve4(b3Simplex *simplex, b3Vec3 q) {
  b3SimplexVertex a = simplex->vertices[0];
  b3SimplexVertex b = simplex->vertices[1];
  b3SimplexVertex c = simplex->vertices[2];
  b3SimplexVertex d = simplex->vertices[3];
  scalar wAB[3], wAC[3], wAD[3], wBC[3], wCD[3], wDB[3];
  barycentric_segment(wAB, a.point, b.point, q);
  barycentric_segment(wBC, b.point, c.point, q);
  barycentric_segment(wAC, a.point, c.point, q);
  barycentric_segment(wAD, a.point, d.point, q);
  barycentric_segment(wCD, c.point, d.point, q);
  barycentric_segment(wDB, d.point, b.point, q);

  if (wAB[1] <= 0.0f && wAC[1] <= 0.0f && wAD[1] <= 0.0f) {
    simplex_set1(simplex, a);
    return;
  }
  if (wAB[0] <= 0.0f && wDB[0] <= 0.0f && wBC[1] <= 0.0f) {
    simplex_set1(simplex, b);
    return;
  }
  if (wAC[0] <= 0.0f && wBC[0] <= 0.0f && wCD[1] <= 0.0f) {
    simplex_set1(simplex, c);
    return;
  }
  if (wAD[0] <= 0.0f && wCD[0] <= 0.0f && wDB[1] <= 0.0f) {
    simplex_set1(simplex, d);
    return;
  }

  scalar wACB[4], wABD[4], wADC[4], wBCD[4];
  barycentric_triangle(wACB, a.point, c.point, b.point, q);
  barycentric_triangle(wABD, a.point, b.point, d.point, q);
  barycentric_triangle(wADC, a.point, d.point, c.point, q);
  barycentric_triangle(wBCD, b.point, c.point, d.point, q);

  if (wABD[2] <= 0.0f && wACB[1] <= 0.0f && wAB[0] > 0.0f &&
      wAB[1] > 0.0f) {
    scalar s = 1.0f / wAB[2];
    simplex_set2(simplex, a, b, s * wAB[0], s * wAB[1]);
    return;
  }
  if (wACB[2] <= 0.0f && wADC[1] <= 0.0f && wAC[0] > 0.0f &&
      wAC[1] > 0.0f) {
    scalar s = 1.0f / wAC[2];
    simplex_set2(simplex, a, c, s * wAC[0], s * wAC[1]);
    return;
  }
  if (wADC[2] <= 0.0f && wABD[1] <= 0.0f && wAD[0] > 0.0f &&
      wAD[1] > 0.0f) {
    scalar s = 1.0f / wAD[2];
    simplex_set2(simplex, a, d, s * wAD[0], s * wAD[1]);
    return;
  }
  if (wACB[0] <= 0.0f && wBCD[2] <= 0.0f && wBC[0] > 0.0f &&
      wBC[1] > 0.0f) {
    scalar s = 1.0f / wBC[2];
    simplex_set2(simplex, b, c, s * wBC[0], s * wBC[1]);
    return;
  }
  if (wADC[0] <= 0.0f && wBCD[0] <= 0.0f && wCD[0] > 0.0f &&
      wCD[1] > 0.0f) {
    scalar s = 1.0f / wCD[2];
    simplex_set2(simplex, c, d, s * wCD[0], s * wCD[1]);
    return;
  }
  if (wABD[0] <= 0.0f && wBCD[1] <= 0.0f && wDB[0] > 0.0f &&
      wDB[1] > 0.0f) {
    scalar s = 1.0f / wDB[2];
    simplex_set2(simplex, d, b, s * wDB[0], s * wDB[1]);
    return;
  }

  scalar wABCD[5];
  barycentric_tetrahedron(wABCD, a.point, b.point, c.point, d.point, q);

  if (wABCD[3] <= 0.0f && wACB[0] > 0.0f && wACB[1] > 0.0f &&
      wACB[2] > 0.0f) {
    scalar divisor = wACB[0] + wACB[1] + wACB[2];
    scalar s = 1.0f / divisor;
    simplex_set3(simplex, a, c, b, s * wACB[0], s * wACB[1],
                 s * wACB[2]);
    return;
  }
  if (wABCD[2] <= 0.0f && wABD[0] > 0.0f && wABD[1] > 0.0f &&
      wABD[2] > 0.0f) {
    scalar divisor = wABD[0] + wABD[1] + wABD[2];
    scalar s = 1.0f / divisor;
    simplex_set3(simplex, a, b, d, s * wABD[0], s * wABD[1],
                 s * wABD[2]);
    return;
  }
  if (wABCD[1] <= 0.0f && wADC[0] > 0.0f && wADC[1] > 0.0f &&
      wADC[2] > 0.0f) {
    scalar divisor = wADC[0] + wADC[1] + wADC[2];
    scalar s = 1.0f / divisor;
    simplex_set3(simplex, a, d, c, s * wADC[0], s * wADC[1],
                 s * wADC[2]);
    return;
  }
  if (wABCD[0] <= 0.0f && wBCD[0] > 0.0f && wBCD[1] > 0.0f &&
      wBCD[2] > 0.0f) {
    scalar divisor = wBCD[0] + wBCD[1] + wBCD[2];
    scalar s = 1.0f / divisor;
    simplex_set3(simplex, b, c, d, s * wBCD[0], s * wBCD[1],
                 s * wBCD[2]);
    return;
  }

  scalar divisor = wABCD[0] + wABCD[1] + wABCD[2] + wABCD[3];
  if (divisor <= 0.0f) {
    return;
  }
  scalar s = 1.0f / divisor;
  simplex->count = 4u;
  simplex->vertices[0].weight = s * wABCD[0];
  simplex->vertices[1].weight = s * wABCD[1];
  simplex->vertices[2].weight = s * wABCD[2];
  simplex->vertices[3].weight = s * wABCD[3];
}

static void simplex_read_cache(b3Simplex *simplex, const b3SimplexCache *cache,
                               b3Transform xf1, const b3GJKProxy *proxy1,
                               b3Transform xf2, const b3GJKProxy *proxy2) {
  simplex->count = cache->count <= 4u ? cache->count : 0u;
  for (uint32 i = 0u; i < simplex->count; ++i) {
    b3SimplexVertex *v = &simplex->vertices[i];
    v->index1 = cache->index1[i];
    v->index2 = cache->index2[i];
    v->point1 = b3Transform_MulPoint(xf1, proxy_vertex(proxy1, v->index1));
    v->point2 = b3Transform_MulPoint(xf2, proxy_vertex(proxy2, v->index2));
    v->point = vec3_sub(v->point2, v->point1);
    v->weight = 0.0f;
  }

  if (simplex->count > 1u) {
    scalar metric1 = cache->metric;
    scalar metric2 = simplex_get_metric(simplex);
    if (metric2 < 0.5f * metric1 || 2.0f * metric1 < metric2 ||
        metric2 < B3_EPSILON) {
      simplex->count = 0u;
    }
  }

  if (simplex->count == 0u) {
    b3SimplexVertex *v = &simplex->vertices[0];
    v->index1 = 0u;
    v->index2 = 0u;
    v->point1 = b3Transform_MulPoint(xf1, proxy_vertex(proxy1, 0u));
    v->point2 = b3Transform_MulPoint(xf2, proxy_vertex(proxy2, 0u));
    v->point = vec3_sub(v->point2, v->point1);
    v->weight = 1.0f;
    simplex->count = 1u;
  }
}

static void simplex_write_cache(const b3Simplex *simplex,
                                b3SimplexCache *cache) {
  cache->metric = simplex_get_metric(simplex);
  cache->count = (uint16_t)simplex->count;
  for (uint32 i = 0u; i < simplex->count; ++i) {
    cache->index1[i] = (uint8_t)simplex->vertices[i].index1;
    cache->index2[i] = (uint8_t)simplex->vertices[i].index2;
  }
}

b3Vec3 b3Simplex_GetSearchDirection(const b3Simplex *simplex, b3Vec3 point) {
  return simplex != NULL ? simplex_get_search_direction(simplex, point)
                         : b3Vec3_Make(0.0f, 0.0f, 0.0f);
}

