#include <math.h>
#include <stdlib.h>
#include <string.h>

#define B3_AABB_EXTENSION 0.2f
#define B3_AABB_MULTIPLIER 2.0f

struct b3DynamicTree {
  uint32 root;
  b3DynamicNode *nodes;
  uint32 nodeCount;
  uint32 nodeCapacity;
  uint32 freeList;
};

struct b3BroadPhase {
  b3DynamicTree *tree;
  uint32 proxyCount;
  uint32 queryProxyId;
  uint32 *moveBuffer;
  uint32 moveBufferCount;
  uint32 moveBufferCapacity;
  b3Pair *pairs;
  uint32 pairCount;
  uint32 pairCapacity;
};

static b3Vec3 dt_vec3_add(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x + b.x, a.y + b.y, a.z + b.z);
}

static b3Vec3 dt_vec3_sub(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x - b.x, a.y - b.y, a.z - b.z);
}

static b3Vec3 dt_vec3_mul(b3Vec3 v, scalar s) {
  return b3Vec3_Make(v.x * s, v.y * s, v.z * s);
}

static b3Vec3 dt_vec3_mul_comp(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x * b.x, a.y * b.y, a.z * b.z);
}

static scalar dt_vec3_dot(b3Vec3 a, b3Vec3 b) {
  return a.x * b.x + a.y * b.y + a.z * b.z;
}

static b3Vec3 dt_vec3_cross(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.y * b.z - a.z * b.y, a.z * b.x - a.x * b.z,
                     a.x * b.y - a.y * b.x);
}

static b3Vec3 dt_vec3_abs(b3Vec3 v) {
  return b3Vec3_Make(fabsf(v.x), fabsf(v.y), fabsf(v.z));
}

static b3Vec3 dt_vec3_min(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x < b.x ? a.x : b.x, a.y < b.y ? a.y : b.y,
                     a.z < b.z ? a.z : b.z);
}

static b3Vec3 dt_vec3_max(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x > b.x ? a.x : b.x, a.y > b.y ? a.y : b.y,
                     a.z > b.z ? a.z : b.z);
}

static scalar dt_vec3_get(b3Vec3 v, uint32 index) {
  switch (index) {
  case 0u:
    return v.x;
  case 1u:
    return v.y;
  default:
    return v.z;
  }
}

static scalar dt_vec3_length_sq(b3Vec3 v) { return dt_vec3_dot(v, v); }

static b3Vec3 dt_vec3_normalize(b3Vec3 v) {
  scalar lenSq = dt_vec3_length_sq(v);
  if (lenSq <= B3_EPSILON) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  return dt_vec3_mul(v, 1.0f / sqrtf(lenSq));
}

static b3Quat dt_quat_normalize(b3Quat q) {
  scalar len = sqrtf(dt_vec3_dot(q.v, q.v) + q.s * q.s);
  if (len <= B3_EPSILON) {
    return b3Quat_Identity();
  }
  scalar invLen = 1.0f / len;
  return b3Quat_Make(q.v.x * invLen, q.v.y * invLen, q.v.z * invLen,
                     q.s * invLen);
}

static b3Vec3 dt_quat_rotate_vec3(b3Quat q, b3Vec3 v) {
  b3Vec3 t = dt_vec3_mul(dt_vec3_cross(q.v, v), 2.0f);
  return dt_vec3_add(dt_vec3_add(v, dt_vec3_mul(t, q.s)),
                     dt_vec3_cross(q.v, t));
}

static b3Mat33 dt_quat_to_abs_mat33(b3Quat q) {
  q = dt_quat_normalize(q);
  b3Mat33 m;
  m.x = dt_vec3_abs(dt_quat_rotate_vec3(q, b3Vec3_Make(1.0f, 0.0f, 0.0f)));
  m.y = dt_vec3_abs(dt_quat_rotate_vec3(q, b3Vec3_Make(0.0f, 1.0f, 0.0f)));
  m.z = dt_vec3_abs(dt_quat_rotate_vec3(q, b3Vec3_Make(0.0f, 0.0f, 1.0f)));
  return m;
}

static int32_t dt_max_i32(int32_t a, int32_t b) { return a > b ? a : b; }

static bool dt_node_is_leaf(const b3DynamicNode *node) {
  return node->child1 == B3_NULL_DYNAMIC_NODE;
}

b3AABB b3AABB_Make(b3Vec3 lowerBound, b3Vec3 upperBound) {
  b3AABB aabb;
  aabb.lowerBound = lowerBound;
  aabb.upperBound = upperBound;
  return aabb;
}

b3AABB b3AABB_FromCenterExtents(b3Vec3 center, b3Vec3 extents) {
  return b3AABB_Make(dt_vec3_sub(center, extents),
                     dt_vec3_add(center, extents));
}

b3AABB b3AABB_FromCenterRadius(b3Vec3 center, scalar radius) {
  b3Vec3 extents = b3Vec3_Make(radius, radius, radius);
  return b3AABB_FromCenterExtents(center, extents);
}

b3AABB b3AABB_FromPoints(const b3Vec3 *points, uint32 count) {
  if (points == NULL || count == 0u) {
    return b3AABB_Make(b3Vec3_Make(0.0f, 0.0f, 0.0f),
                       b3Vec3_Make(0.0f, 0.0f, 0.0f));
  }

  b3AABB aabb = b3AABB_Make(points[0], points[0]);
  for (uint32 i = 1u; i < count; ++i) {
    aabb.lowerBound = dt_vec3_min(aabb.lowerBound, points[i]);
    aabb.upperBound = dt_vec3_max(aabb.upperBound, points[i]);
  }
  return aabb;
}

b3AABB b3AABB_FromTransformedPoints(const b3Vec3 *points, uint32 count,
                                    b3Transform transform) {
  if (points == NULL || count == 0u) {
    return b3AABB_Make(b3Vec3_Make(0.0f, 0.0f, 0.0f),
                       b3Vec3_Make(0.0f, 0.0f, 0.0f));
  }

  b3Vec3 first = b3Transform_MulPoint(transform, points[0]);
  b3AABB aabb = b3AABB_Make(first, first);
  for (uint32 i = 1u; i < count; ++i) {
    b3Vec3 point = b3Transform_MulPoint(transform, points[i]);
    aabb.lowerBound = dt_vec3_min(aabb.lowerBound, point);
    aabb.upperBound = dt_vec3_max(aabb.upperBound, point);
  }
  return aabb;
}

b3AABB b3AABB_FromScaledTransformedPoints(const b3Vec3 *points, uint32 count,
                                          b3Vec3 scale,
                                          b3Transform transform) {
  if (points == NULL || count == 0u) {
    return b3AABB_Make(b3Vec3_Make(0.0f, 0.0f, 0.0f),
                       b3Vec3_Make(0.0f, 0.0f, 0.0f));
  }

  b3Vec3 first =
      b3Transform_MulPoint(transform, dt_vec3_mul_comp(scale, points[0]));
  b3AABB aabb = b3AABB_Make(first, first);
  for (uint32 i = 1u; i < count; ++i) {
    b3Vec3 point =
        b3Transform_MulPoint(transform, dt_vec3_mul_comp(scale, points[i]));
    aabb.lowerBound = dt_vec3_min(aabb.lowerBound, point);
    aabb.upperBound = dt_vec3_max(aabb.upperBound, point);
  }
  return aabb;
}

b3Vec3 b3AABB_GetSupportVertex(b3AABB aabb, b3Vec3 direction) {
  return b3Vec3_Make(direction.x < 0.0f ? aabb.lowerBound.x
                                        : aabb.upperBound.x,
                     direction.y < 0.0f ? aabb.lowerBound.y
                                        : aabb.upperBound.y,
                     direction.z < 0.0f ? aabb.lowerBound.z
                                        : aabb.upperBound.z);
}

b3AABB b3AABB_Combine(b3AABB a, b3AABB b) {
  return b3AABB_Make(dt_vec3_min(a.lowerBound, b.lowerBound),
                     dt_vec3_max(a.upperBound, b.upperBound));
}

b3AABB b3Combine(b3AABB a, b3AABB b) {
  return b3AABB_Combine(a, b);
}

b3Vec3 b3AABB_GetCenter(b3AABB aabb) {
  return dt_vec3_mul(dt_vec3_add(aabb.lowerBound, aabb.upperBound), 0.5f);
}

b3Vec3 b3AABB_GetExtents(b3AABB aabb) {
  return dt_vec3_mul(dt_vec3_sub(aabb.upperBound, aabb.lowerBound), 0.5f);
}

scalar b3AABB_GetWidth(b3AABB aabb) {
  return aabb.upperBound.x - aabb.lowerBound.x;
}

scalar b3AABB_GetHeight(b3AABB aabb) {
  return aabb.upperBound.y - aabb.lowerBound.y;
}

scalar b3AABB_GetDepth(b3AABB aabb) {
  return aabb.upperBound.z - aabb.lowerBound.z;
}

scalar b3AABB_GetVolume(b3AABB aabb) {
  b3Vec3 d = dt_vec3_sub(aabb.upperBound, aabb.lowerBound);
  return d.x * d.y * d.z;
}

uint32 b3AABB_GetLongestAxisIndex(b3AABB aabb) {
  b3Vec3 d = dt_vec3_sub(aabb.upperBound, aabb.lowerBound);
  scalar maxValue = d.x;
  uint32 maxIndex = 0u;
  if (d.y > maxValue) {
    maxValue = d.y;
    maxIndex = 1u;
  }
  if (d.z > maxValue) {
    maxIndex = 2u;
  }
  return maxIndex;
}

bool b3AABB_TestOverlap(b3AABB a, b3AABB b) {
  return a.lowerBound.x <= b.upperBound.x && a.upperBound.x >= b.lowerBound.x &&
         a.lowerBound.y <= b.upperBound.y && a.upperBound.y >= b.lowerBound.y &&
         a.lowerBound.z <= b.upperBound.z && a.upperBound.z >= b.lowerBound.z;
}

bool b3TestOverlap(b3AABB a, b3AABB b) {
  return b3AABB_TestOverlap(a, b);
}

bool b3AABB_ContainsPoint(b3AABB aabb, b3Vec3 point) {
  return aabb.lowerBound.x <= point.x && point.x <= aabb.upperBound.x &&
         aabb.lowerBound.y <= point.y && point.y <= aabb.upperBound.y &&
         aabb.lowerBound.z <= point.z && point.z <= aabb.upperBound.z;
}

bool b3AABB_ContainsAABB(b3AABB outer, b3AABB inner) {
  return b3AABB_ContainsPoint(outer, inner.lowerBound) &&
         b3AABB_ContainsPoint(outer, inner.upperBound);
}

scalar b3AABB_GetSurfaceArea(b3AABB aabb) {
  b3Vec3 d = dt_vec3_sub(aabb.upperBound, aabb.lowerBound);
  return 2.0f * (d.x * d.y + d.y * d.z + d.z * d.x);
}

b3AABB b3AABB_ExtendScalar(b3AABB aabb, scalar amount) {
  b3Vec3 r = b3Vec3_Make(amount, amount, amount);
  return b3AABB_Make(dt_vec3_sub(aabb.lowerBound, r),
                     dt_vec3_add(aabb.upperBound, r));
}

b3AABB b3AABB_Extend(b3AABB aabb, b3Vec3 amount) {
  return b3AABB_Make(dt_vec3_sub(aabb.lowerBound, amount),
                     dt_vec3_add(aabb.upperBound, amount));
}

bool b3AABB_RayCast(b3ShapeRayCastOutput *out, b3AABB aabb,
                    b3RayCastInput input) {
  if (out == NULL || input.maxFraction < 0.0f) {
    return false;
  }
  memset(out, 0, sizeof(*out));

  b3Vec3 p1 = input.p1;
  b3Vec3 p2 = input.p2;
  b3Vec3 d = dt_vec3_sub(p2, p1);
  b3Vec3 normals[6] = {
      b3Vec3_Make(-1.0f, 0.0f, 0.0f), b3Vec3_Make(1.0f, 0.0f, 0.0f),
      b3Vec3_Make(0.0f, -1.0f, 0.0f), b3Vec3_Make(0.0f, 1.0f, 0.0f),
      b3Vec3_Make(0.0f, 0.0f, -1.0f), b3Vec3_Make(0.0f, 0.0f, 1.0f),
  };

  uint32 index = B3_MAX_U32;
  scalar lower = 0.0f;
  scalar upper = input.maxFraction;
  uint32 planeIndex = 0u;

  for (uint32 i = 0u; i < 3u; ++i) {
    scalar p = dt_vec3_get(p1, i);
    scalar di = dt_vec3_get(d, i);
    scalar lowerBound = dt_vec3_get(aabb.lowerBound, i);
    scalar upperBound = dt_vec3_get(aabb.upperBound, i);
    scalar numerators[2] = {p - lowerBound, upperBound - p};
    scalar denominators[2] = {-di, di};

    for (uint32 j = 0u; j < 2u; ++j) {
      scalar numerator = numerators[j];
      scalar denominator = denominators[j];
      if (denominator == 0.0f) {
        if (numerator < 0.0f) {
          return false;
        }
      } else {
        if (denominator < 0.0f) {
          if (numerator < lower * denominator) {
            lower = numerator / denominator;
            index = planeIndex;
          }
        } else {
          if (numerator < upper * denominator) {
            upper = numerator / denominator;
          }
        }
        if (upper < lower) {
          return false;
        }
      }
      ++planeIndex;
    }
  }

  if (index == B3_MAX_U32) {
    return false;
  }

  out->fraction = lower;
  out->normal = normals[index];
  out->point = dt_vec3_add(p1, dt_vec3_mul(d, lower));
  return true;
}

b3AABB b3AABB_Translate(b3AABB aabb, b3Vec3 translation) {
  return b3AABB_Make(dt_vec3_add(aabb.lowerBound, translation),
                     dt_vec3_add(aabb.upperBound, translation));
}

b3AABB b3AABB_Scale(b3AABB aabb, b3Vec3 scale) {
  b3Vec3 scaledLower = dt_vec3_mul_comp(scale, aabb.lowerBound);
  b3Vec3 scaledUpper = dt_vec3_mul_comp(scale, aabb.upperBound);
  return b3AABB_Make(dt_vec3_min(scaledLower, scaledUpper),
                     dt_vec3_max(scaledLower, scaledUpper));
}

b3AABB b3AABB_Transform(b3AABB aabb, b3Transform transform) {
  b3Vec3 localCenter = b3AABB_GetCenter(aabb);
  b3Vec3 localRadius = b3AABB_GetExtents(aabb);
  b3Vec3 center = b3Transform_MulPoint(transform, localCenter);
  b3Mat33 absRotation = dt_quat_to_abs_mat33(transform.rotation);
  b3Vec3 radius =
      b3Vec3_Make(dt_vec3_dot(localRadius, absRotation.x),
                  dt_vec3_dot(localRadius, absRotation.y),
                  dt_vec3_dot(localRadius, absRotation.z));
  return b3AABB_FromCenterExtents(center, radius);
}

b3AABB b3AABB_TransformWithScale(b3AABB aabb, b3Transform transform,
                                  b3Vec3 scale) {
  b3Vec3 localCenter = b3AABB_GetCenter(aabb);
  b3Vec3 localRadius =
      dt_vec3_mul_comp(dt_vec3_abs(scale), b3AABB_GetExtents(aabb));
  b3Vec3 center = b3Transform_MulPoint(transform, localCenter);
  b3Mat33 absRotation = dt_quat_to_abs_mat33(transform.rotation);
  b3Vec3 radius =
      b3Vec3_Make(dt_vec3_dot(localRadius, absRotation.x),
                  dt_vec3_dot(localRadius, absRotation.y),
                  dt_vec3_dot(localRadius, absRotation.z));
  return b3AABB_FromCenterExtents(center, radius);
}

b3TOIOutput b3TimeOfImpactAABB(b3AABB aabb1, b3Vec3 displacement1,
                               b3AABB aabb2, b3Vec3 displacement2) {
  b3TOIOutput output;
  output.state = e_toiUnknown;
  output.t = 0.0f;
  output.iterations = 0u;

  if (b3AABB_TestOverlap(aabb1, aabb2)) {
    output.state = e_toiOverlapped;
    return output;
  }

  scalar lowerA[3] = {aabb1.lowerBound.x, aabb1.lowerBound.y,
                      aabb1.lowerBound.z};
  scalar upperA[3] = {aabb1.upperBound.x, aabb1.upperBound.y,
                      aabb1.upperBound.z};
  scalar lowerB[3] = {aabb2.lowerBound.x, aabb2.lowerBound.y,
                      aabb2.lowerBound.z};
  scalar upperB[3] = {aabb2.upperBound.x, aabb2.upperBound.y,
                      aabb2.upperBound.z};
  scalar d[3] = {displacement2.x - displacement1.x,
                 displacement2.y - displacement1.y,
                 displacement2.z - displacement1.z};
  scalar t1[3] = {0.0f, 0.0f, 0.0f};
  scalar t2[3] = {1.0f, 1.0f, 1.0f};

  for (uint32 i = 0u; i < 3u; ++i) {
    if (d[i] == 0.0f) {
      if (lowerA[i] > upperB[i] || upperA[i] < lowerB[i]) {
        output.state = e_toiSeparated;
        output.t = 1.0f;
        return output;
      }
    }

    if (d[i] < 0.0f) {
      if (upperB[i] < lowerA[i]) {
        output.state = e_toiSeparated;
        output.t = 1.0f;
        return output;
      }
      t2[i] = (lowerA[i] - upperB[i]) / d[i];

      if (lowerB[i] > upperA[i]) {
        t1[i] = (upperA[i] - lowerB[i]) / d[i];
        if (t1[i] >= 1.0f) {
          output.state = e_toiSeparated;
          output.t = 1.0f;
          return output;
        }
      }
    }

    if (d[i] > 0.0f) {
      if (lowerB[i] > upperA[i]) {
        output.state = e_toiSeparated;
        output.t = 1.0f;
        return output;
      }
      t2[i] = (upperA[i] - lowerB[i]) / d[i];

      if (upperB[i] < lowerA[i]) {
        t1[i] = (lowerA[i] - upperB[i]) / d[i];
        if (t1[i] >= 1.0f) {
          output.state = e_toiSeparated;
          output.t = 1.0f;
          return output;
        }
      }
    }
  }

  scalar t1Max = fmaxf(t1[0], fmaxf(t1[1], t1[2]));
  scalar t2Min = fminf(t2[0], fminf(t2[1], t2[2]));
  if (t1Max > t2Min) {
    output.state = e_toiSeparated;
    output.t = 0.0f;
    return output;
  }

  output.state = e_toiTouching;
  output.t = t1Max;
  return output;
}

static b3Vec3 dt_aabb_center(b3AABB aabb) {
  return dt_vec3_mul(dt_vec3_add(aabb.lowerBound, aabb.upperBound), 0.5f);
}

static b3Vec3 dt_aabb_extents(b3AABB aabb) {
  return dt_vec3_mul(dt_vec3_sub(aabb.upperBound, aabb.lowerBound), 0.5f);
}

static void dt_aabb_extend(b3AABB *aabb, scalar amount) {
  b3Vec3 r = b3Vec3_Make(amount, amount, amount);
  aabb->lowerBound = dt_vec3_sub(aabb->lowerBound, r);
  aabb->upperBound = dt_vec3_add(aabb->upperBound, r);
}

static bool dt_reserve_stack(uint32 **stack, uint32 *capacity, uint32 count) {
  if (count < *capacity) {
    return true;
  }
  uint32 newCapacity = *capacity * 2u;
  uint32 *newStack = (uint32 *)realloc(*stack, newCapacity * sizeof(uint32));
  if (newStack == NULL) {
    return false;
  }
  *stack = newStack;
  *capacity = newCapacity;
  return true;
}

static void dt_add_to_free_list(b3DynamicTree *tree, uint32 node) {
  for (uint32 i = node; i < tree->nodeCapacity - 1u; ++i) {
    tree->nodes[i].next = i + 1u;
    tree->nodes[i].height = -1;
  }
  tree->nodes[tree->nodeCapacity - 1u].next = B3_NULL_DYNAMIC_NODE;
  tree->nodes[tree->nodeCapacity - 1u].height = -1;
  tree->freeList = node;
}

static uint32 dt_allocate_node(b3DynamicTree *tree) {
  if (tree->freeList == B3_NULL_DYNAMIC_NODE) {
    uint32 oldCapacity = tree->nodeCapacity;
    uint32 newCapacity = oldCapacity * 2u;
    b3DynamicNode *newNodes =
        (b3DynamicNode *)calloc(newCapacity, sizeof(b3DynamicNode));
    if (newNodes == NULL) {
      return B3_NULL_DYNAMIC_NODE;
    }
    memcpy(newNodes, tree->nodes, oldCapacity * sizeof(b3DynamicNode));
    free(tree->nodes);
    tree->nodes = newNodes;
    tree->nodeCapacity = newCapacity;
    dt_add_to_free_list(tree, oldCapacity);
  }

  uint32 node = tree->freeList;
  tree->freeList = tree->nodes[node].next;
  tree->nodes[node].parent = B3_NULL_DYNAMIC_NODE;
  tree->nodes[node].child1 = B3_NULL_DYNAMIC_NODE;
  tree->nodes[node].child2 = B3_NULL_DYNAMIC_NODE;
  tree->nodes[node].height = 0;
  tree->nodes[node].userData = NULL;
  tree->nodeCount++;
  return node;
}

static void dt_free_node(b3DynamicTree *tree, uint32 node) {
  tree->nodes[node].next = tree->freeList;
  tree->nodes[node].height = -1;
  tree->freeList = node;
  tree->nodeCount--;
}

static uint32 dt_balance(b3DynamicTree *tree, uint32 iA) {
  b3DynamicNode *A = tree->nodes + iA;
  if (dt_node_is_leaf(A) || A->height < 2) {
    return iA;
  }

  uint32 iB = A->child1;
  uint32 iC = A->child2;
  b3DynamicNode *B = tree->nodes + iB;
  b3DynamicNode *C = tree->nodes + iC;
  int32_t balance = C->height - B->height;

  if (balance > 1) {
    uint32 iF = C->child1;
    uint32 iG = C->child2;
    b3DynamicNode *F = tree->nodes + iF;
    b3DynamicNode *G = tree->nodes + iG;

    C->child1 = iA;
    C->parent = A->parent;
    A->parent = iC;

    if (C->parent != B3_NULL_DYNAMIC_NODE) {
      if (tree->nodes[C->parent].child1 == iA) {
        tree->nodes[C->parent].child1 = iC;
      } else {
        tree->nodes[C->parent].child2 = iC;
      }
    } else {
      tree->root = iC;
    }

    if (F->height > G->height) {
      C->child2 = iF;
      A->child2 = iG;
      G->parent = iA;
      A->aabb = b3AABB_Combine(B->aabb, G->aabb);
      C->aabb = b3AABB_Combine(A->aabb, F->aabb);
      A->height = 1 + dt_max_i32(B->height, G->height);
      C->height = 1 + dt_max_i32(A->height, F->height);
    } else {
      C->child2 = iG;
      A->child2 = iF;
      F->parent = iA;
      A->aabb = b3AABB_Combine(B->aabb, F->aabb);
      C->aabb = b3AABB_Combine(A->aabb, G->aabb);
      A->height = 1 + dt_max_i32(B->height, F->height);
      C->height = 1 + dt_max_i32(A->height, G->height);
    }
    return iC;
  }

  if (balance < -1) {
    uint32 iD = B->child1;
    uint32 iE = B->child2;
    b3DynamicNode *D = tree->nodes + iD;
    b3DynamicNode *E = tree->nodes + iE;

    B->child1 = iA;
    B->parent = A->parent;
    A->parent = iB;

    if (B->parent != B3_NULL_DYNAMIC_NODE) {
      if (tree->nodes[B->parent].child1 == iA) {
        tree->nodes[B->parent].child1 = iB;
      } else {
        tree->nodes[B->parent].child2 = iB;
      }
    } else {
      tree->root = iB;
    }

    if (D->height > E->height) {
      B->child2 = iD;
      A->child1 = iE;
      E->parent = iA;
      A->aabb = b3AABB_Combine(C->aabb, E->aabb);
      B->aabb = b3AABB_Combine(A->aabb, D->aabb);
      A->height = 1 + dt_max_i32(C->height, E->height);
      B->height = 1 + dt_max_i32(A->height, D->height);
    } else {
      B->child2 = iE;
      A->child1 = iD;
      D->parent = iA;
      A->aabb = b3AABB_Combine(C->aabb, D->aabb);
      B->aabb = b3AABB_Combine(A->aabb, E->aabb);
      A->height = 1 + dt_max_i32(C->height, D->height);
      B->height = 1 + dt_max_i32(A->height, E->height);
    }
    return iB;
  }

  return iA;
}

static void dt_refit(b3DynamicTree *tree, uint32 node) {
  while (node != B3_NULL_DYNAMIC_NODE) {
    node = dt_balance(tree, node);
    uint32 child1 = tree->nodes[node].child1;
    uint32 child2 = tree->nodes[node].child2;
    tree->nodes[node].height =
        1 + dt_max_i32(tree->nodes[child1].height, tree->nodes[child2].height);
    tree->nodes[node].aabb =
        b3AABB_Combine(tree->nodes[child1].aabb, tree->nodes[child2].aabb);
    node = tree->nodes[node].parent;
  }
}

static uint32 dt_pick_best(const b3DynamicTree *tree, b3AABB leafAABB) {
  uint32 index = tree->root;
  while (!dt_node_is_leaf(&tree->nodes[index])) {
    scalar branchArea = b3AABB_GetSurfaceArea(tree->nodes[index].aabb);
    b3AABB combinedAABB = b3AABB_Combine(leafAABB, tree->nodes[index].aabb);
    scalar combinedArea = b3AABB_GetSurfaceArea(combinedAABB);
    scalar branchCost = 2.0f * combinedArea;
    scalar inheritanceCost = 2.0f * (combinedArea - branchArea);
    uint32 child1 = tree->nodes[index].child1;
    uint32 child2 = tree->nodes[index].child2;

    b3AABB aabb1 = b3AABB_Combine(leafAABB, tree->nodes[child1].aabb);
    scalar childCost1;
    if (dt_node_is_leaf(&tree->nodes[child1])) {
      childCost1 = b3AABB_GetSurfaceArea(aabb1);
    } else {
      childCost1 = (b3AABB_GetSurfaceArea(aabb1) -
                    b3AABB_GetSurfaceArea(tree->nodes[child1].aabb)) +
                   inheritanceCost;
    }

    b3AABB aabb2 = b3AABB_Combine(leafAABB, tree->nodes[child2].aabb);
    scalar childCost2;
    if (dt_node_is_leaf(&tree->nodes[child2])) {
      childCost2 = b3AABB_GetSurfaceArea(aabb2);
    } else {
      childCost2 = (b3AABB_GetSurfaceArea(aabb2) -
                    b3AABB_GetSurfaceArea(tree->nodes[child2].aabb)) +
                   inheritanceCost;
    }

    if (branchCost < childCost1 && branchCost < childCost2) {
      break;
    }
    index = childCost1 < childCost2 ? child1 : child2;
  }
  return index;
}

static void dt_insert_leaf(b3DynamicTree *tree, uint32 leaf) {
  if (tree->root == B3_NULL_DYNAMIC_NODE) {
    tree->root = leaf;
    tree->nodes[tree->root].parent = B3_NULL_DYNAMIC_NODE;
    return;
  }

  b3AABB leafAABB = tree->nodes[leaf].aabb;
  uint32 sibling = dt_pick_best(tree, leafAABB);
  uint32 oldParent = tree->nodes[sibling].parent;
  uint32 newParent = dt_allocate_node(tree);
  if (newParent == B3_NULL_DYNAMIC_NODE) {
    return;
  }

  tree->nodes[newParent].parent = oldParent;
  tree->nodes[newParent].child1 = sibling;
  tree->nodes[sibling].parent = newParent;
  tree->nodes[newParent].child2 = leaf;
  tree->nodes[leaf].parent = newParent;
  tree->nodes[newParent].userData = NULL;
  tree->nodes[newParent].aabb = b3AABB_Combine(leafAABB, tree->nodes[sibling].aabb);
  tree->nodes[newParent].height = tree->nodes[sibling].height + 1;

  if (oldParent != B3_NULL_DYNAMIC_NODE) {
    if (tree->nodes[oldParent].child1 == sibling) {
      tree->nodes[oldParent].child1 = newParent;
    } else {
      tree->nodes[oldParent].child2 = newParent;
    }
  } else {
    tree->root = newParent;
  }

  dt_refit(tree, tree->nodes[leaf].parent);
}

static void dt_remove_leaf(b3DynamicTree *tree, uint32 leaf) {
  if (leaf == tree->root) {
    tree->root = B3_NULL_DYNAMIC_NODE;
    return;
  }

  uint32 parent = tree->nodes[leaf].parent;
  uint32 grandParent = tree->nodes[parent].parent;
  uint32 sibling = tree->nodes[parent].child1 == leaf ? tree->nodes[parent].child2
                                                      : tree->nodes[parent].child1;

  if (grandParent != B3_NULL_DYNAMIC_NODE) {
    if (tree->nodes[grandParent].child1 == parent) {
      tree->nodes[grandParent].child1 = sibling;
    } else {
      tree->nodes[grandParent].child2 = sibling;
    }
    tree->nodes[sibling].parent = grandParent;
    dt_free_node(tree, parent);
    dt_refit(tree, grandParent);
  } else {
    tree->root = sibling;
    tree->nodes[sibling].parent = B3_NULL_DYNAMIC_NODE;
    dt_free_node(tree, parent);
  }
}

b3DynamicTree *b3DynamicTree_Create(void) {
  b3DynamicTree *tree = (b3DynamicTree *)calloc(1, sizeof(*tree));
  if (tree == NULL) {
    return NULL;
  }

  tree->root = B3_NULL_DYNAMIC_NODE;
  tree->nodeCapacity = 32u;
  tree->nodes = (b3DynamicNode *)calloc(tree->nodeCapacity, sizeof(b3DynamicNode));
  if (tree->nodes == NULL) {
    free(tree);
    return NULL;
  }
  dt_add_to_free_list(tree, 0u);
  return tree;
}

void b3DynamicTree_Destroy(b3DynamicTree *tree) {
  if (tree == NULL) {
    return;
  }
  free(tree->nodes);
  free(tree);
}

uint32 b3DynamicTree_CreateProxy(b3DynamicTree *tree, b3AABB aabb,
                                 void *userData) {
  if (tree == NULL) {
    return B3_NULL_DYNAMIC_NODE;
  }

  uint32 proxyId = dt_allocate_node(tree);
  if (proxyId == B3_NULL_DYNAMIC_NODE) {
    return B3_NULL_DYNAMIC_NODE;
  }
  tree->nodes[proxyId].aabb = aabb;
  dt_aabb_extend(&tree->nodes[proxyId].aabb, B3_AABB_EXTENSION);
  tree->nodes[proxyId].userData = userData;
  tree->nodes[proxyId].height = 0;
  dt_insert_leaf(tree, proxyId);
  return proxyId;
}

void b3DynamicTree_DestroyProxy(b3DynamicTree *tree, uint32 proxyId) {
  if (tree == NULL || proxyId == B3_NULL_DYNAMIC_NODE ||
      proxyId >= tree->nodeCapacity || !dt_node_is_leaf(&tree->nodes[proxyId])) {
    return;
  }
  dt_remove_leaf(tree, proxyId);
  dt_free_node(tree, proxyId);
}

bool b3DynamicTree_MoveProxy(b3DynamicTree *tree, uint32 proxyId, b3AABB aabb,
                             b3Vec3 displacement) {
  if (tree == NULL || proxyId == B3_NULL_DYNAMIC_NODE ||
      proxyId >= tree->nodeCapacity || !dt_node_is_leaf(&tree->nodes[proxyId])) {
    return false;
  }

  b3AABB fatAABB = aabb;
  dt_aabb_extend(&fatAABB, B3_AABB_EXTENSION);
  b3Vec3 d = dt_vec3_mul(displacement, B3_AABB_MULTIPLIER);

  if (d.x < 0.0f) {
    fatAABB.lowerBound.x += d.x;
  } else {
    fatAABB.upperBound.x += d.x;
  }
  if (d.y < 0.0f) {
    fatAABB.lowerBound.y += d.y;
  } else {
    fatAABB.upperBound.y += d.y;
  }
  if (d.z < 0.0f) {
    fatAABB.lowerBound.z += d.z;
  } else {
    fatAABB.upperBound.z += d.z;
  }

  b3AABB treeAABB = tree->nodes[proxyId].aabb;
  if (b3AABB_ContainsAABB(treeAABB, aabb)) {
    b3AABB hugeAABB = fatAABB;
    dt_aabb_extend(&hugeAABB, 4.0f * B3_AABB_EXTENSION);
    if (b3AABB_ContainsAABB(hugeAABB, treeAABB)) {
      return false;
    }
  }

  dt_remove_leaf(tree, proxyId);
  tree->nodes[proxyId].aabb = fatAABB;
  dt_insert_leaf(tree, proxyId);
  return true;
}

b3AABB b3DynamicTree_GetFatAABB(const b3DynamicTree *tree, uint32 proxyId) {
  if (tree == NULL || proxyId == B3_NULL_DYNAMIC_NODE ||
      proxyId >= tree->nodeCapacity) {
    return b3AABB_Make(b3Vec3_Make(0.0f, 0.0f, 0.0f),
                       b3Vec3_Make(0.0f, 0.0f, 0.0f));
  }
  return tree->nodes[proxyId].aabb;
}

void *b3DynamicTree_GetUserData(const b3DynamicTree *tree, uint32 proxyId) {
  if (tree == NULL || proxyId == B3_NULL_DYNAMIC_NODE ||
      proxyId >= tree->nodeCapacity) {
    return NULL;
  }
  return tree->nodes[proxyId].userData;
}

bool b3DynamicTree_TestOverlap(const b3DynamicTree *tree, uint32 proxy1,
                               uint32 proxy2) {
  if (tree == NULL || proxy1 == B3_NULL_DYNAMIC_NODE ||
      proxy2 == B3_NULL_DYNAMIC_NODE || proxy1 >= tree->nodeCapacity ||
      proxy2 >= tree->nodeCapacity) {
    return false;
  }
  return b3AABB_TestOverlap(tree->nodes[proxy1].aabb, tree->nodes[proxy2].aabb);
}

void b3DynamicTree_QueryAABB(const b3DynamicTree *tree, b3AABB aabb,
                             b3DynamicTreeQueryCallback callback,
                             void *context) {
  if (tree == NULL || callback == NULL) {
    return;
  }

  uint32 capacity = 256u;
  uint32 count = 0u;
  uint32 localStack[256];
  uint32 *stack = localStack;
  stack[count++] = tree->root;

  while (count > 0u) {
    uint32 nodeIndex = stack[--count];
    if (nodeIndex == B3_NULL_DYNAMIC_NODE) {
      continue;
    }

    const b3DynamicNode *node = tree->nodes + nodeIndex;
    if (!b3AABB_TestOverlap(node->aabb, aabb)) {
      continue;
    }

    if (dt_node_is_leaf(node)) {
      if (!callback(nodeIndex, context)) {
        break;
      }
    } else {
      if (!dt_reserve_stack(&stack, &capacity, count + 2u)) {
        break;
      }
      stack[count++] = node->child1;
      stack[count++] = node->child2;
    }
  }

  if (stack != localStack) {
    free(stack);
  }
}

void b3DynamicTree_RayCast(const b3DynamicTree *tree, b3RayCastInput input,
                           b3DynamicTreeRayCastCallback callback,
                           void *context) {
  if (tree == NULL || callback == NULL ||
      dt_vec3_length_sq(dt_vec3_sub(input.p2, input.p1)) <= B3_EPSILON) {
    return;
  }

  b3Vec3 p1 = input.p1;
  b3Vec3 p2 = input.p2;
  b3Vec3 r = dt_vec3_normalize(dt_vec3_sub(p2, p1));
  scalar maxFraction = input.maxFraction;
  b3Vec3 q2 = dt_vec3_add(p1, dt_vec3_mul(dt_vec3_sub(p2, p1), maxFraction));
  b3AABB segmentAABB = b3AABB_Make(dt_vec3_min(p1, q2), dt_vec3_max(p1, q2));

  uint32 capacity = 256u;
  uint32 count = 0u;
  uint32 localStack[256];
  uint32 *stack = localStack;
  stack[count++] = tree->root;

  while (count > 0u) {
    uint32 nodeIndex = stack[--count];
    if (nodeIndex == B3_NULL_DYNAMIC_NODE) {
      continue;
    }

    const b3DynamicNode *node = tree->nodes + nodeIndex;
    if (!b3AABB_TestOverlap(segmentAABB, node->aabb)) {
      continue;
    }

    b3Vec3 c = dt_aabb_center(node->aabb);
    b3Vec3 h = dt_aabb_extents(node->aabb);
    b3Vec3 s = dt_vec3_sub(p1, c);
    b3Vec3 t = dt_vec3_sub(q2, c);
    scalar test = fabsf(s.x + t.x) - (fabsf(s.x - t.x) + 2.0f * h.x);
    if (test > 0.0f) {
      continue;
    }
    test = fabsf(s.y + t.y) - (fabsf(s.y - t.y) + 2.0f * h.y);
    if (test > 0.0f) {
      continue;
    }
    test = fabsf(s.z + t.z) - (fabsf(s.z - t.z) + 2.0f * h.z);
    if (test > 0.0f) {
      continue;
    }

    b3Vec3 axes[3] = {
        b3Vec3_Make(1.0f, 0.0f, 0.0f),
        b3Vec3_Make(0.0f, 1.0f, 0.0f),
        b3Vec3_Make(0.0f, 0.0f, 1.0f),
    };
    bool separated = false;
    for (int i = 0; i < 3; ++i) {
      b3Vec3 v = dt_vec3_cross(axes[i], r);
      test = fabsf(dt_vec3_dot(v, s)) - dt_vec3_dot(dt_vec3_abs(v), h);
      if (test > 0.0f) {
        separated = true;
        break;
      }
    }
    if (separated) {
      continue;
    }

    if (dt_node_is_leaf(node)) {
      b3RayCastInput subInput = input;
      subInput.maxFraction = maxFraction;
      scalar newMaxFraction = callback(&subInput, nodeIndex, context);
      if (newMaxFraction == 0.0f) {
        break;
      }
      if (newMaxFraction > 0.0f) {
        maxFraction = newMaxFraction;
        q2 = dt_vec3_add(p1, dt_vec3_mul(dt_vec3_sub(p2, p1), maxFraction));
        segmentAABB = b3AABB_Make(dt_vec3_min(p1, q2), dt_vec3_max(p1, q2));
      }
    } else {
      if (!dt_reserve_stack(&stack, &capacity, count + 2u)) {
        break;
      }
      stack[count++] = node->child1;
      stack[count++] = node->child2;
    }
  }

  if (stack != localStack) {
    free(stack);
  }
}

uint32 b3DynamicTree_GetNodeCount(const b3DynamicTree *tree) {
  return tree != NULL ? tree->nodeCount : 0u;
}

uint32 b3DynamicTree_GetHeight(const b3DynamicTree *tree) {
  if (tree == NULL || tree->root == B3_NULL_DYNAMIC_NODE) {
    return 0u;
  }
  return (uint32)tree->nodes[tree->root].height;
}

void b3DynamicTree_DebugDraw(const b3DynamicTree *tree,
                             const b3DebugDraw *draw) {
  if (tree == NULL || draw == NULL || draw->DrawAABB == NULL ||
      tree->root == B3_NULL_DYNAMIC_NODE) {
    return;
  }

  uint32 capacity = 256u;
  uint32 count = 0u;
  uint32 localStack[256];
  uint32 *stack = localStack;
  stack[count++] = tree->root;

  while (count > 0u) {
    uint32 nodeIndex = stack[--count];
    if (nodeIndex == B3_NULL_DYNAMIC_NODE) {
      continue;
    }

    const b3DynamicNode *node = tree->nodes + nodeIndex;
    if (dt_node_is_leaf(node)) {
      draw->DrawAABB(draw->context, node->aabb,
                     (b3Color){1.0f, 0.0f, 0.0f, 1.0f});
      continue;
    }

    draw->DrawAABB(draw->context, node->aabb,
                   (b3Color){0.0f, 1.0f, 0.0f, 1.0f});
    if (!dt_reserve_stack(&stack, &capacity, count + 2u)) {
      break;
    }
    stack[count++] = node->child1;
    stack[count++] = node->child2;
  }

  if (stack != localStack) {
    free(stack);
  }
}

static bool broad_phase_buffer_move(b3BroadPhase *broadPhase, uint32 proxyId) {
  if (broadPhase == NULL || proxyId == B3_NULL_PROXY) {
    return false;
  }

  if (broadPhase->moveBufferCount == broadPhase->moveBufferCapacity) {
    uint32 newCapacity = broadPhase->moveBufferCapacity * 2u;
    uint32 *newBuffer =
        (uint32 *)realloc(broadPhase->moveBuffer,
                          newCapacity * sizeof(*broadPhase->moveBuffer));
    if (newBuffer == NULL) {
      return false;
    }
    broadPhase->moveBuffer = newBuffer;
    broadPhase->moveBufferCapacity = newCapacity;
  }

  broadPhase->moveBuffer[broadPhase->moveBufferCount++] = proxyId;
  return true;
}

static void broad_phase_unbuffer_move(b3BroadPhase *broadPhase,
                                      uint32 proxyId) {
  if (broadPhase == NULL) {
    return;
  }
  for (uint32 i = 0u; i < broadPhase->moveBufferCount; ++i) {
    if (broadPhase->moveBuffer[i] == proxyId) {
      broadPhase->moveBuffer[i] = B3_NULL_PROXY;
    }
  }
}

static bool broad_phase_add_pair(b3BroadPhase *broadPhase, uint32 proxy1,
                                 uint32 proxy2) {
  if (broadPhase == NULL || proxy1 == proxy2 || proxy1 == B3_NULL_PROXY ||
      proxy2 == B3_NULL_PROXY) {
    return false;
  }

  if (broadPhase->pairCount == broadPhase->pairCapacity) {
    uint32 newCapacity = broadPhase->pairCapacity * 2u;
    b3Pair *newPairs =
        (b3Pair *)realloc(broadPhase->pairs,
                          newCapacity * sizeof(*broadPhase->pairs));
    if (newPairs == NULL) {
      return false;
    }
    broadPhase->pairs = newPairs;
    broadPhase->pairCapacity = newCapacity;
  }

  b3Pair *pair = &broadPhase->pairs[broadPhase->pairCount++];
  pair->proxy1 = proxy1 < proxy2 ? proxy1 : proxy2;
  pair->proxy2 = proxy1 < proxy2 ? proxy2 : proxy1;
  return true;
}

static bool broad_phase_report_proxy(uint32 proxyId, void *context) {
  b3BroadPhase *broadPhase = (b3BroadPhase *)context;
  if (broadPhase == NULL || proxyId == broadPhase->queryProxyId) {
    return true;
  }
  broad_phase_add_pair(broadPhase, proxyId, broadPhase->queryProxyId);
  return true;
}

static uint64_t broad_phase_pair_key(b3Pair pair) {
  return ((uint64_t)pair.proxy1 << 32u) | (uint64_t)pair.proxy2;
}

static bool broad_phase_pair_less(b3Pair a, b3Pair b) {
  return broad_phase_pair_key(a) < broad_phase_pair_key(b);
}

static void broad_phase_swap_pairs(b3Pair *a, b3Pair *b) {
  b3Pair tmp = *a;
  *a = *b;
  *b = tmp;
}

static void broad_phase_sift_pair_heap(b3Pair *pairs, uint32 root,
                                       uint32 end) {
  while (true) {
    uint32 child = 2u * root + 1u;
    if (child >= end) {
      return;
    }
    if (child + 1u < end &&
        broad_phase_pair_less(pairs[child], pairs[child + 1u])) {
      ++child;
    }
    if (!broad_phase_pair_less(pairs[root], pairs[child])) {
      return;
    }
    broad_phase_swap_pairs(&pairs[root], &pairs[child]);
    root = child;
  }
}

static void broad_phase_sort_pairs(b3Pair *pairs, uint32 count) {
  if (pairs == NULL || count < 2u) {
    return;
  }

  for (uint32 start = count / 2u; start > 0u; --start) {
    broad_phase_sift_pair_heap(pairs, start - 1u, count);
  }
  for (uint32 end = count; end > 1u; --end) {
    broad_phase_swap_pairs(&pairs[0], &pairs[end - 1u]);
    broad_phase_sift_pair_heap(pairs, 0u, end - 1u);
  }
}

b3BroadPhase *b3BroadPhase_Create(void) {
  b3BroadPhase *broadPhase = (b3BroadPhase *)calloc(1, sizeof(*broadPhase));
  if (broadPhase == NULL) {
    return NULL;
  }

  broadPhase->tree = b3DynamicTree_Create();
  broadPhase->moveBufferCapacity = 16u;
  broadPhase->pairCapacity = 16u;
  broadPhase->moveBuffer =
      (uint32 *)calloc(broadPhase->moveBufferCapacity,
                       sizeof(*broadPhase->moveBuffer));
  broadPhase->pairs =
      (b3Pair *)calloc(broadPhase->pairCapacity, sizeof(*broadPhase->pairs));
  broadPhase->queryProxyId = B3_NULL_PROXY;
  if (broadPhase->tree == NULL || broadPhase->moveBuffer == NULL ||
      broadPhase->pairs == NULL) {
    b3BroadPhase_Destroy(broadPhase);
    return NULL;
  }
  return broadPhase;
}

void b3BroadPhase_Destroy(b3BroadPhase *broadPhase) {
  if (broadPhase == NULL) {
    return;
  }
  b3DynamicTree_Destroy(broadPhase->tree);
  free(broadPhase->moveBuffer);
  free(broadPhase->pairs);
  free(broadPhase);
}

uint32 b3BroadPhase_CreateProxy(b3BroadPhase *broadPhase, b3AABB aabb,
                                void *userData) {
  if (broadPhase == NULL || broadPhase->tree == NULL) {
    return B3_NULL_PROXY;
  }
  uint32 proxyId = b3DynamicTree_CreateProxy(broadPhase->tree, aabb, userData);
  if (proxyId == B3_NULL_DYNAMIC_NODE) {
    return B3_NULL_PROXY;
  }
  ++broadPhase->proxyCount;
  broad_phase_buffer_move(broadPhase, proxyId);
  return proxyId;
}

void b3BroadPhase_DestroyProxy(b3BroadPhase *broadPhase, uint32 proxyId) {
  if (broadPhase == NULL || proxyId == B3_NULL_PROXY) {
    return;
  }
  if (broadPhase->tree == NULL || proxyId >= broadPhase->tree->nodeCapacity ||
      !dt_node_is_leaf(&broadPhase->tree->nodes[proxyId])) {
    return;
  }
  broad_phase_unbuffer_move(broadPhase, proxyId);
  if (broadPhase->proxyCount > 0u) {
    --broadPhase->proxyCount;
  }
  b3DynamicTree_DestroyProxy(broadPhase->tree, proxyId);
}

void b3BroadPhase_MoveProxy(b3BroadPhase *broadPhase, uint32 proxyId,
                            b3AABB aabb, b3Vec3 displacement) {
  if (broadPhase == NULL || proxyId == B3_NULL_PROXY) {
    return;
  }
  if (b3DynamicTree_MoveProxy(broadPhase->tree, proxyId, aabb, displacement)) {
    broad_phase_buffer_move(broadPhase, proxyId);
  }
}

void b3BroadPhase_TouchProxy(b3BroadPhase *broadPhase, uint32 proxyId) {
  broad_phase_buffer_move(broadPhase, proxyId);
}

b3AABB b3BroadPhase_GetFatAABB(const b3BroadPhase *broadPhase,
                               uint32 proxyId) {
  return broadPhase != NULL ? b3DynamicTree_GetFatAABB(broadPhase->tree, proxyId)
                            : b3AABB_Make(b3Vec3_Make(0.0f, 0.0f, 0.0f),
                                          b3Vec3_Make(0.0f, 0.0f, 0.0f));
}

void *b3BroadPhase_GetUserData(const b3BroadPhase *broadPhase,
                               uint32 proxyId) {
  return broadPhase != NULL ? b3DynamicTree_GetUserData(broadPhase->tree,
                                                        proxyId)
                            : NULL;
}

uint32 b3BroadPhase_GetProxyCount(const b3BroadPhase *broadPhase) {
  return broadPhase != NULL ? broadPhase->proxyCount : 0u;
}

bool b3BroadPhase_TestOverlap(const b3BroadPhase *broadPhase, uint32 proxy1,
                              uint32 proxy2) {
  return broadPhase != NULL &&
         b3DynamicTree_TestOverlap(broadPhase->tree, proxy1, proxy2);
}

void b3BroadPhase_QueryAABB(const b3BroadPhase *broadPhase, b3AABB aabb,
                            b3DynamicTreeQueryCallback callback,
                            void *context) {
  if (broadPhase == NULL) {
    return;
  }
  b3DynamicTree_QueryAABB(broadPhase->tree, aabb, callback, context);
}

void b3BroadPhase_RayCast(const b3BroadPhase *broadPhase,
                          b3RayCastInput input,
                          b3DynamicTreeRayCastCallback callback,
                          void *context) {
  if (broadPhase == NULL) {
    return;
  }
  b3DynamicTree_RayCast(broadPhase->tree, input, callback, context);
}

void b3BroadPhase_FindPairs(b3BroadPhase *broadPhase,
                            b3BroadPhasePairCallback callback,
                            void *context) {
  if (broadPhase == NULL || broadPhase->tree == NULL) {
    return;
  }

  broadPhase->pairCount = 0u;
  for (uint32 i = 0u; i < broadPhase->moveBufferCount; ++i) {
    broadPhase->queryProxyId = broadPhase->moveBuffer[i];
    if (broadPhase->queryProxyId == B3_NULL_PROXY) {
      continue;
    }
    b3AABB aabb =
        b3DynamicTree_GetFatAABB(broadPhase->tree, broadPhase->queryProxyId);
    b3DynamicTree_QueryAABB(broadPhase->tree, aabb, broad_phase_report_proxy,
                            broadPhase);
  }
  broadPhase->queryProxyId = B3_NULL_PROXY;
  broadPhase->moveBufferCount = 0u;

  if (broadPhase->pairCount == 0u || callback == NULL) {
    return;
  }

  broad_phase_sort_pairs(broadPhase->pairs, broadPhase->pairCount);
  uint32 index = 0u;
  while (index < broadPhase->pairCount) {
    b3Pair pair = broadPhase->pairs[index];
    callback(b3DynamicTree_GetUserData(broadPhase->tree, pair.proxy1),
             b3DynamicTree_GetUserData(broadPhase->tree, pair.proxy2),
             context);

    ++index;
    while (index < broadPhase->pairCount &&
           broadPhase->pairs[index].proxy1 == pair.proxy1 &&
           broadPhase->pairs[index].proxy2 == pair.proxy2) {
      ++index;
    }
  }
}

void b3BroadPhase_DebugDraw(const b3BroadPhase *broadPhase,
                            const b3DebugDraw *draw) {
  if (broadPhase == NULL) {
    return;
  }
  b3DynamicTree_DebugDraw(broadPhase->tree, draw);
}
