void b3CollideTriangleAndHull(b3Manifold *manifold, b3Transform xf1,
                              const b3TriangleShape *shape1, b3Transform xf2,
                              const b3HullShape *shape2) {
  b3Vec3 hullGuardScratch[8];
  const b3Vec3 *hullGuardVertices = NULL;
  uint32 hullGuardVertexCount = 0u;
  if (manifold == NULL || shape1 == NULL || shape2 == NULL ||
      !collide_hull_vertices(shape2, hullGuardScratch, &hullGuardVertices,
                             &hullGuardVertexCount)) {
    return;
  }
  b3Manifold_Clear(manifold);

  b3Vec3 triangleLocal[3] = {shape1->vertex1, shape1->vertex2,
                             shape1->vertex3};
  b3Vec3 triangleWorld[3];
  transform_vertices(xf1, triangleLocal, triangleWorld, 3u);

  if (shape2->genericHull != NULL || hull_shape_has_builtin_topology(shape2)) {
    b3HullTopology triangleTopology;
    b3HullTopology hullTopology;
    b3BuiltInHullTopology builtIn;
    b3HalfEdge triangleEdges[6];
    b3Face triangleFaces[2];
    b3Plane trianglePlanes[2];
    b3HullShape triangleHullShape;
    b3HullShape_InitWithVertices(&triangleHullShape, triangleLocal, 3u,
                                 shape1->base.radius);
    if (triangle_topology_from_shape(shape1, triangleLocal, triangleEdges,
                                     triangleFaces, trianglePlanes,
                                     &triangleTopology) &&
        hull_topology_from_shape_with_builtin(shape2, &hullTopology,
                                              &builtIn) &&
        collide_topology_hulls(manifold, xf1, &triangleHullShape,
                               &triangleTopology, xf2, shape2, &hullTopology,
                               10.0f * B3_EPSILON, 10.0f * B3_EPSILON,
                               NULL)) {
      return;
    }
  }

  if (build_triangle_vertex_hull_contacts(manifold, xf1, shape1,
                                          triangleWorld, xf2, shape2)) {
    return;
  }

  if (shape2->hull == NULL) {
    b3GJKProxy triangleProxy;
    b3GJKProxy hullProxy;
    b3Vec3 hullScratch[8];
    b3GJKProxy_Init(&triangleProxy, triangleLocal, 3u, shape1->base.radius);
    if (!collide_hull_proxy(shape2, hullScratch, &hullProxy)) {
      return;
    }
    b3GJKOutput gjk =
        b3GJK_Distance(xf1, &triangleProxy, xf2, &hullProxy, false, NULL);
    scalar totalRadius = shape1->base.radius + shape2->base.radius;
    if (gjk.distance > totalRadius) {
      return;
    }
    set_gjk_manifold_point(manifold, xf1, xf2, &gjk);
    return;
  }

  b3Vec3 boxLocal[8];
  b3Vec3 boxWorld[8];
  box_hull_vertices(shape2->hull, boxLocal);
  transform_vertices(xf2, boxLocal, boxWorld, 8u);

  b3Vec3 triangleCenter =
      collide_vec3_mul(collide_vec3_add(
                           collide_vec3_add(triangleWorld[0], triangleWorld[1]),
                           triangleWorld[2]),
                       1.0f / 3.0f);
  b3Vec3 boxCenter = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  for (uint32 i = 0u; i < 8u; ++i) {
    boxCenter = collide_vec3_add(boxCenter, boxWorld[i]);
  }
  boxCenter = collide_vec3_mul(boxCenter, 1.0f / 8.0f);
  b3Vec3 centerDelta = collide_vec3_sub(boxCenter, triangleCenter);

  scalar bestPenetration = 3.402823466e+38f;
  b3Vec3 bestAxis = b3Vec3_Make(0.0f, 1.0f, 0.0f);

  b3Vec3 triEdges[3] = {
      collide_vec3_sub(triangleWorld[1], triangleWorld[0]),
      collide_vec3_sub(triangleWorld[2], triangleWorld[1]),
      collide_vec3_sub(triangleWorld[0], triangleWorld[2]),
  };
  b3Vec3 triNormal = collide_cross(triEdges[0],
                                   collide_vec3_sub(triangleWorld[2],
                                                    triangleWorld[0]));
  if (!test_sat_axis_counts(triangleWorld, 3u, boxWorld, 8u, centerDelta,
                            triNormal, &bestPenetration, &bestAxis)) {
    return;
  }

  b3Vec3 boxAxes[3] = {
      rotate_local_to_world(xf2, b3Vec3_Make(1.0f, 0.0f, 0.0f)),
      rotate_local_to_world(xf2, b3Vec3_Make(0.0f, 1.0f, 0.0f)),
      rotate_local_to_world(xf2, b3Vec3_Make(0.0f, 0.0f, 1.0f)),
  };
  for (uint32 i = 0u; i < 3u; ++i) {
    if (!test_sat_axis_counts(triangleWorld, 3u, boxWorld, 8u, centerDelta,
                              boxAxes[i], &bestPenetration, &bestAxis)) {
      return;
    }
  }

  for (uint32 i = 0u; i < 3u; ++i) {
    for (uint32 j = 0u; j < 3u; ++j) {
      if (!test_sat_axis_counts(triangleWorld, 3u, boxWorld, 8u, centerDelta,
                                collide_cross(triEdges[i], boxAxes[j]),
                                &bestPenetration, &bestAxis)) {
        return;
      }
    }
  }

  b3Vec3 point1 = support_vertex(triangleWorld, 3u, bestAxis);
  b3Vec3 point2 = support_vertex(boxWorld, 8u, collide_vec3_mul(bestAxis, -1.0f));
  set_single_manifold_point(manifold, rotate_world_to_local(xf1, bestAxis),
                            b3Transform_MulTPoint(xf1, point1),
                            b3Transform_MulTPoint(xf2, point2));
}

void b3CollideTriangleAndHullTopologyCached(
    b3Manifold *manifold, b3Transform xf1, const b3TriangleShape *shape1,
    b3Transform xf2, const b3HullShape *shape2, b3FeatureCache *cache) {
  b3Vec3 hullGuardScratch[8];
  const b3Vec3 *hullGuardVertices = NULL;
  uint32 hullGuardVertexCount = 0u;
  if (manifold == NULL || shape1 == NULL || shape2 == NULL ||
      !collide_hull_vertices(shape2, hullGuardScratch, &hullGuardVertices,
                             &hullGuardVertexCount)) {
    return;
  }
  b3Manifold_Clear(manifold);

  b3Vec3 triangleLocal[3] = {shape1->vertex1, shape1->vertex2,
                             shape1->vertex3};
  if (shape2->genericHull != NULL || hull_shape_has_builtin_topology(shape2)) {
    b3HullTopology triangleTopology;
    b3HullTopology hullTopology;
    b3BuiltInHullTopology builtIn;
    b3HalfEdge triangleEdges[6];
    b3Face triangleFaces[2];
    b3Plane trianglePlanes[2];
    b3HullShape triangleHullShape;
    b3HullShape_InitWithVertices(&triangleHullShape, triangleLocal, 3u,
                                 shape1->base.radius);
    if (triangle_topology_from_shape(shape1, triangleLocal, triangleEdges,
                                     triangleFaces, trianglePlanes,
                                     &triangleTopology) &&
        hull_topology_from_shape_with_builtin(shape2, &hullTopology,
                                              &builtIn) &&
        collide_topology_hulls(manifold, xf1, &triangleHullShape,
                               &triangleTopology, xf2, shape2, &hullTopology,
                               10.0f * B3_EPSILON, 10.0f * B3_EPSILON,
                               cache)) {
      return;
    }
  }

  if (cache != NULL) {
    cache->featurePair.state = e_empty;
  }
  b3CollideTriangleAndHull(manifold, xf1, shape1, xf2, shape2);
}

typedef struct b3MeshSphereCollideContext {
  b3Manifold *manifold;
  b3Transform meshTransform;
  const b3MeshShape *meshShape;
  b3Transform sphereTransform;
  const b3SphereShape *sphere;
} b3MeshSphereCollideContext;

typedef struct b3MeshManifoldCollector {
  b3Manifold manifolds[B3_MAX_CLUSTER_OBSERVATIONS];
  uint32 count;
} b3MeshManifoldCollector;

static bool mesh_collect_child_manifold(b3MeshManifoldCollector *collector,
                                        const b3Manifold *child,
                                        uint32 triangleKey) {
  if (collector == NULL || child == NULL || child->pointCount == 0u) {
    return true;
  }
  if (collector->count >= B3_MAX_CLUSTER_OBSERVATIONS) {
    return false;
  }

  b3Manifold *manifold = &collector->manifolds[collector->count++];
  *manifold = *child;
  for (uint32 i = 0u; i < manifold->pointCount; ++i) {
    manifold->points[i].key.triangleKey = triangleKey;
  }
  return collector->count < B3_MAX_CLUSTER_OBSERVATIONS;
}

static void mesh_cluster_child_manifolds(
    b3Manifold outManifolds[B3_MAX_MANIFOLDS], uint32 *outCount,
    const b3MeshManifoldCollector *collector, b3Transform meshTransform,
    scalar meshRadius, b3Transform shapeTransform, scalar shapeRadius) {
  if (outCount != NULL) {
    *outCount = 0u;
  }
  if (outManifolds == NULL || outCount == NULL) {
    return;
  }
  if (collector == NULL || collector->count == 0u) {
    for (uint32 i = 0u; i < B3_MAX_MANIFOLDS; ++i) {
      b3Manifold_Clear(&outManifolds[i]);
    }
    return;
  }

  b3ClusterSolver clusterSolver;
  b3ClusterSolver_Run(&clusterSolver, outManifolds, outCount,
                      collector->manifolds, collector->count, meshTransform,
                      meshRadius, shapeTransform, shapeRadius);
}

typedef struct b3MeshSphereManifoldContext {
  b3MeshManifoldCollector *collector;
  b3Transform meshTransform;
  const b3MeshShape *meshShape;
  b3Transform sphereTransform;
  const b3SphereShape *sphere;
} b3MeshSphereManifoldContext;

static bool mesh_sphere_collide_tree_callback(uint32 proxyId, void *context) {
  b3MeshSphereCollideContext *ctx = (b3MeshSphereCollideContext *)context;
  void *userData =
      b3DynamicTree_GetUserData(ctx->meshShape->mesh->tree, proxyId);
  uint32 index = 0u;
  if (!mesh_triangle_index_from_user_data(ctx->meshShape->mesh, userData,
                                          &index)) {
    return true;
  }

  b3TriangleShape triangle;
  if (!mesh_get_child_triangle(ctx->meshShape, index, &triangle)) {
    return true;
  }
  b3Manifold childManifold;
  b3CollideTriangleAndSphere(&childManifold, ctx->meshTransform, &triangle,
                             ctx->sphereTransform, ctx->sphere);
  append_mesh_child_manifold(ctx->manifold, &childManifold, index);
  return ctx->manifold->pointCount < B3_MAX_MANIFOLD_POINTS;
}

static bool mesh_sphere_manifold_tree_callback(uint32 proxyId, void *context) {
  b3MeshSphereManifoldContext *ctx =
      (b3MeshSphereManifoldContext *)context;
  void *userData =
      b3DynamicTree_GetUserData(ctx->meshShape->mesh->tree, proxyId);
  uint32 index = 0u;
  if (!mesh_triangle_index_from_user_data(ctx->meshShape->mesh, userData,
                                          &index)) {
    return true;
  }

  b3TriangleShape triangle;
  if (!mesh_get_child_triangle(ctx->meshShape, index, &triangle)) {
    return true;
  }
  b3Manifold childManifold;
  b3Manifold_Clear(&childManifold);
  b3CollideTriangleAndSphere(&childManifold, ctx->meshTransform, &triangle,
                             ctx->sphereTransform, ctx->sphere);
  return mesh_collect_child_manifold(ctx->collector, &childManifold, index);
}

