void b3CollideMeshAndSphere(b3Manifold *manifold, b3Transform xf1,
                            const b3MeshShape *shape1, b3Transform xf2,
                            const b3SphereShape *shape2) {
  if (manifold == NULL || shape1 == NULL || shape1->mesh == NULL ||
      shape2 == NULL) {
    return;
  }
  b3Manifold_Clear(manifold);
  if (mesh_shape_has_tree(shape1)) {
    b3Vec3 center =
        b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, shape2->center));
    scalar radius = shape1->base.radius + shape2->base.radius;
    b3Vec3 r = b3Vec3_Make(radius, radius, radius);
    b3AABB query =
        mesh_unscale_aabb(shape1, collide_vec3_sub(center, r),
                          collide_vec3_add(center, r));
    b3MeshSphereCollideContext context;
    context.manifold = manifold;
    context.meshTransform = xf1;
    context.meshShape = shape1;
    context.sphereTransform = xf2;
    context.sphere = shape2;
    b3DynamicTree_QueryAABB(shape1->mesh->tree, query,
                            mesh_sphere_collide_tree_callback, &context);
    return;
  }
  for (uint32 i = 0u; i < shape1->mesh->triangleCount; ++i) {
    b3TriangleShape triangle;
    if (!mesh_get_child_triangle(shape1, i, &triangle)) {
      continue;
    }
    b3Manifold childManifold;
    b3CollideTriangleAndSphere(&childManifold, xf1, &triangle, xf2, shape2);
    append_mesh_child_manifold(manifold, &childManifold, i);
    if (manifold->pointCount >= B3_MAX_MANIFOLD_POINTS) {
      return;
    }
  }
}

void b3CollideMeshAndSphereManifolds(
    b3Manifold outManifolds[B3_MAX_MANIFOLDS], uint32 *outCount,
    b3Transform xf1, const b3MeshShape *shape1, b3Transform xf2,
    const b3SphereShape *shape2) {
  if (outCount != NULL) {
    *outCount = 0u;
  }
  if (outManifolds == NULL || outCount == NULL || shape1 == NULL ||
      shape1->mesh == NULL || shape2 == NULL) {
    return;
  }

  b3MeshManifoldCollector collector;
  memset(&collector, 0, sizeof(collector));
  if (mesh_shape_has_tree(shape1)) {
    b3Vec3 center =
        b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, shape2->center));
    scalar radius = shape1->base.radius + shape2->base.radius;
    b3Vec3 r = b3Vec3_Make(radius, radius, radius);
    b3AABB query =
        mesh_unscale_aabb(shape1, collide_vec3_sub(center, r),
                          collide_vec3_add(center, r));
    b3MeshSphereManifoldContext context;
    context.collector = &collector;
    context.meshTransform = xf1;
    context.meshShape = shape1;
    context.sphereTransform = xf2;
    context.sphere = shape2;
    b3DynamicTree_QueryAABB(shape1->mesh->tree, query,
                            mesh_sphere_manifold_tree_callback, &context);
  } else {
    for (uint32 i = 0u; i < shape1->mesh->triangleCount; ++i) {
      b3TriangleShape triangle;
      if (!mesh_get_child_triangle(shape1, i, &triangle)) {
        continue;
      }
      b3Manifold childManifold;
      b3Manifold_Clear(&childManifold);
      b3CollideTriangleAndSphere(&childManifold, xf1, &triangle, xf2, shape2);
      if (!mesh_collect_child_manifold(&collector, &childManifold, i)) {
        break;
      }
    }
  }

  mesh_cluster_child_manifolds(outManifolds, outCount, &collector, xf1,
                               shape1->base.radius, xf2,
                               shape2->base.radius);
}

void b3CollideMeshAndCapsule(b3Manifold *manifold, b3Transform xf1,
                             const b3MeshShape *shape1, b3Transform xf2,
                             const b3CapsuleShape *shape2) {
  if (manifold == NULL || shape1 == NULL || shape1->mesh == NULL ||
      shape2 == NULL) {
    return;
  }
  b3Manifold_Clear(manifold);
  if (mesh_shape_has_tree(shape1)) {
    b3Vec3 p1 =
        b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, shape2->point1));
    b3Vec3 p2 =
        b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, shape2->point2));
    scalar radius = shape1->base.radius + shape2->base.radius;
    b3Vec3 r = b3Vec3_Make(radius, radius, radius);
    b3AABB query =
        mesh_unscale_aabb(shape1, collide_vec3_sub(collide_vec3_min(p1, p2), r),
                          collide_vec3_add(collide_vec3_max(p1, p2), r));
    b3MeshCapsuleCollideContext context;
    context.manifold = manifold;
    context.meshTransform = xf1;
    context.meshShape = shape1;
    context.capsuleTransform = xf2;
    context.capsule = shape2;
    b3DynamicTree_QueryAABB(shape1->mesh->tree, query,
                            mesh_capsule_collide_tree_callback, &context);
    return;
  }
  for (uint32 i = 0u; i < shape1->mesh->triangleCount; ++i) {
    b3TriangleShape triangle;
    if (!mesh_get_child_triangle(shape1, i, &triangle)) {
      continue;
    }
    b3Manifold childManifold;
    b3CollideTriangleAndCapsule(&childManifold, xf1, &triangle, xf2, shape2);
    append_mesh_child_manifold(manifold, &childManifold, i);
    if (manifold->pointCount >= B3_MAX_MANIFOLD_POINTS) {
      return;
    }
  }
}

