void b3CollideMeshAndHull(b3Manifold *manifold, b3Transform xf1,
                          const b3MeshShape *shape1, b3Transform xf2,
                          const b3HullShape *shape2) {
  if (manifold == NULL || shape1 == NULL || shape1->mesh == NULL ||
      shape2 == NULL ||
      (shape2->hull == NULL &&
       (shape2->vertices == NULL || shape2->vertexCount == 0u))) {
    return;
  }
  b3Manifold_Clear(manifold);
  if (mesh_shape_has_tree(shape1)) {
    b3Vec3 hullScratch[8];
    const b3Vec3 *hullVertices = NULL;
    uint32 hullVertexCount = 0u;
    if (!collide_hull_vertices(shape2, hullScratch, &hullVertices,
                               &hullVertexCount)) {
      return;
    }
    b3Vec3 lower = b3Transform_MulTPoint(
        xf1, b3Transform_MulPoint(xf2, hullVertices[0]));
    b3Vec3 upper = lower;
    for (uint32 i = 1u; i < hullVertexCount; ++i) {
      b3Vec3 p =
          b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, hullVertices[i]));
      lower = collide_vec3_min(lower, p);
      upper = collide_vec3_max(upper, p);
    }
    scalar radius = shape1->base.radius + shape2->base.radius;
    b3Vec3 r = b3Vec3_Make(radius, radius, radius);
    b3AABB query =
        mesh_unscale_aabb(shape1, collide_vec3_sub(lower, r),
                          collide_vec3_add(upper, r));
    b3MeshHullCollideContext context;
    context.manifold = manifold;
    context.meshTransform = xf1;
    context.meshShape = shape1;
    context.hullTransform = xf2;
    context.hull = shape2;
    b3DynamicTree_QueryAABB(shape1->mesh->tree, query,
                            mesh_hull_collide_tree_callback, &context);
    return;
  }
  for (uint32 i = 0u; i < shape1->mesh->triangleCount; ++i) {
    b3TriangleShape triangle;
    if (!mesh_get_child_triangle(shape1, i, &triangle)) {
      continue;
    }
    b3Manifold childManifold;
    b3CollideTriangleAndHull(&childManifold, xf1, &triangle, xf2, shape2);
    append_mesh_child_manifold(manifold, &childManifold, i);
    if (manifold->pointCount >= B3_MAX_MANIFOLD_POINTS) {
      return;
    }
  }
}

void b3CollideMeshAndHullManifolds(
    b3Manifold outManifolds[B3_MAX_MANIFOLDS], uint32 *outCount,
    b3Transform xf1, const b3MeshShape *shape1, b3Transform xf2,
    const b3HullShape *shape2) {
  if (outCount != NULL) {
    *outCount = 0u;
  }
  if (outManifolds == NULL || outCount == NULL || shape1 == NULL ||
      shape1->mesh == NULL || shape2 == NULL ||
      (shape2->hull == NULL &&
       (shape2->vertices == NULL || shape2->vertexCount == 0u))) {
    return;
  }

  b3MeshManifoldCollector collector;
  memset(&collector, 0, sizeof(collector));
  if (mesh_shape_has_tree(shape1)) {
    b3Vec3 hullScratch[8];
    const b3Vec3 *hullVertices = NULL;
    uint32 hullVertexCount = 0u;
    if (!collide_hull_vertices(shape2, hullScratch, &hullVertices,
                               &hullVertexCount)) {
      return;
    }
    b3Vec3 lower = b3Transform_MulTPoint(
        xf1, b3Transform_MulPoint(xf2, hullVertices[0]));
    b3Vec3 upper = lower;
    for (uint32 i = 1u; i < hullVertexCount; ++i) {
      b3Vec3 p =
          b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, hullVertices[i]));
      lower = collide_vec3_min(lower, p);
      upper = collide_vec3_max(upper, p);
    }
    scalar radius = shape1->base.radius + shape2->base.radius;
    b3Vec3 r = b3Vec3_Make(radius, radius, radius);
    b3AABB query =
        mesh_unscale_aabb(shape1, collide_vec3_sub(lower, r),
                          collide_vec3_add(upper, r));
    b3MeshHullManifoldContext context;
    context.collector = &collector;
    context.meshTransform = xf1;
    context.meshShape = shape1;
    context.hullTransform = xf2;
    context.hull = shape2;
    b3DynamicTree_QueryAABB(shape1->mesh->tree, query,
                            mesh_hull_manifold_tree_callback, &context);
  } else {
    for (uint32 i = 0u; i < shape1->mesh->triangleCount; ++i) {
      b3TriangleShape triangle;
      if (!mesh_get_child_triangle(shape1, i, &triangle)) {
        continue;
      }
      b3Manifold childManifold;
      b3Manifold_Clear(&childManifold);
      b3CollideTriangleAndHull(&childManifold, xf1, &triangle, xf2, shape2);
      if (!mesh_collect_child_manifold(&collector, &childManifold, i)) {
        break;
      }
    }
  }

  mesh_cluster_child_manifolds(outManifolds, outCount, &collector, xf1,
                               shape1->base.radius, xf2,
                               shape2->base.radius);
}

void b3CollideCapsuleAndSphere(b3Manifold *manifold, b3Transform xf1,
                               const b3CapsuleShape *shape1, b3Transform xf2,
                               const b3SphereShape *shape2) {
  if (manifold == NULL || shape1 == NULL || shape2 == NULL) {
    return;
  }
  b3Manifold_Clear(manifold);

  b3Vec3 q = b3Transform_MulTPoint(xf1, b3Transform_MulPoint(xf2, shape2->center));
  b3Vec3 a = shape1->point1;
  b3Vec3 b = shape1->point2;
  b3Vec3 ab = collide_vec3_sub(b, a);
  b3Vec3 p = closest_point_on_segment(q, a, b);
  b3Vec3 d = collide_vec3_sub(q, p);
  scalar radius = shape1->base.radius + shape2->base.radius;
  if (collide_length_sq(d) > radius * radius) {
    return;
  }

  b3Vec3 n = collide_normalize_or_y(d);
  scalar u = collide_dot(collide_vec3_sub(b, q), ab);
  scalar v = collide_dot(collide_vec3_sub(q, a), ab);
  if (u > 0.0f && v > 0.0f && collide_length_sq(ab) > B3_EPSILON &&
      collide_length_sq(d) > B3_EPSILON) {
    b3Vec3 aq = collide_vec3_sub(q, a);
    b3Vec3 n2 = collide_cross(collide_cross(ab, aq), ab);
    if (collide_dot(n2, aq) < 0.0f) {
      n2 = collide_vec3_mul(n2, -1.0f);
    }
    n = collide_normalize_or_y(n2);
  }

  manifold->pointCount = 1u;
  manifold->points[0].localNormal1 = n;
  manifold->points[0].localPoint1 = p;
  manifold->points[0].localPoint2 = shape2->center;
  manifold->points[0].key.triangleKey = B3_NULL_TRIANGLE;
}

void b3CollideCapsuleAndCapsule(b3Manifold *manifold, b3Transform xf1,
                                const b3CapsuleShape *shape1, b3Transform xf2,
                                const b3CapsuleShape *shape2) {
  if (manifold == NULL || shape1 == NULL || shape2 == NULL) {
    return;
  }
  b3Manifold_Clear(manifold);

  b3Vec3 a1 = b3Transform_MulPoint(xf1, shape1->point1);
  b3Vec3 b1 = b3Transform_MulPoint(xf1, shape1->point2);
  b3Vec3 a2 = b3Transform_MulPoint(xf2, shape2->point1);
  b3Vec3 b2 = b3Transform_MulPoint(xf2, shape2->point2);

  b3Vec3 point1;
  b3Vec3 point2;
  closest_points_segments(&point1, &point2, a1, b1, a2, b2);
  b3Vec3 delta = collide_vec3_sub(point2, point1);
  scalar distance = collide_length(delta);
  scalar totalRadius = shape1->base.radius + shape2->base.radius;
  if (distance > totalRadius) {
    return;
  }

  if (distance <= 0.0f) {
    return;
  }

  if (segments_are_parallel(a1, b1, a2, b2)) {
    b3ClipVertex edge1[2];
    build_capsule_edge(edge1, a1, b1);

    b3ClipVertex clipped[2];
    uint32 clipCount = clip_edge_to_capsule_face(clipped, edge1, a2, b2);
    if (clipCount == 2u) {
      b3Vec3 closest1 =
          closest_point_on_segment(clipped[0].position, a2, b2);
      b3Vec3 closest2 =
          closest_point_on_segment(clipped[1].position, a2, b2);

      scalar distance1 =
          collide_length(collide_vec3_sub(clipped[0].position, closest1));
      scalar distance2 =
          collide_length(collide_vec3_sub(clipped[1].position, closest2));

      if (distance1 > B3_EPSILON && distance1 <= totalRadius &&
          distance2 > B3_EPSILON && distance2 <= totalRadius) {
        b3Vec3 normal1 = collide_vec3_mul(
            collide_vec3_sub(closest1, clipped[0].position),
            1.0f / distance1);
        b3Vec3 normal2 = collide_vec3_mul(
            collide_vec3_sub(closest2, clipped[1].position),
            1.0f / distance2);

        manifold->pointCount = 2u;
        manifold->points[0].localNormal1 =
            b3Transform_MulTPoint(b3Transform_Make(
                                      b3Vec3_Make(0.0f, 0.0f, 0.0f),
                                      xf1.rotation),
                                  normal1);
        manifold->points[0].localPoint1 = b3Transform_MulTPoint(
            xf1, clipped[0].position);
        manifold->points[0].localPoint2 = b3Transform_MulTPoint(xf2, closest1);
        manifold->points[0].key = make_key(clipped[0].pair);

        manifold->points[1].localNormal1 =
            b3Transform_MulTPoint(b3Transform_Make(
                                      b3Vec3_Make(0.0f, 0.0f, 0.0f),
                                      xf1.rotation),
                                  normal2);
        manifold->points[1].localPoint1 = b3Transform_MulTPoint(
            xf1, clipped[1].position);
        manifold->points[1].localPoint2 = b3Transform_MulTPoint(xf2, closest2);
        manifold->points[1].key = make_key(clipped[1].pair);
        return;
      }
    }
  }

  b3Vec3 normal = collide_vec3_mul(delta, 1.0f / distance);
  manifold->pointCount = 1u;
  manifold->points[0].localNormal1 =
      b3Transform_MulTPoint(b3Transform_Make(b3Vec3_Make(0.0f, 0.0f, 0.0f),
                                             xf1.rotation),
                            normal);
  manifold->points[0].localPoint1 = b3Transform_MulTPoint(xf1, point1);
  manifold->points[0].localPoint2 = b3Transform_MulTPoint(xf2, point2);
  manifold->points[0].key.triangleKey = B3_NULL_TRIANGLE;
}
