static b3Vec3 vec3_add(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x + b.x, a.y + b.y, a.z + b.z);
}

static b3Vec3 vec3_sub(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x - b.x, a.y - b.y, a.z - b.z);
}

static b3Vec3 vec3_mul(b3Vec3 v, scalar s) {
  return b3Vec3_Make(v.x * s, v.y * s, v.z * s);
}

static b3Vec3 vec3_mul_comp(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x * b.x, a.y * b.y, a.z * b.z);
}

static b3Vec3 vec3_min(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x < b.x ? a.x : b.x, a.y < b.y ? a.y : b.y,
                     a.z < b.z ? a.z : b.z);
}

static b3Vec3 vec3_max(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.x > b.x ? a.x : b.x, a.y > b.y ? a.y : b.y,
                     a.z > b.z ? a.z : b.z);
}

static scalar vec3_dot(b3Vec3 a, b3Vec3 b) {
  return a.x * b.x + a.y * b.y + a.z * b.z;
}

static b3Vec3 vec3_cross(b3Vec3 a, b3Vec3 b) {
  return b3Vec3_Make(a.y * b.z - a.z * b.y, a.z * b.x - a.x * b.z,
                     a.x * b.y - a.y * b.x);
}

static scalar vec3_length_sq(b3Vec3 v) { return vec3_dot(v, v); }

static scalar vec3_length(b3Vec3 v) { return sqrtf(vec3_length_sq(v)); }

static b3Vec3 vec3_clamp_length(b3Vec3 v, scalar maxLength) {
  scalar lengthSq = vec3_length_sq(v);
  if (maxLength < 0.0f || lengthSq <= maxLength * maxLength) {
    return v;
  }
  scalar length = sqrtf(lengthSq);
  if (length <= B3_EPSILON) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  return vec3_mul(v, maxLength / length);
}

static b3Vec3 vec3_normalize_or_zero(b3Vec3 v) {
  scalar len = vec3_length(v);
  if (len <= B3_EPSILON) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  return vec3_mul(v, 1.0f / len);
}

static b3Vec3 vec3_perp(b3Vec3 v) {
  static const scalar sqrtInv3 = 0.57735026918962576451f;
  b3Vec3 perp = fabsf(v.x) >= sqrtInv3 ? b3Vec3_Make(v.y, -v.x, 0.0f)
                                       : b3Vec3_Make(0.0f, v.z, -v.y);
  return vec3_normalize_or_zero(perp);
}

static scalar scalar_max(scalar a, scalar b) { return a > b ? a : b; }

static scalar scalar_min(scalar a, scalar b) { return a < b ? a : b; }

static scalar scalar_clamp(scalar value, scalar low, scalar high) {
  return scalar_min(scalar_max(value, low), high);
}

static b3Mat33 mat33_zero(void) {
  b3Mat33 out;
  out.x = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out.y = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out.z = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  return out;
}

static b3Mat33 mat33_diagonal(scalar x, scalar y, scalar z) {
  b3Mat33 out = mat33_zero();
  out.x.x = x;
  out.y.y = y;
  out.z.z = z;
  return out;
}

static b3Mat33 mat33_add(b3Mat33 a, b3Mat33 b) {
  b3Mat33 out;
  out.x = vec3_add(a.x, b.x);
  out.y = vec3_add(a.y, b.y);
  out.z = vec3_add(a.z, b.z);
  return out;
}

static b3Mat33 mat33_sub(b3Mat33 a, b3Mat33 b) {
  b3Mat33 out;
  out.x = vec3_sub(a.x, b.x);
  out.y = vec3_sub(a.y, b.y);
  out.z = vec3_sub(a.z, b.z);
  return out;
}

static b3Mat33 mat33_mul_scalar(b3Mat33 m, scalar s) {
  b3Mat33 out;
  out.x = vec3_mul(m.x, s);
  out.y = vec3_mul(m.y, s);
  out.z = vec3_mul(m.z, s);
  return out;
}

static inline b3Vec3 mat33_mul_vec3_ptr(const b3Mat33 *m, b3Vec3 v) {
  return vec3_add(vec3_add(vec3_mul(m->x, v.x), vec3_mul(m->y, v.y)),
                  vec3_mul(m->z, v.z));
}

static inline b3Vec3 mat33_mul_vec3(b3Mat33 m, b3Vec3 v) {
  return mat33_mul_vec3_ptr(&m, v);
}

static b3Mat33 mat33_mul(b3Mat33 a, b3Mat33 b) {
  b3Mat33 out;
  out.x = mat33_mul_vec3(a, b.x);
  out.y = mat33_mul_vec3(a, b.y);
  out.z = mat33_mul_vec3(a, b.z);
  return out;
}

static scalar mat33_det(b3Mat33 m) {
  return vec3_dot(m.x, vec3_cross(m.y, m.z));
}

static b3Vec3 mat33_solve(b3Mat33 m, b3Vec3 b) {
  scalar det = mat33_det(m);
  if (det != 0.0f) {
    det = 1.0f / det;
  }
  return b3Vec3_Make(det * vec3_dot(b, vec3_cross(m.y, m.z)),
                     det * vec3_dot(m.x, vec3_cross(b, m.z)),
                     det * vec3_dot(m.x, vec3_cross(m.y, b)));
}

static b3Mat33 mat33_transpose(b3Mat33 m) {
  b3Mat33 out;
  out.x = b3Vec3_Make(m.x.x, m.y.x, m.z.x);
  out.y = b3Vec3_Make(m.x.y, m.y.y, m.z.y);
  out.z = b3Vec3_Make(m.x.z, m.y.z, m.z.z);
  return out;
}

static b3Mat33 mat33_skew(b3Vec3 v) {
  b3Mat33 out;
  out.x = b3Vec3_Make(0.0f, v.z, -v.y);
  out.y = b3Vec3_Make(-v.z, 0.0f, v.x);
  out.z = b3Vec3_Make(v.y, -v.x, 0.0f);
  return out;
}

static b3Mat33 mat33_inverse(b3Mat33 m) {
  scalar a11 = m.x.x, a12 = m.y.x, a13 = m.z.x;
  scalar a21 = m.x.y, a22 = m.y.y, a23 = m.z.y;
  scalar a31 = m.x.z, a32 = m.y.z, a33 = m.z.z;
  scalar c11 = a22 * a33 - a23 * a32;
  scalar c12 = -(a21 * a33 - a23 * a31);
  scalar c13 = a21 * a32 - a22 * a31;
  scalar c21 = -(a12 * a33 - a13 * a32);
  scalar c22 = a11 * a33 - a13 * a31;
  scalar c23 = -(a11 * a32 - a12 * a31);
  scalar c31 = a12 * a23 - a13 * a22;
  scalar c32 = -(a11 * a23 - a13 * a21);
  scalar c33 = a11 * a22 - a12 * a21;
  scalar det = a11 * c11 + a12 * c12 + a13 * c13;
  scalar scale = 0.0f;
  scale = fmaxf(scale, fabsf(a11));
  scale = fmaxf(scale, fabsf(a12));
  scale = fmaxf(scale, fabsf(a13));
  scale = fmaxf(scale, fabsf(a21));
  scale = fmaxf(scale, fabsf(a22));
  scale = fmaxf(scale, fabsf(a23));
  scale = fmaxf(scale, fabsf(a31));
  scale = fmaxf(scale, fabsf(a32));
  scale = fmaxf(scale, fabsf(a33));
  if (scale <= FLT_MIN ||
      fabsf(det) <= FLT_EPSILON * scale * scale * scale) {
    return mat33_zero();
  }
  scalar invDet = 1.0f / det;
  b3Mat33 out;
  out.x = b3Vec3_Make(c11 * invDet, c12 * invDet, c13 * invDet);
  out.y = b3Vec3_Make(c21 * invDet, c22 * invDet, c23 * invDet);
  out.z = b3Vec3_Make(c31 * invDet, c32 * invDet, c33 * invDet);
  return out;
}

static b3Mat33 mat33_steiner(b3Vec3 v) {
  scalar xx = v.x * v.x;
  scalar yy = v.y * v.y;
  scalar zz = v.z * v.z;
  b3Mat33 out;
  out.x = b3Vec3_Make(yy + zz, -v.x * v.y, -v.x * v.z);
  out.y = b3Vec3_Make(-v.x * v.y, xx + zz, -v.y * v.z);
  out.z = b3Vec3_Make(-v.x * v.z, -v.y * v.z, xx + yy);
  return out;
}

static b3Quat quat_mul(b3Quat a, b3Quat b) {
  b3Quat result;
  result.v = vec3_add(vec3_add(vec3_cross(a.v, b.v), vec3_mul(b.v, a.s)),
                      vec3_mul(a.v, b.s));
  result.s = a.s * b.s - vec3_dot(a.v, b.v);
  return result;
}

static b3Quat quat_conjugate(b3Quat q) {
  q.v = vec3_mul(q.v, -1.0f);
  return q;
}

static b3Quat quat_normalize(b3Quat q) {
  scalar len = sqrtf(vec3_dot(q.v, q.v) + q.s * q.s);
  if (len <= B3_EPSILON) {
    return b3Quat_Identity();
  }
  scalar invLen = 1.0f / len;
  return b3Quat_Make(q.v.x * invLen, q.v.y * invLen, q.v.z * invLen,
                     q.s * invLen);
}

static b3Vec3 quat_rotate_vec3(b3Quat q, b3Vec3 v) {
  b3Vec3 t = vec3_mul(vec3_cross(q.v, v), 2.0f);
  return vec3_add(vec3_add(v, vec3_mul(t, q.s)), vec3_cross(q.v, t));
}

static b3Vec3 quat_unrotate_vec3(b3Quat q, b3Vec3 v) {
  return quat_rotate_vec3(quat_conjugate(quat_normalize(q)), v);
}

static b3Vec3 transform_mul_point_local(b3Transform transform, b3Vec3 point) {
  return vec3_add(quat_rotate_vec3(transform.rotation, point),
                  transform.translation);
}

static inline b3Vec3 transform_mul_point_mat33(b3Mat33 rotation,
                                               b3Vec3 translation,
                                               b3Vec3 point) {
  return vec3_add(mat33_mul_vec3(rotation, point), translation);
}

static b3Mat33 quat_to_mat33(b3Quat q) {
  scalar x = q.v.x;
  scalar y = q.v.y;
  scalar z = q.v.z;
  scalar w = q.s;
  scalar x2 = x + x;
  scalar y2 = y + y;
  scalar z2 = z + z;
  scalar xx = x * x2;
  scalar xy = x * y2;
  scalar xz = x * z2;
  scalar yy = y * y2;
  scalar yz = y * z2;
  scalar zz = z * z2;
  scalar wx = w * x2;
  scalar wy = w * y2;
  scalar wz = w * z2;
  return b3Mat33_Make(
      b3Vec3_Make(1.0f - (yy + zz), xy + wz, xz - wy),
      b3Vec3_Make(xy - wz, 1.0f - (xx + zz), yz + wx),
      b3Vec3_Make(xz + wy, yz - wx, 1.0f - (xx + yy)));
}

static bool mat33_is_diagonal(b3Mat33 m) {
  return m.x.y == 0.0f && m.x.z == 0.0f && m.y.x == 0.0f &&
         m.y.z == 0.0f && m.z.x == 0.0f && m.z.y == 0.0f;
}

static b3Mat33 mat33_rotate_diagonal_to_frame(b3Vec3 diagonal,
                                              b3Quat rotation) {
  b3Mat33 r = quat_to_mat33(rotation);
  b3Vec3 c0 = r.x;
  b3Vec3 c1 = r.y;
  b3Vec3 c2 = r.z;
  b3Vec3 dc0 = vec3_mul(c0, diagonal.x);
  b3Vec3 dc1 = vec3_mul(c1, diagonal.y);
  b3Vec3 dc2 = vec3_mul(c2, diagonal.z);
  b3Mat33 out;
  out.x = vec3_add(
      vec3_add(vec3_mul(dc0, c0.x), vec3_mul(dc1, c1.x)),
      vec3_mul(dc2, c2.x));
  out.y = vec3_add(
      vec3_add(vec3_mul(dc0, c0.y), vec3_mul(dc1, c1.y)),
      vec3_mul(dc2, c2.y));
  out.z = vec3_add(
      vec3_add(vec3_mul(dc0, c0.z), vec3_mul(dc1, c1.z)),
      vec3_mul(dc2, c2.z));
  return out;
}

static b3Mat33 mat33_rotate_to_frame(b3Mat33 inertia, b3Quat rotation) {
  if (rotation.v.x == 0.0f && rotation.v.y == 0.0f &&
      rotation.v.z == 0.0f && rotation.s == 1.0f) {
    return inertia;
  }
  if (mat33_is_diagonal(inertia)) {
    return mat33_rotate_diagonal_to_frame(
        b3Vec3_Make(inertia.x.x, inertia.y.y, inertia.z.z), rotation);
  }
  b3Mat33 r = quat_to_mat33(rotation);
  return mat33_mul(mat33_mul(r, inertia), mat33_transpose(r));
}

static b3Quat quat_from_mat33_columns(b3Vec3 x, b3Vec3 y, b3Vec3 z) {
  scalar m00 = x.x;
  scalar m01 = y.x;
  scalar m02 = z.x;
  scalar m10 = x.y;
  scalar m11 = y.y;
  scalar m12 = z.y;
  scalar m20 = x.z;
  scalar m21 = y.z;
  scalar m22 = z.z;
  scalar trace = m00 + m11 + m22;
  b3Quat q;

  if (trace > 0.0f) {
    scalar root = sqrtf(trace + 1.0f);
    q.s = 0.5f * root;
    scalar inv = 0.5f / root;
    q.v.x = (m21 - m12) * inv;
    q.v.y = (m02 - m20) * inv;
    q.v.z = (m10 - m01) * inv;
  } else if (m00 >= m11 && m00 >= m22) {
    scalar root = sqrtf(1.0f + m00 - m11 - m22);
    q.v.x = 0.5f * root;
    scalar inv = 0.5f / root;
    q.v.y = (m01 + m10) * inv;
    q.v.z = (m02 + m20) * inv;
    q.s = (m21 - m12) * inv;
  } else if (m11 > m22) {
    scalar root = sqrtf(1.0f + m11 - m00 - m22);
    q.v.y = 0.5f * root;
    scalar inv = 0.5f / root;
    q.v.x = (m01 + m10) * inv;
    q.v.z = (m12 + m21) * inv;
    q.s = (m02 - m20) * inv;
  } else {
    scalar root = sqrtf(1.0f + m22 - m00 - m11);
    q.v.z = 0.5f * root;
    scalar inv = 0.5f / root;
    q.v.x = (m02 + m20) * inv;
    q.v.y = (m12 + m21) * inv;
    q.s = (m10 - m01) * inv;
  }

  return quat_normalize(q);
}

static b3Quat quat_integrate(b3Quat orientation, b3Vec3 angularVelocity,
                             scalar dt) {
  b3Quat w = b3Quat_Make(angularVelocity.x, angularVelocity.y,
                         angularVelocity.z, 0.0f);
  b3Quat qdot = quat_mul(w, orientation);
  qdot.v = vec3_mul(qdot.v, 0.5f);
  qdot.s *= 0.5f;

  orientation.v = vec3_add(orientation.v, vec3_mul(qdot.v, dt));
  orientation.s += dt * qdot.s;
  return quat_normalize(orientation);
}

static bool hull_shape_vertices(const b3HullShape *shape,
                                const b3Vec3 **outVertices,
                                uint32 *outCount) {
  if (outVertices == NULL || outCount == NULL || shape == NULL) {
    return false;
  }
  if (shape->vertices != NULL && shape->vertexCount > 0u) {
    *outVertices = shape->vertices;
    *outCount = shape->vertexCount;
    return true;
  }
  if (shape->genericHull != NULL && shape->genericHull->vertices != NULL &&
      shape->genericHull->vertexCount > 0u) {
    *outVertices = shape->genericHull->vertices;
    *outCount = shape->genericHull->vertexCount;
    return true;
  }
  if (shape->hull != NULL && shape->hull->vertexCount > 0u) {
    *outVertices = shape->hull->vertices;
    *outCount = shape->hull->vertexCount;
    return true;
  }
  *outVertices = NULL;
  *outCount = 0u;
  return false;
}

static bool hull_shape_local_aabb(const b3HullShape *shape, b3Aabb *out) {
  if (shape == NULL || out == NULL) {
    return false;
  }
  const b3Vec3 *vertices = NULL;
  uint32 vertexCount = 0u;
  if (hull_shape_vertices(shape, &vertices, &vertexCount)) {
    out->min = vertices[0];
    out->max = vertices[0];
    for (uint32 i = 1u; i < vertexCount; ++i) {
      out->min = vec3_min(out->min, vertices[i]);
      out->max = vec3_max(out->max, vertices[i]);
    }
    b3Vec3 r =
        b3Vec3_Make(shape->base.radius, shape->base.radius, shape->base.radius);
    out->min = vec3_sub(out->min, r);
    out->max = vec3_add(out->max, r);
    return true;
  }
  if (shape->hull != NULL) {
    out->min = vec3_mul(shape->hull->halfExtents, -1.0f);
    out->max = shape->hull->halfExtents;
    return true;
  }
  return false;
}

static void shape_local_aabb(const b3Shape *shape, b3Aabb *out) {
  out->min = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out->max = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  if (shape == NULL) {
    return;
  }

  switch (shape->type) {
  case e_sphereShape: {
    const b3SphereShape *sphere = (const b3SphereShape *)shape;
    scalar r = shape->radius;
    out->min = vec3_sub(sphere->center, b3Vec3_Make(r, r, r));
    out->max = vec3_add(sphere->center, b3Vec3_Make(r, r, r));
    break;
  }
  case e_capsuleShape: {
    const b3CapsuleShape *capsule = (const b3CapsuleShape *)shape;
    scalar r = shape->radius;
    out->min = b3Vec3_Make(scalar_min(capsule->point1.x, capsule->point2.x) - r,
                           scalar_min(capsule->point1.y, capsule->point2.y) - r,
                           scalar_min(capsule->point1.z, capsule->point2.z) -
                               r);
    out->max = b3Vec3_Make(scalar_max(capsule->point1.x, capsule->point2.x) + r,
                           scalar_max(capsule->point1.y, capsule->point2.y) + r,
                           scalar_max(capsule->point1.z, capsule->point2.z) +
                               r);
    break;
  }
  case e_triangleShape: {
    const b3TriangleShape *triangle = (const b3TriangleShape *)shape;
    scalar r = shape->radius;
    b3Vec3 lower =
        vec3_min(triangle->vertex1, vec3_min(triangle->vertex2,
                                             triangle->vertex3));
    b3Vec3 upper =
        vec3_max(triangle->vertex1, vec3_max(triangle->vertex2,
                                             triangle->vertex3));
    out->min = vec3_sub(lower, b3Vec3_Make(r, r, r));
    out->max = vec3_add(upper, b3Vec3_Make(r, r, r));
    break;
  }
  case e_hullShape: {
    const b3HullShape *hullShape = (const b3HullShape *)shape;
    hull_shape_local_aabb(hullShape, out);
    break;
  }
  case e_meshShape: {
    const b3MeshShape *meshShape = (const b3MeshShape *)shape;
    if (meshShape->mesh == NULL || meshShape->mesh->vertices == NULL ||
        meshShape->mesh->vertexCount == 0u) {
      break;
    }
    b3Vec3 lower =
        vec3_mul_comp(meshShape->mesh->vertices[0], meshShape->scale);
    b3Vec3 upper = lower;
    for (uint32 i = 1u; i < meshShape->mesh->vertexCount; ++i) {
      b3Vec3 v =
          vec3_mul_comp(meshShape->mesh->vertices[i], meshShape->scale);
      lower = vec3_min(lower, v);
      upper = vec3_max(upper, v);
    }
    scalar r = shape->radius;
    out->min = vec3_sub(lower, b3Vec3_Make(r, r, r));
    out->max = vec3_add(upper, b3Vec3_Make(r, r, r));
    break;
  }
  default:
    break;
  }
}

static void aabb_include_point(b3Aabb *aabb, b3Vec3 point) {
  aabb->min = vec3_min(aabb->min, point);
  aabb->max = vec3_max(aabb->max, point);
}

static void aabb_expand_radius(b3Aabb *aabb, scalar radius) {
  b3Vec3 r = b3Vec3_Make(radius, radius, radius);
  aabb->min = vec3_sub(aabb->min, r);
  aabb->max = vec3_add(aabb->max, r);
}

static void aabb_transform_local_bounds(const b3Aabb *local,
                                        b3Transform transform, b3Aabb *out) {
  b3Vec3 corners[8] = {
      b3Vec3_Make(local->min.x, local->min.y, local->min.z),
      b3Vec3_Make(local->max.x, local->min.y, local->min.z),
      b3Vec3_Make(local->min.x, local->max.y, local->min.z),
      b3Vec3_Make(local->max.x, local->max.y, local->min.z),
      b3Vec3_Make(local->min.x, local->min.y, local->max.z),
      b3Vec3_Make(local->max.x, local->min.y, local->max.z),
      b3Vec3_Make(local->min.x, local->max.y, local->max.z),
      b3Vec3_Make(local->max.x, local->max.y, local->max.z),
  };
  b3Vec3 first = transform_mul_point_local(transform, corners[0]);
  out->min = first;
  out->max = first;
  for (uint32 i = 1u; i < 8u; ++i) {
    aabb_include_point(out, transform_mul_point_local(transform, corners[i]));
  }
}

static void aabb_transform_box_hull(const b3BoxHull *box,
                                    b3Transform transform, b3Aabb *out) {
  b3Vec3 center = transform_mul_point_local(transform, box->centroid);
  b3Mat33 r = quat_to_mat33(transform.rotation);
  b3Vec3 e = box->halfExtents;
  b3Vec3 extents = b3Vec3_Make(
      fabsf(r.x.x) * e.x + fabsf(r.y.x) * e.y + fabsf(r.z.x) * e.z,
      fabsf(r.x.y) * e.x + fabsf(r.y.y) * e.y + fabsf(r.z.y) * e.z,
      fabsf(r.x.z) * e.x + fabsf(r.y.z) * e.y + fabsf(r.z.z) * e.z);
  out->min = vec3_sub(center, extents);
  out->max = vec3_add(center, extents);
}

static void shape_world_aabb(const b3Shape *shape, b3Transform transform,
                             b3Aabb *out) {
  out->min = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out->max = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  if (shape == NULL) {
    return;
  }

  switch (shape->type) {
  case e_sphereShape: {
    const b3SphereShape *sphere = (const b3SphereShape *)shape;
    b3Vec3 center = transform_mul_point_local(transform, sphere->center);
    out->min = center;
    out->max = center;
    aabb_expand_radius(out, shape->radius);
    break;
  }
  case e_capsuleShape: {
    const b3CapsuleShape *capsule = (const b3CapsuleShape *)shape;
    b3Vec3 p1 = transform_mul_point_local(transform, capsule->point1);
    b3Vec3 p2 = transform_mul_point_local(transform, capsule->point2);
    out->min = vec3_min(p1, p2);
    out->max = vec3_max(p1, p2);
    aabb_expand_radius(out, shape->radius);
    break;
  }
  case e_triangleShape: {
    const b3TriangleShape *triangle = (const b3TriangleShape *)shape;
    b3Vec3 p1 = transform_mul_point_local(transform, triangle->vertex1);
    b3Vec3 p2 = transform_mul_point_local(transform, triangle->vertex2);
    b3Vec3 p3 = transform_mul_point_local(transform, triangle->vertex3);
    out->min = vec3_min(p1, vec3_min(p2, p3));
    out->max = vec3_max(p1, vec3_max(p2, p3));
    aabb_expand_radius(out, shape->radius);
    break;
  }
  case e_hullShape: {
    const b3HullShape *hullShape = (const b3HullShape *)shape;
    if (hullShape->hull != NULL) {
      aabb_transform_box_hull(hullShape->hull, transform, out);
      aabb_expand_radius(out, shape->radius);
      break;
    }
    const b3Vec3 *vertices = NULL;
    uint32 vertexCount = 0u;
    if (hull_shape_vertices(hullShape, &vertices, &vertexCount)) {
      b3Mat33 rotation = quat_to_mat33(transform.rotation);
      b3Vec3 first =
          transform_mul_point_mat33(rotation, transform.translation, vertices[0]);
      out->min = first;
      out->max = first;
      for (uint32 i = 1u; i < vertexCount; ++i) {
        aabb_include_point(
            out,
            transform_mul_point_mat33(rotation, transform.translation,
                                      vertices[i]));
      }
      aabb_expand_radius(out, shape->radius);
    } else {
      b3Aabb local;
      shape_local_aabb(shape, &local);
      aabb_transform_local_bounds(&local, transform, out);
    }
    break;
  }
  case e_meshShape: {
    const b3MeshShape *meshShape = (const b3MeshShape *)shape;
    if (meshShape->mesh != NULL && meshShape->mesh->vertices != NULL &&
        meshShape->mesh->vertexCount > 0u) {
      b3Mat33 rotation = quat_to_mat33(transform.rotation);
      b3Vec3 first = transform_mul_point_mat33(
          rotation, transform.translation,
          vec3_mul_comp(meshShape->mesh->vertices[0], meshShape->scale));
      out->min = first;
      out->max = first;
      for (uint32 i = 1u; i < meshShape->mesh->vertexCount; ++i) {
        b3Vec3 vertex =
            vec3_mul_comp(meshShape->mesh->vertices[i], meshShape->scale);
        aabb_include_point(
            out,
            transform_mul_point_mat33(rotation, transform.translation, vertex));
      }
      aabb_expand_radius(out, shape->radius);
    }
    break;
  }
  default: {
    b3Aabb local;
    shape_local_aabb(shape, &local);
    aabb_transform_local_bounds(&local, transform, out);
    break;
  }
  }
}

static void aabb_translate(b3Aabb *aabb, b3Vec3 translation) {
  aabb->min = vec3_add(aabb->min, translation);
  aabb->max = vec3_add(aabb->max, translation);
}

static b3AABB aabb_to_public(b3Aabb aabb) {
  return b3AABB_Make(aabb.min, aabb.max);
}

static b3Aabb aabb_from_public(b3AABB aabb) {
  b3Aabb out;
  out.min = aabb.lowerBound;
  out.max = aabb.upperBound;
  return out;
}

static bool aabb_overlap(const b3Aabb *a, const b3Aabb *b) {
  return a->min.x <= b->max.x && a->max.x >= b->min.x &&
         a->min.y <= b->max.y && a->max.y >= b->min.y &&
         a->min.z <= b->max.z && a->max.z >= b->min.z;
}

static bool ray_cast_aabb(const b3Aabb *aabb, b3Vec3 point1, b3Vec3 point2,
                          scalar *outFraction, b3Vec3 *outNormal) {
  b3Vec3 d = vec3_sub(point2, point1);
  scalar tmin = 0.0f;
  scalar tmax = 1.0f;
  b3Vec3 normal = b3Vec3_Make(0.0f, 0.0f, 0.0f);

  const scalar p[3] = {point1.x, point1.y, point1.z};
  const scalar dir[3] = {d.x, d.y, d.z};
  const scalar minv[3] = {aabb->min.x, aabb->min.y, aabb->min.z};
  const scalar maxv[3] = {aabb->max.x, aabb->max.y, aabb->max.z};

  for (int axis = 0; axis < 3; ++axis) {
    if (fabsf(dir[axis]) <= B3_EPSILON) {
      if (p[axis] < minv[axis] || p[axis] > maxv[axis]) {
        return false;
      }
      continue;
    }

    scalar invD = 1.0f / dir[axis];
    scalar t1 = (minv[axis] - p[axis]) * invD;
    scalar t2 = (maxv[axis] - p[axis]) * invD;
    scalar enterSign = -1.0f;
    if (t1 > t2) {
      scalar tmp = t1;
      t1 = t2;
      t2 = tmp;
      enterSign = 1.0f;
    }

    if (t1 > tmin) {
      tmin = t1;
      normal = b3Vec3_Make(0.0f, 0.0f, 0.0f);
      if (axis == 0) {
        normal.x = enterSign;
      } else if (axis == 1) {
        normal.y = enterSign;
      } else {
        normal.z = enterSign;
      }
    }
    tmax = scalar_min(tmax, t2);
    if (tmin > tmax) {
      return false;
    }
  }

  if (outFraction != NULL) {
    *outFraction = tmin;
  }
  if (outNormal != NULL) {
    *outNormal = normal;
  }
  return true;
}

static b3Aabb fixture_world_aabb_at(const b3Fixture *fixture,
                                    b3Transform transform) {
  b3Aabb aabb;
  shape_world_aabb(&fixture->storage.base, transform, &aabb);
  return aabb;
}

static void fixture_store_world_aabb(b3Fixture *fixture, b3Aabb aabb) {
  if (fixture != NULL) {
    fixture->worldAabb = aabb;
    fixture->worldAabbValid = true;
  }
}

static void fixture_invalidate_world_aabb(b3Fixture *fixture) {
  if (fixture != NULL) {
    fixture->worldAabbValid = false;
  }
}

static b3Aabb fixture_world_aabb(const b3Fixture *fixture) {
  if (fixture->worldAabbValid) {
    return fixture->worldAabb;
  }
  b3Aabb aabb = fixture_world_aabb_at(fixture, body_transform(fixture->body));
  fixture_store_world_aabb((b3Fixture *)fixture, aabb);
  return aabb;
}

static b3Vec3 aabb_center(b3Aabb aabb) {
  return vec3_mul(vec3_add(aabb.min, aabb.max), 0.5f);
}

static b3Aabb aabb_combine(b3Aabb aabb1, b3Aabb aabb2) {
  b3Aabb out;
  out.min.x = scalar_min(aabb1.min.x, aabb2.min.x);
  out.min.y = scalar_min(aabb1.min.y, aabb2.min.y);
  out.min.z = scalar_min(aabb1.min.z, aabb2.min.z);
  out.max.x = scalar_max(aabb1.max.x, aabb2.max.x);
  out.max.y = scalar_max(aabb1.max.y, aabb2.max.y);
  out.max.z = scalar_max(aabb1.max.z, aabb2.max.z);
  return out;
}

static void body_invalidate_world_aabb(b3Body *body) {
  if (body == NULL) {
    return;
  }
  body->transformValid = false;
  body->worldAabbValid = false;
  for (b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    fixture_invalidate_world_aabb(fixture);
  }
}

static bool aabb_contains_point(const b3Aabb *aabb, b3Vec3 point) {
  return aabb != NULL && point.x >= aabb->min.x && point.x <= aabb->max.x &&
         point.y >= aabb->min.y && point.y <= aabb->max.y &&
         point.z >= aabb->min.z && point.z <= aabb->max.z;
}

static b3Vec3 aabb_overlap_normal_for_sweep(b3Aabb fixtureAabb, b3Vec3 center,
                                            b3Vec3 halfExtents,
                                            b3Vec3 displacement) {
  b3Aabb movingAabb;
  movingAabb.min = vec3_sub(center, halfExtents);
  movingAabb.max = vec3_add(center, halfExtents);

  b3Vec3 movingCenter = aabb_center(movingAabb);
  b3Vec3 fixtureCenter = aabb_center(fixtureAabb);
  scalar overlapX =
      scalar_min(movingAabb.max.x - fixtureAabb.min.x,
                 fixtureAabb.max.x - movingAabb.min.x);
  scalar overlapY =
      scalar_min(movingAabb.max.y - fixtureAabb.min.y,
                 fixtureAabb.max.y - movingAabb.min.y);
  scalar overlapZ =
      scalar_min(movingAabb.max.z - fixtureAabb.min.z,
                 fixtureAabb.max.z - movingAabb.min.z);

  b3Vec3 normal =
      b3Vec3_Make(movingCenter.x >= fixtureCenter.x ? 1.0f : -1.0f, 0.0f,
                  0.0f);
  scalar penetration = overlapX;
  if (overlapY < penetration) {
    normal = b3Vec3_Make(0.0f,
                         movingCenter.y >= fixtureCenter.y ? 1.0f : -1.0f,
                         0.0f);
    penetration = overlapY;
  }
  if (overlapZ < penetration) {
    normal = b3Vec3_Make(0.0f, 0.0f,
                         movingCenter.z >= fixtureCenter.z ? 1.0f : -1.0f);
  }
  return shape_cast_normal_opposing_displacement(normal, displacement);
}

static void fixture_create_proxy(b3Fixture *fixture) {
  if (fixture == NULL || fixture->body == NULL || fixture->body->world == NULL ||
      fixture->body->world->broadPhase == NULL) {
    return;
  }
  b3Aabb aabb = fixture_world_aabb(fixture);
  fixture->proxyId = b3BroadPhase_CreateProxy(fixture->body->world->broadPhase,
                                              aabb_to_public(aabb), fixture);
  if (fixture->proxyId != B3_NULL_DYNAMIC_NODE) {
    fixture->body->world->newContacts = true;
  }
}

static void fixture_destroy_proxy(b3Fixture *fixture) {
  if (fixture == NULL || fixture->body == NULL || fixture->body->world == NULL ||
      fixture->body->world->broadPhase == NULL ||
      fixture->proxyId == B3_NULL_DYNAMIC_NODE) {
    return;
  }
  b3BroadPhase_DestroyProxy(fixture->body->world->broadPhase,
                            fixture->proxyId);
  fixture->proxyId = B3_NULL_DYNAMIC_NODE;
}

static void body_sync_fixtures_between(b3Body *body, b3Transform oldTransform,
                                       b3Transform newTransform) {
  if (body == NULL || body->world == NULL || body->world->broadPhase == NULL) {
    return;
  }
  for (b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    if (fixture->proxyId == B3_NULL_DYNAMIC_NODE) {
      fixture_create_proxy(fixture);
      continue;
    }
    b3Aabb aabb1 = fixture->worldAabbValid
                        ? fixture->worldAabb
                        : fixture_world_aabb_at(fixture, oldTransform);
    b3Aabb aabb2 = fixture_world_aabb_at(fixture, newTransform);
    fixture_store_world_aabb(fixture, aabb2);
    b3Aabb sweptAabb = aabb_combine(aabb1, aabb2);
    b3Vec3 displacement = vec3_sub(aabb_center(aabb2), aabb_center(aabb1));
    b3BroadPhase_MoveProxy(body->world->broadPhase, fixture->proxyId,
                           aabb_to_public(sweptAabb), displacement);
  }
}

static void body_sync_fixtures(b3Body *body, b3Vec3 displacement) {
  if (body == NULL || body->world == NULL || body->world->broadPhase == NULL) {
    return;
  }
  for (b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    if (fixture->proxyId == B3_NULL_DYNAMIC_NODE) {
      fixture_create_proxy(fixture);
      continue;
    }
    b3Aabb aabb = fixture_world_aabb_at(fixture, body_transform(body));
    fixture_store_world_aabb(fixture, aabb);
    b3BroadPhase_MoveProxy(body->world->broadPhase, fixture->proxyId,
                           aabb_to_public(aabb), displacement);
  }
}

static bool body_compute_world_aabb(const b3Body *body, b3Aabb *out) {
  if (body == NULL || out == NULL) {
    return false;
  }

  bool found = false;
  for (const b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    if (fixture->sensor) {
      continue;
    }

    b3Aabb local = fixture_world_aabb(fixture);
    if (!found) {
      *out = local;
      found = true;
    } else {
      out->min.x = scalar_min(out->min.x, local.min.x);
      out->min.y = scalar_min(out->min.y, local.min.y);
      out->min.z = scalar_min(out->min.z, local.min.z);
      out->max.x = scalar_max(out->max.x, local.max.x);
      out->max.y = scalar_max(out->max.y, local.max.y);
      out->max.z = scalar_max(out->max.z, local.max.z);
    }
  }
  return found;
}

static bool body_world_aabb(const b3Body *body, b3Aabb *out) {
  if (body == NULL || out == NULL) {
    return false;
  }

  if (body->worldAabbValid) {
    *out = body->worldAabb;
    return true;
  }

  if (!body_compute_world_aabb(body, out)) {
    return false;
  }

  b3Body *mutableBody = (b3Body *)body;
  mutableBody->worldAabb = *out;
  mutableBody->worldAabbValid = true;
  return true;
}

static b3Mat33 shape_box_inertia_from_aabb(b3Aabb aabb, scalar mass,
                                           b3Vec3 center) {
  b3Vec3 size = vec3_sub(aabb.max, aabb.min);
  b3Mat33 inertia =
      mat33_diagonal((mass / 12.0f) * (size.y * size.y + size.z * size.z),
                     (mass / 12.0f) * (size.x * size.x + size.z * size.z),
                     (mass / 12.0f) * (size.x * size.x + size.y * size.y));
  return mat33_add(inertia, mat33_mul_scalar(mat33_steiner(center), mass));
}

static bool hull_compute_mass_data(const b3Hull *hull, scalar density,
                                   b3MassData *out) {
  if (hull == NULL || out == NULL || density <= 0.0f ||
      !b3Hull_Validate(hull)) {
    return false;
  }

  b3Vec3 shift = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  for (uint32 i = 0u; i < hull->vertexCount; ++i) {
    shift = vec3_add(shift, hull->vertices[i]);
  }
  shift = vec3_mul(shift, 1.0f / (scalar)hull->vertexCount);

  scalar volume = 0.0f;
  b3Vec3 center = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  scalar xx = 0.0f;
  scalar xy = 0.0f;
  scalar yy = 0.0f;
  scalar xz = 0.0f;
  scalar zz = 0.0f;
  scalar yz = 0.0f;

  for (uint32 i = 0u; i < hull->faceCount; ++i) {
    uint32 beginIndex = hull->faces[i].edge;
    const b3HalfEdge *begin = &hull->edges[beginIndex];
    uint32 edgeIndex = begin->next;
    uint32 guard = 0u;

    while (edgeIndex < hull->edgeCount && guard++ < hull->edgeCount) {
      const b3HalfEdge *edge = &hull->edges[edgeIndex];
      const b3HalfEdge *next = &hull->edges[edge->next];
      b3Vec3 v1 = vec3_sub(hull->vertices[begin->origin], shift);
      b3Vec3 v2 = vec3_sub(hull->vertices[edge->origin], shift);
      b3Vec3 v3 = vec3_sub(hull->vertices[next->origin], shift);
      scalar d = b3Vec3_Det(v1, v2, v3);
      b3Vec3 v4 = vec3_add(vec3_add(v1, v2), v3);

      volume += d;
      center = vec3_add(center, vec3_mul(v4, d));
      xx += d * (v1.x * v1.x + v2.x * v2.x + v3.x * v3.x + v4.x * v4.x);
      yy += d * (v1.y * v1.y + v2.y * v2.y + v3.y * v3.y + v4.y * v4.y);
      zz += d * (v1.z * v1.z + v2.z * v2.z + v3.z * v3.z + v4.z * v4.z);
      xy += d * (v1.x * v1.y + v2.x * v2.y + v3.x * v3.y + v4.x * v4.y);
      xz += d * (v1.x * v1.z + v2.x * v2.z + v3.x * v3.z + v4.x * v4.z);
      yz += d * (v1.y * v1.z + v2.y * v2.z + v3.y * v3.z + v4.y * v4.z);

      edgeIndex = edge->next;
      if (hull->edges[edgeIndex].next == beginIndex) {
        break;
      }
    }
  }

  if (volume <= B3_EPSILON) {
    return false;
  }

  center = vec3_mul(center, 1.0f / (4.0f * volume));
  out->mass = density * volume / 6.0f;
  out->center = vec3_add(center, shift);
  out->I.x = b3Vec3_Make(yy + zz, -xy, -xz);
  out->I.y = b3Vec3_Make(-xy, xx + zz, -yz);
  out->I.z = b3Vec3_Make(-xz, -yz, xx + yy);
  out->I = mat33_mul_scalar(out->I, density / 120.0f);
  out->I =
      mat33_add(out->I,
                mat33_mul_scalar(
                    mat33_sub(mat33_steiner(out->center),
                              mat33_steiner(center)),
                    out->mass));
  return true;
}

static bool vertex_hull_compute_mass_data(const b3HullShape *shape,
                                          scalar density, b3MassData *out) {
  if (shape == NULL || shape->vertices == NULL || shape->vertexCount < 4u ||
      out == NULL) {
    return false;
  }

  b3Hull *hull =
      b3Hull_Create(shape->vertices, shape->vertexCount, B3_LINEAR_SLOP);
  if (hull == NULL) {
    return false;
  }

  bool computed = hull_compute_mass_data(hull, density, out);
  b3Hull_Destroy(hull);
  return computed;
}

static void shape_compute_mass(const b3Shape *shape, scalar density,
                               b3MassData *out) {
  if (out == NULL) {
    return;
  }
  out->center = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out->mass = 0.0f;
  out->I = mat33_zero();
  if (shape == NULL || density <= 0.0f) {
    return;
  }

  switch (shape->type) {
  case e_sphereShape: {
    const b3SphereShape *sphere = (const b3SphereShape *)shape;
    scalar r = shape->radius;
    scalar mass = (4.0f / 3.0f) * B3_PI * r * r * r * density;
    scalar centerOffset = vec3_dot(sphere->center, sphere->center);
    scalar inertia = mass * (0.4f * r * r + centerOffset);
    out->center = sphere->center;
    out->mass = mass;
    out->I = mat33_diagonal(inertia, inertia, inertia);
    break;
  }
  case e_capsuleShape: {
    const b3CapsuleShape *capsule = (const b3CapsuleShape *)shape;
    b3Vec3 d = vec3_sub(capsule->point2, capsule->point1);
    scalar h = vec3_length(d);
    if (h <= B3_LINEAR_SLOP) {
      return;
    }

    scalar h2 = h * h;
    scalar r = shape->radius;
    scalar r2 = r * r;
    scalar r3 = r2 * r;
    b3Vec3 center = vec3_mul(vec3_add(capsule->point1, capsule->point2), 0.5f);

    b3Vec3 axisY = vec3_mul(d, 1.0f / h);
    b3Vec3 axisX = vec3_perp(axisY);
    b3Vec3 axisZ = vec3_cross(axisY, axisX);
    b3Mat33 rotation;
    rotation.x = axisX;
    rotation.y = axisY;
    rotation.z = axisZ;

    scalar mass = 0.0f;
    b3Mat33 inertia = mat33_zero();

    scalar cylinderMass = density * B3_PI * r2 * h;
    scalar cylinderIxx =
        (1.0f / 12.0f) * cylinderMass * (3.0f * r2 + h2);
    scalar cylinderIyy = 0.5f * cylinderMass * r2;
    b3Mat33 cylinderI =
        mat33_diagonal(cylinderIxx, cylinderIyy, cylinderIxx);
    cylinderI = mat33_mul(mat33_mul(rotation, cylinderI),
                          mat33_transpose(rotation));
    cylinderI =
        mat33_add(cylinderI,
                  mat33_mul_scalar(mat33_steiner(center), cylinderMass));
    mass += cylinderMass;
    inertia = mat33_add(inertia, cylinderI);

    scalar hemiMass = density * (2.0f / 3.0f) * B3_PI * r3;
    scalar Io = (2.0f / 5.0f) * hemiMass * r2;
    scalar coy = (3.0f / 8.0f) * r;
    scalar hemiIyy = Io - hemiMass * coy * coy;
    scalar ccy = coy + 0.5f * h;
    scalar hemiIxx = Io + hemiMass * ccy * ccy;
    b3Mat33 hemiI = mat33_diagonal(hemiIxx, hemiIyy, hemiIxx);
    hemiI = mat33_mul(mat33_mul(rotation, hemiI), mat33_transpose(rotation));
    hemiI = mat33_add(hemiI, mat33_mul_scalar(mat33_steiner(center), hemiMass));
    mass += 2.0f * hemiMass;
    inertia = mat33_add(inertia, mat33_mul_scalar(hemiI, 2.0f));

    out->center = center;
    out->mass = mass;
    out->I = inertia;
    break;
  }
  case e_triangleShape: {
    const b3TriangleShape *triangle = (const b3TriangleShape *)shape;
    out->center =
        vec3_mul(vec3_add(vec3_add(triangle->vertex1, triangle->vertex2),
                          triangle->vertex3),
                 1.0f / 3.0f);
    break;
  }
  case e_meshShape:
    break;
  case e_hullShape: {
    const b3HullShape *hull = (const b3HullShape *)shape;
    if (hull->genericHull != NULL &&
        hull_compute_mass_data(hull->genericHull, density, out)) {
      break;
    }
    if (vertex_hull_compute_mass_data(hull, density, out)) {
      break;
    }
    b3Aabb aabb;
    shape_local_aabb(shape, &aabb);
    b3Vec3 size = vec3_sub(aabb.max, aabb.min);
    if (size.x <= 0.0f || size.y <= 0.0f || size.z <= 0.0f) {
      return;
    }
    out->center = vec3_mul(vec3_add(aabb.min, aabb.max), 0.5f);
    out->mass = size.x * size.y * size.z * density;
    out->I = shape_box_inertia_from_aabb(aabb, out->mass, out->center);
    break;
  }
  default: {
    b3Aabb aabb;
    shape_local_aabb(shape, &aabb);
    b3Vec3 size = vec3_sub(aabb.max, aabb.min);
    if (size.x <= 0.0f || size.y <= 0.0f || size.z <= 0.0f) {
      return;
    }
    out->center = vec3_mul(vec3_add(aabb.min, aabb.max), 0.5f);
    out->mass = size.x * size.y * size.z * density;
    out->I = shape_box_inertia_from_aabb(aabb, out->mass, out->center);
    break;
  }
  }
}

static void body_update_world_inv_inertia(b3Body *body) {
  if (body == NULL) {
    return;
  }
  body->worldInvInertia =
      mat33_rotate_to_frame(body->invInertia, body->orientation);
}

static void body_apply_fixed_rotation_masks(b3Body *body) {
  if (body == NULL) {
    return;
  }
  if (body->fixedRotationX) {
    body->invInertia.y.y = 0.0f;
    body->invInertia.z.y = 0.0f;
    body->invInertia.y.z = 0.0f;
    body->invInertia.z.z = 0.0f;
    body->worldInvInertia.y.y = 0.0f;
    body->worldInvInertia.z.y = 0.0f;
    body->worldInvInertia.y.z = 0.0f;
    body->worldInvInertia.z.z = 0.0f;
  }
  if (body->fixedRotationY) {
    body->invInertia.x.x = 0.0f;
    body->invInertia.x.z = 0.0f;
    body->invInertia.z.x = 0.0f;
    body->invInertia.z.z = 0.0f;
    body->worldInvInertia.x.x = 0.0f;
    body->worldInvInertia.x.z = 0.0f;
    body->worldInvInertia.z.x = 0.0f;
    body->worldInvInertia.z.z = 0.0f;
  }
  if (body->fixedRotationZ) {
    body->invInertia.x.x = 0.0f;
    body->invInertia.x.y = 0.0f;
    body->invInertia.y.x = 0.0f;
    body->invInertia.y.y = 0.0f;
    body->worldInvInertia.x.x = 0.0f;
    body->worldInvInertia.x.y = 0.0f;
    body->worldInvInertia.y.x = 0.0f;
    body->worldInvInertia.y.y = 0.0f;
  }
}

static void body_reset_mass(b3Body *body) {
  if (body->type != e_dynamicBody) {
    body->mass = 0.0f;
    body->invMass = 0.0f;
    body->localCenter = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    body->inertia = mat33_zero();
    body->invInertia = mat33_zero();
    body->worldInvInertia = mat33_zero();
    body_update_world_center(body);
    body_reset_sweep(body);
    return;
  }

  b3Vec3 oldCenter = body_current_world_center(body);
  scalar mass = 0.0f;
  b3Vec3 localCenter = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  b3Mat33 inertia = mat33_zero();
  for (b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    if (fixture->density <= 0.0f) {
      continue;
    }
    b3MassData massData;
    shape_compute_mass(&fixture->storage.base, fixture->density, &massData);
    mass += massData.mass;
    localCenter =
        vec3_add(localCenter, vec3_mul(massData.center, massData.mass));
    inertia = mat33_add(inertia, massData.I);
  }

  if (mass <= 0.0f) {
    mass = 1.0f;
  }
  body->mass = mass;
  body->invMass = 1.0f / mass;
  body->localCenter = vec3_mul(localCenter, body->invMass);
  body_update_world_center(body);
  body->inertia = mat33_sub(
      inertia, mat33_mul_scalar(mat33_steiner(body->localCenter), mass));
  body->invInertia = mat33_inverse(body->inertia);
  body_update_world_inv_inertia(body);
  body_apply_fixed_rotation_masks(body);
  b3Vec3 newCenter = body_current_world_center(body);
  body_reset_sweep(body);
  body->linearVelocity = vec3_add(
      body->linearVelocity,
      vec3_cross(body->angularVelocity, vec3_sub(newCenter, oldCenter)));
}

static void fixture_copy_shape(b3Fixture *fixture, const b3Shape *shape) {
  memset(&fixture->storage, 0, sizeof(fixture->storage));
  if (shape == NULL) {
    return;
  }

  switch (shape->type) {
  case e_sphereShape:
    fixture->storage.sphere = *(const b3SphereShape *)shape;
    break;
  case e_capsuleShape:
    fixture->storage.capsule = *(const b3CapsuleShape *)shape;
    break;
  case e_triangleShape:
    fixture->storage.triangle = *(const b3TriangleShape *)shape;
    break;
  case e_meshShape:
    fixture->storage.mesh = *(const b3MeshShape *)shape;
    break;
  case e_hullShape: {
    const b3HullShape *hullShape = (const b3HullShape *)shape;
    fixture->storage.hull.shape = *hullShape;
    if (hullShape->hull != NULL) {
      fixture->storage.hull.hull = *hullShape->hull;
      fixture->storage.hull.shape.hull = &fixture->storage.hull.hull;
    }
    if (hullShape->vertices != NULL && hullShape->vertexCount > 0u) {
      uint32 count = hullShape->vertexCount < B3_MAX_HULL_VERTICES
                         ? hullShape->vertexCount
                         : B3_MAX_HULL_VERTICES;
      for (uint32 i = 0u; i < count; ++i) {
        fixture->storage.hull.vertices[i] = hullShape->vertices[i];
      }
      fixture->storage.hull.shape.vertices = fixture->storage.hull.vertices;
      fixture->storage.hull.shape.vertexCount = count;
    }
    break;
  }
  default:
    fixture->storage.base = *shape;
    break;
  }
}

static scalar body_restitution(const b3Body *body) {
  if (body == NULL) {
    return 0.0f;
  }
  scalar restitution = 0.0f;
  for (const b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    restitution = scalar_max(restitution, fixture->restitution);
  }
  return restitution;
}

static scalar body_pair_restitution(const b3Body *bodyA,
                                    const b3Body *bodyB) {
  return b3MixRestitution(body_restitution(bodyA), body_restitution(bodyB));
}

static scalar contact_pair_restitution(const b3Contact *contact,
                                       const b3Body *bodyA,
                                       const b3Body *bodyB) {
  if (contact != NULL && contact->fixtureA != NULL &&
      contact->fixtureB != NULL) {
    return b3MixRestitution(contact->fixtureA->restitution,
                            contact->fixtureB->restitution);
  }
  return body_pair_restitution(bodyA, bodyB);
}

static scalar restitution_for_normal_velocity(scalar restitution,
                                              scalar normalVelocity) {
  return normalVelocity < -B3_VELOCITY_THRESHOLD ? restitution : 0.0f;
}

static scalar body_friction(const b3Body *body) {
  if (body == NULL) {
    return 0.0f;
  }
  scalar friction = 0.0f;
  for (const b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    friction = scalar_max(friction, fixture->friction);
  }
  return friction;
}

static scalar mix_friction(scalar frictionA, scalar frictionB) {
  return b3MixFriction(frictionA, frictionB);
}

static scalar body_pair_friction(const b3Body *bodyA, const b3Body *bodyB) {
  return mix_friction(body_friction(bodyA), body_friction(bodyB));
}

static scalar contact_pair_friction(const b3Contact *contact,
                                    const b3Body *bodyA,
                                    const b3Body *bodyB) {
  if (contact != NULL && contact->fixtureA != NULL &&
      contact->fixtureB != NULL) {
    return mix_friction(contact->fixtureA->friction,
                        contact->fixtureB->friction);
  }
  return body_pair_friction(bodyA, bodyB);
}

