static bool contact_position_constraints_solved(const b3Contact *contact) {
  if (contact == NULL) {
    return true;
  }

  for (uint32 i = 0u; i < contact->manifold.pointCount; ++i) {
    b3ContactPositionPoint point;
    if (!contact_position_point_from_manifold(contact, i, &point)) {
      return true;
    }
    if (point.separation < -3.0f * B3_LINEAR_SLOP) {
      return false;
    }
  }
  return true;
}

static b3Color debug_color(scalar r, scalar g, scalar b) {
  b3Color color;
  color.r = r;
  color.g = g;
  color.b = b;
  color.a = 1.0f;
  return color;
}

static b3Color debug_body_color(const b3Body *body) {
  if (body == NULL) {
    return debug_color(0.7f, 0.7f, 0.7f);
  }
  if (body->type == e_dynamicBody) {
    return debug_color(0.2f, 0.8f, 0.35f);
  }
  if (body->type == e_kinematicBody) {
    return debug_color(0.2f, 0.55f, 0.9f);
  }
  return debug_color(0.45f, 0.45f, 0.45f);
}

static void debug_draw_segment(const b3DebugDraw *draw, b3Vec3 p1, b3Vec3 p2,
                               b3Color color) {
  if (draw != NULL && draw->DrawSegment != NULL) {
    draw->DrawSegment(draw->context, p1, p2, color);
  }
}

static void debug_draw_point(const b3DebugDraw *draw, b3Vec3 point, scalar size,
                             b3Color color) {
  if (draw != NULL && draw->DrawPoint != NULL) {
    draw->DrawPoint(draw->context, point, size, color);
  }
}

static void debug_draw_solid_triangle(const b3DebugDraw *draw, b3Vec3 normal,
                                      b3Vec3 p1, b3Vec3 p2, b3Vec3 p3,
                                      b3Color color) {
  if (draw != NULL && draw->DrawSolidTriangle != NULL) {
    draw->DrawSolidTriangle(draw->context, normal, p1, p2, p3, color);
  }
}

static void debug_draw_solid_polygon(const b3DebugDraw *draw, b3Vec3 normal,
                                     const b3Vec3 *vertices, uint32 count,
                                     b3Color color) {
  if (draw != NULL && draw->DrawSolidPolygon != NULL) {
    draw->DrawSolidPolygon(draw->context, normal, vertices, count, color);
    return;
  }
  if (draw != NULL && draw->DrawTriangle != NULL && vertices != NULL &&
      count >= 3u) {
    for (uint32 i = 1u; i + 1u < count; ++i) {
      draw->DrawTriangle(draw->context, vertices[0], vertices[i],
                         vertices[i + 1u], color);
    }
  }
}

static void debug_draw_half_edges(const b3DebugDraw *draw, b3Transform xf,
                                  const b3Vec3 *vertices, uint32 vertexCount,
                                  const b3HalfEdge *edges, uint32 edgeCount,
                                  b3Color color) {
  if (draw == NULL || draw->DrawSegment == NULL || vertices == NULL ||
      edges == NULL) {
    return;
  }
  for (uint32 i = 0u; i < edgeCount; ++i) {
    const b3HalfEdge *edge = &edges[i];
    if (edge->twin >= edgeCount || edge->origin >= vertexCount ||
        edges[edge->twin].origin >= vertexCount || edge->twin < i) {
      continue;
    }
    debug_draw_segment(draw, b3Transform_MulPoint(xf, vertices[edge->origin]),
                       b3Transform_MulPoint(xf,
                                            vertices[edges[edge->twin].origin]),
                       color);
  }
}

static void debug_draw_solid_hull_faces(const b3DebugDraw *draw,
                                        b3Transform xf,
                                        const b3Vec3 *vertices,
                                        uint32 vertexCount,
                                        const b3HalfEdge *edges,
                                        uint32 edgeCount,
                                        const b3Face *faces,
                                        const b3Plane *planes,
                                        uint32 faceCount,
                                        b3Color color) {
  if (draw == NULL || draw->DrawSolidTriangle == NULL || vertices == NULL ||
      edges == NULL || faces == NULL || planes == NULL) {
    return;
  }
  for (uint32 i = 0u; i < faceCount; ++i) {
    uint32 beginIndex = faces[i].edge;
    if (beginIndex >= edgeCount) {
      continue;
    }
    uint32 edgeIndex = edges[beginIndex].next;
    b3Vec3 normal = b3Quat_RotateVec3(xf.rotation, planes[i].normal);
    for (uint32 guard = 0u; guard < edgeCount; ++guard) {
      if (edgeIndex >= edgeCount || edges[edgeIndex].next >= edgeCount) {
        break;
      }
      uint32 nextIndex = edges[edgeIndex].next;
      uint32 i1 = edges[beginIndex].origin;
      uint32 i2 = edges[edgeIndex].origin;
      uint32 i3 = edges[nextIndex].origin;
      if (i1 >= vertexCount || i2 >= vertexCount || i3 >= vertexCount) {
        break;
      }
      debug_draw_solid_triangle(draw, normal,
                                b3Transform_MulPoint(xf, vertices[i1]),
                                b3Transform_MulPoint(xf, vertices[i2]),
                                b3Transform_MulPoint(xf, vertices[i3]),
                                color);
      edgeIndex = nextIndex;
      if (edges[edgeIndex].next == beginIndex) {
        break;
      }
    }
  }
}

static void debug_draw_box_hull(const b3DebugDraw *draw, b3Transform xf,
                                b3Vec3 halfExtents, b3Color color) {
  b3Vec3 vertices[8];
  vertices[0] = b3Vec3_Make(-halfExtents.x, -halfExtents.y, -halfExtents.z);
  vertices[1] = b3Vec3_Make(halfExtents.x, -halfExtents.y, -halfExtents.z);
  vertices[2] = b3Vec3_Make(halfExtents.x, halfExtents.y, -halfExtents.z);
  vertices[3] = b3Vec3_Make(-halfExtents.x, halfExtents.y, -halfExtents.z);
  vertices[4] = b3Vec3_Make(-halfExtents.x, -halfExtents.y, halfExtents.z);
  vertices[5] = b3Vec3_Make(halfExtents.x, -halfExtents.y, halfExtents.z);
  vertices[6] = b3Vec3_Make(halfExtents.x, halfExtents.y, halfExtents.z);
  vertices[7] = b3Vec3_Make(-halfExtents.x, halfExtents.y, halfExtents.z);
  for (uint32 i = 0u; i < 8u; ++i) {
    vertices[i] = b3Transform_MulPoint(xf, vertices[i]);
  }

  static const uint8_t edges[12][2] = {
      {0u, 1u}, {1u, 2u}, {2u, 3u}, {3u, 0u},
      {4u, 5u}, {5u, 6u}, {6u, 7u}, {7u, 4u},
      {0u, 4u}, {1u, 5u}, {2u, 6u}, {3u, 7u},
  };
  for (uint32 i = 0u; i < 12u; ++i) {
    debug_draw_segment(draw, vertices[edges[i][0]], vertices[edges[i][1]],
                       color);
  }
}

static void debug_draw_shape_solid(const b3DebugDraw *draw,
                                   const b3Shape *shape, b3Transform xf,
                                   b3Color color) {
  if (draw == NULL || shape == NULL) {
    return;
  }

  switch (shape->type) {
  case e_sphereShape: {
    const b3SphereShape *sphere = (const b3SphereShape *)shape;
    if (draw->DrawSolidSphere != NULL) {
      draw->DrawSolidSphere(draw->context, b3Quat_GetYAxis(xf.rotation),
                            b3Transform_MulPoint(xf, sphere->center),
                            sphere->base.radius, color);
    }
    break;
  }
  case e_capsuleShape: {
    const b3CapsuleShape *capsule = (const b3CapsuleShape *)shape;
    if (draw->DrawSolidCapsule != NULL) {
      draw->DrawSolidCapsule(draw->context, b3Quat_GetYAxis(xf.rotation),
                             b3Transform_MulPoint(xf, capsule->point1),
                             b3Transform_MulPoint(xf, capsule->point2),
                             capsule->base.radius, color);
    }
    break;
  }
  case e_triangleShape: {
    const b3TriangleShape *triangle = (const b3TriangleShape *)shape;
    b3Vec3 p1 = b3Transform_MulPoint(xf, triangle->vertex1);
    b3Vec3 p2 = b3Transform_MulPoint(xf, triangle->vertex2);
    b3Vec3 p3 = b3Transform_MulPoint(xf, triangle->vertex3);
    b3Vec3 normal = vec3_normalize_or_zero(vec3_cross(vec3_sub(p2, p1),
                                                      vec3_sub(p3, p1)));
    debug_draw_solid_triangle(draw, vec3_mul(normal, -1.0f), p3, p2, p1,
                              color);
    debug_draw_solid_triangle(draw, normal, p1, p2, p3, color);
    break;
  }
  case e_hullShape: {
    const b3HullShape *hull = (const b3HullShape *)shape;
    if (hull->hull != NULL) {
      debug_draw_solid_hull_faces(draw, xf, hull->hull->vertices,
                                  hull->hull->vertexCount, hull->hull->edges,
                                  hull->hull->edgeCount, hull->hull->faces,
                                  hull->hull->planes, hull->hull->faceCount,
                                  color);
      break;
    }
    if (hull->genericHull != NULL) {
      debug_draw_solid_hull_faces(
          draw, xf, hull->genericHull->vertices, hull->genericHull->vertexCount,
          hull->genericHull->edges, hull->genericHull->edgeCount,
          hull->genericHull->faces, hull->genericHull->planes,
          hull->genericHull->faceCount, color);
    }
    break;
  }
  case e_meshShape: {
    const b3MeshShape *meshShape = (const b3MeshShape *)shape;
    if (meshShape->mesh == NULL || meshShape->mesh->vertices == NULL ||
        meshShape->mesh->triangles == NULL) {
      break;
    }
    for (uint32 i = 0u; i < meshShape->mesh->triangleCount; ++i) {
      const b3MeshTriangle *triangle = &meshShape->mesh->triangles[i];
      b3Vec3 p1 = b3Transform_MulPoint(
          xf, vec3_mul_comp(meshShape->mesh->vertices[triangle->v1],
                            meshShape->scale));
      b3Vec3 p2 = b3Transform_MulPoint(
          xf, vec3_mul_comp(meshShape->mesh->vertices[triangle->v2],
                            meshShape->scale));
      b3Vec3 p3 = b3Transform_MulPoint(
          xf, vec3_mul_comp(meshShape->mesh->vertices[triangle->v3],
                            meshShape->scale));
      b3Vec3 normal = vec3_normalize_or_zero(vec3_cross(vec3_sub(p2, p1),
                                                        vec3_sub(p3, p1)));
      debug_draw_solid_triangle(draw, normal, p1, p2, p3, color);
      debug_draw_solid_triangle(draw, vec3_mul(normal, -1.0f), p3, p2, p1,
                                color);
    }
    break;
  }
  case e_shapeTypeCount:
    break;
  }
}

static void debug_draw_shape(const b3DebugDraw *draw, const b3Shape *shape,
                             b3Transform xf, b3Color color) {
  if (draw == NULL || shape == NULL) {
    return;
  }

  switch (shape->type) {
  case e_sphereShape: {
    const b3SphereShape *sphere = (const b3SphereShape *)shape;
    if (draw->DrawSphere != NULL) {
      draw->DrawSphere(draw->context, b3Transform_MulPoint(xf, sphere->center),
                       sphere->base.radius, color);
    }
    break;
  }
  case e_capsuleShape: {
    const b3CapsuleShape *capsule = (const b3CapsuleShape *)shape;
    b3Vec3 p1 = b3Transform_MulPoint(xf, capsule->point1);
    b3Vec3 p2 = b3Transform_MulPoint(xf, capsule->point2);
    if (draw->DrawCapsule != NULL) {
      draw->DrawCapsule(draw->context, p1, p2, capsule->base.radius, color);
    } else {
      debug_draw_segment(draw, p1, p2, color);
    }
    break;
  }
  case e_triangleShape: {
    const b3TriangleShape *triangle = (const b3TriangleShape *)shape;
    b3Vec3 p1 = b3Transform_MulPoint(xf, triangle->vertex1);
    b3Vec3 p2 = b3Transform_MulPoint(xf, triangle->vertex2);
    b3Vec3 p3 = b3Transform_MulPoint(xf, triangle->vertex3);
    if (draw->DrawTriangle != NULL) {
      draw->DrawTriangle(draw->context, p1, p2, p3, color);
    } else {
      debug_draw_segment(draw, p1, p2, color);
      debug_draw_segment(draw, p2, p3, color);
      debug_draw_segment(draw, p3, p1, color);
    }
    break;
  }
  case e_hullShape: {
    const b3HullShape *hull = (const b3HullShape *)shape;
    if (hull->hull != NULL) {
      debug_draw_box_hull(draw, xf, hull->hull->halfExtents, color);
      break;
    }
    if (hull->genericHull != NULL && hull->genericHull->edgeCount > 0u) {
      debug_draw_half_edges(draw, xf, hull->genericHull->vertices,
                            hull->genericHull->vertexCount,
                            hull->genericHull->edges,
                            hull->genericHull->edgeCount, color);
      break;
    }
    const b3Vec3 *vertices = NULL;
    uint32 vertexCount = 0u;
    if (hull_shape_vertices(hull, &vertices, &vertexCount)) {
      for (uint32 i = 0u; i < vertexCount; ++i) {
        debug_draw_point(draw, b3Transform_MulPoint(xf, vertices[i]), 4.0f,
                         color);
      }
    }
    break;
  }
  case e_meshShape: {
    const b3MeshShape *meshShape = (const b3MeshShape *)shape;
    if (meshShape->mesh == NULL || meshShape->mesh->vertices == NULL ||
        meshShape->mesh->triangles == NULL || draw->DrawTriangle == NULL) {
      break;
    }
    for (uint32 i = 0u; i < meshShape->mesh->triangleCount; ++i) {
      const b3MeshTriangle *triangle = &meshShape->mesh->triangles[i];
      b3Vec3 p1 = b3Transform_MulPoint(
          xf, vec3_mul_comp(meshShape->mesh->vertices[triangle->v1],
                            meshShape->scale));
      b3Vec3 p2 = b3Transform_MulPoint(
          xf, vec3_mul_comp(meshShape->mesh->vertices[triangle->v2],
                            meshShape->scale));
      b3Vec3 p3 = b3Transform_MulPoint(
          xf, vec3_mul_comp(meshShape->mesh->vertices[triangle->v3],
                            meshShape->scale));
      draw->DrawTriangle(draw->context, p1, p2, p3, color);
    }
    break;
  }
  case e_shapeTypeCount:
    break;
  }
}

static void debug_draw_joint(const b3DebugDraw *draw, const b3Joint *joint) {
  if (draw == NULL || draw->DrawSegment == NULL || joint == NULL ||
      joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }
  b3Color color = {0.4f, 0.8f, 1.0f, 1.0f};
  b3Vec3 centerA = b3Body_GetWorldCenter(joint->bodyA);
  b3Vec3 centerB = b3Body_GetWorldCenter(joint->bodyB);
  b3Vec3 anchorA = b3Body_GetWorldPoint(joint->bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(joint->bodyB, joint->localAnchorB);
  draw->DrawSegment(draw->context, centerA, anchorA, color);
  draw->DrawSegment(draw->context, anchorA, anchorB, color);
  draw->DrawSegment(draw->context, anchorB, centerB, color);
}

static bool bodies_collide(const b3Body *a, const b3Body *b) {
  if (a == NULL || b == NULL) {
    return false;
  }
  if (!bodies_should_collide(a, b)) {
    return false;
  }

  b3Transform xfA = body_transform(a);
  b3Transform xfB = body_transform(b);
  for (const b3Fixture *fixtureA = a->fixtures; fixtureA != NULL;
       fixtureA = fixtureA->next) {
    if (fixtureA->sensor) {
      continue;
    }
    for (const b3Fixture *fixtureB = b->fixtures; fixtureB != NULL;
         fixtureB = fixtureB->next) {
      if (fixtureB->sensor) {
        continue;
      }
      b3Aabb aabbA = fixture_world_aabb(fixtureA);
      b3Aabb aabbB = fixture_world_aabb(fixtureB);
      if (!aabb_overlap(&aabbA, &aabbB)) {
        continue;
      }
      if (!fixtures_allow_contact(fixtureA, fixtureB)) {
        continue;
      }
      if (!fixtures_allow_response(fixtureA, fixtureB)) {
        continue;
      }

      b3Manifold manifold;
      if (b3CollideShapes(&manifold, xfA, &fixtureA->storage.base, xfB,
                          &fixtureB->storage.base)) {
        return true;
      }
    }
  }
  return false;
}

static bool resolve_dynamic_against_static(b3Body *body, const b3Body *other,
                                           const b3Contact *contact,
                                           bool solvePosition,
                                           bool solveVelocity) {
  if (body == NULL || !body->awake) {
    return true;
  }

  if (solvePosition && !solveVelocity && contact != NULL &&
      contact->manifold.pointCount > 0u) {
    contact_mark_solved(contact);
    bool solved = true;
    solve_dynamic_static_contact_point_positions(contact, body, &solved);
    return solved;
  }

  b3Vec3 normal;
  scalar penetration;
  if (contact == NULL) {
    contact = find_responding_body_contact(body->world, body, other);
  }
  b3WorldManifold worldManifold;
  bool haveWorldManifold =
      contact != NULL && b3Contact_GetWorldManifold(contact, &worldManifold);
  if (!(haveWorldManifold &&
        contact_normal_for_body_from_world(contact, body, &worldManifold,
                                           &normal, &penetration))) {
    if (!bodies_collide(body, other)) {
      return true;
    }

    b3Aabb a;
    b3Aabb b;
    if (!body_world_aabb(body, &a) || !body_world_aabb(other, &b) ||
        !aabb_overlap(&a, &b)) {
      return true;
    }

    b3Vec3 centerA = vec3_mul(vec3_add(a.min, a.max), 0.5f);
    b3Vec3 centerB = vec3_mul(vec3_add(b.min, b.max), 0.5f);
    scalar overlapX = scalar_min(a.max.x - b.min.x, b.max.x - a.min.x);
    scalar overlapY = scalar_min(a.max.y - b.min.y, b.max.y - a.min.y);
    scalar overlapZ = scalar_min(a.max.z - b.min.z, b.max.z - a.min.z);

    normal = b3Vec3_Make(centerA.x >= centerB.x ? 1.0f : -1.0f, 0.0f,
                         0.0f);
    penetration = overlapX;
    if (overlapY < penetration) {
      normal = b3Vec3_Make(0.0f, centerA.y >= centerB.y ? 1.0f : -1.0f,
                           0.0f);
      penetration = overlapY;
    }
    if (overlapZ < penetration) {
      normal = b3Vec3_Make(0.0f, 0.0f, centerA.z >= centerB.z ? 1.0f : -1.0f);
      penetration = overlapZ;
    }
  }

  contact_mark_solved(contact);

  bool positionSolved = true;
  if (solvePosition) {
    bool correctedPoints =
        solve_dynamic_static_contact_point_positions(contact, body, NULL);
    if (!correctedPoints) {
      b3Vec3 contactPoint;
      if (!contact_center_point(contact, &contactPoint)) {
        contactPoint = body_current_world_center(body);
      }
      scalar normalInvMass =
          body_direction_inv_mass_at_point(body, contactPoint, normal);
      scalar correction =
          contact_position_correction_from_separation(-penetration);
      if (normalInvMass > B3_EPSILON && correction > 0.0f) {
        body_apply_position_impulse_at_point(
          body, vec3_mul(normal, correction / normalInvMass), contactPoint);
      }
    }
    positionSolved = contact != NULL
                         ? contact_position_constraints_solved(contact)
                         : penetration <= B3_LINEAR_SLOP;
  }

  if (!solveVelocity) {
    return positionSolved;
  }

  b3Vec3 contactPoint;
  if (!(haveWorldManifold &&
        contact_center_point_from_world(&worldManifold, &contactPoint))) {
    contactPoint = body_current_world_center(body);
  }

  b3Vec3 pointVelocity = b3Body_GetPointVelocity(body, contactPoint);
  scalar vn = vec3_dot(pointVelocity, normal);
  scalar normalImpulse = 0.0f;
  scalar pairRestitution = contact_pair_restitution(contact, body, other);
  bool solvedPointNormals = false;
  if (haveWorldManifold && worldManifold.pointCount > 1u) {
    for (uint32 i = 0u; i < worldManifold.pointCount; ++i) {
      normalImpulse += solve_dynamic_static_contact_point_normal(
          contact, i, body, worldManifold.points[i].point, normal);
    }
    solvedPointNormals = true;
  }

  if (!solvedPointNormals && vn < 0.0f) {
    scalar restitution = restitution_for_normal_velocity(pairRestitution, vn);
    scalar normalInvMass =
        body_direction_inv_mass_at_point(body, contactPoint, normal);
    if (normalInvMass > B3_EPSILON) {
      normalImpulse = -(1.0f + restitution) * vn / normalInvMass;
      body_apply_impulse_at_point(body, vec3_mul(normal, normalImpulse),
                                  contactPoint);
      contact_store_normal_impulse(contact, normalImpulse);
    }
  }

  if (normalImpulse > 0.0f && body->invMass > B3_EPSILON) {
    scalar friction = contact_pair_friction(contact, body, other);
    pointVelocity = b3Body_GetPointVelocity(body, contactPoint);
    if (!solve_dynamic_static_tangent_friction(
            contact, body, other, haveWorldManifold ? &worldManifold : NULL,
            contactPoint, normal, normalImpulse)) {
      b3Vec3 tangentVelocity = vec3_sub(
          pointVelocity, vec3_mul(normal, vec3_dot(pointVelocity, normal)));
      b3Vec3 tangentTarget;
      if (contact_tangent_target_for_body_from_world(
              contact, body, haveWorldManifold ? &worldManifold : NULL,
              &tangentTarget)) {
        tangentVelocity = vec3_sub(tangentVelocity, tangentTarget);
      }
      scalar tangentSpeed = vec3_length(tangentVelocity);
      if (tangentSpeed > B3_EPSILON) {
        b3Vec3 tangent = vec3_mul(tangentVelocity, 1.0f / tangentSpeed);
        scalar tangentInvMass =
            body_direction_inv_mass_at_point(body, contactPoint, tangent);
        if (tangentInvMass > B3_EPSILON) {
          scalar tangentImpulse = tangentSpeed / tangentInvMass;
          tangentImpulse = scalar_min(tangentImpulse, friction * normalImpulse);
          b3Vec3 impulse = vec3_mul(tangent, -tangentImpulse);
          body_apply_impulse_at_point(body, impulse, contactPoint);
          contact_store_tangent_impulse_for_body(contact, body, impulse);
        }
      }
    }

    b3Vec3 motorAxis;
    scalar motorTargetSpeed;
    if (contact_motor_target_for_body_from_world(
            contact, body, haveWorldManifold ? &worldManifold : NULL,
            &motorAxis, &motorTargetSpeed)) {
      scalar motorInvMass =
          vec3_dot(motorAxis,
                   mat33_mul_vec3(body->worldInvInertia, motorAxis));
      if (motorInvMass > B3_EPSILON) {
        scalar motorSpeed = vec3_dot(body->angularVelocity, motorAxis);
        scalar motorImpulse = -(motorSpeed - motorTargetSpeed) / motorInvMass;
        scalar oldMotorImpulse = 0.0f;
        contact_motor_impulse_for_body(contact, body, &oldMotorImpulse);
        scalar totalNormalImpulse = contact_total_normal_impulse(contact);
        if (totalNormalImpulse <= B3_EPSILON) {
          totalNormalImpulse = normalImpulse;
        }
        scalar maxMotorImpulse = friction * totalNormalImpulse;
        scalar newMotorImpulse = scalar_clamp(oldMotorImpulse + motorImpulse,
                                             -maxMotorImpulse,
                                             maxMotorImpulse);
        motorImpulse = newMotorImpulse - oldMotorImpulse;
        if (fabsf(motorImpulse) > B3_EPSILON) {
          body_apply_angular_impulse(body, vec3_mul(motorAxis, motorImpulse));
          contact_store_motor_impulse_for_body(contact, body, motorImpulse);
        }
      }
    }
  }
  return positionSolved;
}

static bool resolve_body_pair(b3Body *aBody, b3Body *bBody,
                              const b3Contact *contact,
                              bool solvePosition, bool solveVelocity) {
  if (aBody == NULL || bBody == NULL || aBody->type == e_staticBody ||
      bBody->type == e_staticBody) {
    return true;
  }
  if (!aBody->awake && !bBody->awake) {
    return true;
  }

  scalar invMassA = aBody->type == e_dynamicBody ? aBody->invMass : 0.0f;
  scalar invMassB = bBody->type == e_dynamicBody ? bBody->invMass : 0.0f;
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return true;
  }

  body_wake_from_awake_island(aBody, bBody);
  body_wake_from_awake_island(bBody, aBody);

  if (solvePosition && !solveVelocity && contact != NULL &&
      contact->manifold.pointCount > 0u) {
    contact_mark_solved(contact);
    bool solved = true;
    solve_body_pair_contact_point_positions(contact, aBody, bBody, &solved);
    return solved;
  }

  b3Vec3 normal;
  scalar penetration;
  if (contact == NULL) {
    contact = find_responding_body_contact(aBody->world, aBody, bBody);
  }
  b3WorldManifold worldManifold;
  bool haveWorldManifold =
      contact != NULL && b3Contact_GetWorldManifold(contact, &worldManifold);
  if (!(haveWorldManifold &&
        contact_normal_for_body_from_world(contact, aBody, &worldManifold,
                                           &normal, &penetration))) {
    if (!bodies_collide(aBody, bBody)) {
      return true;
    }

    b3Aabb a;
    b3Aabb b;
    if (!body_world_aabb(aBody, &a) || !body_world_aabb(bBody, &b) ||
        !aabb_overlap(&a, &b)) {
      return true;
    }

    b3Vec3 centerA = vec3_mul(vec3_add(a.min, a.max), 0.5f);
    b3Vec3 centerB = vec3_mul(vec3_add(b.min, b.max), 0.5f);
    scalar overlapX = scalar_min(a.max.x - b.min.x, b.max.x - a.min.x);
    scalar overlapY = scalar_min(a.max.y - b.min.y, b.max.y - a.min.y);
    scalar overlapZ = scalar_min(a.max.z - b.min.z, b.max.z - a.min.z);

    normal = b3Vec3_Make(centerA.x >= centerB.x ? 1.0f : -1.0f, 0.0f,
                         0.0f);
    penetration = overlapX;
    if (overlapY < penetration) {
      normal = b3Vec3_Make(0.0f, centerA.y >= centerB.y ? 1.0f : -1.0f,
                           0.0f);
      penetration = overlapY;
    }
    if (overlapZ < penetration) {
      normal = b3Vec3_Make(0.0f, 0.0f, centerA.z >= centerB.z ? 1.0f : -1.0f);
      penetration = overlapZ;
    }
  }

  contact_mark_solved(contact);

  bool positionSolved = true;
  if (solvePosition) {
    bool correctedPoints =
        solve_body_pair_contact_point_positions(contact, aBody, bBody, NULL);
    if (!correctedPoints) {
      b3Vec3 contactPoint;
      if (!contact_center_point(contact, &contactPoint)) {
        contactPoint =
            vec3_mul(vec3_add(body_current_world_center(aBody),
                              body_current_world_center(bBody)),
                     0.5f);
      }
      scalar normalInvMass =
          pair_direction_inv_mass_at_point(aBody, bBody, contactPoint, normal);
      scalar correction =
          contact_position_correction_from_separation(-penetration);
      if (normalInvMass > B3_EPSILON && correction > 0.0f) {
        b3Vec3 impulse = vec3_mul(normal, correction / normalInvMass);
        body_apply_position_impulse_at_point(aBody, impulse, contactPoint);
        body_apply_position_impulse_at_point(bBody, vec3_mul(impulse, -1.0f),
                                             contactPoint);
      }
    }
    positionSolved = contact != NULL
                         ? contact_position_constraints_solved(contact)
                         : penetration <= B3_LINEAR_SLOP;
  }

  if (!solveVelocity) {
    return positionSolved;
  }

  b3Vec3 contactPoint;
  if (!(haveWorldManifold &&
        contact_center_point_from_world(&worldManifold, &contactPoint))) {
    contactPoint =
        vec3_mul(vec3_add(body_current_world_center(aBody),
                          body_current_world_center(bBody)),
                 0.5f);
  }

  b3Vec3 relativeVelocity =
      vec3_sub(b3Body_GetPointVelocity(aBody, contactPoint),
               b3Body_GetPointVelocity(bBody, contactPoint));
  scalar vn = vec3_dot(relativeVelocity, normal);
  scalar normalImpulseMagnitude = 0.0f;
  scalar pairRestitution = contact_pair_restitution(contact, aBody, bBody);
  bool solvedPointNormals = false;
  if (haveWorldManifold && worldManifold.pointCount > 1u) {
    for (uint32 i = 0u; i < worldManifold.pointCount; ++i) {
      normalImpulseMagnitude += solve_body_pair_contact_point_normal(
          contact, i, aBody, bBody, worldManifold.points[i].point, normal);
    }
    solvedPointNormals = true;
  }

  if (!solvedPointNormals && vn < 0.0f) {
    scalar restitution = restitution_for_normal_velocity(pairRestitution, vn);
    scalar normalInvMass =
        pair_direction_inv_mass_at_point(aBody, bBody, contactPoint, normal);
    if (normalInvMass > B3_EPSILON) {
      normalImpulseMagnitude = -(1.0f + restitution) * vn / normalInvMass;
      b3Vec3 impulse = vec3_mul(normal, normalImpulseMagnitude);
      body_apply_impulse_at_point(aBody, impulse, contactPoint);
      body_apply_impulse_at_point(bBody, vec3_mul(impulse, -1.0f),
                                  contactPoint);
      contact_store_normal_impulse(contact, normalImpulseMagnitude);
    }
  }

  if (normalImpulseMagnitude > 0.0f) {
    scalar friction = contact_pair_friction(contact, aBody, bBody);
    relativeVelocity =
        vec3_sub(b3Body_GetPointVelocity(aBody, contactPoint),
                 b3Body_GetPointVelocity(bBody, contactPoint));
    if (!solve_body_pair_tangent_friction(
            contact, aBody, bBody, haveWorldManifold ? &worldManifold : NULL,
            contactPoint, normal, normalImpulseMagnitude)) {
      b3Vec3 tangentVelocity =
          vec3_sub(relativeVelocity,
                   vec3_mul(normal, vec3_dot(relativeVelocity, normal)));
      b3Vec3 tangentTarget;
      if (contact_tangent_target_for_pair_from_world(
              contact, aBody, bBody,
              haveWorldManifold ? &worldManifold : NULL, &tangentTarget)) {
        tangentVelocity = vec3_sub(tangentVelocity, tangentTarget);
      }
      scalar tangentSpeed = vec3_length(tangentVelocity);
      if (tangentSpeed > B3_EPSILON) {
        b3Vec3 tangent = vec3_mul(tangentVelocity, 1.0f / tangentSpeed);
        scalar tangentInvMass = pair_direction_inv_mass_at_point(
            aBody, bBody, contactPoint, tangent);
        if (tangentInvMass > B3_EPSILON) {
          scalar tangentImpulseMagnitude = tangentSpeed / tangentInvMass;
          tangentImpulseMagnitude =
              scalar_min(tangentImpulseMagnitude,
                         friction * normalImpulseMagnitude);
          b3Vec3 impulse = vec3_mul(tangent, -tangentImpulseMagnitude);
          body_apply_impulse_at_point(aBody, impulse, contactPoint);
          body_apply_impulse_at_point(bBody, vec3_mul(impulse, -1.0f),
                                      contactPoint);
          contact_store_tangent_impulse_for_body(contact, aBody, impulse);
        }
      }
    }

    b3Vec3 motorAxis;
    scalar motorTargetSpeed;
    if (contact_motor_target_for_pair_from_world(
            contact, aBody, bBody, haveWorldManifold ? &worldManifold : NULL,
            &motorAxis, &motorTargetSpeed)) {
      scalar motorInvMass =
          joint_angular_axis_inv_mass(aBody, bBody, motorAxis);
      if (motorInvMass > B3_EPSILON) {
        scalar motorSpeed =
            vec3_dot(vec3_sub(aBody->angularVelocity, bBody->angularVelocity),
                     motorAxis);
        scalar motorImpulse =
            -(motorSpeed - motorTargetSpeed) / motorInvMass;
        scalar oldMotorImpulse = 0.0f;
        contact_motor_impulse_for_body(contact, aBody, &oldMotorImpulse);
        scalar totalNormalImpulse = contact_total_normal_impulse(contact);
        if (totalNormalImpulse <= B3_EPSILON) {
          totalNormalImpulse = normalImpulseMagnitude;
        }
        scalar maxMotorImpulse = friction * totalNormalImpulse;
        scalar newMotorImpulse = scalar_clamp(oldMotorImpulse + motorImpulse,
                                             -maxMotorImpulse,
                                             maxMotorImpulse);
        motorImpulse = newMotorImpulse - oldMotorImpulse;
        if (fabsf(motorImpulse) > B3_EPSILON) {
          b3Vec3 impulse = vec3_mul(motorAxis, motorImpulse);
          body_apply_angular_impulse(aBody, impulse);
          body_apply_angular_impulse(bBody, vec3_mul(impulse, -1.0f));
          contact_store_motor_impulse_for_body(contact, aBody, motorImpulse);
        }
      }
    }
  }
  return positionSolved;
}

static bool solve_contact_constraint(const b3Contact *contact,
                                     bool solvePosition, bool solveVelocity) {
  if (contact == NULL || !contact->respond || contact->fixtureA == NULL ||
      contact->fixtureB == NULL || contact->fixtureA->body == NULL ||
      contact->fixtureB->body == NULL) {
    return true;
  }

  bool solved = true;
  b3Body *bodyA = contact->fixtureA->body;
  b3Body *bodyB = contact->fixtureB->body;
  if (contact->manifoldCount > 1u) {
    b3Contact *mutableContact = (b3Contact *)contact;
    for (uint32 i = 0u; i < contact->manifoldCount && i < B3_MAX_MANIFOLDS;
         ++i) {
      b3Contact view = contact_make_manifold_view(contact, i);
      bool viewSolved = true;
      if (bodyA->type == e_staticBody && bodyB->type == e_dynamicBody) {
        viewSolved = resolve_dynamic_against_static(
            bodyB, bodyA, &view, solvePosition, solveVelocity);
      } else if (bodyB->type == e_staticBody &&
                 bodyA->type == e_dynamicBody) {
        viewSolved = resolve_dynamic_against_static(
            bodyA, bodyB, &view, solvePosition, solveVelocity);
      } else if (bodyA->type != e_staticBody && bodyB->type != e_staticBody) {
        viewSolved = resolve_body_pair(bodyA, bodyB, &view, solvePosition,
                                       solveVelocity);
      }
      contact_store_manifold_view(mutableContact, i, &view);
      solved = viewSolved && solved;
    }
    return solved;
  }
  if (bodyA->type == e_staticBody && bodyB->type == e_dynamicBody) {
    return resolve_dynamic_against_static(bodyB, bodyA, contact, solvePosition,
                                          solveVelocity);
  }
  if (bodyB->type == e_staticBody && bodyA->type == e_dynamicBody) {
    return resolve_dynamic_against_static(bodyA, bodyB, contact, solvePosition,
                                          solveVelocity);
  }
  if (bodyA->type != e_staticBody && bodyB->type != e_staticBody) {
    return resolve_body_pair(bodyA, bodyB, contact, solvePosition,
                             solveVelocity);
  }
  return true;
}

static bool contact_position_body_cache_ready(const b3World *world,
                                              const b3Contact *contact) {
  if (world == NULL || contact == NULL || !contact->respond ||
      contact->fixtureA == NULL || contact->fixtureB == NULL ||
      contact->fixtureA->body == NULL || contact->fixtureB->body == NULL) {
    return true;
  }

  const b3Body *bodies[2] = {contact->fixtureA->body, contact->fixtureB->body};
  for (uint32 i = 0u; i < 2u; ++i) {
    const b3Body *body = bodies[i];
    if (body->type != e_dynamicBody) {
      continue;
    }
    if (!body->awake || body->solverIndex >= world->solverPositionBodyCount) {
      return false;
    }
    const b3PositionBodyState *state =
        &world->solverPositionStates[body->solverIndex];
    if (state->body != body) {
      return false;
    }
  }
  return true;
}

static bool world_position_body_cache_ready(const b3World *world) {
  if (world == NULL || world->solverPositionBodyCount == 0u) {
    return false;
  }

  if (world_has_active_island(world) && world->activeIslandContacts != NULL) {
    for (uint32 contactIndex = 0u;
         contactIndex < world->activeIslandContactCount; ++contactIndex) {
      if (!contact_position_body_cache_ready(
              world, world->activeIslandContacts[contactIndex])) {
        return false;
      }
    }
    return true;
  }

  for (const b3Contact *contact = world->contacts; contact != NULL;
       contact = contact->next) {
    if (contact_in_active_island(world, contact) &&
        !contact_position_body_cache_ready(world, contact)) {
      return false;
    }
  }
  return true;
}

static b3PositionBodyState *
contact_cached_position_state_for_body(b3World *world, b3Body *body,
                                       b3PositionBodyState *localState) {
  if (body == NULL) {
    return NULL;
  }
  if (body->type == e_dynamicBody) {
    return world_position_state_for_body(world, body);
  }
  if (localState == NULL) {
    return NULL;
  }
  *localState = position_body_state_from_body(body);
  return localState;
}

static bool solve_contact_position_constraint_cached(b3World *world,
                                                     const b3Contact *contact) {
  if (world == NULL || contact == NULL || !contact->respond ||
      contact->fixtureA == NULL || contact->fixtureB == NULL ||
      contact->fixtureA->body == NULL || contact->fixtureB->body == NULL) {
    return true;
  }

  bool solved = true;
  b3Body *bodyA = contact->fixtureA->body;
  b3Body *bodyB = contact->fixtureB->body;
  if (contact->manifoldCount > 1u) {
    b3Contact *mutableContact = (b3Contact *)contact;
    for (uint32 i = 0u; i < contact->manifoldCount && i < B3_MAX_MANIFOLDS;
         ++i) {
      b3Contact view = contact_make_manifold_view(contact, i);
      bool viewSolved =
          solve_contact_position_constraint_cached(world, &view);
      contact_store_manifold_view(mutableContact, i, &view);
      solved = viewSolved && solved;
    }
    return solved;
  }

  if (contact->manifold.pointCount == 0u) {
    return true;
  }

  if (bodyA->type == e_staticBody && bodyB->type == e_dynamicBody) {
    b3PositionBodyState localA;
    b3PositionBodyState *stateA =
        contact_cached_position_state_for_body(world, bodyA, &localA);
    b3PositionBodyState *stateB =
        contact_cached_position_state_for_body(world, bodyB, NULL);
    if (stateA == NULL || stateB == NULL) {
      return true;
    }
    contact_mark_solved(contact);
    bool contactSolved = true;
    solve_dynamic_static_contact_point_positions_cached(
        contact, bodyB, stateA, stateB, &contactSolved);
    return contactSolved;
  }

  if (bodyB->type == e_staticBody && bodyA->type == e_dynamicBody) {
    b3PositionBodyState localB;
    b3PositionBodyState *stateA =
        contact_cached_position_state_for_body(world, bodyA, NULL);
    b3PositionBodyState *stateB =
        contact_cached_position_state_for_body(world, bodyB, &localB);
    if (stateA == NULL || stateB == NULL) {
      return true;
    }
    contact_mark_solved(contact);
    bool contactSolved = true;
    solve_dynamic_static_contact_point_positions_cached(
        contact, bodyA, stateA, stateB, &contactSolved);
    return contactSolved;
  }

  if (bodyA->type != e_staticBody && bodyB->type != e_staticBody) {
    if (!bodyA->awake && !bodyB->awake) {
      return true;
    }
    scalar invMassA = bodyA->type == e_dynamicBody ? bodyA->invMass : 0.0f;
    scalar invMassB = bodyB->type == e_dynamicBody ? bodyB->invMass : 0.0f;
    if (invMassA + invMassB <= B3_EPSILON) {
      return true;
    }

    b3PositionBodyState localA;
    b3PositionBodyState localB;
    b3PositionBodyState *stateA =
        contact_cached_position_state_for_body(world, bodyA, &localA);
    b3PositionBodyState *stateB =
        contact_cached_position_state_for_body(world, bodyB, &localB);
    if (stateA == NULL || stateB == NULL) {
      return true;
    }

    contact_mark_solved(contact);
    bool contactSolved = true;
    solve_body_pair_contact_point_positions_cached(
        contact, bodyA, bodyB, stateA, stateB, &contactSolved);
    return contactSolved;
  }

  return true;
}

static bool solve_world_contact_position_constraints_cached(b3World *world) {
  if (world == NULL) {
    return true;
  }

  bool solved = true;
  if (world_has_active_island(world) && world->activeIslandContacts != NULL) {
    for (uint32 contactIndex = 0u;
         contactIndex < world->activeIslandContactCount; ++contactIndex) {
      solved = solve_contact_position_constraint_cached(
                   world, world->activeIslandContacts[contactIndex]) &&
               solved;
    }
    return solved;
  }

  for (const b3Contact *contact = world->contacts; contact != NULL;
       contact = contact->next) {
    if (contact_in_active_island(world, contact)) {
      solved =
          solve_contact_position_constraint_cached(world, contact) && solved;
    }
  }
  return solved;
}

static bool solve_world_contact_constraints(b3World *world, bool solvePosition,
                                            bool solveVelocity) {
  if (world == NULL || (!solvePosition && !solveVelocity)) {
    return true;
  }

  bool solved = true;
  if (world_has_active_island(world) && world->activeIslandContacts != NULL) {
    for (uint32 contactIndex = 0u;
         contactIndex < world->activeIslandContactCount; ++contactIndex) {
      solved =
          solve_contact_constraint(world->activeIslandContacts[contactIndex],
                                   solvePosition, solveVelocity) &&
          solved;
    }
    return solved;
  }

  for (const b3Contact *contact = world->contacts; contact != NULL;
       contact = contact->next) {
    if (contact_in_active_island(world, contact)) {
      solved =
          solve_contact_constraint(contact, solvePosition, solveVelocity) &&
          solved;
    }
  }
  return solved;
}

static bool body_find_translation_toi(const b3Body *body, b3Vec3 displacement,
                                      scalar targetMotionDt,
                                      b3BodyType bodyType,
                                      bool filterByBodyType,
                                      scalar *outFraction,
                                      b3Vec3 *outNormal,
                                      const b3Body **outBody) {
  if (body == NULL || body->world == NULL ||
      vec3_length_sq(displacement) <= B3_EPSILON * B3_EPSILON) {
    return false;
  }

  bool hit = false;
  scalar bestFraction = 1.0f;
  b3Vec3 bestNormal = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  const b3Body *bestBody = NULL;
  b3Transform transform = body_transform(body);
  for (const b3Fixture *fixture = body->fixtures; fixture != NULL;
       fixture = fixture->next) {
    if (fixture->sensor) {
      continue;
    }

    b3ShapeCastOutput output;
    if (world_shape_cast_closest_filtered_with_target_motion(
            body->world, &fixture->storage.base, transform, displacement,
            targetMotionDt, bodyType, body, filterByBodyType, true, NULL, NULL,
            fixture, &output) &&
        output.fraction < bestFraction) {
      hit = true;
      bestFraction = output.fraction;
      bestNormal = output.normal;
      bestBody = output.body;
    }
  }

  if (hit) {
    if (outFraction != NULL) {
      *outFraction = bestFraction;
    }
    if (outNormal != NULL) {
      *outNormal = bestNormal;
    }
    if (outBody != NULL) {
      *outBody = bestBody;
    }
  }
  return hit;
}

static bool body_is_awake_island_source(const b3Body *body) {
  return body != NULL && body->type != e_staticBody && body->awake;
}

static bool body_wake_from_awake_island(const b3Body *source,
                                        b3Body *target) {
  if (!body_is_awake_island_source(source) || target == NULL ||
      target->type == e_staticBody || target->awake) {
    return false;
  }
  body_mark_awake(target);
  return true;
}

static bool contact_is_awake_island_edge(const b3Contact *contact) {
  return contact != NULL && contact->touching && contact->respond &&
         !contact->sensor && contact->fixtureA != NULL &&
         contact->fixtureB != NULL && contact->fixtureA->body != NULL &&
         contact->fixtureB->body != NULL;
}

static void world_clear_island_tags(b3World *world) {
  if (world == NULL) {
    return;
  }
  for (b3Body *body = world->bodies; body != NULL; body = body->next) {
    body->islandTag = 0u;
  }
  for (b3Contact *contact = world->contacts; contact != NULL;
       contact = contact->next) {
    contact->islandTag = 0u;
  }
  for (b3Joint *joint = world->joints; joint != NULL; joint = joint->next) {
    joint->islandTag = 0u;
  }
  world->activeIslandTag = 0u;
}

static void world_push_island_body(b3Body **stack, uint32 stackCapacity,
                                   uint32 *stackCount, b3Body *body,
                                   uint32 islandTag) {
  if (stack == NULL || stackCount == NULL || body == NULL ||
      body->type == e_staticBody || body->islandTag != 0u ||
      *stackCount >= stackCapacity) {
    return;
  }
  body->islandTag = islandTag;
  stack[(*stackCount)++] = body;
}

static bool world_reserve_island_stack(b3World *world, uint32 capacity) {
  if (world == NULL) {
    return false;
  }
  if (capacity <= world->islandStackCapacity) {
    return true;
  }

  b3Body **stack =
      (b3Body **)realloc(world->islandStack, capacity * sizeof(*stack));
  if (stack == NULL) {
    return false;
  }
  world->islandStack = stack;
  world->islandStackCapacity = capacity;
  return true;
}

static bool world_reserve_island_positions(b3World *world, uint32 capacity) {
  if (world == NULL) {
    return false;
  }
  if (capacity <= world->islandPositionsSolvedCapacity) {
    return true;
  }

  bool *positions =
      (bool *)realloc(world->islandPositionsSolved, capacity * sizeof(*positions));
  if (positions == NULL) {
    return false;
  }
  world->islandPositionsSolved = positions;
  world->islandPositionsSolvedCapacity = capacity;
  return true;
}

static bool world_reserve_island_contact_lists(b3World *world,
                                               uint32 islandCount) {
  if (world == NULL) {
    return false;
  }

  uint32 metaCapacity = islandCount + 1u;
  if (metaCapacity > world->islandContactMetaCapacity) {
    uint32 *starts = (uint32 *)realloc(
        world->islandContactStarts, metaCapacity * sizeof(*starts));
    if (starts == NULL) {
      return false;
    }
    world->islandContactStarts = starts;

    uint32 *counts = (uint32 *)realloc(
        world->islandContactCounts, metaCapacity * sizeof(*counts));
    if (counts == NULL) {
      return false;
    }
    world->islandContactCounts = counts;

    uint32 *write = (uint32 *)realloc(
        world->islandContactWrite, metaCapacity * sizeof(*write));
    if (write == NULL) {
      return false;
    }
    world->islandContactWrite = write;
    world->islandContactMetaCapacity = metaCapacity;
  }

  if (world->contactCount > world->islandContactCapacity) {
    b3Contact **contacts = (b3Contact **)realloc(
        world->islandContacts, world->contactCount * sizeof(*contacts));
    if (contacts == NULL) {
      return false;
    }
    world->islandContacts = contacts;
    world->islandContactCapacity = world->contactCount;
  }

  return true;
}

static bool world_begin_island_contact_counts(b3World *world) {
  if (world == NULL || world->bodyCount == 0u) {
    return false;
  }
  if (!world_reserve_island_contact_lists(world, world->bodyCount)) {
    return false;
  }

  uint32 metaCapacity = world->bodyCount + 1u;
  memset(world->islandContactCounts, 0,
         (size_t)metaCapacity * sizeof(*world->islandContactCounts));
  return true;
}

static bool world_prepare_island_contact_lists(b3World *world,
                                               uint32 islandCount,
                                               bool countsReady) {
  if (world == NULL || islandCount == 0u) {
    return false;
  }
  if (!countsReady &&
      !world_reserve_island_contact_lists(world, islandCount)) {
    return false;
  }
  if (islandCount + 1u > world->islandContactMetaCapacity ||
      world->contactCount > world->islandContactCapacity) {
    return false;
  }

  uint32 metaCapacity = islandCount + 1u;
  memset(world->islandContactStarts, 0,
         (size_t)metaCapacity * sizeof(*world->islandContactStarts));
  memset(world->islandContactWrite, 0,
         (size_t)metaCapacity * sizeof(*world->islandContactWrite));

  if (!countsReady) {
    memset(world->islandContactCounts, 0,
           (size_t)metaCapacity * sizeof(*world->islandContactCounts));
    for (b3Contact *contact = world->contacts; contact != NULL;
         contact = contact->next) {
      if (contact->islandTag > 0u && contact->islandTag <= islandCount) {
        ++world->islandContactCounts[contact->islandTag];
      }
    }
  }

  uint32 total = 0u;
  for (uint32 islandTag = 1u; islandTag <= islandCount; ++islandTag) {
    world->islandContactStarts[islandTag] = total;
    total += world->islandContactCounts[islandTag];
  }

  for (b3Contact *contact = world->contacts; contact != NULL;
       contact = contact->next) {
    uint32 islandTag = contact->islandTag;
    if (islandTag == 0u || islandTag > islandCount) {
      continue;
    }
    uint32 index =
        world->islandContactStarts[islandTag] +
        world->islandContactWrite[islandTag]++;
    world->islandContacts[index] = contact;
  }

  return true;
}

static void world_clear_active_island_contacts(b3World *world) {
  if (world == NULL) {
    return;
  }
  world->activeIslandContacts = NULL;
  world->activeIslandContactCount = 0u;
}

static void world_set_active_island_contacts(b3World *world,
                                             uint32 islandTag) {
  if (world == NULL || islandTag == 0u ||
      islandTag >= world->islandContactMetaCapacity ||
      world->islandContacts == NULL || world->islandContactStarts == NULL ||
      world->islandContactCounts == NULL) {
    world_clear_active_island_contacts(world);
    return;
  }

  uint32 start = world->islandContactStarts[islandTag];
  world->activeIslandContacts = world->islandContacts + start;
  world->activeIslandContactCount = world->islandContactCounts[islandTag];
}

static uint32 world_build_awake_islands(b3World *world,
                                        bool countIslandContacts) {
  if (world == NULL || world->bodyCount == 0u) {
    return 0u;
  }

  world_clear_island_tags(world);
  if (!world_reserve_island_stack(world, world->bodyCount)) {
    return 0u;
  }
  b3Body **stack = world->islandStack;

  uint32 islandTag = 0u;
  for (b3Body *seed = world->bodies; seed != NULL; seed = seed->next) {
    if (seed->islandTag != 0u || !seed->awake ||
        seed->type == e_staticBody) {
      continue;
    }

    ++islandTag;
    uint32 stackCount = 0u;
    world_push_island_body(stack, world->bodyCount, &stackCount, seed,
                           islandTag);

    while (stackCount > 0u) {
      b3Body *body = stack[--stackCount];
      if (body == NULL || body->type == e_staticBody) {
        continue;
      }
      /* Match the C++ island solver: bodies wake as the island expands. */
      body_mark_awake(body);

      for (b3Fixture *fixture = body->fixtures; fixture != NULL;
           fixture = fixture->next) {
        for (b3ContactEdge *edge = fixture->contacts; edge != NULL;
             edge = edge->next) {
          b3Contact *contact = edge->contact;
          if (contact == NULL || contact->islandTag != 0u ||
              !contact_is_awake_island_edge(contact)) {
            continue;
          }

          contact->islandTag = islandTag;
          if (countIslandContacts &&
              islandTag < world->islandContactMetaCapacity) {
            ++world->islandContactCounts[islandTag];
          }
          b3Fixture *otherFixture = edge->other;
          b3Body *otherBody =
              otherFixture != NULL ? otherFixture->body : NULL;
          world_push_island_body(stack, world->bodyCount, &stackCount,
                                 otherBody, islandTag);
        }
      }

      for (b3JointEdge *edge = body->joints; edge != NULL; edge = edge->next) {
        b3Joint *joint = edge->joint;
        if (joint == NULL || joint->islandTag != 0u) {
          continue;
        }

        joint->islandTag = islandTag;
        world_push_island_body(stack, world->bodyCount, &stackCount,
                               edge->other, islandTag);
      }
    }
  }

  return islandTag;
}

static bool body_blocks_sleeping(b3Body *body, scalar dt) {
  if (body == NULL || body->type == e_staticBody || !body->awake) {
    return false;
  }

  scalar linearSpeedSq = vec3_length_sq(body->linearVelocity);
  scalar angularSpeedSq = vec3_length_sq(body->angularVelocity);
  scalar linearTol = body->linearSleepTolerance;
  scalar angularTol = body->angularSleepTolerance;
  if (!body->allowSleep || linearSpeedSq > linearTol * linearTol ||
      angularSpeedSq > angularTol * angularTol) {
    body->sleepTime = 0.0f;
    return true;
  }

  body->sleepTime += dt;
  return body->sleepTime < B3_TIME_TO_SLEEP;
}

static void world_update_sleeping(b3World *world, scalar dt,
                                  uint32 islandCount,
                                  const bool *islandPositionsSolved) {
  if (world == NULL || !world->sleeping || dt <= 0.0f ||
      islandPositionsSolved == NULL) {
    return;
  }

  if (islandCount == 0u) {
    return;
  }

  for (uint32 islandTag = 1u; islandTag <= islandCount; ++islandTag) {
    if (!islandPositionsSolved[islandTag]) {
      continue;
    }

    bool blocked = false;
    scalar minSleepTime = FLT_MAX;
    for (b3Body *body = world->bodies; body != NULL; body = body->next) {
      if (body->islandTag != islandTag || body->type == e_staticBody ||
          !body->awake) {
        continue;
      }
      if (body_blocks_sleeping(body, dt)) {
        blocked = true;
      }
      minSleepTime = scalar_min(minSleepTime, body->sleepTime);
    }

    if (blocked || minSleepTime < B3_TIME_TO_SLEEP) {
      continue;
    }
    for (b3Body *body = world->bodies; body != NULL; body = body->next) {
      if (body->islandTag == islandTag && body->awake) {
        b3Body_SetAwake(body, false);
      }
    }
    for (b3Contact *contact = world->contacts; contact != NULL;
         contact = contact->next) {
      if (contact->islandTag != islandTag) {
        continue;
      }
      b3Body *bodyA =
          contact->fixtureA != NULL ? contact->fixtureA->body : NULL;
      b3Body *bodyB =
          contact->fixtureB != NULL ? contact->fixtureB->body : NULL;
      if (bodyA != NULL && bodyA->type == e_staticBody && bodyA->awake) {
        b3Body_SetAwake(bodyA, false);
      }
      if (bodyB != NULL && bodyB->type == e_staticBody && bodyB->awake) {
        b3Body_SetAwake(bodyB, false);
      }
    }
  }
}

static bool solve_sphere_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return true;
  }

  b3Vec3 worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 error = vec3_sub(worldAnchorB, worldAnchorA);
  b3Mat33 positionMass =
      pair_point_mass_matrix(bodyA, worldAnchorA, bodyB, worldAnchorB);
  b3Vec3 positionImpulse =
      mat33_mul_vec3(positionMass, vec3_mul(error, -1.0f));
  pair_apply_position_impulse_at_points(bodyA, worldAnchorA, bodyB,
                                        worldAnchorB, positionImpulse);

  worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  error = vec3_sub(worldAnchorB, worldAnchorA);
  return vec3_length(error) <= B3_LINEAR_SLOP;
}

static void solve_sphere_joint_velocity(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  b3Vec3 worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 relativeVelocity =
      vec3_sub(b3Body_GetPointVelocity(bodyB, worldAnchorB),
               b3Body_GetPointVelocity(bodyA, worldAnchorA));
  b3Mat33 pointMass =
      pair_point_mass_matrix(bodyA, worldAnchorA, bodyB, worldAnchorB);
  b3Vec3 impulse =
      mat33_mul_vec3(pointMass, vec3_mul(relativeVelocity, -1.0f));
  joint->linearImpulse = vec3_add(joint->linearImpulse, impulse);
  body_apply_impulse_at_point(bodyA, vec3_mul(impulse, -1.0f), worldAnchorA);
  body_apply_impulse_at_point(bodyB, impulse, worldAnchorB);
}

static bool solve_spring_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL ||
      joint->frequencyHz > 0.0f) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return true;
  }

  b3Vec3 worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 delta = vec3_sub(worldAnchorB, worldAnchorA);
  scalar distance = vec3_length(delta);
  if (distance <= B3_EPSILON) {
    return true;
  }

  b3Vec3 normal = vec3_mul(delta, 1.0f / distance);
  scalar correction = scalar_clamp(distance - joint->length,
                                   -B3_MAX_LINEAR_CORRECTION,
                                   B3_MAX_LINEAR_CORRECTION);

  scalar positionInvMass =
      pair_direction_inv_mass_at_points(bodyA, worldAnchorA, bodyB,
                                        worldAnchorB, normal);
  if (positionInvMass > B3_EPSILON) {
    b3Vec3 positionImpulse =
        vec3_mul(normal, -correction / positionInvMass);
    pair_apply_position_impulse_at_points(bodyA, worldAnchorA, bodyB,
                                          worldAnchorB, positionImpulse);
  }

  worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  delta = vec3_sub(worldAnchorB, worldAnchorA);
  distance = vec3_length(delta);
  return fabsf(distance - joint->length) <= B3_LINEAR_SLOP;
}

static void solve_spring_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL ||
      dt <= 0.0f) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  b3Vec3 worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 delta = vec3_sub(worldAnchorB, worldAnchorA);
  scalar distance = vec3_length(delta);
  if (distance <= B3_EPSILON) {
    return;
  }

  b3Vec3 normal = vec3_mul(delta, 1.0f / distance);
  scalar correction = distance - joint->length;
  b3Vec3 relativeVelocity =
      vec3_sub(b3Body_GetPointVelocity(bodyB, worldAnchorB),
               b3Body_GetPointVelocity(bodyA, worldAnchorA));
  scalar speed = vec3_dot(relativeVelocity, normal);
  scalar axisInvMass =
      pair_direction_inv_mass_at_points(bodyA, worldAnchorA, bodyB,
                                        worldAnchorB, normal);
  if (axisInvMass <= B3_EPSILON) {
    return;
  }

  scalar bias = 0.0f;
  scalar gamma = 0.0f;
  if (joint->frequencyHz > 0.0f) {
    scalar mass = 1.0f / axisInvMass;
    scalar omega = 2.0f * B3_PI * joint->frequencyHz;
    scalar damping = 2.0f * mass * joint->dampingRatio * omega;
    scalar stiffness = mass * omega * omega;
    gamma = dt * (damping + dt * stiffness);
    gamma = gamma > B3_EPSILON ? 1.0f / gamma : 0.0f;
    bias = gamma * dt * stiffness * correction;
  }

  scalar impulseMagnitude =
      -(speed + bias + gamma * joint->springImpulse) / (axisInvMass + gamma);
  joint->springImpulse += impulseMagnitude;
  b3Vec3 impulse = vec3_mul(normal, impulseMagnitude);
  pair_apply_impulse_at_points(bodyA, worldAnchorA, bodyB, worldAnchorB,
                               impulse);
}

static void compute_soft_constraint_coefficients(
    scalar *gammaOut, scalar *biasOut, scalar frequencyHz, scalar dampingRatio,
    scalar mass, scalar error, scalar dt) {
  scalar omega = 2.0f * B3_PI * frequencyHz;
  scalar stiffness = omega * omega * mass;
  scalar damping = 2.0f * dampingRatio * omega * mass;
  scalar gamma = dt * (damping + dt * stiffness);
  gamma = gamma > B3_EPSILON ? 1.0f / gamma : 0.0f;
  if (gammaOut != NULL) {
    *gammaOut = gamma;
  }
  if (biasOut != NULL) {
    *biasOut = gamma * dt * stiffness * error;
  }
}

static void solve_soft_weld_angular_constraint(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL ||
      dt <= 0.0f || joint->frequencyHz <= 0.0f) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  b3Mat33 invMass =
      mat33_add(joint_body_world_inv_inertia(bodyA),
                joint_body_world_inv_inertia(bodyB));
  b3Mat33 mass = mat33_inverse(invMass);
  b3Vec3 error = vec3_mul(reference_rotation_error_vector(joint), -1.0f);
  b3Vec3 gamma;
  b3Vec3 bias;
  compute_soft_constraint_coefficients(&gamma.x, &bias.x, joint->frequencyHz,
                                       joint->dampingRatio, mass.x.x, error.x,
                                       dt);
  compute_soft_constraint_coefficients(&gamma.y, &bias.y, joint->frequencyHz,
                                       joint->dampingRatio, mass.y.y, error.y,
                                       dt);
  compute_soft_constraint_coefficients(&gamma.z, &bias.z, joint->frequencyHz,
                                       joint->dampingRatio, mass.z.z, error.z,
                                       dt);

  b3Mat33 gammaMatrix = mat33_diagonal(gamma.x, gamma.y, gamma.z);
  b3Mat33 angularMass = mat33_inverse(mat33_add(invMass, gammaMatrix));
  b3Vec3 relativeAngularVelocity =
      vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
  b3Vec3 gammaImpulse = mat33_mul_vec3(gammaMatrix, joint->angularImpulse);
  b3Vec3 rhs =
      vec3_add(vec3_add(relativeAngularVelocity, bias), gammaImpulse);
  b3Vec3 impulse = mat33_mul_vec3(angularMass, vec3_mul(rhs, -1.0f));
  joint->angularImpulse = vec3_add(joint->angularImpulse, impulse);
  body_apply_negative_angular_impulse(bodyA, impulse);
  body_apply_angular_impulse(bodyB, impulse);
}

static bool solve_weld_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  bool solved = solve_sphere_joint_position(joint);
  if (joint->frequencyHz <= 0.0f) {
    solved = solve_reference_rotation_position(joint) && solved;
  }
  return solved;
}

static void solve_weld_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  solve_sphere_joint_velocity(joint);

  if (joint->frequencyHz > 0.0f && dt > 0.0f) {
    solve_soft_weld_angular_constraint(joint, dt);
  } else {
    solve_reference_rotation_velocity(joint);
  }
}

static bool solve_friction_joint_position(b3Joint *joint) {
  (void)joint;
  return true;
}

static void solve_friction_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL ||
      dt <= 0.0f) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  b3Vec3 worldAnchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 worldAnchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 relativeVelocity =
      vec3_sub(b3Body_GetPointVelocity(bodyB, worldAnchorB),
               b3Body_GetPointVelocity(bodyA, worldAnchorA));
  b3Mat33 linearMass =
      pair_point_mass_matrix(bodyA, worldAnchorA, bodyB, worldAnchorB);
  b3Vec3 impulse =
      mat33_mul_vec3(linearMass, vec3_mul(relativeVelocity, -1.0f));
  b3Vec3 oldLinearImpulse = joint->linearImpulse;
  joint->linearImpulse =
      vec3_clamp_length(vec3_add(oldLinearImpulse, impulse),
                        joint->maxForce * dt);
  impulse = vec3_sub(joint->linearImpulse, oldLinearImpulse);
  body_apply_impulse_at_point(bodyA, vec3_mul(impulse, -1.0f), worldAnchorA);
  body_apply_impulse_at_point(bodyB, impulse, worldAnchorB);

  b3Vec3 relativeAngularVelocity =
      vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
  b3Vec3 angularImpulse =
      mat33_mul_vec3(joint_angular_mass_matrix(bodyA, bodyB),
                     vec3_mul(relativeAngularVelocity, -1.0f));
  b3Vec3 oldAngularImpulse = joint->angularImpulse;
  joint->angularImpulse =
      vec3_clamp_length(vec3_add(oldAngularImpulse, angularImpulse),
                        joint->maxTorque * dt);
  angularImpulse = vec3_sub(joint->angularImpulse, oldAngularImpulse);
  if (invMassA > 0.0f) {
    body_apply_negative_angular_impulse(bodyA, angularImpulse);
  }
  if (invMassB > 0.0f) {
    body_apply_angular_impulse(bodyB, angularImpulse);
  }
}

static bool solve_motor_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar correction =
      joint->correctionFactor > 0.0f ? joint->correctionFactor : 1.0f;
  b3Quat targetOrientation =
      quat_mul(bodyA->orientation, quat_normalize(joint->angularOffset));
  if (invMassB > 0.0f) {
    b3Quat blended = b3Quat_Make(
        bodyB->orientation.v.x +
            correction * (targetOrientation.v.x - bodyB->orientation.v.x),
        bodyB->orientation.v.y +
            correction * (targetOrientation.v.y - bodyB->orientation.v.y),
        bodyB->orientation.v.z +
            correction * (targetOrientation.v.z - bodyB->orientation.v.z),
        bodyB->orientation.s +
            correction * (targetOrientation.s - bodyB->orientation.s));
    body_set_orientation_preserve_center(bodyB, blended);
  }

  b3Quat error =
      quat_normalize(quat_mul(targetOrientation,
                              quat_conjugate(bodyB->orientation)));
  return vec3_length(error.v) <= sinf(0.5f * B3_ANGULAR_SLOP);
}

static void solve_motor_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL ||
      dt <= 0.0f) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  b3Vec3 targetPosition = b3Body_GetWorldPoint(bodyA, joint->linearOffset);
  b3Vec3 bodyBPoint = body_current_world_center(bodyB);
  b3Vec3 positionError = vec3_sub(bodyBPoint, targetPosition);
  scalar correction =
      joint->correctionFactor > 0.0f ? joint->correctionFactor : 1.0f;
  b3Vec3 desiredRelativeVelocity =
      vec3_mul(positionError, -correction / dt);
  b3Vec3 relativeVelocity =
      vec3_sub(b3Body_GetPointVelocity(bodyB, bodyBPoint),
               b3Body_GetPointVelocity(bodyA, targetPosition));
  b3Mat33 linearMass =
      pair_point_mass_matrix(bodyA, targetPosition, bodyB, bodyBPoint);
  b3Vec3 impulse =
      mat33_mul_vec3(linearMass,
                     vec3_sub(desiredRelativeVelocity, relativeVelocity));
  b3Vec3 oldLinearImpulse = joint->linearImpulse;
  joint->linearImpulse =
      vec3_clamp_length(vec3_add(oldLinearImpulse, impulse),
                        joint->maxForce * dt);
  impulse = vec3_sub(joint->linearImpulse, oldLinearImpulse);
  pair_apply_impulse_at_points(bodyA, targetPosition, bodyB, bodyBPoint,
                               impulse);

  b3Vec3 relativeAngularVelocity =
      vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
  b3Vec3 angularImpulse =
      mat33_mul_vec3(joint_angular_mass_matrix(bodyA, bodyB),
                     vec3_mul(relativeAngularVelocity, -1.0f));
  b3Vec3 oldAngularImpulse = joint->angularImpulse;
  joint->angularImpulse =
      vec3_clamp_length(vec3_add(oldAngularImpulse, angularImpulse),
                        joint->maxTorque * dt);
  angularImpulse = vec3_sub(joint->angularImpulse, oldAngularImpulse);
  if (invMassA > 0.0f) {
    body_apply_negative_angular_impulse(bodyA, angularImpulse);
  }
  if (invMassB > 0.0f) {
    body_apply_angular_impulse(bodyB, angularImpulse);
  }
}

static bool solve_mouse_joint_position(b3Joint *joint) {
  (void)joint;
  return true;
}

static void solve_mouse_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyB == NULL || dt <= 0.0f) {
    return;
  }

  b3Body *bodyB = joint->bodyB;
  scalar invMassB = joint_body_inv_mass(bodyB);
  if (invMassB <= B3_EPSILON) {
    return;
  }

  b3Vec3 anchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 error = vec3_sub(anchorB, joint->target);
  b3Vec3 pointVelocity = b3Body_GetPointVelocity(bodyB, anchorB);
  b3Mat33 pointMass =
      pair_point_mass_matrix(NULL, joint->target, bodyB, anchorB);
  b3Vec3 gamma;
  b3Vec3 bias;
  compute_soft_constraint_coefficients(&gamma.x, &bias.x, joint->frequencyHz,
                                       joint->dampingRatio, pointMass.x.x,
                                       error.x, dt);
  compute_soft_constraint_coefficients(&gamma.y, &bias.y, joint->frequencyHz,
                                       joint->dampingRatio, pointMass.y.y,
                                       error.y, dt);
  compute_soft_constraint_coefficients(&gamma.z, &bias.z, joint->frequencyHz,
                                       joint->dampingRatio, pointMass.z.z,
                                       error.z, dt);
  b3Mat33 gammaMatrix = mat33_diagonal(gamma.x, gamma.y, gamma.z);
  b3Mat33 softMass =
      mat33_inverse(mat33_add(mat33_inverse(pointMass), gammaMatrix));
  b3Vec3 gammaImpulse = mat33_mul_vec3(gammaMatrix, joint->linearImpulse);
  b3Vec3 rhs = vec3_add(vec3_add(pointVelocity, bias), gammaImpulse);
  b3Vec3 impulse = mat33_mul_vec3(softMass, vec3_mul(rhs, -1.0f));
  b3Vec3 oldImpulse = joint->linearImpulse;
  joint->linearImpulse =
      vec3_clamp_length(vec3_add(oldImpulse, impulse), joint->maxForce * dt);
  impulse = vec3_sub(joint->linearImpulse, oldImpulse);

  body_apply_impulse_at_point(bodyB, impulse, anchorB);
}

static b3Vec3 joint_world_axis_a(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  b3Vec3 axis = b3Body_GetWorldVector(joint->bodyA, joint->localAxisA);
  scalar length = vec3_length(axis);
  if (length <= B3_EPSILON) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  return vec3_mul(axis, 1.0f / length);
}

static scalar joint_prismatic_translation(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return 0.0f;
  }
  b3Vec3 axis = joint_world_axis_a(joint);
  b3Vec3 anchorA = b3Body_GetWorldPoint(joint->bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(joint->bodyB, joint->localAnchorB);
  return vec3_dot(vec3_sub(anchorB, anchorA), axis);
}

static bool joint_prismatic_has_equal_limits(const b3Joint *joint) {
  return joint != NULL && joint->enableLimit &&
         fabsf(joint->upperLimit - joint->lowerLimit) <
             2.0f * B3_LINEAR_SLOP;
}

static b3Vec3 reference_rotation_error_vector(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }

  b3Quat reference = quat_normalize(joint->referenceRotation);
  b3Quat targetB = quat_mul(joint->bodyA->orientation, reference);
  b3Quat error =
      quat_normalize(quat_mul(targetB,
                              quat_conjugate(joint->bodyB->orientation)));
  if (error.s < 0.0f) {
    error.v = vec3_mul(error.v, -1.0f);
    error.s = -error.s;
  }

  scalar errorLength = vec3_length(error.v);
  if (errorLength <= B3_EPSILON) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }

  b3Vec3 axis = vec3_mul(error.v, 1.0f / errorLength);
  scalar angle = 2.0f * atan2f(errorLength, error.s);
  return vec3_mul(axis, angle);
}

static bool solve_reference_rotation_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  b3Vec3 error = reference_rotation_error_vector(joint);
  scalar errorLength = vec3_length(error);
  if (errorLength > B3_EPSILON) {
    b3Vec3 axis = vec3_mul(error, 1.0f / errorLength);
    scalar angle = errorLength;
    scalar factor =
        joint->correctionFactor > 0.0f
            ? scalar_min(joint->correctionFactor, 1.0f)
            : 1.0f;
    scalar correctionAngle =
        scalar_clamp(angle * factor, 0.0f, B3_MAX_ANGULAR_CORRECTION);
    scalar invA = vec3_dot(
        axis, mat33_mul_vec3(joint_body_world_inv_inertia(bodyA), axis));
    scalar invB = vec3_dot(
        axis, mat33_mul_vec3(joint_body_world_inv_inertia(bodyB), axis));
    scalar angularInvMass = invA + invB;
    if (angularInvMass > B3_EPSILON) {
      body_apply_orientation_correction(
          bodyA, axis, -correctionAngle * invA / angularInvMass);
      body_apply_orientation_correction(
          bodyB, axis, correctionAngle * invB / angularInvMass);
    }
  }

  return errorLength <= B3_ANGULAR_SLOP;
}

static void solve_reference_rotation_velocity_target(b3Joint *joint,
                                                     b3Vec3 targetVelocity) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  b3Vec3 relativeAngularVelocity =
      vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
  b3Mat33 angularMass = joint_angular_mass_matrix(bodyA, bodyB);
  b3Vec3 angularImpulse = mat33_mul_vec3(
      angularMass, vec3_sub(targetVelocity, relativeAngularVelocity));
  joint->angularImpulse = vec3_add(joint->angularImpulse, angularImpulse);
  body_apply_negative_angular_impulse(bodyA, angularImpulse);
  body_apply_angular_impulse(bodyB, angularImpulse);
}

static void solve_reference_rotation_velocity(b3Joint *joint) {
  solve_reference_rotation_velocity_target(
      joint, b3Vec3_Make(0.0f, 0.0f, 0.0f));
}

static bool solve_prismatic_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return true;
  }

  b3Vec3 axis = joint_world_axis_a(joint);
  b3Vec3 anchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 error = vec3_sub(anchorB, anchorA);
  scalar translation = vec3_dot(error, axis);
  b3Vec3 correction =
      vec3_sub(error, vec3_mul(axis, translation));

  if (joint->enableLimit) {
    scalar limitedTranslation =
        scalar_max(joint->lowerLimit, scalar_min(translation, joint->upperLimit));
    correction = vec3_add(
        correction, vec3_mul(axis, translation - limitedTranslation));
  }

  scalar factor =
      joint->correctionFactor > 0.0f ? scalar_min(joint->correctionFactor, 1.0f)
                                     : 1.0f;
  correction = vec3_mul(correction, factor);

  b3Vec3 oldPositionA = bodyA->position;
  b3Vec3 oldPositionB = bodyB->position;
  bool deferSyncA = body_defer_sync_if_needed(bodyA);
  bool deferSyncB = body_defer_sync_if_needed(bodyB);
  if (invMassA > 0.0f) {
    bodyA->position =
        vec3_add(bodyA->position, vec3_mul(correction, invMassA / totalInvMass));
  }
  if (invMassB > 0.0f) {
    bodyB->position =
        vec3_sub(bodyB->position, vec3_mul(correction, invMassB / totalInvMass));
  }
  body_invalidate_world_aabb(bodyA);
  body_invalidate_world_aabb(bodyB);
  body_update_world_center(bodyA);
  body_update_world_center(bodyB);
  body_invalidate_contact_world_manifolds(bodyA);
  body_invalidate_contact_world_manifolds(bodyB);
  if (!deferSyncA) {
    body_sync_fixtures(bodyA, vec3_sub(bodyA->position, oldPositionA));
  }
  if (!deferSyncB) {
    body_sync_fixtures(bodyB, vec3_sub(bodyB->position, oldPositionB));
  }
  bool rotationSolved = solve_reference_rotation_position(joint);
  return vec3_length(correction) <= B3_LINEAR_SLOP && rotationSolved;
}

static void solve_prismatic_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  b3Vec3 axis = joint_world_axis_a(joint);
  b3Vec3 anchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  scalar translation = vec3_dot(vec3_sub(anchorB, anchorA), axis);
  bool equalLimit = joint_prismatic_has_equal_limits(joint);
  bool lowerLimit = joint->enableLimit && translation <= joint->lowerLimit;
  bool upperLimit = joint->enableLimit && translation >= joint->upperLimit;
  solve_reference_rotation_velocity(joint);

  anchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  anchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 tangent1 = vec3_perp(axis);
  b3Vec3 tangent2 = vec3_normalize_or_zero(vec3_cross(axis, tangent1));
  const b3Vec3 tangents[2] = {tangent1, tangent2};
  for (uint32 i = 0u; i < 2u; ++i) {
    b3Vec3 tangent = tangents[i];
    if (vec3_length_sq(tangent) <= B3_EPSILON * B3_EPSILON) {
      continue;
    }
    b3Vec3 relativeVelocity =
        vec3_sub(b3Body_GetPointVelocity(bodyB, anchorB),
                 b3Body_GetPointVelocity(bodyA, anchorA));
    scalar speed = vec3_dot(relativeVelocity, tangent);
    scalar invMass =
        pair_direction_inv_mass_at_points(bodyA, anchorA, bodyB, anchorB,
                                          tangent);
    if (invMass <= B3_EPSILON) {
      continue;
    }
    b3Vec3 impulse = vec3_mul(tangent, -speed / invMass);
    joint->linearImpulse = vec3_add(joint->linearImpulse, impulse);
    pair_apply_impulse_at_points(bodyA, anchorA, bodyB, anchorB, impulse);
  }

  if (joint->enableMotor && !equalLimit && dt > 0.0f) {
    b3Vec3 relativeVelocity =
        vec3_sub(b3Body_GetPointVelocity(bodyB, anchorB),
                 b3Body_GetPointVelocity(bodyA, anchorA));
    scalar speedAlongAxis = vec3_dot(relativeVelocity, axis);
    scalar axisInvMass =
        pair_direction_inv_mass_at_points(bodyA, anchorA, bodyB, anchorB, axis);
    if (axisInvMass <= B3_EPSILON) {
      return;
    }
    scalar impulseMagnitude =
        (joint->motorSpeed - speedAlongAxis) / axisInvMass;
    scalar oldImpulse = joint->motorImpulse;
    scalar maxImpulse = joint->maxMotorForce * dt;
    joint->motorImpulse = scalar_clamp(oldImpulse + impulseMagnitude,
                                       -maxImpulse, maxImpulse);
    impulseMagnitude = joint->motorImpulse - oldImpulse;
    b3Vec3 impulse = vec3_mul(axis, impulseMagnitude);
    pair_apply_impulse_at_points(bodyA, anchorA, bodyB, anchorB, impulse);
  } else {
    joint->motorImpulse = 0.0f;
  }

  if (joint->enableLimit && dt > 0.0f) {
    scalar currentTranslation = joint_prismatic_translation(joint);
    if (!equalLimit) {
      lowerLimit =
          lowerLimit || currentTranslation <= joint->lowerLimit + B3_LINEAR_SLOP;
      upperLimit =
          upperLimit || currentTranslation >= joint->upperLimit - B3_LINEAR_SLOP;
    }
    if (!equalLimit && !lowerLimit && !upperLimit) {
      joint->limitImpulse = 0.0f;
      return;
    }

    b3Vec3 relativeVelocity =
        vec3_sub(b3Body_GetPointVelocity(bodyB, anchorB),
                 b3Body_GetPointVelocity(bodyA, anchorA));
    scalar speedAlongAxis = vec3_dot(relativeVelocity, axis);
    scalar targetSpeed = 0.0f;
    if (equalLimit) {
      targetSpeed = (joint->lowerLimit - currentTranslation) / dt;
    } else if (currentTranslation < joint->lowerLimit) {
      targetSpeed = (joint->lowerLimit - currentTranslation) / dt;
    } else if (currentTranslation > joint->upperLimit) {
      targetSpeed = (joint->upperLimit - currentTranslation) / dt;
    }
    scalar axisInvMass =
        pair_direction_inv_mass_at_points(bodyA, anchorA, bodyB, anchorB, axis);
    if (axisInvMass <= B3_EPSILON) {
      return;
    }
    scalar impulseMagnitude =
        (targetSpeed - speedAlongAxis) / axisInvMass;
    scalar oldImpulse = joint->limitImpulse;
    if (equalLimit) {
      joint->limitImpulse = oldImpulse + impulseMagnitude;
    } else if (lowerLimit) {
      joint->limitImpulse = scalar_max(oldImpulse + impulseMagnitude, 0.0f);
    } else {
      joint->limitImpulse = scalar_min(oldImpulse + impulseMagnitude, 0.0f);
    }
    impulseMagnitude = joint->limitImpulse - oldImpulse;
    b3Vec3 impulse = vec3_mul(axis, impulseMagnitude);
    pair_apply_impulse_at_points(bodyA, anchorA, bodyB, anchorB, impulse);
  } else {
    joint->limitImpulse = 0.0f;
  }
}

static b3Vec3 joint_hinge_axis_a(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  b3Vec3 localAxis =
      quat_rotate_vec3(joint->localRotationA, b3Vec3_Make(0.0f, 0.0f, 1.0f));
  b3Vec3 axis = b3Body_GetWorldVector(joint->bodyA, localAxis);
  scalar length = vec3_length(axis);
  if (length <= B3_EPSILON) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  return vec3_mul(axis, 1.0f / length);
}

static scalar joint_revolute_angle(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return 0.0f;
  }
  b3Quat frameA = quat_mul(joint->bodyA->orientation, joint->localRotationA);
  b3Quat frameB = quat_mul(joint->bodyB->orientation, joint->localRotationB);
  b3Quat relative = quat_mul(quat_conjugate(frameA), frameB);
  relative = quat_mul(quat_conjugate(joint->referenceRotation), relative);
  if (relative.s < 0.0f) {
    relative.v = vec3_mul(relative.v, -1.0f);
    relative.s = -relative.s;
  }
  return 2.0f * atan2f(relative.v.z, relative.s);
}

static bool joint_revolute_has_equal_limits(const b3Joint *joint) {
  return joint != NULL && joint->enableLimit &&
         fabsf(joint->upperLimit - joint->lowerLimit) <
             2.0f * B3_ANGULAR_SLOP;
}

static bool solve_revolute_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  bool solved = solve_sphere_joint_position(joint);

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return solved;
  }

  b3Vec3 axis = joint_hinge_axis_a(joint);
  bool angularSolved = true;
  if (joint->enableLimit) {
    scalar angle = joint_revolute_angle(joint);
    scalar correction = 0.0f;
    if (joint_revolute_has_equal_limits(joint)) {
      correction = scalar_clamp(angle - joint->lowerLimit,
                                -B3_MAX_ANGULAR_CORRECTION,
                                B3_MAX_ANGULAR_CORRECTION);
    } else if (angle <= joint->lowerLimit) {
      correction = scalar_clamp(angle - joint->lowerLimit + B3_ANGULAR_SLOP,
                                -B3_MAX_ANGULAR_CORRECTION, 0.0f);
    } else if (angle >= joint->upperLimit) {
      correction = scalar_clamp(angle - joint->upperLimit - B3_ANGULAR_SLOP,
                                0.0f, B3_MAX_ANGULAR_CORRECTION);
    }
    angularSolved = fabsf(correction) <= B3_ANGULAR_SLOP;
    if (fabsf(correction) > B3_EPSILON) {
      scalar invA = vec3_dot(axis, mat33_mul_vec3(
                                       joint_body_world_inv_inertia(bodyA),
                                       axis));
      scalar invB = vec3_dot(axis, mat33_mul_vec3(
                                       joint_body_world_inv_inertia(bodyB),
                                       axis));
      scalar angularInvMass = invA + invB;
      if (angularInvMass > 0.0f) {
        scalar impulseMagnitude = -correction / angularInvMass;
        body_apply_orientation_correction(
            bodyA, axis, -impulseMagnitude * invA);
        body_apply_orientation_correction(
            bodyB, axis, impulseMagnitude * invB);
        axis = joint_hinge_axis_a(joint);
      }
    }
  }

  return solved && angularSolved;
}

static void solve_revolute_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  solve_sphere_joint_velocity(joint);

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  b3Vec3 axis = joint_hinge_axis_a(joint);
  bool equalLimit = joint_revolute_has_equal_limits(joint);
  b3Vec3 relativeAngularVelocity =
      vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
  scalar speedAlongAxis = vec3_dot(relativeAngularVelocity, axis);
  b3Vec3 perpendicularVelocity =
      vec3_sub(relativeAngularVelocity, vec3_mul(axis, speedAlongAxis));
  b3Mat33 angularMass = joint_angular_mass_matrix(bodyA, bodyB);
  b3Vec3 perpendicularImpulse =
      mat33_mul_vec3(angularMass, vec3_mul(perpendicularVelocity, -1.0f));
  joint->angularImpulse = vec3_add(joint->angularImpulse,
                                   perpendicularImpulse);
  if (invMassA > 0.0f) {
    body_apply_negative_angular_impulse(bodyA, perpendicularImpulse);
  }
  if (invMassB > 0.0f) {
    body_apply_angular_impulse(bodyB, perpendicularImpulse);
  }

  if (joint->enableMotor && !equalLimit && dt > 0.0f) {
    relativeAngularVelocity =
        vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
    speedAlongAxis = vec3_dot(relativeAngularVelocity, axis);
    scalar angularInvMass =
        joint_angular_axis_inv_mass(bodyA, bodyB, axis);
    if (angularInvMass > 0.0f) {
      scalar impulseMagnitude =
          (joint->motorSpeed - speedAlongAxis) / angularInvMass;
      scalar maxImpulse = joint->maxTorque * dt;
      scalar oldImpulse = joint->motorImpulse;
      joint->motorImpulse = scalar_clamp(oldImpulse + impulseMagnitude,
                                         -maxImpulse, maxImpulse);
      impulseMagnitude = joint->motorImpulse - oldImpulse;
      b3Vec3 impulse = vec3_mul(axis, impulseMagnitude);
      if (invMassA > 0.0f) {
        body_apply_negative_angular_impulse(bodyA, impulse);
      }
      if (invMassB > 0.0f) {
        body_apply_angular_impulse(bodyB, impulse);
      }
    } else {
      joint->motorImpulse = 0.0f;
    }
  } else {
    joint->motorImpulse = 0.0f;
  }

  if (joint->enableLimit && dt > 0.0f) {
    scalar angle = joint_revolute_angle(joint);
    bool lowerLimit = angle <= joint->lowerLimit;
    bool upperLimit = angle >= joint->upperLimit;
    if (!equalLimit && !lowerLimit && !upperLimit) {
      joint->limitImpulse = 0.0f;
      return;
    }

    relativeAngularVelocity =
        vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
    speedAlongAxis = vec3_dot(relativeAngularVelocity, axis);
    scalar angularInvMass =
        joint_angular_axis_inv_mass(bodyA, bodyB, axis);
    if (angularInvMass <= 0.0f) {
      return;
    }
    scalar impulseMagnitude = -speedAlongAxis / angularInvMass;
    scalar oldImpulse = joint->limitImpulse;
    if (equalLimit) {
      joint->limitImpulse = oldImpulse + impulseMagnitude;
    } else if (lowerLimit) {
      joint->limitImpulse = scalar_max(oldImpulse + impulseMagnitude, 0.0f);
    } else {
      joint->limitImpulse = scalar_min(oldImpulse + impulseMagnitude, 0.0f);
    }
    impulseMagnitude = joint->limitImpulse - oldImpulse;
    b3Vec3 impulse = vec3_mul(axis, impulseMagnitude);
    if (invMassA > 0.0f) {
      body_apply_negative_angular_impulse(bodyA, impulse);
    }
    if (invMassB > 0.0f) {
      body_apply_angular_impulse(bodyB, impulse);
    }
  } else {
    joint->limitImpulse = 0.0f;
  }
}

static bool solve_cone_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  bool angularSolved = true;

  if (joint->enableConeLimit) {
    b3Body *bodyA = joint->bodyA;
    b3Body *bodyB = joint->bodyB;
    scalar invMassA = joint_body_inv_mass(bodyA);
    scalar invMassB = joint_body_inv_mass(bodyB);
    scalar totalInvMass = invMassA + invMassB;
    if (totalInvMass > B3_EPSILON) {
      b3Vec3 localAxisA =
          quat_rotate_vec3(joint->localRotationA,
                           b3Vec3_Make(1.0f, 0.0f, 0.0f));
      b3Vec3 localAxisB =
          quat_rotate_vec3(joint->localRotationB,
                           b3Vec3_Make(1.0f, 0.0f, 0.0f));
      b3Vec3 axisA =
          vec3_normalize_or_zero(b3Body_GetWorldVector(bodyA, localAxisA));
      b3Vec3 axisB =
          vec3_normalize_or_zero(b3Body_GetWorldVector(bodyB, localAxisB));
      if (vec3_length_sq(axisA) > B3_EPSILON * B3_EPSILON &&
          vec3_length_sq(axisB) > B3_EPSILON * B3_EPSILON) {
        scalar cosine = scalar_clamp(vec3_dot(axisA, axisB), -1.0f, 1.0f);
        scalar angle = acosf(cosine);
        scalar limit = scalar_max(0.0f, 0.5f * joint->coneAngle);
        if (angle > limit + B3_EPSILON) {
          b3Vec3 correctionAxis =
              vec3_normalize_or_zero(vec3_cross(axisB, axisA));
          if (vec3_length_sq(correctionAxis) >
              B3_EPSILON * B3_EPSILON) {
            scalar invA =
                vec3_dot(correctionAxis,
                         mat33_mul_vec3(joint_body_world_inv_inertia(bodyA),
                                        correctionAxis));
            scalar invB =
                vec3_dot(correctionAxis,
                         mat33_mul_vec3(joint_body_world_inv_inertia(bodyB),
                                        correctionAxis));
            scalar angularInvMass = invA + invB;
            if (angularInvMass > B3_EPSILON) {
              scalar correctionAngle = angle - limit;
              angularSolved = correctionAngle <= B3_ANGULAR_SLOP;
              correctionAngle =
                  scalar_clamp(correctionAngle, 0.0f,
                               B3_MAX_ANGULAR_CORRECTION);
              if (correctionAngle > B3_EPSILON) {
                body_apply_orientation_correction(
                    bodyA, correctionAxis,
                    -correctionAngle * invA / angularInvMass);
                body_apply_orientation_correction(
                    bodyB, correctionAxis,
                    correctionAngle * invB / angularInvMass);
              }
            }
          }
        }
      }
    }
  }

  return solve_sphere_joint_position(joint) && angularSolved;
}

static void solve_cone_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  if (joint->enableConeLimit && dt > 0.0f) {
    b3Body *bodyA = joint->bodyA;
    b3Body *bodyB = joint->bodyB;
    scalar invMassA = joint_body_inv_mass(bodyA);
    scalar invMassB = joint_body_inv_mass(bodyB);
    scalar totalInvMass = invMassA + invMassB;
    if (totalInvMass > B3_EPSILON) {
      b3Vec3 localAxisA =
          quat_rotate_vec3(joint->localRotationA,
                           b3Vec3_Make(1.0f, 0.0f, 0.0f));
      b3Vec3 localAxisB =
          quat_rotate_vec3(joint->localRotationB,
                           b3Vec3_Make(1.0f, 0.0f, 0.0f));
      b3Vec3 axisA =
          vec3_normalize_or_zero(b3Body_GetWorldVector(bodyA, localAxisA));
      b3Vec3 axisB =
          vec3_normalize_or_zero(b3Body_GetWorldVector(bodyB, localAxisB));
      if (vec3_length_sq(axisA) > B3_EPSILON * B3_EPSILON &&
          vec3_length_sq(axisB) > B3_EPSILON * B3_EPSILON) {
        scalar cosine = scalar_clamp(vec3_dot(axisA, axisB), -1.0f, 1.0f);
        scalar angle = acosf(cosine);
        scalar limit = scalar_max(0.0f, 0.5f * joint->coneAngle);
        if (angle > limit + B3_EPSILON) {
          b3Vec3 correctionAxis =
              vec3_normalize_or_zero(vec3_cross(axisB, axisA));
          if (vec3_length_sq(correctionAxis) >
              B3_EPSILON * B3_EPSILON) {
            scalar invA =
                vec3_dot(correctionAxis,
                         mat33_mul_vec3(joint_body_world_inv_inertia(bodyA),
                                        correctionAxis));
            scalar invB =
                vec3_dot(correctionAxis,
                         mat33_mul_vec3(joint_body_world_inv_inertia(bodyB),
                                        correctionAxis));
            scalar angularInvMass = invA + invB;
            if (angularInvMass > B3_EPSILON) {
              b3Vec3 relativeAngularVelocity =
                  vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
              scalar speed = vec3_dot(relativeAngularVelocity, correctionAxis);
              scalar impulseMagnitude = -speed / angularInvMass;
              scalar oldImpulse = joint->limitImpulse;
              joint->limitImpulse =
                  scalar_max(oldImpulse + impulseMagnitude, 0.0f);
              impulseMagnitude = joint->limitImpulse - oldImpulse;
              b3Vec3 impulse = vec3_mul(correctionAxis, impulseMagnitude);
              if (invMassA > 0.0f) {
                body_apply_negative_angular_impulse(bodyA, impulse);
              }
              if (invMassB > 0.0f) {
                body_apply_angular_impulse(bodyB, impulse);
              }
            }
          }
        } else {
          joint->limitImpulse = 0.0f;
        }
      }
    }
  } else {
    joint->limitImpulse = 0.0f;
  }

  solve_sphere_joint_velocity(joint);
}

static b3Vec3 joint_world_axis_b(const b3Joint *joint) {
  if (joint == NULL || joint->bodyB == NULL) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  b3Vec3 axis = b3Body_GetWorldVector(joint->bodyB, joint->localAxisB);
  scalar length = vec3_length(axis);
  if (length <= B3_EPSILON) {
    return b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  return vec3_mul(axis, 1.0f / length);
}

static bool solve_wheel_angular_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  b3Vec3 axisA = joint_world_axis_a(joint);
  b3Vec3 axisB = joint_world_axis_b(joint);
  b3Vec3 u = vec3_cross(axisA, axisB);
  scalar uLength = vec3_length(u);
  if (uLength <= B3_EPSILON) {
    return true;
  }
  b3Vec3 correctionAxis = vec3_mul(u, 1.0f / uLength);

  scalar cosine = scalar_clamp(vec3_dot(axisA, axisB), -1.0f, 1.0f);
  scalar angle = atan2f(uLength, cosine);
  scalar angleError = angle - joint->referenceAngle;

  scalar invA = vec3_dot(correctionAxis,
                         mat33_mul_vec3(joint_body_world_inv_inertia(bodyA),
                                        correctionAxis));
  scalar invB = vec3_dot(correctionAxis,
                         mat33_mul_vec3(joint_body_world_inv_inertia(bodyB),
                                        correctionAxis));
  scalar angularInvMass = invA + invB;
  if (angularInvMass <= B3_EPSILON) {
    return true;
  }

  bool solved = fabsf(angleError) <= B3_ANGULAR_SLOP;
  scalar correctionAngle =
      scalar_clamp(-angleError, -B3_MAX_ANGULAR_CORRECTION,
                   B3_MAX_ANGULAR_CORRECTION);
  if (fabsf(correctionAngle) > B3_EPSILON) {
    body_apply_orientation_correction(
        bodyA, correctionAxis, -correctionAngle * invA / angularInvMass);
    body_apply_orientation_correction(
        bodyB, correctionAxis, correctionAngle * invB / angularInvMass);
  }

  return solved;
}

static void solve_wheel_angular_velocity(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  b3Vec3 axisB = joint_world_axis_b(joint);
  b3Vec3 relativeAngularVelocity =
      vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
  scalar spinSpeed = vec3_dot(relativeAngularVelocity, axisB);
  b3Vec3 perpendicularVelocity =
      vec3_sub(relativeAngularVelocity, vec3_mul(axisB, spinSpeed));
  if (vec3_length_sq(perpendicularVelocity) <= B3_EPSILON * B3_EPSILON) {
    return;
  }

  b3Mat33 angularMass = joint_angular_mass_matrix(bodyA, bodyB);
  b3Vec3 impulse =
      mat33_mul_vec3(angularMass, vec3_mul(perpendicularVelocity, -1.0f));
  body_apply_negative_angular_impulse(bodyA, impulse);
  body_apply_angular_impulse(bodyB, impulse);
}

static bool solve_wheel_joint_position(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return true;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return true;
  }

  b3Vec3 axisA = joint_world_axis_a(joint);
  b3Vec3 anchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  b3Vec3 tangent1 = vec3_perp(axisA);
  b3Vec3 tangent2 = vec3_normalize_or_zero(vec3_cross(axisA, tangent1));
  bool linearSolved = true;
  if (vec3_length_sq(tangent1) > B3_EPSILON * B3_EPSILON &&
      vec3_length_sq(tangent2) > B3_EPSILON * B3_EPSILON) {
    b3Vec3 error = vec3_sub(anchorB, anchorA);
    b3Vec2 positionError =
        b3Vec2_Make(vec3_dot(error, tangent1), vec3_dot(error, tangent2));
    linearSolved = b3Vec2_Length(positionError) <= B3_LINEAR_SLOP;
    scalar k11 = 0.0f;
    scalar k12 = 0.0f;
    scalar k22 = 0.0f;
    body_add_tangent_inv_mass_terms(bodyA, anchorA, tangent1, tangent2, &k11,
                                    &k12, &k22);
    body_add_tangent_inv_mass_terms(bodyB, anchorB, tangent1, tangent2, &k11,
                                    &k12, &k22);
    b3Mat22 positionMass;
    if (tangent_mass_from_terms(k11, k12, k22, &positionMass)) {
      b3Vec2 impulse2 =
          b3Mat22_MulVec2(positionMass, b3Vec2_Negate(positionError));
      b3Vec3 impulse =
          vec3_add(vec3_mul(tangent1, impulse2.x),
                   vec3_mul(tangent2, impulse2.y));
      pair_apply_position_impulse_at_points(bodyA, anchorA, bodyB, anchorB,
                                            impulse);
    }
  }

  return solve_wheel_angular_position(joint) && linearSolved;
}

static void solve_wheel_joint_velocity(b3Joint *joint, scalar dt) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  b3Body *bodyA = joint->bodyA;
  b3Body *bodyB = joint->bodyB;
  scalar invMassA = joint_body_inv_mass(bodyA);
  scalar invMassB = joint_body_inv_mass(bodyB);
  scalar totalInvMass = invMassA + invMassB;
  if (totalInvMass <= B3_EPSILON) {
    return;
  }

  solve_wheel_angular_velocity(joint);

  b3Vec3 axisA = joint_world_axis_a(joint);
  b3Vec3 tangent1 = vec3_perp(axisA);
  b3Vec3 tangent2 = vec3_normalize_or_zero(vec3_cross(axisA, tangent1));
  b3Vec3 anchorA = b3Body_GetWorldPoint(bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(bodyB, joint->localAnchorB);
  scalar translation = vec3_dot(vec3_sub(anchorB, anchorA), axisA);
  const b3Vec3 tangents[2] = {tangent1, tangent2};
  for (uint32 i = 0u; i < 2u; ++i) {
    b3Vec3 tangent = tangents[i];
    if (vec3_length_sq(tangent) <= B3_EPSILON * B3_EPSILON) {
      continue;
    }
    b3Vec3 relativeVelocity =
        vec3_sub(b3Body_GetPointVelocity(bodyB, anchorB),
                 b3Body_GetPointVelocity(bodyA, anchorA));
    scalar speed = vec3_dot(relativeVelocity, tangent);
    scalar invMass =
        pair_direction_inv_mass_at_points(bodyA, anchorA, bodyB, anchorB,
                                          tangent);
    if (invMass <= B3_EPSILON) {
      continue;
    }
    b3Vec3 impulse = vec3_mul(tangent, -speed / invMass);
    pair_apply_impulse_at_points(bodyA, anchorA, bodyB, anchorB, impulse);
  }

  if (joint->frequencyHz > 0.0f && dt > 0.0f) {
    b3Vec3 relativeVelocity =
        vec3_sub(b3Body_GetPointVelocity(bodyB, anchorB),
                 b3Body_GetPointVelocity(bodyA, anchorA));
    scalar speedAlongAxis = vec3_dot(relativeVelocity, axisA);
    scalar axisInvMass =
        pair_direction_inv_mass_at_points(bodyA, anchorA, bodyB, anchorB,
                                          axisA);
    if (axisInvMass <= B3_EPSILON) {
      return;
    }
    scalar springMass = 1.0f / axisInvMass;
    scalar omega = 2.0f * B3_PI * joint->frequencyHz;
    scalar dampingCoefficient =
        2.0f * springMass * scalar_max(0.0f, joint->dampingRatio) * omega;
    scalar stiffness = springMass * omega * omega;
    scalar gamma = dt * (dampingCoefficient + dt * stiffness);
    if (gamma > 0.0f) {
      gamma = 1.0f / gamma;
    }
    scalar bias = (translation - joint->length) * dt * stiffness * gamma;
    scalar effectiveMass = axisInvMass + gamma;
    if (effectiveMass <= B3_EPSILON) {
      return;
    }
    effectiveMass = 1.0f / effectiveMass;
    scalar impulseMagnitude =
        -effectiveMass * (speedAlongAxis + bias +
                          gamma * joint->springImpulse);
    joint->springImpulse += impulseMagnitude;
    b3Vec3 impulse = vec3_mul(axisA, impulseMagnitude);
    pair_apply_impulse_at_points(bodyA, anchorA, bodyB, anchorB, impulse);
  }

  if (joint->enableMotor && dt > 0.0f) {
    b3Vec3 axisB = joint_world_axis_b(joint);
    b3Vec3 relativeAngularVelocity =
        vec3_sub(bodyB->angularVelocity, bodyA->angularVelocity);
    scalar angularSpeed = vec3_dot(relativeAngularVelocity, axisB);
    scalar angularInvMass =
        joint_angular_axis_inv_mass(bodyA, bodyB, axisB);
    if (angularInvMass <= B3_EPSILON) {
      return;
    }
    scalar impulseMagnitude =
        (joint->motorSpeed - angularSpeed) / angularInvMass;
    scalar oldImpulse = joint->motorImpulse;
    scalar maxImpulse = joint->maxTorque * dt;
    joint->motorImpulse = scalar_clamp(oldImpulse + impulseMagnitude,
                                       -maxImpulse, maxImpulse);
    impulseMagnitude = joint->motorImpulse - oldImpulse;
    b3Vec3 impulse = vec3_mul(axisB, impulseMagnitude);
    if (invMassA > 0.0f) {
      body_apply_negative_angular_impulse(bodyA, impulse);
    }
    if (invMassB > 0.0f) {
      body_apply_angular_impulse(bodyB, impulse);
    }
  } else {
    joint->motorImpulse = 0.0f;
  }
}

static void joint_clear_cached_impulses(b3Joint *joint) {
  if (joint == NULL) {
    return;
  }
  joint->linearImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  joint->springImpulse = 0.0f;
  joint->limitImpulse = 0.0f;
  joint->motorImpulse = 0.0f;
}

static void joint_scale_cached_impulses(b3Joint *joint, scalar dtRatio) {
  if (joint == NULL) {
    return;
  }
  joint->linearImpulse = vec3_mul(joint->linearImpulse, dtRatio);
  joint->angularImpulse = vec3_mul(joint->angularImpulse, dtRatio);
  joint->springImpulse *= dtRatio;
  joint->limitImpulse *= dtRatio;
  joint->motorImpulse *= dtRatio;
}

static void warm_start_joint_linear_impulse(b3Joint *joint, b3Vec3 pointA,
                                            b3Vec3 pointB, b3Vec3 impulse) {
  if (joint == NULL || vec3_length_sq(impulse) <= B3_EPSILON * B3_EPSILON) {
    return;
  }
  pair_apply_impulse_at_points(joint->bodyA, pointA, joint->bodyB, pointB,
                               impulse);
}

static void warm_start_joint_angular_impulse(b3Joint *joint,
                                             b3Vec3 impulse) {
  if (joint == NULL || vec3_length_sq(impulse) <= B3_EPSILON * B3_EPSILON) {
    return;
  }
  body_apply_negative_angular_impulse(joint->bodyA, impulse);
  body_apply_angular_impulse(joint->bodyB, impulse);
}

static bool joint_cone_limit_axis(const b3Joint *joint, b3Vec3 *outAxis) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL ||
      outAxis == NULL) {
    return false;
  }
  b3Vec3 localAxisA =
      quat_rotate_vec3(joint->localRotationA, b3Vec3_Make(1.0f, 0.0f, 0.0f));
  b3Vec3 localAxisB =
      quat_rotate_vec3(joint->localRotationB, b3Vec3_Make(1.0f, 0.0f, 0.0f));
  b3Vec3 axisA =
      vec3_normalize_or_zero(b3Body_GetWorldVector(joint->bodyA, localAxisA));
  b3Vec3 axisB =
      vec3_normalize_or_zero(b3Body_GetWorldVector(joint->bodyB, localAxisB));
  if (vec3_length_sq(axisA) <= B3_EPSILON * B3_EPSILON ||
      vec3_length_sq(axisB) <= B3_EPSILON * B3_EPSILON) {
    return false;
  }
  scalar cosine = scalar_clamp(vec3_dot(axisA, axisB), -1.0f, 1.0f);
  scalar angle = acosf(cosine);
  scalar limit = scalar_max(0.0f, 0.5f * joint->coneAngle);
  if (angle <= limit + B3_EPSILON) {
    return false;
  }
  b3Vec3 correctionAxis = vec3_normalize_or_zero(vec3_cross(axisB, axisA));
  if (vec3_length_sq(correctionAxis) <= B3_EPSILON * B3_EPSILON) {
    return false;
  }
  *outAxis = correctionAxis;
  return true;
}

static void warm_start_joint(b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return;
  }

  b3Vec3 anchorA = b3Body_GetWorldPoint(joint->bodyA, joint->localAnchorA);
  b3Vec3 anchorB = b3Body_GetWorldPoint(joint->bodyB, joint->localAnchorB);

  switch (joint->type) {
  case e_sphereJoint:
    joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->springImpulse = 0.0f;
    joint->limitImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    joint->linearImpulse);
    break;

  case e_springJoint: {
    joint->linearImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->limitImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    b3Vec3 delta = vec3_sub(anchorB, anchorA);
    scalar distance = vec3_length(delta);
    if (distance > B3_EPSILON) {
      b3Vec3 axis = vec3_mul(delta, 1.0f / distance);
      warm_start_joint_linear_impulse(
          joint, anchorA, anchorB, vec3_mul(axis, joint->springImpulse));
    } else {
      joint->springImpulse = 0.0f;
    }
    break;
  }

  case e_weldJoint:
    joint->springImpulse = 0.0f;
    joint->limitImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    joint->linearImpulse);
    warm_start_joint_angular_impulse(joint, joint->angularImpulse);
    break;

  case e_frictionJoint:
    joint->springImpulse = 0.0f;
    joint->limitImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    joint->linearImpulse);
    warm_start_joint_angular_impulse(joint, joint->angularImpulse);
    break;

  case e_motorJoint: {
    joint->springImpulse = 0.0f;
    joint->limitImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    b3Vec3 targetPosition =
        b3Body_GetWorldPoint(joint->bodyA, joint->linearOffset);
    b3Vec3 bodyBPoint = body_current_world_center(joint->bodyB);
    warm_start_joint_linear_impulse(joint, targetPosition, bodyBPoint,
                                    joint->linearImpulse);
    warm_start_joint_angular_impulse(joint, joint->angularImpulse);
    break;
  }

  case e_mouseJoint:
    joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->springImpulse = 0.0f;
    joint->limitImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    body_apply_impulse_at_point(joint->bodyB, joint->linearImpulse, anchorB);
    break;

  case e_prismaticJoint: {
    joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->springImpulse = 0.0f;
    b3Vec3 axis = joint_world_axis_a(joint);
    joint->linearImpulse =
        vec3_sub(joint->linearImpulse,
                 vec3_mul(axis, vec3_dot(joint->linearImpulse, axis)));
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    joint->linearImpulse);
    if (!joint->enableMotor || joint_prismatic_has_equal_limits(joint)) {
      joint->motorImpulse = 0.0f;
    }
    warm_start_joint_linear_impulse(
        joint, anchorA, anchorB,
        vec3_mul(axis, joint->motorImpulse + joint->limitImpulse));
    break;
  }

  case e_revoluteJoint: {
    joint->springImpulse = 0.0f;
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    joint->linearImpulse);
    b3Vec3 axis = joint_hinge_axis_a(joint);
    joint->angularImpulse =
        vec3_sub(joint->angularImpulse,
                 vec3_mul(axis, vec3_dot(joint->angularImpulse, axis)));
    warm_start_joint_angular_impulse(joint, joint->angularImpulse);
    if (!joint->enableMotor || joint_revolute_has_equal_limits(joint)) {
      joint->motorImpulse = 0.0f;
    }
    warm_start_joint_angular_impulse(
        joint, vec3_mul(axis, joint->motorImpulse + joint->limitImpulse));
    break;
  }

  case e_coneJoint: {
    joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->springImpulse = 0.0f;
    joint->motorImpulse = 0.0f;
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    joint->linearImpulse);
    b3Vec3 axis;
    if (joint_cone_limit_axis(joint, &axis)) {
      warm_start_joint_angular_impulse(joint,
                                       vec3_mul(axis, joint->limitImpulse));
    } else {
      joint->limitImpulse = 0.0f;
    }
    break;
  }

  case e_wheelJoint: {
    joint->linearImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    joint->limitImpulse = 0.0f;
    b3Vec3 axisA = joint_world_axis_a(joint);
    warm_start_joint_linear_impulse(joint, anchorA, anchorB,
                                    vec3_mul(axisA, joint->springImpulse));
    b3Vec3 axisB = joint_world_axis_b(joint);
    if (!joint->enableMotor) {
      joint->motorImpulse = 0.0f;
    }
    warm_start_joint_angular_impulse(joint,
                                     vec3_mul(axisB, joint->motorImpulse));
    break;
  }
  }
}

static void world_prepare_joint_warm_start(b3World *world) {
  if (world == NULL) {
    return;
  }
  for (b3Joint *joint = world->joints; joint != NULL; joint = joint->next) {
    if (!joint_in_active_island(world, joint)) {
      continue;
    }
    if (!world->warmStarting || world->dtRatio <= 0.0f) {
      joint_clear_cached_impulses(joint);
      continue;
    }
    joint_scale_cached_impulses(joint, world->dtRatio);
    warm_start_joint(joint);
  }
}

static bool world_should_solve_joint(b3World *world, b3Joint *joint) {
  if (world == NULL || joint == NULL || !joint_in_active_island(world, joint)) {
    return false;
  }
  if (joint->bodyA != NULL && joint->bodyB != NULL) {
    if (!joint->bodyA->awake && !joint->bodyB->awake) {
      return false;
    }
    body_wake_from_awake_island(joint->bodyA, joint->bodyB);
    body_wake_from_awake_island(joint->bodyB, joint->bodyA);
  }
  return true;
}

static void solve_joint_velocity(b3Joint *joint, scalar dt) {
  switch (joint->type) {
  case e_sphereJoint:
    solve_sphere_joint_velocity(joint);
    break;
  case e_springJoint:
    solve_spring_joint_velocity(joint, dt);
    break;
  case e_weldJoint:
    solve_weld_joint_velocity(joint, dt);
    break;
  case e_frictionJoint:
    solve_friction_joint_velocity(joint, dt);
    break;
  case e_motorJoint:
    solve_motor_joint_velocity(joint, dt);
    break;
  case e_mouseJoint:
    solve_mouse_joint_velocity(joint, dt);
    break;
  case e_prismaticJoint:
    solve_prismatic_joint_velocity(joint, dt);
    break;
  case e_revoluteJoint:
    solve_revolute_joint_velocity(joint, dt);
    break;
  case e_coneJoint:
    solve_cone_joint_velocity(joint, dt);
    break;
  case e_wheelJoint:
    solve_wheel_joint_velocity(joint, dt);
    break;
  }
}

static bool solve_joint_position(b3Joint *joint) {
  switch (joint->type) {
  case e_sphereJoint:
    return solve_sphere_joint_position(joint);
  case e_springJoint:
    return solve_spring_joint_position(joint);
  case e_weldJoint:
    return solve_weld_joint_position(joint);
  case e_frictionJoint:
    return solve_friction_joint_position(joint);
  case e_motorJoint:
    return solve_motor_joint_position(joint);
  case e_mouseJoint:
    return solve_mouse_joint_position(joint);
  case e_prismaticJoint:
    return solve_prismatic_joint_position(joint);
  case e_revoluteJoint:
    return solve_revolute_joint_position(joint);
  case e_coneJoint:
    return solve_cone_joint_position(joint);
  case e_wheelJoint:
    return solve_wheel_joint_position(joint);
  }
  return true;
}

static void solve_world_joint_velocity_constraints(b3World *world, scalar dt) {
  if (world == NULL || world->joints == NULL) {
    return;
  }
  for (b3Joint *joint = world->joints; joint != NULL; joint = joint->next) {
    if (world_should_solve_joint(world, joint)) {
      solve_joint_velocity(joint, dt);
    }
  }
}

static bool solve_world_joint_position_constraints(b3World *world) {
  if (world == NULL || world->joints == NULL) {
    return true;
  }
  bool solved = true;
  for (b3Joint *joint = world->joints; joint != NULL; joint = joint->next) {
    if (world_should_solve_joint(world, joint)) {
      solved = solve_joint_position(joint) && solved;
    }
  }
  return solved;
}

static void solve_world_velocity_iterations(b3World *world, uint32 iterations,
                                            scalar dt) {
  if (world == NULL) {
    return;
  }
  uint32 cacheContactCount =
      world_has_active_island(world) ? world->activeIslandContactCount
                                     : world->contactCount;
  if (cacheContactCount == 0u && world->jointCount == 0u) {
    return;
  }
  b3Profiler_OpenScope(world->profiler, "Initialize Velocity Constraints");
  bool useVelocityBodyCache =
      iterations > 0u && cacheContactCount >= 16u &&
      world_prepare_velocity_body_cache(world);
  bool useFastContacts =
      iterations > 0u && world_initialize_contact_velocity_constraints(world);
  if (!useFastContacts || !world_contact_velocity_cache_ready(world)) {
    useVelocityBodyCache = false;
    world_clear_velocity_body_cache(world);
  }
  if (!useFastContacts) {
    world->contactVelocityConstraintCount = 0u;
    world_prepare_contact_velocity_biases(world);
    world_warm_start_contacts(world);
  } else if (useVelocityBodyCache) {
    world_warm_start_contact_velocity_constraints_cached(world);
  } else {
    world_warm_start_contact_velocity_constraints(world);
  }
  world_prepare_joint_warm_start(world);
  b3Profiler_CloseScope(world->profiler);
  if (iterations == 0u) {
    return;
  }
  b3Profiler_OpenScope(world->profiler, "Solve Velocity Constraints");
  for (uint32 i = 0u; i < iterations; ++i) {
    solve_world_joint_velocity_constraints(world, dt);
    if (useFastContacts) {
      if (useVelocityBodyCache) {
        world_solve_contact_velocity_constraints_cached(world);
      } else {
        world_solve_contact_velocity_constraints(world);
      }
    } else {
      solve_world_contact_constraints(world, false, true);
    }
  }
  if (useFastContacts) {
    world_store_contact_velocity_impulses(world);
    if (useVelocityBodyCache) {
      world_store_velocity_body_cache(world);
    }
  }
  b3Profiler_CloseScope(world->profiler);
}

static bool solve_world_position_iterations(b3World *world,
                                            uint32 iterations) {
  if (world == NULL) {
    return true;
  }
  if (iterations == 0u) {
    return false;
  }
  uint32 cacheContactCount =
      world_has_active_island(world) ? world->activeIslandContactCount
                                     : world->contactCount;
  if (cacheContactCount == 0u && world->jointCount == 0u) {
    return true;
  }
  b3Profiler_OpenScope(world->profiler, "Solve Position Constraints");
  bool usePositionBodyCache =
      cacheContactCount >= 16u && world_prepare_position_body_cache(world);
  if (!usePositionBodyCache || !world_position_body_cache_ready(world)) {
    usePositionBodyCache = false;
    world_clear_position_body_cache(world);
  }
  bool solved = false;
  bool flushBodySync = !world->deferBodySync;
  if (flushBodySync) {
    world->deferBodySync = true;
  }
  for (uint32 i = 0u; i < iterations; ++i) {
    bool contactsSolved =
        usePositionBodyCache
            ? solve_world_contact_position_constraints_cached(world)
            : solve_world_contact_constraints(world, true, false);
    bool jointsSolved = usePositionBodyCache
                            ? true
                            : solve_world_joint_position_constraints(world);
    solved = contactsSolved && jointsSolved;
    if (solved) {
      break;
    }
  }
  if (usePositionBodyCache) {
    world_store_position_body_cache(world);
  }
  if (flushBodySync) {
    world->deferBodySync = false;
    world_flush_deferred_body_sync(world, true);
  }
  b3Profiler_CloseScope(world->profiler);
  return solved;
}

bool b3IsInf(scalar x) { return isinf(x) != 0; }

bool b3IsNaN(scalar x) { return isnan(x) != 0; }

bool b3IsValid(scalar x) { return isfinite(x) != 0; }

scalar b3Sqrt(scalar x) { return sqrtf(x); }

scalar b3Abs(scalar x) { return fabsf(x); }

scalar b3Min(scalar a, scalar b) { return a < b ? a : b; }

scalar b3Max(scalar a, scalar b) { return a > b ? a : b; }

scalar b3Clamp(scalar a, scalar low, scalar high) {
  return b3Max(low, b3Min(a, high));
}

scalar b3Sign(scalar x) { return (scalar)((0.0f < x) - (x < 0.0f)); }

scalar b3MixRestitution(scalar e1, scalar e2) { return b3Max(e1, e2); }

scalar b3MixFriction(scalar u1, scalar u2) { return b3Sqrt(u1 * u2); }

void b3SwapScalar(scalar *a, scalar *b) {
  if (a == NULL || b == NULL) {
    return;
  }
  scalar tmp = *a;
  *a = *b;
  *b = tmp;
}

void b3SwapU32(uint32 *a, uint32 *b) {
  if (a == NULL || b == NULL) {
    return;
  }
  uint32 tmp = *a;
  *a = *b;
  *b = tmp;
}

void b3SwapBytes(void *a, void *b, uint32 size) {
  if (a == NULL || b == NULL || a == b) {
    return;
  }
  unsigned char *bytesA = (unsigned char *)a;
  unsigned char *bytesB = (unsigned char *)b;
  for (uint32 i = 0u; i < size; ++i) {
    unsigned char tmp = bytesA[i];
    bytesA[i] = bytesB[i];
    bytesB[i] = tmp;
  }
}

uint32 b3UniqueCountScalar(const scalar *values, uint32 count) {
  if (values == NULL) {
    return 0u;
  }

  uint32 unique = 0u;
  for (uint32 i = 0u; i < count; ++i) {
    uint32 j = 0u;
    for (; j < count; ++j) {
      if (values[i] == values[j]) {
        break;
      }
    }
    if (i == j) {
      ++unique;
    }
  }
  return unique;
}

uint32 b3UniqueCountU8(const uint8_t *values, uint32 count) {
  if (values == NULL) {
    return 0u;
  }

  uint32 unique = 0u;
  for (uint32 i = 0u; i < count; ++i) {
    uint32 j = 0u;
    for (; j < count; ++j) {
      if (values[i] == values[j]) {
        break;
      }
    }
    if (i == j) {
      ++unique;
    }
  }
  return unique;
}

uint32 b3UniqueCountU32(const uint32 *values, uint32 count) {
  if (values == NULL) {
    return 0u;
  }

  uint32 unique = 0u;
  for (uint32 i = 0u; i < count; ++i) {
    uint32 j = 0u;
    for (; j < count; ++j) {
      if (values[i] == values[j]) {
        break;
      }
    }
    if (i == j) {
      ++unique;
    }
  }
  return unique;
}

uint32 b3UniqueCountBytes(const void *values, uint32 count,
                          uint32 elementSize) {
  if (values == NULL || elementSize == 0u) {
    return 0u;
  }
  const unsigned char *bytes = (const unsigned char *)values;
  uint32 unique = 0u;
  for (uint32 i = 0u; i < count; ++i) {
    uint32 j = 0u;
    for (; j < count; ++j) {
      if (memcmp(bytes + (size_t)i * elementSize,
                 bytes + (size_t)j * elementSize, elementSize) == 0) {
        break;
      }
    }
    if (i == j) {
      ++unique;
    }
  }
  return unique;
}

void b3Mul(scalar *C, const scalar *A, uint32 AM, uint32 AN, const scalar *B,
           uint32 BM, uint32 BN) {
  if (C == NULL || A == NULL || B == NULL || AN != BM) {
    return;
  }

  for (uint32 i = 0u; i < AM; ++i) {
    for (uint32 j = 0u; j < BN; ++j) {
      C[i + AM * j] = 0.0f;
      for (uint32 k = 0u; k < AN; ++k) {
        C[i + AM * j] += A[i + AM * k] * B[k + BM * j];
      }
    }
  }
}

void b3Transpose(scalar *B, const scalar *A, uint32 AM, uint32 AN) {
  if (B == NULL || A == NULL) {
    return;
  }

  for (uint32 i = 0u; i < AM; ++i) {
    for (uint32 j = 0u; j < AN; ++j) {
      B[j + AN * i] = A[i + AM * j];
    }
  }
}

void b3SubMatrix(scalar *out, const scalar *A, uint32 AM, uint32 AN,
                 uint32 row, uint32 col) {
  if (out == NULL || A == NULL || row >= AM || col >= AN) {
    return;
  }

  uint32 count = 0u;
  for (uint32 j = 0u; j < AN; ++j) {
    for (uint32 i = 0u; i < AM; ++i) {
      if (i != row && j != col) {
        out[count++] = A[i + AM * j];
      }
    }
  }
}

scalar b3Length(const scalar *v, uint32 n) {
  if (v == NULL) {
    return 0.0f;
  }

  scalar result = 0.0f;
  for (uint32 i = 0u; i < n; ++i) {
    result += v[i] * v[i];
  }
  return b3Sqrt(result);
}

static void *array_element(const b3Array *array, uint32 index) {
  if (array == NULL || array->elements == NULL || index >= array->count ||
      array->elementSize == 0u) {
    return NULL;
  }
  return (uint8_t *)array->elements + (size_t)index * array->elementSize;
}

bool b3Array_Init(b3Array *array, uint32 elementSize, void *localElements,
                  uint32 capacity) {
  if (array == NULL || elementSize == 0u || capacity == 0u) {
    return false;
  }
  memset(array, 0, sizeof(*array));
  array->elementSize = elementSize;
  array->capacity = capacity;
  array->localElements = localElements;
  if (localElements != NULL) {
    array->elements = localElements;
    return true;
  }
  array->elements = b3Alloc(elementSize * capacity);
  if (array->elements == NULL) {
    memset(array, 0, sizeof(*array));
    return false;
  }
  return true;
}

bool b3Array_InitHeap(b3Array *array, uint32 elementSize, uint32 capacity) {
  return b3Array_Init(array, elementSize, NULL, capacity);
}

void b3Array_Destroy(b3Array *array) {
  if (array == NULL) {
    return;
  }
  if (array->elements != NULL && array->elements != array->localElements) {
    b3Free(array->elements);
  }
  memset(array, 0, sizeof(*array));
}

const void *b3Array_Get(const b3Array *array, uint32 index) {
  return array_element(array, index);
}

void *b3Array_GetMutable(b3Array *array, uint32 index) {
  return array_element(array, index);
}

const void *b3Array_Begin(const b3Array *array) {
  return array != NULL ? array->elements : NULL;
}

void *b3Array_BeginMutable(b3Array *array) {
  return array != NULL ? array->elements : NULL;
}

bool b3Array_Reserve(b3Array *array, uint32 size) {
  if (array == NULL || array->elementSize == 0u) {
    return false;
  }
  if (array->capacity >= size) {
    return true;
  }
  uint32 newCapacity = size > UINT32_MAX / 2u ? size : 2u * size;
  void *newElements = b3Alloc(array->elementSize * newCapacity);
  if (newElements == NULL) {
    return false;
  }
  if (array->elements != NULL && array->count > 0u) {
    memcpy(newElements, array->elements, array->elementSize * array->count);
  }
  if (array->elements != NULL && array->elements != array->localElements) {
    b3Free(array->elements);
  }
  array->elements = newElements;
  array->capacity = newCapacity;
  return true;
}

bool b3Array_PushBack(b3Array *array, const void *element) {
  if (array == NULL || element == NULL || array->elementSize == 0u) {
    return false;
  }
  if (array->count == array->capacity &&
      !b3Array_Reserve(array, array->capacity + 1u)) {
    return false;
  }
  memcpy((uint8_t *)array->elements + (size_t)array->count * array->elementSize,
         element, array->elementSize);
  ++array->count;
  return true;
}

void b3Array_PopBack(b3Array *array) {
  if (array != NULL && array->count > 0u) {
    --array->count;
  }
}

const void *b3Array_Back(const b3Array *array) {
  return array != NULL && array->count > 0u
             ? array_element(array, array->count - 1u)
             : NULL;
}

void *b3Array_BackMutable(b3Array *array) {
  return array != NULL && array->count > 0u
             ? array_element(array, array->count - 1u)
             : NULL;
}

uint32 b3Array_Capacity(const b3Array *array) {
  return array != NULL ? array->capacity : 0u;
}

uint32 b3Array_Count(const b3Array *array) {
  return array != NULL ? array->count : 0u;
}

bool b3Array_IsEmpty(const b3Array *array) {
  return array == NULL || array->count == 0u;
}

void b3Array_Remove(b3Array *array, uint32 index) {
  if (array == NULL || index >= array->count || array->elementSize == 0u) {
    return;
  }
  --array->count;
  if (index < array->count) {
    uint8_t *base = (uint8_t *)array->elements;
    memmove(base + (size_t)index * array->elementSize,
            base + (size_t)(index + 1u) * array->elementSize,
            (size_t)(array->count - index) * array->elementSize);
  }
}

bool b3Array_Resize(b3Array *array, uint32 size) {
  if (!b3Array_Reserve(array, size)) {
    return false;
  }
  array->count = size;
  return true;
}

bool b3Array_Swap(b3Array *array, const b3Array *other) {
  if (array == NULL || other == NULL ||
      array->elementSize != other->elementSize) {
    return false;
  }
  if (array->elements == other->elements) {
    return true;
  }
  if (!b3Array_Reserve(array, other->count)) {
    return false;
  }
  if (other->count > 0u) {
    memcpy(array->elements, other->elements,
           (size_t)other->count * array->elementSize);
  }
  array->count = other->count;
  return true;
}

bool b3StackArray_Init(b3StackArray *array, uint32 elementSize,
                       void *localElements, uint32 capacity) {
  return b3Array_Init(array, elementSize, localElements, capacity);
}

bool b3Stack_Init(b3Stack *stack, uint32 elementSize, void *localElements,
                  uint32 capacity) {
  if (stack == NULL) {
    return false;
  }
  return b3Array_Init(&stack->array, elementSize, localElements, capacity);
}

void b3Stack_Destroy(b3Stack *stack) {
  if (stack != NULL) {
    b3Array_Destroy(&stack->array);
  }
}

const void *b3Stack_Top(const b3Stack *stack) {
  return stack != NULL ? b3Array_Back(&stack->array) : NULL;
}

void *b3Stack_TopMutable(b3Stack *stack) {
  return stack != NULL ? b3Array_BackMutable(&stack->array) : NULL;
}

bool b3Stack_Push(b3Stack *stack, const void *element) {
  return stack != NULL && b3Array_PushBack(&stack->array, element);
}

void b3Stack_Pop(b3Stack *stack) {
  if (stack != NULL) {
    b3Array_PopBack(&stack->array);
  }
}

uint32 b3Stack_Count(const b3Stack *stack) {
  return stack != NULL ? b3Array_Count(&stack->array) : 0u;
}

bool b3Stack_IsEmpty(const b3Stack *stack) {
  return stack == NULL || b3Array_IsEmpty(&stack->array);
}

void b3Stack_Clear(b3Stack *stack) {
  if (stack != NULL) {
    stack->array.count = 0u;
  }
}

b3FeaturePair b3MakePair(uint32 inEdge1, uint32 outEdge1, uint32 inEdge2,
                         uint32 outEdge2) {
  b3FeaturePair out;
  out.inEdge1 = inEdge1;
  out.outEdge1 = outEdge1;
  out.inEdge2 = inEdge2;
  out.outEdge2 = outEdge2;
  return out;
}

b3ManifoldPointKey b3MakeKey(b3FeaturePair featurePair) {
  b3FeaturePairKey featureKey;
  featureKey.pair = featurePair;
  b3ManifoldPointKey key;
  key.triangleKey = B3_NULL_TRIANGLE;
  key.key1 = featureKey.key.key1;
  key.key2 = featureKey.key.key2;
  return key;
}

b3SATFeaturePair b3MakeFeaturePair(b3SATCacheType state,
                                   b3SATFeatureType type, uint32 index1,
                                   uint32 index2) {
  b3SATFeaturePair pair;
  pair.state = state;
  pair.type = type;
  pair.index1 = index1;
  pair.index2 = index2;
  return pair;
}

static bool cluster_is_ccw(b3Vec3 A, b3Vec3 B, b3Vec3 C, b3Vec3 N) {
  b3Vec3 n = b3Vec3_Cross(b3Vec3_Sub(B, A), b3Vec3_Sub(C, A));
  return b3Vec3_Dot(n, N) > 0.0f;
}

static void cluster_swap_vertices(b3ClusterPolygonVertex *a,
                                  b3ClusterPolygonVertex *b) {
  b3ClusterPolygonVertex tmp = *a;
  *a = *b;
  *b = tmp;
}

void b3ClusterPolygon_Init(b3ClusterPolygon *polygon,
                           b3ClusterPolygonVertex *vertices,
                           uint32 capacity) {
  if (polygon == NULL) {
    return;
  }
  polygon->vertices = vertices;
  polygon->count = 0u;
  polygon->capacity = vertices != NULL ? capacity : 0u;
}

void b3ClusterPolygon_Clear(b3ClusterPolygon *polygon) {
  if (polygon != NULL) {
    polygon->count = 0u;
  }
}

bool b3ClusterPolygon_Push(b3ClusterPolygon *polygon,
                           b3ClusterPolygonVertex vertex) {
  if (polygon == NULL || polygon->vertices == NULL ||
      polygon->count >= polygon->capacity) {
    return false;
  }
  polygon->vertices[polygon->count++] = vertex;
  return true;
}

uint32 b3ClusterPolygon_Sort(b3ClusterPolygon *out,
                             const b3ClusterPolygon *in, b3Vec3 normal) {
  if (out == NULL || in == NULL) {
    return 0u;
  }
  out->count =
      b3SortPolygon(out->vertices, out->capacity, in->vertices, in->count,
                    normal);
  return out->count;
}

uint32 b3ClusterPolygon_Reduce(b3ClusterPolygon *out,
                               const b3ClusterPolygon *in, b3Vec3 normal,
                               uint32 initialPoint) {
  if (out == NULL || in == NULL) {
    return 0u;
  }
  out->count = b3ReducePolygon(out->vertices, out->capacity, in->vertices,
                               in->count, normal, initialPoint);
  return out->count;
}

uint32 b3SortPolygon(b3ClusterPolygonVertex *out, uint32 outCapacity,
                     const b3ClusterPolygonVertex *in, uint32 inCount,
                     b3Vec3 normal) {
  if (out == NULL || in == NULL || inCount == 0u || outCapacity < inCount) {
    return 0u;
  }

  for (uint32 i = 0u; i < inCount; ++i) {
    out[i] = in[i];
  }

  b3Vec3 A = out[0].position;
  for (uint32 i = 1u; i < inCount; ++i) {
    b3Vec3 B = out[i].position;
    for (uint32 j = i + 1u; j < inCount; ++j) {
      if (!cluster_is_ccw(A, B, out[j].position, normal)) {
        cluster_swap_vertices(&out[i], &out[j]);
      }
    }
  }
  return inCount;
}

uint32 b3ReducePolygon(b3ClusterPolygonVertex *out, uint32 outCapacity,
                       const b3ClusterPolygonVertex *in, uint32 inCount,
                       b3Vec3 normal, uint32 initialPoint) {
  if (out == NULL || in == NULL || inCount == 0u ||
      initialPoint >= inCount || inCount > B3_MAX_HULL_VERTICES ||
      outCapacity == 0u) {
    return 0u;
  }

  if (inCount <= B3_MAX_MANIFOLD_POINTS) {
    return b3SortPolygon(out, outCapacity, in, inCount, normal);
  }

  bool chosen[B3_MAX_HULL_VERTICES];
  for (uint32 i = 0u; i < inCount; ++i) {
    chosen[i] = false;
  }

  uint32 outCount = 0u;
  out[outCount++] = in[initialPoint];
  chosen[initialPoint] = true;

  uint32 index = 0u;
  scalar maxDistanceSq = -FLT_MAX;
  b3Vec3 A = out[0].position;
  for (uint32 i = 0u; i < inCount; ++i) {
    if (chosen[i]) {
      continue;
    }
    scalar distanceSq = b3Vec3_DistanceSquared(in[i].position, A);
    if (distanceSq > maxDistanceSq) {
      maxDistanceSq = distanceSq;
      index = i;
    }
  }
  if (maxDistanceSq < B3_EPSILON * B3_EPSILON || outCount >= outCapacity) {
    return outCount;
  }
  out[outCount++] = in[index];
  chosen[index] = true;

  index = 0u;
  scalar maxArea = -FLT_MAX;
  A = out[0].position;
  b3Vec3 B = out[1].position;
  for (uint32 i = 0u; i < inCount; ++i) {
    if (chosen[i]) {
      continue;
    }
    b3Vec3 C = in[i].position;
    b3Vec3 N = b3Vec3_Cross(b3Vec3_Sub(B, A), b3Vec3_Sub(C, A));
    scalar area = fabsf(b3Vec3_Dot(N, normal));
    if (area > maxArea) {
      maxArea = area;
      index = i;
    }
  }
  const scalar areaTol = 0.01f;
  if (maxArea < 2.0f * areaTol || outCount >= outCapacity) {
    return outCount;
  }
  b3Vec3 C = in[index].position;
  if (!cluster_is_ccw(A, B, C, normal)) {
    cluster_swap_vertices(&out[0], &out[1]);
  }
  out[outCount++] = in[index];
  chosen[index] = true;

  index = 0u;
  scalar minSignedArea = FLT_MAX;
  A = out[0].position;
  B = out[1].position;
  for (uint32 i = 0u; i < inCount; ++i) {
    if (chosen[i]) {
      continue;
    }
    b3Vec3 D = in[i].position;
    b3Vec3 N = b3Vec3_Cross(b3Vec3_Sub(B, A), b3Vec3_Sub(D, A));
    scalar signedArea = b3Vec3_Dot(N, normal);
    if (signedArea < minSignedArea) {
      minSignedArea = signedArea;
      index = i;
    }
  }
  if (fabsf(minSignedArea) >= 2.0f * areaTol && outCount < outCapacity) {
    out[outCount++] = in[index];
    chosen[index] = true;
  }

  b3ClusterPolygonVertex reduced[B3_MAX_MANIFOLD_POINTS];
  for (uint32 i = 0u; i < outCount; ++i) {
    reduced[i] = out[i];
  }
  return b3SortPolygon(out, outCapacity, reduced, outCount, normal);
}

void b3ClusterSolver_Init(b3ClusterSolver *solver) {
  if (solver != NULL) {
    memset(solver, 0, sizeof(*solver));
  }
}

bool b3ClusterSolver_AddObservation(b3ClusterSolver *solver,
                                    b3Observation observation) {
  if (solver == NULL ||
      solver->observationCount >= B3_MAX_CLUSTER_OBSERVATIONS) {
    return false;
  }
  solver->observations[solver->observationCount++] = observation;
  return true;
}

uint32 b3ClusterSolver_GetIterations(const b3ClusterSolver *solver) {
  return solver != NULL ? solver->iterations : 0u;
}

uint32 b3ClusterSolver_GetObservationCount(const b3ClusterSolver *solver) {
  return solver != NULL ? solver->observationCount : 0u;
}

const b3Observation *
b3ClusterSolver_GetObservations(const b3ClusterSolver *solver) {
  return solver != NULL ? solver->observations : NULL;
}

uint32 b3ClusterSolver_GetClusterCount(const b3ClusterSolver *solver) {
  return solver != NULL ? solver->clusterCount : 0u;
}

const b3Cluster *b3ClusterSolver_GetClusters(const b3ClusterSolver *solver) {
  return solver != NULL ? solver->clusters : NULL;
}

static uint32 cluster_solver_find_cluster(const b3ClusterSolver *solver,
                                          b3Vec3 point) {
  uint32 bestIndex = 0u;
  scalar bestValue = FLT_MAX;
  for (uint32 i = 0u; i < solver->clusterCount; ++i) {
    scalar metric = b3Vec3_DistanceSquared(point, solver->clusters[i].centroid);
    if (metric < bestValue) {
      bestValue = metric;
      bestIndex = i;
    }
  }
  return bestIndex;
}

static void cluster_solver_add_cluster(b3ClusterSolver *solver,
                                       b3Vec3 centroid) {
  if (solver->clusterCount == 0u) {
    solver->clusters[solver->clusterCount++].centroid = centroid;
    return;
  }

  uint32 bestIndex = cluster_solver_find_cluster(solver, centroid);
  b3Cluster *bestCluster = &solver->clusters[bestIndex];
  const scalar tolerance = 0.05f;
  if (b3Vec3_DistanceSquared(centroid, bestCluster->centroid) <=
      tolerance * tolerance) {
    bestCluster->centroid =
        b3Vec3_Normalize(b3Vec3_Add(bestCluster->centroid, centroid));
    return;
  }

  if (solver->clusterCount < B3_MAX_CLUSTER_OBSERVATIONS) {
    solver->clusters[solver->clusterCount++].centroid = centroid;
  }
}

static void cluster_solver_initialize_clusters(b3ClusterSolver *solver) {
  solver->clusterCount = 0u;
  if (solver->observationCount <= B3_MAX_MANIFOLDS) {
    for (uint32 i = 0u; i < solver->observationCount; ++i) {
      cluster_solver_add_cluster(solver, solver->observations[i].point);
    }
    return;
  }

  bool chosen[B3_MAX_CLUSTER_OBSERVATIONS];
  for (uint32 i = 0u; i < solver->observationCount; ++i) {
    chosen[i] = false;
  }

  cluster_solver_add_cluster(solver, solver->observations[0].point);
  chosen[0] = true;

  b3Vec3 A = solver->clusters[0].centroid;
  uint32 index = 0u;
  scalar maxDistanceSq = -FLT_MAX;
  for (uint32 i = 0u; i < solver->observationCount; ++i) {
    if (chosen[i]) {
      continue;
    }
    scalar distanceSq = b3Vec3_DistanceSquared(A, solver->observations[i].point);
    if (distanceSq > maxDistanceSq) {
      maxDistanceSq = distanceSq;
      index = i;
    }
  }
  cluster_solver_add_cluster(solver, solver->observations[index].point);
  chosen[index] = true;

  if (solver->clusterCount == 1u) {
    A = solver->clusters[0].centroid;
    index = 0u;
    maxDistanceSq = -FLT_MAX;
    for (uint32 i = 0u; i < solver->observationCount; ++i) {
      if (chosen[i]) {
        continue;
      }
      scalar distanceSq =
          b3Vec3_DistanceSquared(A, solver->observations[i].point);
      if (distanceSq > maxDistanceSq) {
        maxDistanceSq = distanceSq;
        index = i;
      }
    }
    cluster_solver_add_cluster(solver, solver->observations[index].point);
    chosen[index] = true;
    return;
  }

  A = solver->clusters[0].centroid;
  b3Vec3 B = solver->clusters[1].centroid;
  index = 0u;
  maxDistanceSq = -FLT_MAX;
  for (uint32 i = 0u; i < solver->observationCount; ++i) {
    if (chosen[i]) {
      continue;
    }
    b3Vec3 C = solver->observations[i].point;
    b3Vec3 Q = b3ClosestPointOnSegment(C, A, B);
    scalar distanceSq = b3Vec3_DistanceSquared(C, Q);
    if (distanceSq > maxDistanceSq) {
      maxDistanceSq = distanceSq;
      index = i;
    }
  }
  cluster_solver_add_cluster(solver, solver->observations[index].point);
  chosen[index] = true;
}

static void cluster_solver_move_observations(b3ClusterSolver *solver,
                                             uint32 fromCluster,
                                             uint32 toCluster) {
  for (uint32 i = 0u; i < solver->observationCount; ++i) {
    if (solver->observations[i].cluster == fromCluster) {
      solver->observations[i].cluster = toCluster;
    }
  }
}

void b3ClusterSolver_Solve(b3ClusterSolver *solver) {
  if (solver == NULL || solver->observationCount == 0u) {
    return;
  }

  cluster_solver_initialize_clusters(solver);
  const uint32 maxIterations = 10u;
  uint32 iter = 0u;
  while (iter < maxIterations) {
    for (uint32 i = 0u; i < solver->observationCount; ++i) {
      solver->observations[i].cluster =
          cluster_solver_find_cluster(solver, solver->observations[i].point);
    }

    for (uint32 i = 0u; i < solver->clusterCount; ++i) {
      b3Vec3 centroid = b3Vec3_Zero();
      uint32 pointCount = 0u;
      for (uint32 j = 0u; j < solver->observationCount; ++j) {
        if (solver->observations[j].cluster == i) {
          centroid = b3Vec3_Add(centroid, solver->observations[j].point);
          ++pointCount;
        }
      }
      if (pointCount > 0u) {
        solver->clusters[i].centroid =
            b3Vec3_DivScalar(centroid, (scalar)pointCount);
      }
    }

    ++iter;
  }
  solver->iterations = iter;

  b3Cluster usedClusters[B3_MAX_CLUSTER_OBSERVATIONS];
  uint32 usedCount = 0u;
  for (uint32 i = 0u; i < solver->clusterCount; ++i) {
    uint32 observationCount = 0u;
    for (uint32 j = 0u; j < solver->observationCount; ++j) {
      if (solver->observations[j].cluster == i) {
        ++observationCount;
      }
    }
    if (observationCount > 0u) {
      cluster_solver_move_observations(solver, i, usedCount);
      usedClusters[usedCount++] = solver->clusters[i];
    }
  }

  for (uint32 i = 0u; i < usedCount; ++i) {
    solver->clusters[i] = usedClusters[i];
  }
  solver->clusterCount = usedCount;
}

void b3ClusterSolver_Run(b3ClusterSolver *solver,
                         b3Manifold outManifolds[B3_MAX_MANIFOLDS],
                         uint32 *outCount, const b3Manifold *inManifolds,
                         uint32 inCount, b3Transform xfA, scalar radiusA,
                         b3Transform xfB, scalar radiusB) {
  b3ClusterSolver localSolver;
  if (solver == NULL) {
    solver = &localSolver;
  }
  b3ClusterSolver_Init(solver);
  if (outCount != NULL) {
    *outCount = 0u;
  }
  if (outManifolds == NULL || outCount == NULL || inManifolds == NULL) {
    return;
  }
  for (uint32 i = 0u; i < B3_MAX_MANIFOLDS; ++i) {
    b3Manifold_Clear(&outManifolds[i]);
  }

  for (uint32 i = 0u; i < inCount; ++i) {
    b3WorldManifold worldManifold;
    b3WorldManifold_Init(&worldManifold, &inManifolds[i], radiusA, xfA,
                         radiusB, xfB);
    for (uint32 j = 0u; j < worldManifold.pointCount; ++j) {
      b3Observation observation;
      observation.point = worldManifold.points[j].normal;
      observation.cluster = B3_NULL_CLUSTER;
      observation.manifold = i;
      observation.manifoldPoint = j;
      b3ClusterSolver_AddObservation(solver, observation);
    }
  }

  b3ClusterSolver_Solve(solver);
  for (uint32 i = 0u;
       i < solver->clusterCount && *outCount < B3_MAX_MANIFOLDS; ++i) {
    b3ClusterPolygonVertex polygon[B3_MAX_CLUSTER_OBSERVATIONS];
    uint32 polygonCount = 0u;
    b3Vec3 normal = b3Vec3_Zero();

    for (uint32 j = 0u; j < solver->observationCount; ++j) {
      b3Observation *observation = &solver->observations[j];
      if (observation->cluster != i ||
          observation->manifold >= inCount ||
          observation->manifoldPoint >= B3_MAX_MANIFOLD_POINTS ||
          polygonCount >= B3_MAX_CLUSTER_OBSERVATIONS) {
        continue;
      }
      b3WorldManifold worldManifold;
      b3WorldManifold_Init(&worldManifold,
                           &inManifolds[observation->manifold], radiusA, xfA,
                           radiusB, xfB);
      if (observation->manifoldPoint >= worldManifold.pointCount) {
        continue;
      }
      polygon[polygonCount].position =
          worldManifold.points[observation->manifoldPoint].point;
      polygon[polygonCount].clipIndex = j;
      ++polygonCount;
      normal = b3Vec3_Add(normal, observation->point);
    }
    if (polygonCount == 0u) {
      continue;
    }

    normal = b3Vec3_Normalize(normal);
    uint32 minIndex = 0u;
    scalar minSeparation = FLT_MAX;
    for (uint32 j = 0u; j < polygonCount; ++j) {
      const b3Observation *observation =
          &solver->observations[polygon[j].clipIndex];
      b3WorldManifold worldManifold;
      b3WorldManifold_Init(&worldManifold,
                           &inManifolds[observation->manifold], radiusA, xfA,
                           radiusB, xfB);
      scalar separation =
          worldManifold.points[observation->manifoldPoint].separation;
      if (separation < minSeparation) {
        minIndex = j;
        minSeparation = separation;
      }
      polygon[j].position =
          b3Vec3_Add(polygon[j].position, b3Vec3_MulScalar(normal, separation));
    }

    b3ClusterPolygonVertex reduced[B3_MAX_MANIFOLD_POINTS];
    uint32 reducedCount =
        b3ReducePolygon(reduced, B3_MAX_MANIFOLD_POINTS, polygon, polygonCount,
                        normal, minIndex);
    if (reducedCount == 0u) {
      continue;
    }

    b3Manifold *out = &outManifolds[*outCount];
    b3Manifold_Clear(out);
    for (uint32 j = 0u; j < reducedCount; ++j) {
      const b3Observation *observation =
          &solver->observations[reduced[j].clipIndex];
      if (observation->manifold < inCount &&
          observation->manifoldPoint <
              inManifolds[observation->manifold].pointCount) {
        out->points[out->pointCount++] =
            inManifolds[observation->manifold]
                .points[observation->manifoldPoint];
      }
    }
    if (out->pointCount > 0u) {
      ++*outCount;
    }
  }
}

#undef b3Vec2_Make
b3Vec2 b3Vec2_Make(scalar x, scalar y) { return B3_VEC2_MAKE_VALUE(x, y); }
#define b3Vec2_Make(x, y) B3_VEC2_MAKE_VALUE((x), (y))

b3Vec2 b3Vec2_Zero(void) { return b3Vec2_Make(0.0f, 0.0f); }

b3Vec2 b3Vec2_XAxis(void) { return b3Vec2_Make(1.0f, 0.0f); }

b3Vec2 b3Vec2_YAxis(void) { return b3Vec2_Make(0.0f, 1.0f); }

b3Vec2 b3Vec2_Negate(b3Vec2 v) { return b3Vec2_Make(-v.x, -v.y); }

b3Vec2 b3Vec2_Add(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Make(a.x + b.x, a.y + b.y);
}

b3Vec2 b3Vec2_Sub(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Make(a.x - b.x, a.y - b.y);
}

b3Vec2 b3Vec2_MulScalar(b3Vec2 v, scalar s) {
  return b3Vec2_Make(v.x * s, v.y * s);
}

b3Vec2 b3Vec2_DivScalar(b3Vec2 v, scalar s) {
  return b3Vec2_Make(v.x / s, v.y / s);
}

b3Vec2 b3Vec2_MulComp(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Make(a.x * b.x, a.y * b.y);
}

b3Vec2 b3Vec2_DivComp(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Make(a.x / b.x, a.y / b.y);
}

scalar b3Vec2_Dot(b3Vec2 a, b3Vec2 b) { return a.x * b.x + a.y * b.y; }

scalar b3Vec2_Cross(b3Vec2 a, b3Vec2 b) {
  return a.x * b.y - a.y * b.x;
}

b3Vec2 b3Vec2_CrossVec2Scalar(b3Vec2 v, scalar s) {
  return b3Vec2_Make(s * v.y, -s * v.x);
}

b3Vec2 b3Vec2_CrossScalarVec2(scalar s, b3Vec2 v) {
  return b3Vec2_Make(-s * v.y, s * v.x);
}

scalar b3Vec2_Det(b3Vec2 a, b3Vec2 b) { return b3Vec2_Cross(a, b); }

scalar b3Vec2_Length(b3Vec2 v) { return sqrtf(b3Vec2_Dot(v, v)); }

scalar b3Vec2_LengthSquared(b3Vec2 v) { return b3Vec2_Dot(v, v); }

b3Vec2 b3Vec2_Normalize(b3Vec2 v) {
  scalar length = b3Vec2_Length(v);
  if (length > B3_EPSILON) {
    return b3Vec2_DivScalar(v, length);
  }
  return v;
}

scalar b3Vec2_Distance(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Length(b3Vec2_Sub(a, b));
}

scalar b3Vec2_DistanceSquared(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_LengthSquared(b3Vec2_Sub(a, b));
}

b3Vec2 b3Vec2_Min(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Make(fminf(a.x, b.x), fminf(a.y, b.y));
}

b3Vec2 b3Vec2_Max(b3Vec2 a, b3Vec2 b) {
  return b3Vec2_Make(fmaxf(a.x, b.x), fmaxf(a.y, b.y));
}

b3Vec2 b3Vec2_Abs(b3Vec2 v) {
  return b3Vec2_Make(fabsf(v.x), fabsf(v.y));
}

b3Vec2 b3Vec2_Perp(b3Vec2 v) { return b3Vec2_Make(-v.y, v.x); }

b3Color b3Color_Make(scalar r, scalar g, scalar b, scalar a) {
  b3Color color;
  color.r = r;
  color.g = g;
  color.b = b;
  color.a = a;
  return color;
}

void b3Color_Set(b3Color *color, scalar r, scalar g, scalar b, scalar a) {
  if (color == NULL) {
    return;
  }
  color->r = r;
  color->g = g;
  color->b = b;
  color->a = a;
}

#undef b3Mat22_Make
b3Mat22 b3Mat22_Make(b3Vec2 x, b3Vec2 y) {
  return B3_MAT22_MAKE_VALUE(x, y);
}
#define b3Mat22_Make(x, y) B3_MAT22_MAKE_VALUE((x), (y))

b3Mat22 b3Mat22_Zero(void) {
  return b3Mat22_Make(b3Vec2_Zero(), b3Vec2_Zero());
}

b3Mat22 b3Mat22_Identity(void) {
  return b3Mat22_Make(b3Vec2_XAxis(), b3Vec2_YAxis());
}

b3Mat22 b3Mat22_UniformDiagonal(scalar s) {
  return b3Mat22_Diagonal(s, s);
}

b3Mat22 b3Mat22_Diagonal(scalar x, scalar y) {
  return b3Mat22_Make(b3Vec2_Make(x, 0.0f), b3Vec2_Make(0.0f, y));
}

b3Mat22 b3Mat22Diagonal(scalar x, scalar y) {
  return b3Mat22_Diagonal(x, y);
}

b3Mat22 b3Mat22_Add(b3Mat22 a, b3Mat22 b) {
  return b3Mat22_Make(b3Vec2_Add(a.x, b.x), b3Vec2_Add(a.y, b.y));
}

b3Mat22 b3Mat22_Sub(b3Mat22 a, b3Mat22 b) {
  return b3Mat22_Make(b3Vec2_Sub(a.x, b.x), b3Vec2_Sub(a.y, b.y));
}

b3Mat22 b3Mat22_Negate(b3Mat22 m) {
  return b3Mat22_MulScalar(m, -1.0f);
}

b3Mat22 b3Mat22_MulScalar(b3Mat22 m, scalar s) {
  return b3Mat22_Make(b3Vec2_MulScalar(m.x, s), b3Vec2_MulScalar(m.y, s));
}

b3Vec2 b3Mat22_MulVec2(b3Mat22 m, b3Vec2 v) {
  return b3Vec2_Add(b3Vec2_MulScalar(m.x, v.x),
                    b3Vec2_MulScalar(m.y, v.y));
}

b3Mat22 b3Mat22_Mul(b3Mat22 a, b3Mat22 b) {
  return b3Mat22_Make(b3Mat22_MulVec2(a, b.x), b3Mat22_MulVec2(a, b.y));
}

b3Vec2 b3Mat22_MulTVec2(b3Mat22 m, b3Vec2 v) {
  return b3Vec2_Make(b3Vec2_Dot(m.x, v), b3Vec2_Dot(m.y, v));
}

b3Mat22 b3Mat22_MulT(b3Mat22 a, b3Mat22 b) {
  return b3Mat22_Make(b3Mat22_MulTVec2(a, b.x),
                      b3Mat22_MulTVec2(a, b.y));
}

b3Mat22 b3Mat22_Abs(b3Mat22 m) {
  return b3Mat22_Make(b3Vec2_Abs(m.x), b3Vec2_Abs(m.y));
}

b3Mat22 b3Mat22_Transpose(b3Mat22 m) {
  return b3Mat22_Make(b3Vec2_Make(m.x.x, m.y.x),
                      b3Vec2_Make(m.x.y, m.y.y));
}

b3Mat22 b3Mat22_Adjugate(b3Mat22 m) {
  return b3Mat22_Make(b3Vec2_Make(m.y.y, -m.x.y),
                      b3Vec2_Make(-m.y.x, m.x.x));
}

b3Vec2 b3Mat22_Solve(b3Mat22 m, b3Vec2 b) {
  scalar a11 = m.x.x;
  scalar a12 = m.y.x;
  scalar a21 = m.x.y;
  scalar a22 = m.y.y;

  scalar det = a11 * a22 - a12 * a21;
  if (det != 0.0f) {
    det = 1.0f / det;
  }

  return b3Vec2_Make(det * (a22 * b.x - a12 * b.y),
                     det * (a11 * b.y - a21 * b.x));
}

b3Mat22 b3Mat22_Inverse(b3Mat22 m) {
  scalar det = b3Vec2_Det(m.x, m.y);
  if (det != 0.0f) {
    det = 1.0f / det;
  }
  return b3Mat22_MulScalar(b3Mat22_Adjugate(m), det);
}

b3Mat22 b3Mat22_Outer(b3Vec2 a, b3Vec2 b) {
  return b3Mat22_Make(b3Vec2_MulScalar(a, b.x),
                      b3Vec2_MulScalar(a, b.y));
}

