b3Vec3 b3Vec3_Negate(b3Vec3 v) { return vec3_mul(v, -1.0f); }

b3Vec3 b3Vec3_Add(b3Vec3 a, b3Vec3 b) { return vec3_add(a, b); }

b3Vec3 b3Vec3_Sub(b3Vec3 a, b3Vec3 b) { return vec3_sub(a, b); }

