bool b3DebugPoints_Init(b3DebugPoints *points, uint32 capacity) {
  if (points == NULL) {
    return false;
  }
  memset(points, 0, sizeof(*points));
  points->capacity = capacity;
  points->drawEnabled = true;
  if (capacity == 0u) {
    return true;
  }
  points->points = (b3DebugPoint *)b3Alloc(capacity * sizeof(*points->points));
  if (points->points == NULL) {
    points->capacity = 0u;
    points->drawEnabled = false;
    return false;
  }
  return true;
}

void b3DebugPoints_Destroy(b3DebugPoints *points) {
  if (points == NULL) {
    return;
  }
  b3Free(points->points);
  memset(points, 0, sizeof(*points));
}

void b3DebugPoints_Draw(b3DebugPoints *points, b3Vec3 position, scalar size,
                        b3Color color, bool depthEnabled) {
  if (points == NULL || !points->drawEnabled || points->capacity == 0u) {
    return;
  }
  if (points->count == points->capacity) {
    b3DebugPoints_Flush(points);
  }
  if (points->count == points->capacity) {
    return;
  }
  b3DebugPoint point;
  point.position = position;
  point.color = color;
  point.size = size;
  point.depthEnabled = depthEnabled;
  points->points[points->count++] = point;
}

void b3DebugPoints_Flush(b3DebugPoints *points) {
  if (points == NULL) {
    return;
  }
  b3DebugPointsRenderer *renderer = points->renderer;
  if (renderer == NULL) {
    points->count = 0u;
    return;
  }
  if (renderer->AddPoint != NULL) {
    for (uint32 i = 0u; i < points->count; ++i) {
      b3DebugPoint point = points->points[i];
      if (point.depthEnabled) {
        renderer->AddPoint(renderer->context, point.position, point.color,
                           point.size);
      }
    }
  }
  if (renderer->FlushPoints != NULL) {
    renderer->FlushPoints(renderer->context, true);
  }
  if (renderer->AddPoint != NULL) {
    for (uint32 i = 0u; i < points->count; ++i) {
      b3DebugPoint point = points->points[i];
      if (!point.depthEnabled) {
        renderer->AddPoint(renderer->context, point.position, point.color,
                           point.size);
      }
    }
  }
  if (renderer->FlushPoints != NULL) {
    renderer->FlushPoints(renderer->context, false);
  }
  points->count = 0u;
}

void b3DebugPoints_SetRenderer(b3DebugPoints *points,
                               b3DebugPointsRenderer *renderer) {
  if (points != NULL) {
    points->renderer = renderer;
  }
}

b3DebugPointsRenderer *b3DebugPoints_GetRenderer(b3DebugPoints *points) {
  return points != NULL ? points->renderer : NULL;
}

