static uint32 debug_mesh_vertex_index(uint32 widthSegments, uint32 i,
                                      uint32 j) {
  return i * (widthSegments + 1u) + j;
}

bool b3SphereMesh_Init(b3SphereMesh *mesh, uint32 heightSegments,
                       uint32 widthSegments) {
  if (mesh == NULL || heightSegments == 0u || widthSegments == 0u) {
    return false;
  }
  memset(mesh, 0, sizeof(*mesh));
  mesh->heightSegments = heightSegments;
  mesh->widthSegments = widthSegments;
  mesh->vertexCount = (heightSegments + 1u) * (widthSegments + 1u);
  mesh->indexCount = 3u * 2u * heightSegments * widthSegments;
  mesh->vertices = (b3Vec3 *)b3Alloc(mesh->vertexCount * sizeof(*mesh->vertices));
  mesh->indices = (uint32 *)b3Alloc(mesh->indexCount * sizeof(*mesh->indices));
  if (mesh->vertices == NULL || mesh->indices == NULL) {
    b3SphereMesh_Destroy(mesh);
    return false;
  }

  scalar thetaInc = B3_PI / (scalar)heightSegments;
  scalar phiInc = 2.0f * B3_PI / (scalar)widthSegments;
  for (uint32 i = 0u; i <= heightSegments; ++i) {
    scalar theta = (scalar)i * thetaInc;
    scalar cosTheta = cosf(theta);
    scalar sinTheta = sinf(theta);
    for (uint32 j = 0u; j <= widthSegments; ++j) {
      scalar phi = (scalar)j * phiInc;
      scalar cosPhi = cosf(phi);
      scalar sinPhi = sinf(phi);
      mesh->vertices[b3SphereMesh_GetVertex(mesh, i, j)] =
          b3Vec3_Make(sinTheta * sinPhi, cosTheta, sinTheta * cosPhi);
    }
  }

  uint32 index = 0u;
  for (uint32 i = 0u; i < heightSegments; ++i) {
    for (uint32 j = 0u; j < widthSegments; ++j) {
      uint32 v1 = b3SphereMesh_GetVertex(mesh, i, j);
      uint32 v2 = b3SphereMesh_GetVertex(mesh, i + 1u, j);
      uint32 v3 = b3SphereMesh_GetVertex(mesh, i + 1u, j + 1u);
      uint32 v4 = b3SphereMesh_GetVertex(mesh, i, j + 1u);
      mesh->indices[index++] = v1;
      mesh->indices[index++] = v2;
      mesh->indices[index++] = v3;
      mesh->indices[index++] = v3;
      mesh->indices[index++] = v4;
      mesh->indices[index++] = v1;
    }
  }
  return index == mesh->indexCount;
}

void b3SphereMesh_Destroy(b3SphereMesh *mesh) {
  if (mesh == NULL) {
    return;
  }
  b3Free(mesh->vertices);
  b3Free(mesh->indices);
  memset(mesh, 0, sizeof(*mesh));
}

uint32 b3SphereMesh_GetVertex(const b3SphereMesh *mesh, uint32 i, uint32 j) {
  if (mesh == NULL || i > mesh->heightSegments || j > mesh->widthSegments) {
    return B3_MAX_U32;
  }
  return debug_mesh_vertex_index(mesh->widthSegments, i, j);
}

bool b3CylinderMesh_Init(b3CylinderMesh *mesh, uint32 heightSegments,
                         uint32 widthSegments) {
  if (mesh == NULL || heightSegments == 0u || widthSegments < 2u) {
    return false;
  }
  memset(mesh, 0, sizeof(*mesh));
  mesh->heightSegments = heightSegments;
  mesh->widthSegments = widthSegments;
  mesh->vertexCount = (heightSegments + 1u) * (widthSegments + 1u);
  mesh->indexCount =
      3u * 2u * heightSegments * widthSegments + 3u * 2u * (widthSegments - 1u);
  mesh->vertices = (b3Vec3 *)b3Alloc(mesh->vertexCount * sizeof(*mesh->vertices));
  mesh->indices = (uint32 *)b3Alloc(mesh->indexCount * sizeof(*mesh->indices));
  if (mesh->vertices == NULL || mesh->indices == NULL) {
    b3CylinderMesh_Destroy(mesh);
    return false;
  }

  scalar phiInc = 2.0f * B3_PI / (scalar)widthSegments;
  scalar yInc = 1.0f / (scalar)heightSegments;
  for (uint32 i = 0u; i <= heightSegments; ++i) {
    scalar y = (scalar)i * yInc;
    for (uint32 j = 0u; j <= widthSegments; ++j) {
      scalar phi = (scalar)j * phiInc;
      mesh->vertices[b3CylinderMesh_GetVertex(mesh, i, j)] =
          b3Vec3_Make(cosf(phi), y - 0.5f, sinf(phi));
    }
  }

  uint32 index = 0u;
  for (uint32 i = 0u; i < heightSegments; ++i) {
    for (uint32 j = 0u; j < widthSegments; ++j) {
      uint32 v1 = b3CylinderMesh_GetVertex(mesh, i, j);
      uint32 v2 = b3CylinderMesh_GetVertex(mesh, i + 1u, j);
      uint32 v3 = b3CylinderMesh_GetVertex(mesh, i + 1u, j + 1u);
      uint32 v4 = b3CylinderMesh_GetVertex(mesh, i, j + 1u);
      mesh->indices[index++] = v1;
      mesh->indices[index++] = v2;
      mesh->indices[index++] = v3;
      mesh->indices[index++] = v3;
      mesh->indices[index++] = v4;
      mesh->indices[index++] = v1;
    }
  }
  for (uint32 i2 = 1u; i2 < widthSegments; ++i2) {
    uint32 i3 = i2 + 1u;
    mesh->indices[index++] = b3CylinderMesh_GetVertex(mesh, 0u, 0u);
    mesh->indices[index++] = b3CylinderMesh_GetVertex(mesh, 0u, i2);
    mesh->indices[index++] = b3CylinderMesh_GetVertex(mesh, 0u, i3);
  }
  for (uint32 i2 = 1u; i2 < widthSegments; ++i2) {
    uint32 i3 = i2 + 1u;
    mesh->indices[index++] =
        b3CylinderMesh_GetVertex(mesh, heightSegments, i3);
    mesh->indices[index++] =
        b3CylinderMesh_GetVertex(mesh, heightSegments, i2);
    mesh->indices[index++] =
        b3CylinderMesh_GetVertex(mesh, heightSegments, 0u);
  }
  return index == mesh->indexCount;
}

void b3CylinderMesh_Destroy(b3CylinderMesh *mesh) {
  if (mesh == NULL) {
    return;
  }
  b3Free(mesh->vertices);
  b3Free(mesh->indices);
  memset(mesh, 0, sizeof(*mesh));
}

uint32 b3CylinderMesh_GetVertex(const b3CylinderMesh *mesh, uint32 i,
                                uint32 j) {
  if (mesh == NULL || i > mesh->heightSegments || j > mesh->widthSegments) {
    return B3_MAX_U32;
  }
  return debug_mesh_vertex_index(mesh->widthSegments, i, j);
}

void b3Camera_Default(b3Camera *camera) {
  if (camera == NULL) {
    return;
  }
  camera->width = 1280.0f;
  camera->height = 720.0f;
  camera->zNear = 1.0f;
  camera->zFar = 1000.0f;
  camera->yFov = 0.25f * B3_PI;
  camera->radius = 1.0f;
  camera->polarAngle = 0.0f;
  camera->azimuthalAngle = 0.0f;
  camera->center = b3Vec3_Zero();
}

void b3Camera_SetWidth(b3Camera *camera, scalar width) {
  if (camera != NULL && width > 0.0f) {
    camera->width = width;
  }
}

scalar b3Camera_GetWidth(const b3Camera *camera) {
  return camera != NULL ? camera->width : 0.0f;
}

void b3Camera_SetHeight(b3Camera *camera, scalar height) {
  if (camera != NULL && height > 0.0f) {
    camera->height = height;
  }
}

scalar b3Camera_GetHeight(const b3Camera *camera) {
  return camera != NULL ? camera->height : 0.0f;
}

void b3Camera_SetDistances(b3Camera *camera, scalar zNear, scalar zFar) {
  if (camera != NULL && zNear >= 0.0f && zFar > 0.0f && zNear < zFar) {
    camera->zNear = zNear;
    camera->zFar = zFar;
  }
}

scalar b3Camera_GetZNear(const b3Camera *camera) {
  return camera != NULL ? camera->zNear : 0.0f;
}

scalar b3Camera_GetZFar(const b3Camera *camera) {
  return camera != NULL ? camera->zFar : 0.0f;
}

void b3Camera_SetYFOV(b3Camera *camera, scalar yFov) {
  if (camera != NULL && yFov > 0.0f && yFov < B3_PI) {
    camera->yFov = yFov;
  }
}

scalar b3Camera_GetYFOV(const b3Camera *camera) {
  return camera != NULL ? camera->yFov : 0.0f;
}

void b3Camera_SetRadius(b3Camera *camera, scalar radius) {
  if (camera != NULL && radius >= 0.0f) {
    camera->radius = radius;
  }
}

scalar b3Camera_GetRadius(const b3Camera *camera) {
  return camera != NULL ? camera->radius : 0.0f;
}

void b3Camera_AddRadius(b3Camera *camera, scalar distance) {
  if (camera == NULL) {
    return;
  }
  camera->radius = b3Max(0.0f, camera->radius + distance);
}

void b3Camera_SetPolarAngle(b3Camera *camera, scalar angle) {
  if (camera != NULL && angle >= 0.0f && angle <= B3_PI) {
    camera->polarAngle = angle;
  }
}

scalar b3Camera_GetPolarAngle(const b3Camera *camera) {
  return camera != NULL ? camera->polarAngle : 0.0f;
}

void b3Camera_AddPolarAngle(b3Camera *camera, scalar angle) {
  if (camera != NULL) {
    camera->polarAngle = b3Clamp(camera->polarAngle + angle, 0.0f, B3_PI);
  }
}

void b3Camera_SetAzimuthalAngle(b3Camera *camera, scalar angle) {
  if (camera != NULL && angle >= 0.0f && angle <= 2.0f * B3_PI) {
    camera->azimuthalAngle = angle;
  }
}

scalar b3Camera_GetAzimuthalAngle(const b3Camera *camera) {
  return camera != NULL ? camera->azimuthalAngle : 0.0f;
}

void b3Camera_AddAzimuthalAngle(b3Camera *camera, scalar angle) {
  if (camera == NULL) {
    return;
  }
  scalar twoPi = 2.0f * B3_PI;
  camera->azimuthalAngle += angle;
  camera->azimuthalAngle -= floorf(camera->azimuthalAngle / twoPi) * twoPi;
}

void b3Camera_SetCenter(b3Camera *camera, b3Vec3 center) {
  if (camera != NULL) {
    camera->center = center;
  }
}

b3Vec3 b3Camera_GetCenter(const b3Camera *camera) {
  return camera != NULL ? camera->center : b3Vec3_Zero();
}

void b3Camera_TranslateXAxis(b3Camera *camera, scalar distance) {
  if (camera != NULL) {
    camera->center = b3Vec3_Add(
        camera->center, b3Vec3_MulScalar(b3Camera_BuildXAxis(camera), distance));
  }
}

void b3Camera_TranslateYAxis(b3Camera *camera, scalar distance) {
  if (camera != NULL) {
    camera->center = b3Vec3_Add(
        camera->center, b3Vec3_MulScalar(b3Camera_BuildYAxis(camera), distance));
  }
}

void b3Camera_TranslateZAxis(b3Camera *camera, scalar distance) {
  if (camera != NULL) {
    camera->center = b3Vec3_Add(
        camera->center, b3Vec3_MulScalar(b3Camera_BuildZAxis(camera), distance));
  }
}

static scalar camera_azimuthal_angle(scalar x, scalar y) {
  if (x > 0.0f && y > 0.0f) {
    return atanf(y / x);
  }
  if (x < 0.0f && y > 0.0f) {
    return 0.5f * B3_PI + atanf(-x / y);
  }
  if (x < 0.0f && y < 0.0f) {
    return B3_PI + atanf(y / x);
  }
  if (x > 0.0f && y < 0.0f) {
    return B3_PI + 0.5f * B3_PI + atanf(-x / y);
  }
  if (x == 0.0f && y > 0.0f) {
    return 0.5f * B3_PI;
  }
  if (x == 0.0f && y < 0.0f) {
    return B3_PI + 0.5f * B3_PI;
  }
  if (x > 0.0f && y == 0.0f) {
    return 0.0f;
  }
  if (x < 0.0f && y == 0.0f) {
    return B3_PI;
  }
  return 0.0f;
}

static scalar camera_polar_angle(scalar x, scalar y) {
  if (x > 0.0f && y > 0.0f) {
    return atanf(y / x);
  }
  if (x < 0.0f && y > 0.0f) {
    return 0.5f * B3_PI + atanf(-x / y);
  }
  if (x < 0.0f && y < 0.0f) {
    return atanf(x / y);
  }
  if (x > 0.0f && y < 0.0f) {
    return atanf(-y / x);
  }
  if (x == 0.0f && y != 0.0f) {
    return 0.5f * B3_PI;
  }
  if (y == 0.0f && x > 0.0f) {
    return 0.0f;
  }
  if (y == 0.0f && x < 0.0f) {
    return B3_PI;
  }
  return 0.0f;
}

void b3Camera_LookAt(b3Camera *camera, b3Vec3 eyePosition,
                     b3Vec3 targetPosition) {
  if (camera != NULL) {
    b3Camera_SetPosition(camera, eyePosition);
    camera->center = targetPosition;
  }
}

void b3Camera_SetPosition(b3Camera *camera, b3Vec3 position) {
  if (camera == NULL) {
    return;
  }
  scalar r = b3Sqrt(position.x * position.x + position.y * position.y +
                    position.z * position.z);
  scalar phi = camera_azimuthal_angle(position.z, position.x);
  scalar s = b3Sqrt(position.z * position.z + position.x * position.x);
  scalar theta = camera_polar_angle(position.y, s);
  camera->radius = r;
  camera->azimuthalAngle = phi;
  camera->polarAngle = theta;
}

b3Vec3 b3Camera_BuildPosition(const b3Camera *camera) {
  if (camera == NULL) {
    return b3Vec3_Zero();
  }
  return b3Vec3_Add(
      camera->center,
      b3Vec3_MulScalar(b3Camera_BuildZAxis(camera), camera->radius));
}

b3Vec3 b3Camera_BuildXAxis(const b3Camera *camera) {
  scalar phi = camera != NULL ? camera->azimuthalAngle : 0.0f;
  return b3Vec3_Make(cosf(phi), 0.0f, -sinf(phi));
}

b3Vec3 b3Camera_BuildYAxis(const b3Camera *camera) {
  scalar theta = camera != NULL ? camera->polarAngle : 0.0f;
  scalar phi = camera != NULL ? camera->azimuthalAngle : 0.0f;
  return b3Vec3_Make(-cosf(theta) * sinf(phi), sinf(theta),
                     -cosf(theta) * cosf(phi));
}

b3Vec3 b3Camera_BuildZAxis(const b3Camera *camera) {
  scalar theta = camera != NULL ? camera->polarAngle : 0.0f;
  scalar phi = camera != NULL ? camera->azimuthalAngle : 0.0f;
  return b3Vec3_Make(sinf(theta) * sinf(phi), cosf(theta),
                     sinf(theta) * cosf(phi));
}

b3Mat33 b3Camera_BuildRotation(const b3Camera *camera) {
  return b3Mat33_Make(b3Camera_BuildXAxis(camera), b3Camera_BuildYAxis(camera),
                      b3Camera_BuildZAxis(camera));
}

b3Mat44 b3Camera_BuildViewMatrix(const b3Camera *camera) {
  b3Vec3 translation = b3Camera_BuildPosition(camera);
  b3Mat33 rotation = b3Camera_BuildRotation(camera);
  b3Mat33 R = b3Mat33_Transpose(rotation);
  b3Vec3 t = b3Vec3_Negate(b3Mat33_MulVec3(R, translation));
  return b3Mat44_Make(b3Vec4_Make(R.x.x, R.x.y, R.x.z, 0.0f),
                      b3Vec4_Make(R.y.x, R.y.y, R.y.z, 0.0f),
                      b3Vec4_Make(R.z.x, R.z.y, R.z.z, 0.0f),
                      b3Vec4_Make(t.x, t.y, t.z, 1.0f));
}

b3Mat44 b3Camera_BuildProjectionMatrix(const b3Camera *camera) {
  if (camera == NULL || camera->height <= 0.0f) {
    return b3Mat44_Identity();
  }
  scalar ratio = camera->width / camera->height;
  scalar t = tanf(0.5f * camera->yFov);
  scalar sx = 1.0f / (ratio * t);
  scalar sy = 1.0f / t;
  scalar sz = (camera->zNear + camera->zFar) / (camera->zNear - camera->zFar);
  scalar tz = (camera->zFar * camera->zNear) / (camera->zNear - camera->zFar);
  return b3Mat44_Make(b3Vec4_Make(sx, 0.0f, 0.0f, 0.0f),
                      b3Vec4_Make(0.0f, sy, 0.0f, 0.0f),
                      b3Vec4_Make(0.0f, 0.0f, sz, -1.0f),
                      b3Vec4_Make(0.0f, 0.0f, tz, 0.0f));
}

b3Vec2 b3Camera_ConvertWorldToScreen(const b3Camera *camera, b3Vec3 point) {
  if (camera == NULL) {
    return b3Vec2_Zero();
  }
  b3Mat44 PV = b3Mat44_Mul(b3Camera_BuildProjectionMatrix(camera),
                           b3Camera_BuildViewMatrix(camera));
  b3Vec4 projected = b3Mat44_MulVec4(
      PV, b3Vec4_Make(point.x, point.y, point.z, 1.0f));
  scalar invW = projected.w != 0.0f ? 1.0f / projected.w : 1.0f;
  b3Vec3 normalized =
      b3Vec3_Make(projected.x * invW, projected.y * invW, projected.z * invW);
  scalar u = 0.5f * (normalized.x + 1.0f);
  scalar v = 0.5f * (normalized.y + 1.0f);
  return b3Vec2_Make(u * camera->width, (1.0f - v) * camera->height);
}

b3Vec3 b3Camera_ConvertScreenToWorld(const b3Camera *camera, b3Vec2 point) {
  if (camera == NULL || camera->width <= 0.0f || camera->height <= 0.0f) {
    return b3Vec3_Zero();
  }
  scalar t = tanf(0.5f * camera->yFov);
  scalar ratio = camera->width / camera->height;
  b3Vec3 view = b3Vec3_Make(2.0f * ratio * point.x / camera->width - ratio,
                            -2.0f * point.y / camera->height + 1.0f,
                            -1.0f / t);
  return b3Vec3_Normalize(b3Mat33_MulVec3(b3Camera_BuildRotation(camera), view));
}

b3Vec3 b3MakeVec3(uint32 vertexStride, const void *vertexBase, uint32 vtx) {
  if (vertexBase == NULL || vertexStride < 3u * (uint32)sizeof(scalar)) {
    return b3Vec3_Zero();
  }
  const uint8_t *base = (const uint8_t *)vertexBase;
  const scalar *values =
      (const scalar *)(const void *)(base + vertexStride * vtx);
  return b3Vec3_Make(values[0], values[1], values[2]);
}

void b3DrawPoint(b3DebugDrawData *data, b3Vec3 point, scalar size,
                 b3Color color, bool depthEnabled) {
  (void)depthEnabled;
  if (data != NULL && data->DrawPoint != NULL) {
    data->DrawPoint(data->context, point, size, color);
  }
}

void b3DrawSegment(b3DebugDrawData *data, b3Vec3 point1, b3Vec3 point2,
                   b3Color color, bool depthEnabled) {
  (void)depthEnabled;
  if (data != NULL && data->DrawSegment != NULL) {
    data->DrawSegment(data->context, point1, point2, color);
  }
}

void b3DrawTriangle(b3DebugDrawData *data, b3Vec3 point1, b3Vec3 point2,
                    b3Vec3 point3, b3Color color, bool depthEnabled) {
  (void)depthEnabled;
  if (data == NULL) {
    return;
  }
  if (data->DrawTriangle != NULL) {
    data->DrawTriangle(data->context, point1, point2, point3, color);
    return;
  }
  b3DrawSegment(data, point1, point2, color, depthEnabled);
  b3DrawSegment(data, point2, point3, color, depthEnabled);
  b3DrawSegment(data, point3, point1, color, depthEnabled);
}

void b3DrawSolidTriangle(b3DebugDrawData *data, b3Vec3 normal, b3Vec3 point1,
                         b3Vec3 point2, b3Vec3 point3, b3Color color,
                         bool depthEnabled) {
  (void)depthEnabled;
  if (data != NULL && data->DrawSolidTriangle != NULL) {
    data->DrawSolidTriangle(data->context, normal, point1, point2, point3,
                            color);
  }
}

void b3DrawPolygon(b3DebugDrawData *data, const void *vertices,
                   uint32 vertexStride, uint32 count, b3Color color,
                   bool depthEnabled) {
  if (data == NULL || vertices == NULL || count == 0u) {
    return;
  }
  if (data->DrawPolygon != NULL && vertexStride == (uint32)sizeof(b3Vec3)) {
    data->DrawPolygon(data->context, (const b3Vec3 *)vertices, count, color);
    return;
  }
  b3Vec3 point1 = b3MakeVec3(vertexStride, vertices, count - 1u);
  for (uint32 i = 0u; i < count; ++i) {
    b3Vec3 point2 = b3MakeVec3(vertexStride, vertices, i);
    b3DrawSegment(data, point1, point2, color, depthEnabled);
    point1 = point2;
  }
}

void b3DrawSolidPolygon(b3DebugDrawData *data, b3Vec3 normal,
                        const void *vertices, uint32 vertexStride,
                        uint32 count, b3Color color, bool depthEnabled) {
  if (data == NULL || vertices == NULL || count < 3u) {
    return;
  }
  if (data->DrawSolidPolygon != NULL &&
      vertexStride == (uint32)sizeof(b3Vec3)) {
    data->DrawSolidPolygon(data->context, normal, (const b3Vec3 *)vertices,
                           count, color);
    return;
  }
  b3Vec3 point1 = b3MakeVec3(vertexStride, vertices, 0u);
  for (uint32 i = 1u; i + 1u < count; ++i) {
    b3DrawSolidTriangle(data, normal, point1,
                        b3MakeVec3(vertexStride, vertices, i),
                        b3MakeVec3(vertexStride, vertices, i + 1u), color,
                        depthEnabled);
  }
}

