void b3DrawCapsule(b3DebugDrawData *data, b3Vec3 point1, b3Vec3 point2,
                   scalar radius, b3Color color, bool depthEnabled) {
  if (data == NULL) {
    return;
  }
  if (data->DrawCapsule != NULL) {
    data->DrawCapsule(data->context, point1, point2, radius, color);
    return;
  }
  b3DrawSphere(data, point1, radius, color, depthEnabled);
  b3Vec3 delta = b3Vec3_Sub(point1, point2);
  scalar height = b3Vec3_Length(delta);
  if (height > B3_EPSILON) {
    b3Vec3 axis = b3Vec3_DivScalar(delta, height);
    b3Vec3 center = b3Vec3_MulScalar(b3Vec3_Add(point1, point2), 0.5f);
    b3DrawCylinder(data, axis, center, radius, height, color, depthEnabled);
    b3DrawSphere(data, point2, radius, color, depthEnabled);
  }
}

void b3DrawSolidCapsule(b3DebugDrawData *data, b3Vec3 axis, b3Vec3 point1,
                        b3Vec3 point2, scalar radius, b3Color color,
                        bool depthEnabled) {
  if (data == NULL) {
    return;
  }
  if (data->DrawSolidCapsule != NULL) {
    data->DrawSolidCapsule(data->context, axis, point1, point2, radius, color);
    return;
  }
  b3DrawSolidSphere(data, axis, point1, radius, color, depthEnabled);
  b3Vec3 delta = b3Vec3_Sub(point1, point2);
  scalar height = b3Vec3_Length(delta);
  if (height > B3_EPSILON) {
    b3Vec3 capsuleAxis = b3Vec3_DivScalar(delta, height);
    b3Vec3 center = b3Vec3_MulScalar(b3Vec3_Add(point1, point2), 0.5f);
    b3DrawSolidCylinder(data, capsuleAxis, center, radius, height, color,
                        depthEnabled);
    b3DrawSolidSphere(data, axis, point2, radius, color, depthEnabled);
  }
}

void b3DrawAABB(b3DebugDrawData *data, b3Vec3 lowerBound, b3Vec3 upperBound,
                b3Color color, bool depthEnabled) {
  if (data == NULL) {
    return;
  }
  if (data->DrawAABB != NULL) {
    b3AABB aabb;
    aabb.lowerBound = lowerBound;
    aabb.upperBound = upperBound;
    data->DrawAABB(data->context, aabb, color);
    return;
  }

  b3Vec3 vertices[8];
  vertices[0] = lowerBound;
  vertices[1] = b3Vec3_Make(lowerBound.x, upperBound.y, lowerBound.z);
  vertices[2] = b3Vec3_Make(upperBound.x, upperBound.y, lowerBound.z);
  vertices[3] = b3Vec3_Make(upperBound.x, lowerBound.y, lowerBound.z);
  vertices[4] = upperBound;
  vertices[5] = b3Vec3_Make(upperBound.x, lowerBound.y, upperBound.z);
  vertices[6] = b3Vec3_Make(lowerBound.x, lowerBound.y, upperBound.z);
  vertices[7] = b3Vec3_Make(lowerBound.x, upperBound.y, upperBound.z);
  b3DrawSegment(data, vertices[0], vertices[1], color, depthEnabled);
  b3DrawSegment(data, vertices[1], vertices[2], color, depthEnabled);
  b3DrawSegment(data, vertices[2], vertices[3], color, depthEnabled);
  b3DrawSegment(data, vertices[3], vertices[0], color, depthEnabled);
  b3DrawSegment(data, vertices[4], vertices[5], color, depthEnabled);
  b3DrawSegment(data, vertices[5], vertices[6], color, depthEnabled);
  b3DrawSegment(data, vertices[6], vertices[7], color, depthEnabled);
  b3DrawSegment(data, vertices[7], vertices[4], color, depthEnabled);
  b3DrawSegment(data, vertices[2], vertices[4], color, depthEnabled);
  b3DrawSegment(data, vertices[5], vertices[3], color, depthEnabled);
  b3DrawSegment(data, vertices[6], vertices[0], color, depthEnabled);
  b3DrawSegment(data, vertices[1], vertices[7], color, depthEnabled);
}

void b3DrawTransform(b3DebugDrawData *data, b3Transform transform,
                     bool depthEnabled) {
  if (data == NULL) {
    return;
  }
  if (data->DrawTransform != NULL) {
    data->DrawTransform(data->context, transform);
    return;
  }
  b3Vec3 translation = transform.translation;
  b3DrawSegment(data, translation,
                b3Vec3_Add(translation, b3Quat_GetXAxis(transform.rotation)),
                b3Color_red, depthEnabled);
  b3DrawSegment(data, translation,
                b3Vec3_Add(translation, b3Quat_GetYAxis(transform.rotation)),
                b3Color_green, depthEnabled);
  b3DrawSegment(data, translation,
                b3Vec3_Add(translation, b3Quat_GetZAxis(transform.rotation)),
                b3Color_blue, depthEnabled);
}

void b3Manifold_Clear(b3Manifold *manifold) {
  if (manifold != NULL) {
    manifold->pointCount = 0u;
    manifold->tangentImpulse1 = 0.0f;
    manifold->tangentImpulse2 = 0.0f;
    manifold->motorImpulse = 0.0f;
    manifold->motorSpeed = 0.0f;
    manifold->tangentSpeed1 = 0.0f;
    manifold->tangentSpeed2 = 0.0f;
    for (uint32 i = 0u; i < B3_MAX_MANIFOLD_POINTS; ++i) {
      manifold->points[i].normalImpulse = 0.0f;
      manifold->points[i].persistCount = 0u;
      manifold->points[i].edgeContact = false;
    }
  }
}

void b3WorldManifold_Init(b3WorldManifold *out, const b3Manifold *manifold,
                          scalar radiusA, b3Transform xfA, scalar radiusB,
                          b3Transform xfB) {
  if (out == NULL) {
    return;
  }
  out->pointCount = 0u;
  out->normal = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out->tangent1 = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out->tangent2 = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  out->center = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  if (manifold == NULL) {
    return;
  }

  out->pointCount = manifold->pointCount;
  for (uint32 i = 0u; i < manifold->pointCount; ++i) {
    const b3ManifoldPoint *point = &manifold->points[i];
    b3WorldManifoldPoint *worldPoint = &out->points[i];
    b3Vec3 normal = quat_rotate_vec3(xfA.rotation, point->localNormal1);
    b3Vec3 centerA = transform_mul_point_local(xfA, point->localPoint1);
    b3Vec3 centerB = transform_mul_point_local(xfB, point->localPoint2);
    b3Vec3 pointA = vec3_add(centerA, vec3_mul(normal, radiusA));
    b3Vec3 pointB = vec3_sub(centerB, vec3_mul(normal, radiusB));

    worldPoint->point = vec3_mul(vec3_add(pointA, pointB), 0.5f);
    worldPoint->normal = normal;
    worldPoint->separation =
        vec3_dot(vec3_sub(centerB, centerA), normal) - radiusA - radiusB;
    out->center = vec3_add(out->center, worldPoint->point);
    out->normal = vec3_add(out->normal, normal);
  }

  if (out->pointCount > 0u) {
    out->center = vec3_mul(out->center, 1.0f / (scalar)out->pointCount);
    out->normal = vec3_normalize_or_zero(out->normal);
    out->tangent1 = vec3_perp(out->normal);
    out->tangent2 = vec3_cross(out->tangent1, out->normal);
  }
}

void b3SphereShape_Init(b3SphereShape *shape, scalar radius) {
  b3SphereShape_InitWithCenter(shape, b3Vec3_Make(0.0f, 0.0f, 0.0f), radius);
}

