void b3HullShape_Init(b3HullShape *shape, const b3BoxHull *hull) {
  if (shape == NULL) {
    return;
  }
  shape->base.type = e_hullShape;
  shape->base.radius = 0.0f;
  shape->hull = hull;
  shape->genericHull = NULL;
  shape->vertices = NULL;
  shape->vertexCount = 0u;
  shape->builtinHullType = B3_HULL_SHAPE_BUILTIN_NONE;
  shape->builtinRadius = 0.0f;
  shape->builtinEy = 0.0f;
}

void b3HullShape_InitWithHull(b3HullShape *shape, const b3Hull *hull,
                              scalar radius) {
  if (shape == NULL) {
    return;
  }
  shape->base.type = e_hullShape;
  shape->base.radius = radius;
  shape->hull = NULL;
  shape->genericHull = hull;
  shape->vertices = NULL;
  shape->vertexCount = 0u;
  shape->builtinHullType = B3_HULL_SHAPE_BUILTIN_NONE;
  shape->builtinRadius = 0.0f;
  shape->builtinEy = 0.0f;
}

void b3HullShape_InitWithTriangleHull(b3HullShape *shape,
                                      const b3TriangleHull *hull,
                                      scalar radius) {
  b3HullShape_InitWithVertices(
      shape, hull != NULL ? hull->vertices : NULL,
      hull != NULL ? hull->vertexCount : 0u, radius);
}

void b3HullShape_InitWithCylinderHull(b3HullShape *shape,
                                      const b3CylinderHull *hull,
                                      scalar radius) {
  b3HullShape_InitWithVertices(
      shape, hull != NULL ? hull->vertices : NULL,
      hull != NULL ? hull->vertexCount : 0u, radius);
  if (shape != NULL && hull != NULL) {
    shape->builtinHullType = B3_HULL_SHAPE_BUILTIN_CYLINDER;
    shape->builtinRadius = hull->radius;
    shape->builtinEy = hull->ey;
  }
}

void b3HullShape_InitWithConeHull(b3HullShape *shape, const b3ConeHull *hull,
                                  scalar radius) {
  b3HullShape_InitWithVertices(
      shape, hull != NULL ? hull->vertices : NULL,
      hull != NULL ? hull->vertexCount : 0u, radius);
  if (shape != NULL && hull != NULL) {
    shape->builtinHullType = B3_HULL_SHAPE_BUILTIN_CONE;
    shape->builtinRadius = hull->radius;
    shape->builtinEy = hull->ey;
  }
}

void b3HullShape_InitWithVertices(b3HullShape *shape, const b3Vec3 *vertices,
                                  uint32 vertexCount, scalar radius) {
  if (shape == NULL) {
    return;
  }
  shape->base.type = e_hullShape;
  shape->base.radius = radius;
  shape->hull = NULL;
  shape->genericHull = NULL;
  shape->vertices = vertices;
  if (vertices == NULL) {
    shape->vertexCount = 0u;
  } else {
    shape->vertexCount = vertexCount < B3_MAX_HULL_VERTICES
                             ? vertexCount
                             : B3_MAX_HULL_VERTICES;
  }
  shape->builtinHullType = B3_HULL_SHAPE_BUILTIN_NONE;
  shape->builtinRadius = 0.0f;
  shape->builtinEy = 0.0f;
}

const b3BoxHull *b3HullShape_GetBoxHull(const b3HullShape *shape) {
  return shape != NULL ? shape->hull : NULL;
}

const b3Hull *b3HullShape_GetHull(const b3HullShape *shape) {
  return shape != NULL ? shape->genericHull : NULL;
}

uint32 b3HullShape_GetVertexCount(const b3HullShape *shape) {
  if (shape == NULL) {
    return 0u;
  }
  if (shape->vertices != NULL) {
    return shape->vertexCount;
  }
  if (shape->genericHull != NULL) {
    return shape->genericHull->vertexCount;
  }
  return shape->hull != NULL ? shape->hull->vertexCount : 0u;
}

const b3Vec3 *b3HullShape_GetVertices(const b3HullShape *shape) {
  if (shape == NULL) {
    return NULL;
  }
  if (shape->vertices != NULL) {
    return shape->vertices;
  }
  if (shape->genericHull != NULL) {
    return shape->genericHull->vertices;
  }
  return shape->hull != NULL ? shape->hull->vertices : NULL;
}

