void b3World_SetContactFilterObject(b3World *world,
                                    const b3ContactFilter *filter) {
  if (world == NULL) {
    return;
  }
  if (filter == NULL) {
    b3World_SetContactFilter(world, NULL, NULL);
    b3World_SetContactResponseFilter(world, NULL, NULL);
    return;
  }
  b3World_SetContactFilter(world, contact_filter_object_should_collide,
                           (void *)filter);
  b3World_SetContactResponseFilter(world, contact_filter_object_should_respond,
                                   (void *)filter);
}

