void b3World_ClearForces(b3World *world) {
  if (world == NULL) {
    return;
  }

  for (b3Body *body = world->bodies; body != NULL; body = body->next) {
    body->force = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    body->torque = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
}

b3Body *b3World_CreateBody(b3World *world, const b3BodyDef *def) {
  if (world == NULL) {
    return NULL;
  }

  b3BodyDef localDef;
  if (def == NULL) {
    b3BodyDef_Default(&localDef);
    def = &localDef;
  }

  b3Body *body = (b3Body *)calloc(1, sizeof(*body));
  if (body == NULL) {
    return NULL;
  }

  body->world = world;
  body->type = def->type;
  body->awake = def->awake;
  body->allowSleep = def->allowSleep;
  if (body->type == e_dynamicBody) {
    body->fixedRotationX = def->fixedRotationX;
    body->fixedRotationY = def->fixedRotationY;
    body->fixedRotationZ = def->fixedRotationZ;
  }
  body->userData = def->userData;
  body->position = def->position;
  body->orientation = quat_normalize(def->orientation);
  body_update_world_center(body);
  body->linearVelocity = def->linearVelocity;
  body->angularVelocity = def->angularVelocity;
  body->linearDamping = def->linearDamping;
  body->angularDamping = def->angularDamping;
  body->gravityScale = def->gravityScale;
  body->maxLinearVelocity = def->maxLinearVelocity;
  body->maxAngularVelocity = def->maxAngularVelocity;
  body->linearSleepTolerance = def->linearSleepTolerance;
  body->angularSleepTolerance = def->angularSleepTolerance;
  body->solverIndex = B3_MAX_U32;
  body_reset_mass(body);

  body->next = world->bodies;
  if (world->bodies != NULL) {
    world->bodies->prev = body;
  }
  world->bodies = body;
  world->bodyCount++;
  return body;
}

void b3World_DestroyBody(b3World *world, b3Body *body) {
  if (world == NULL || body == NULL || body->world != world) {
    return;
  }

  b3Joint *joint = world->joints;
  while (joint != NULL) {
    b3Joint *next = joint->next;
    if (joint->bodyA == body || joint->bodyB == body) {
      b3World_DestroyJoint(world, joint);
    }
    joint = next;
  }

  world_remove_contacts(world, body, NULL, true);

  b3Fixture *fixture = body->fixtures;
  while (fixture != NULL) {
    b3Fixture *next = fixture->next;
    fixture_destroy_proxy(fixture);
    free(fixture);
    fixture = next;
  }

  if (body->prev != NULL) {
    body->prev->next = body->next;
  } else {
    world->bodies = body->next;
  }
  if (body->next != NULL) {
    body->next->prev = body->prev;
  }

  world->bodyCount--;
  free(body);
}

static void joint_link_body_edge(b3Body *body, b3JointEdge *edge,
                                 b3Body *other, b3Joint *joint) {
  edge->other = other;
  edge->joint = joint;
  edge->prev = NULL;
  edge->next = body->joints;
  if (body->joints != NULL) {
    body->joints->prev = edge;
  }
  body->joints = edge;
}

static void joint_link_bodies(b3Joint *joint) {
  joint_link_body_edge(joint->bodyA, &joint->edgeA, joint->bodyB, joint);
  joint_link_body_edge(joint->bodyB, &joint->edgeB, joint->bodyA, joint);
}

static void joint_unlink_body_edge(b3Body *body, b3JointEdge *edge) {
  if (edge->prev != NULL) {
    edge->prev->next = edge->next;
  } else if (body->joints == edge) {
    body->joints = edge->next;
  }
  if (edge->next != NULL) {
    edge->next->prev = edge->prev;
  }
  edge->other = NULL;
  edge->joint = NULL;
  edge->prev = NULL;
  edge->next = NULL;
}

static void joint_unlink_bodies(b3Joint *joint) {
  joint_unlink_body_edge(joint->bodyA, &joint->edgeA);
  joint_unlink_body_edge(joint->bodyB, &joint->edgeB);
}

