  joint->bodyB = def->bodyB;
  joint->userData = def->userData;
  joint->localAnchorA = def->localAnchorA;
  joint->localAnchorB = def->localAnchorB;
  joint->localAxisA = vec3_normalize_or_zero(def->localAxisA);
  if (vec3_length_sq(joint->localAxisA) <= B3_EPSILON * B3_EPSILON) {
    joint->localAxisA = b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  joint->referenceRotation = quat_normalize(def->referenceRotation);
  joint->enableLimit = def->enableLimit;
  joint->lowerLimit = def->lowerTranslation;
  joint->upperLimit = def->upperTranslation;
  if (joint->lowerLimit > joint->upperLimit) {
    scalar lower = joint->upperLimit;
    joint->upperLimit = joint->lowerLimit;
    joint->lowerLimit = lower;
  }
  joint->enableMotor = def->enableMotor;
  joint->maxMotorForce = scalar_max(0.0f, def->maxMotorForce);
  joint->motorSpeed = def->motorSpeed;
  joint->correctionFactor = scalar_max(0.0f, def->correctionFactor);
  joint->collideConnected = def->collideConnected;
