b3Joint *b3World_CreateWheelJoint(b3World *world, const b3WheelJointDef *def) {
  if (world == NULL || def == NULL || def->bodyA == NULL ||
      def->bodyB == NULL || def->bodyA->world != world ||
      def->bodyB->world != world || def->bodyA == def->bodyB) {
    return NULL;
  }

  b3Joint *joint = (b3Joint *)calloc(1, sizeof(*joint));
  if (joint == NULL) {
    return NULL;
  }
  joint->world = world;
  joint->type = e_wheelJoint;
  joint->bodyA = def->bodyA;
  joint->bodyB = def->bodyB;
  joint->userData = def->userData;
  joint->localAnchorA = def->localAnchorA;
  joint->localAnchorB = def->localAnchorB;
  joint->localAxisA = vec3_normalize_or_zero(def->localAxisA);
  if (vec3_length_sq(joint->localAxisA) <= B3_EPSILON * B3_EPSILON) {
    joint->localAxisA = b3Vec3_Make(0.0f, 1.0f, 0.0f);
  }
  joint->localAxisB = vec3_normalize_or_zero(def->localAxisB);
  if (vec3_length_sq(joint->localAxisB) <= B3_EPSILON * B3_EPSILON) {
    joint->localAxisB = b3Vec3_Make(1.0f, 0.0f, 0.0f);
  }
  b3Vec3 axisA = b3Body_GetWorldVector(def->bodyA, joint->localAxisA);
  b3Vec3 axisB = b3Body_GetWorldVector(def->bodyB, joint->localAxisB);
  b3Vec3 cross = vec3_cross(axisA, axisB);
  joint->referenceCosine = scalar_clamp(vec3_dot(axisA, axisB), -1.0f, 1.0f);
  joint->referenceAngle = atan2f(vec3_length(cross), joint->referenceCosine);
  joint->enableMotor = def->enableMotor;
  joint->maxTorque = scalar_max(0.0f, def->maxMotorTorque);
  joint->motorSpeed = def->motorSpeed;
  joint->frequencyHz = scalar_max(0.0f, def->frequencyHz);
  joint->dampingRatio = scalar_max(0.0f, def->dampingRatio);
  joint->collideConnected = def->collideConnected;
  joint->length = joint_prismatic_translation(joint);
  joint_link_bodies(joint);

  joint->next = world->joints;
  if (world->joints != NULL) {
    world->joints->prev = joint;
  }
  world->joints = joint;
  world->jointCount++;
  return joint;
}

void b3World_DestroyJoint(b3World *world, b3Joint *joint) {
  if (world == NULL || joint == NULL || joint->world != world) {
    return;
  }
  body_mark_awake(joint->bodyA);
  body_mark_awake(joint->bodyB);
  if (joint->prev != NULL) {
    joint->prev->next = joint->next;
  } else {
    world->joints = joint->next;
  }
  if (joint->next != NULL) {
    joint->next->prev = joint->prev;
  }
  joint_unlink_bodies(joint);
  world->jointCount--;
  free(joint);
}

void b3World_Step(b3World *world, scalar dt, uint32 velocityIterations,
                  uint32 positionIterations) {
  if (world == NULL) {
    return;
  }
  b3Profiler_OpenScope(world->profiler, "Step");
  world->dtRatio = dt > 0.0f ? world->invDt0 * dt : 0.0f;
  if (dt <= 0.0f) {
    world_update_contacts(world);
    if (world->clearForces) {
      b3World_ClearForces(world);
    }
    b3Profiler_CloseScope(world->profiler);
    return;
  }

  world_update_contacts(world);
  b3Profiler_OpenScope(world->profiler, "Solve");

  for (b3Body *body = world->bodies; body != NULL; body = body->next) {
    body_reset_sweep(body);
  }

  bool islandContactCountsReady = world_begin_island_contact_counts(world);
  uint32 islandCount =
      world_build_awake_islands(world, islandContactCountsReady);
  bool useIslandContactLists =
      world_prepare_island_contact_lists(world, islandCount,
                                         islandContactCountsReady);

  for (b3Body *body = world->bodies; body != NULL; body = body->next) {
    if (body->type == e_staticBody || !body->awake) {
      continue;
    }

    if (body->type == e_dynamicBody) {
      b3Vec3 gravity = vec3_mul_comp(world->gravity, body->gravityScale);
      body->linearVelocity = vec3_add(
          body->linearVelocity,
          vec3_mul(vec3_add(gravity, vec3_mul(body->force, body->invMass)), dt));
      b3Vec3 torqueVelocity =
          vec3_mul(mat33_mul_vec3(body->worldInvInertia, body->torque), dt);
      body->angularVelocity =
          vec3_add(body_solve_gyro(body->orientation, body->inertia,
                                   body->angularVelocity, dt),
                   torqueVelocity);

      body->linearVelocity.x *= 1.0f / (1.0f + dt * body->linearDamping.x);
      body->linearVelocity.y *= 1.0f / (1.0f + dt * body->linearDamping.y);
      body->linearVelocity.z *= 1.0f / (1.0f + dt * body->linearDamping.z);

      body->angularVelocity.x *= 1.0f / (1.0f + dt * body->angularDamping.x);
      body->angularVelocity.y *= 1.0f / (1.0f + dt * body->angularDamping.y);
      body->angularVelocity.z *= 1.0f / (1.0f + dt * body->angularDamping.z);

      body_clamp_velocity_limits(body);
    }
  }

  if (islandCount > 0u) {
    for (uint32 islandTag = 1u; islandTag <= islandCount; ++islandTag) {
      world->activeIslandTag = islandTag;
      if (useIslandContactLists) {
        world_set_active_island_contacts(world, islandTag);
      } else {
        world_clear_active_island_contacts(world);
      }
      solve_world_velocity_iterations(world, velocityIterations, dt);
    }
    world->activeIslandTag = 0u;
    world_clear_active_island_contacts(world);
  } else {
    solve_world_velocity_iterations(world, velocityIterations, dt);
  }
  world_clamp_velocity_limits(world);

  world->deferBodySync = true;
  for (b3Body *body = world->bodies; body != NULL; body = body->next) {
    if (body->type == e_staticBody || !body->awake) {
      continue;
    }

    b3Vec3 displacement = vec3_mul(body->linearVelocity, dt);
    scalar displacementLength = vec3_length(displacement);
    if (displacementLength > B3_MAX_TRANSLATION) {
      scalar ratio = B3_MAX_TRANSLATION / displacementLength;
      body->linearVelocity = vec3_mul(body->linearVelocity, ratio);
      displacement = vec3_mul(body->linearVelocity, dt);
      displacementLength = B3_MAX_TRANSLATION;
    }

    b3Vec3 rotation = vec3_mul(body->angularVelocity, dt);
    scalar rotationLength = vec3_length(rotation);
    if (rotationLength > B3_MAX_ROTATION) {
      body->angularVelocity =
          vec3_mul(body->angularVelocity, B3_MAX_ROTATION / rotationLength);
    }

    if (world->continuousCollision && body->type != e_staticBody &&
        displacementLength > 100.0f * B3_LINEAR_SLOP) {
      scalar toiFraction = 1.0f;
      b3Vec3 toiNormal = b3Vec3_Make(0.0f, 0.0f, 0.0f);
      const b3Body *toiBody = NULL;
      bool filterToStatic = body->type == e_kinematicBody;
      if (body_find_translation_toi(body, displacement, dt, e_staticBody,
                                    filterToStatic, &toiFraction, &toiNormal,
                                    &toiBody)) {
        scalar allowedFraction = toiFraction;
        if (displacementLength > B3_EPSILON) {
          allowedFraction =
              scalar_max(0.0f, toiFraction - B3_LINEAR_SLOP / displacementLength);
        }
        displacement = vec3_mul(displacement, allowedFraction);
        b3Vec3 targetVelocity =
            toiBody != NULL && toiBody->type != e_staticBody
                ? toiBody->linearVelocity
                : b3Vec3_Make(0.0f, 0.0f, 0.0f);
        scalar vn = vec3_dot(body->linearVelocity, toiNormal);
        scalar targetVn = vec3_dot(targetVelocity, toiNormal);
        if (vn * targetVn > 0.0f) {
          vn -= targetVn;
        }
        if (vn < 0.0f) {
          body->linearVelocity =
              vec3_sub(body->linearVelocity, vec3_mul(toiNormal, vn));
        }
      }
    }

    b3Vec3 center = vec3_add(body_current_world_center(body), displacement);
    b3Quat orientation =
        quat_integrate(body->orientation, body->angularVelocity, dt);
    body_set_center_and_orientation(body, center, orientation);
  }

  bool *islandPositionsSolved = NULL;
  if (islandCount > 0u) {
    if (world_reserve_island_positions(world, islandCount + 1u)) {
      islandPositionsSolved = world->islandPositionsSolved;
      memset(islandPositionsSolved, 0,
             ((size_t)islandCount + 1u) * sizeof(*islandPositionsSolved));
    }
    for (uint32 islandTag = 1u; islandTag <= islandCount; ++islandTag) {
      world->activeIslandTag = islandTag;
      if (useIslandContactLists) {
        world_set_active_island_contacts(world, islandTag);
      } else {
        world_clear_active_island_contacts(world);
      }
      bool positionsSolved =
          positionIterations > 0u &&
          solve_world_position_iterations(world, positionIterations);
      if (islandPositionsSolved != NULL) {
        islandPositionsSolved[islandTag] = positionsSolved;
      }
    }
    world->activeIslandTag = 0u;
    world_clear_active_island_contacts(world);
  } else {
    solve_world_position_iterations(world, positionIterations);
  }
  world->deferBodySync = false;
  /* Integration already invalidated contact manifolds for this deferred step. */
  world_flush_deferred_body_sync(world, false);

  world_clamp_velocity_limits(world);
  world_notify_post_solve(world);
  world_update_sleeping(world, dt, islandCount, islandPositionsSolved);
  b3Profiler_OpenScope(world->profiler, "Find New Pairs");
  world_find_new_contacts(world);
  b3Profiler_CloseScope(world->profiler);
  b3Profiler_CloseScope(world->profiler);

  if (world->clearForces) {
    b3World_ClearForces(world);
  }
  world->invDt0 = 1.0f / dt;
  b3Profiler_CloseScope(world->profiler);
}

void b3World_DebugDraw(const b3World *world, const b3DebugDraw *draw) {
  if (world == NULL || draw == NULL) {
    return;
  }

  for (const b3Body *body = world->bodies; body != NULL; body = body->next) {
    b3Transform xf = body_transform(body);
    if ((draw->flags & B3_DRAW_CENTER_OF_MASSES) != 0u &&
        draw->DrawTransform != NULL) {
      draw->DrawTransform(draw->context, xf);
    }

    b3Color color = debug_body_color(body);
    for (const b3Fixture *fixture = body->fixtures; fixture != NULL;
         fixture = fixture->next) {
      if ((draw->flags & B3_DRAW_AABBS) != 0u && draw->DrawAABB != NULL) {
        draw->DrawAABB(draw->context, aabb_to_public(fixture_world_aabb(fixture)),
                       color);
      }
      if ((draw->flags & B3_DRAW_SHAPES) != 0u) {
        debug_draw_shape(draw, &fixture->storage.base, xf, color);
        debug_draw_shape_solid(draw, &fixture->storage.base, xf, color);
      }
    }
  }

  if ((draw->flags & B3_DRAW_JOINTS) != 0u) {
    for (const b3Joint *joint = world->joints; joint != NULL;
         joint = joint->next) {
      debug_draw_joint(draw, joint);
    }
  }

  uint32 contactFlags = B3_DRAW_CONTACT_POINTS | B3_DRAW_CONTACT_NORMALS |
                        B3_DRAW_CONTACT_TANGENTS | B3_DRAW_CONTACT_POLYGONS;
  if ((draw->flags & contactFlags) != 0u) {
    for (const b3Contact *contact = world->contacts; contact != NULL;
         contact = contact->next) {
      uint32 manifoldCount = b3Contact_GetManifoldCount(contact);
      for (uint32 m = 0u; m < manifoldCount && m < B3_MAX_MANIFOLDS; ++m) {
        b3WorldManifold worldManifold;
        if (!b3Contact_GetWorldManifoldAt(contact, m, &worldManifold)) {
          continue;
        }
        for (uint32 i = 0u; i < worldManifold.pointCount; ++i) {
          b3Vec3 point = worldManifold.points[i].point;
          if ((draw->flags & B3_DRAW_CONTACT_POINTS) != 0u) {
            b3Color color = {1.0f, 0.2f, 0.2f, 1.0f};
            debug_draw_point(draw, point, 4.0f, color);
          }
          if ((draw->flags & B3_DRAW_CONTACT_NORMALS) != 0u) {
            b3Color color = {1.0f, 1.0f, 1.0f, 1.0f};
            debug_draw_segment(draw, point,
                               vec3_add(point, worldManifold.points[i].normal),
                               color);
          }
          if ((draw->flags & B3_DRAW_CONTACT_TANGENTS) != 0u) {
            b3Color color = {1.0f, 1.0f, 0.0f, 1.0f};
            debug_draw_segment(draw, point,
                               vec3_add(point, worldManifold.tangent1), color);
            debug_draw_segment(draw, point,
                               vec3_add(point, worldManifold.tangent2), color);
          }
        }
        if ((draw->flags & B3_DRAW_CONTACT_POLYGONS) != 0u &&
            worldManifold.pointCount >= 3u) {
          b3Color color = {1.0f, 0.4f, 0.8f, 1.0f};
          b3Vec3 points[B3_MAX_MANIFOLD_POINTS];
          for (uint32 i = 0u; i < worldManifold.pointCount; ++i) {
            points[i] = worldManifold.points[i].point;
          }
          debug_draw_solid_polygon(draw, worldManifold.normal, points,
                                   worldManifold.pointCount, color);
        }
      }
    }
  }
}

