static void world_query_aabb_filtered(const b3World *world, b3AABB aabb,
                                      b3BodyType bodyType,
                                      const b3Body *ignoredBody,
                                      bool filterByBodyType,
                                      bool ignoreSensors,
                                      b3WorldFixtureFilterCallback filter,
                                      void *filterContext,
                                      b3WorldQueryCallback callback,
                                      void *callbackContext) {
  if (world == NULL || world->broadPhase == NULL || callback == NULL) {
    return;
  }

  b3WorldQueryAABBContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.bodyType = bodyType;
  context.query = aabb_from_public(aabb);
  context.filter = filter;
  context.filterContext = filterContext;
  context.callback = callback;
  context.callbackContext = callbackContext;
  context.filterByBodyType = filterByBodyType;
  context.ignoreSensors = ignoreSensors;
  b3BroadPhase_QueryAABB(world->broadPhase, aabb, world_query_aabb_tree_callback,
                         &context);
}

