static bool world_ray_cast_closest_filtered(
    const b3World *world, b3Vec3 point1, b3Vec3 point2, b3BodyType bodyType,
    const b3Body *ignoredBody, bool filterByBodyType, bool ignoreSensors,
    b3WorldFixtureFilterCallback filter, void *filterContext,
    b3RayCastOutput *out) {
  if (world == NULL || world->broadPhase == NULL || out == NULL) {
    return false;
  }

  b3WorldRayContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.bodyType = bodyType;
  context.filterByBodyType = filterByBodyType;
  context.ignoreSensors = ignoreSensors;
  context.filter = filter;
  context.filterContext = filterContext;
  context.point1 = point1;
  context.point2 = point2;
  context.bestFraction = 1.0f;
  b3RayCastInput input = {.p1 = point1, .p2 = point2, .maxFraction = 1.0f};
  b3BroadPhase_RayCast(world->broadPhase, input, world_ray_tree_callback,
                       &context);

  if (context.hit) {
    *out = context.best;
  }
  return context.hit;
}

