static bool world_shape_cast_closest_filtered_internal(
    const b3World *world, const b3Shape *shape, b3Transform transform,
    b3Vec3 displacement, scalar targetMotionDt, bool useTargetMotion,
    b3BodyType bodyType, const b3Body *ignoredBody, bool filterByBodyType,
    bool ignoreSensors,
    b3WorldFixtureFilterCallback filter, void *filterContext,
    const b3Fixture *sourceFixture,
    b3ShapeCastOutput *out) {
  if (world == NULL || world->broadPhase == NULL || shape == NULL ||
      out == NULL ||
      vec3_length_sq(displacement) <= B3_EPSILON * B3_EPSILON) {
    return false;
  }

  b3ShapeProxyData movingProxy;
  if (!shape_build_gjk_proxy(shape, &movingProxy)) {
    return false;
  }

  b3WorldShapeCastContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.sourceFixture = sourceFixture;
  context.shape = shape;
  context.bodyType = bodyType;
  context.filter = filter;
  context.filterContext = filterContext;
  context.filterByBodyType = filterByBodyType;
  context.ignoreSensors = ignoreSensors;
  context.useTargetMotion = useTargetMotion;
  context.targetMotionDt = targetMotionDt;
  context.shapeTransform = transform;
  context.shapeProxy = movingProxy.proxy;
  context.displacement = displacement;
  context.maxFraction = 1.0f;

  b3Aabb sweepAabb =
      shape_proxy_sweep_aabb_in_space(&context.shapeProxy, transform,
                                      displacement, b3Transform_Identity(),
                                      false);
  if (useTargetMotion) {
    b3Vec3 margin =
        b3Vec3_Make(B3_MAX_TRANSLATION, B3_MAX_TRANSLATION, B3_MAX_TRANSLATION);
    sweepAabb.min = vec3_sub(sweepAabb.min, margin);
    sweepAabb.max = vec3_add(sweepAabb.max, margin);
  }
  b3BroadPhase_QueryAABB(world->broadPhase, aabb_to_public(sweepAabb),
                         world_shape_cast_tree_callback, &context);
  if (context.hit) {
    *out = context.best;
  }
  return context.hit;
}

static bool world_shape_cast_closest_filtered(
    const b3World *world, const b3Shape *shape, b3Transform transform,
    b3Vec3 displacement, b3BodyType bodyType, const b3Body *ignoredBody,
    bool filterByBodyType, bool ignoreSensors,
    b3WorldFixtureFilterCallback filter, void *filterContext,
    const b3Fixture *sourceFixture,
    b3ShapeCastOutput *out) {
  return world_shape_cast_closest_filtered_internal(
      world, shape, transform, displacement, 0.0f, false, bodyType,
      ignoredBody, filterByBodyType, ignoreSensors, filter, filterContext,
      sourceFixture, out);
}

