static bool world_sweep_aabb_closest_filtered(
    const b3World *world, b3Vec3 center, b3Vec3 halfExtents,
    b3Vec3 displacement, b3BodyType bodyType, const b3Body *ignoredBody,
    bool filterByBodyType, b3WorldFixtureFilterCallback filter,
    void *filterContext, b3ShapeCastOutput *out) {
  if (world == NULL || world->broadPhase == NULL || out == NULL) {
    return false;
  }

  b3Vec3 end = vec3_add(center, displacement);
  b3Aabb sweepAabb;
  sweepAabb.min =
      vec3_min(vec3_sub(center, halfExtents), vec3_sub(end, halfExtents));
  sweepAabb.max =
      vec3_max(vec3_add(center, halfExtents), vec3_add(end, halfExtents));

  b3WorldSweepContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.bodyType = bodyType;
  context.filterByBodyType = filterByBodyType;
  context.filter = filter;
  context.filterContext = filterContext;
  context.center = center;
  context.end = end;
  context.displacement = displacement;
  context.halfExtents = halfExtents;
  context.bestFraction = 1.0f;
  b3BroadPhase_QueryAABB(world->broadPhase, aabb_to_public(sweepAabb),
                         world_sweep_tree_callback, &context);

  if (context.hit) {
    *out = context.best;
  }
  return context.hit;
}

