static bool world_test_aabb_filtered(const b3World *world, b3Vec3 center,
                                     b3Vec3 halfExtents, b3BodyType bodyType,
                                     const b3Body *ignoredBody,
                                     bool filterByBodyType,
                                     b3WorldFixtureFilterCallback filter,
                                     void *filterContext) {
  if (world == NULL || world->broadPhase == NULL) {
    return false;
  }

  b3Aabb query;
  query.min = vec3_sub(center, halfExtents);
  query.max = vec3_add(center, halfExtents);

  b3WorldTestContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.bodyType = bodyType;
  context.filterByBodyType = filterByBodyType;
  context.filter = filter;
  context.filterContext = filterContext;
  context.query = query;
  b3BroadPhase_QueryAABB(world->broadPhase, aabb_to_public(query),
                         world_test_tree_callback, &context);
  return context.hit;
}

