static bool world_test_capsule_filtered(const b3World *world, b3Vec3 origin,
                                        scalar radius, scalar height,
                                        b3BodyType bodyType,
                                        const b3Body *ignoredBody,
                                        bool filterByBodyType,
                                        b3WorldFixtureFilterCallback filter,
                                        void *filterContext) {
  if (world == NULL || world->broadPhase == NULL || radius <= 0.0f ||
      height <= 0.0f) {
    return false;
  }

  b3CapsuleShape capsule;
  make_vertical_capsule(&capsule, radius, height);
  b3Aabb query;
  shape_local_aabb(&capsule.base, &query);
  aabb_translate(&query, origin);

  b3WorldShapeTestContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.bodyType = bodyType;
  context.filterByBodyType = filterByBodyType;
  context.filter = filter;
  context.filterContext = filterContext;
  context.shape = &capsule.base;
  context.transform = b3Transform_Make(origin, b3Quat_Identity());
  b3BroadPhase_QueryAABB(world->broadPhase, aabb_to_public(query),
                         world_shape_test_tree_callback, &context);
  return context.hit;
}

