static bool world_sweep_capsule_closest_filtered(
    const b3World *world, b3Vec3 origin, scalar radius, scalar height,
    b3Vec3 displacement, b3BodyType bodyType, const b3Body *ignoredBody,
    bool filterByBodyType, b3WorldFixtureFilterCallback filter,
    void *filterContext, b3ShapeCastOutput *out) {
  if (world == NULL || world->broadPhase == NULL || out == NULL ||
      radius <= 0.0f || height <= 0.0f) {
    return false;
  }

  b3WorldCapsuleSweepContext context;
  memset(&context, 0, sizeof(context));
  context.world = world;
  context.ignoredBody = ignoredBody;
  context.bodyType = bodyType;
  context.filterByBodyType = filterByBodyType;
  context.filter = filter;
  context.filterContext = filterContext;
  context.displacement = displacement;
  context.bestFraction = 1.0f;
  make_vertical_capsule(&context.capsuleShape, radius, height);
  context.capsuleVertices[0] =
      context.capsuleShape.point1;
  context.capsuleVertices[1] =
      context.capsuleShape.point2;
  b3GJKProxy_Init(&context.capsuleProxy, context.capsuleVertices, 2u, radius);
  context.capsuleTransform = b3Transform_Make(origin, b3Quat_Identity());

  b3Vec3 capsuleMin =
      vec3_sub(vec3_min(context.capsuleVertices[0], context.capsuleVertices[1]),
               b3Vec3_Make(radius, radius, radius));
  b3Vec3 capsuleMax =
      vec3_add(vec3_max(context.capsuleVertices[0], context.capsuleVertices[1]),
               b3Vec3_Make(radius, radius, radius));
  b3Vec3 startMin = vec3_add(origin, capsuleMin);
  b3Vec3 startMax = vec3_add(origin, capsuleMax);
  b3Vec3 endOrigin = vec3_add(origin, displacement);
  b3Vec3 endMin = vec3_add(endOrigin, capsuleMin);
  b3Vec3 endMax = vec3_add(endOrigin, capsuleMax);
  b3Aabb sweepAabb;
  sweepAabb.min = vec3_min(startMin, endMin);
  sweepAabb.max = vec3_max(startMax, endMax);

  b3BroadPhase_QueryAABB(world->broadPhase, aabb_to_public(sweepAabb),
                         world_capsule_sweep_tree_callback, &context);
  if (context.hit) {
    *out = context.best;
  }
  return context.hit;
}

