b3Fixture *b3Body_CreateFixture(b3Body *body, const b3FixtureDef *def) {
  if (body == NULL || def == NULL || def->shape == NULL) {
    return NULL;
  }

  b3Fixture *fixture = (b3Fixture *)calloc(1, sizeof(*fixture));
  if (fixture == NULL) {
    return NULL;
  }

  fixture->body = body;
  fixture->proxyId = B3_NULL_DYNAMIC_NODE;
  fixture->userData = def->userData;
  fixture->friction = def->friction;
  fixture->restitution = def->restitution;
  fixture->density = def->density;
  fixture->sensor = def->sensor;
  fixture_copy_shape(fixture, def->shape);

  fixture->next = body->fixtures;
  body->fixtures = fixture;
  body->fixtureCount++;
  body_invalidate_world_aabb(body);
  body_invalidate_contact_world_manifolds(body);
  fixture_create_proxy(fixture);
  if (fixture->density > 0.0f) {
    body_reset_mass(body);
  }
  return fixture;
}

void b3Body_DestroyFixture(b3Body *body, b3Fixture *fixture) {
  if (body == NULL || fixture == NULL || fixture->body != body) {
    return;
  }

  b3Fixture **cursor = &body->fixtures;
  while (*cursor != NULL && *cursor != fixture) {
    cursor = &(*cursor)->next;
  }
  if (*cursor == NULL) {
    return;
  }

  *cursor = fixture->next;
  world_remove_contacts(body->world, NULL, fixture, true);
  fixture_destroy_proxy(fixture);
  body->fixtureCount--;
  body_invalidate_world_aabb(body);
  body_invalidate_contact_world_manifolds(body);
  fixture->body = NULL;
  fixture->next = NULL;
  free(fixture);
  body_reset_mass(body);
}

