b3Vec3 b3Joint_GetAnchorA(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  if (joint->type == e_mouseJoint) {
    return joint->target;
  }
  if (joint->type == e_motorJoint) {
    return b3Body_GetPosition(joint->bodyA);
  }
  return b3Body_GetWorldPoint(joint->bodyA, joint->localAnchorA);
}

b3Vec3 b3Joint_GetAnchorB(const b3Joint *joint) {
  if (joint == NULL || joint->bodyB == NULL) {
    return b3Vec3_Make(0.0f, 0.0f, 0.0f);
  }
  if (joint->type == e_motorJoint) {
    return b3Body_GetPosition(joint->bodyB);
  }
  return b3Body_GetWorldPoint(joint->bodyB, joint->localAnchorB);
}

void b3Joint_SetAnchor(b3Joint *joint, b3Vec3 anchor) {
  if (joint == NULL || joint->type != e_weldJoint || joint->bodyA == NULL ||
      joint->bodyB == NULL) {
    return;
  }

  joint->localAnchorA = b3Body_GetLocalPoint(joint->bodyA, anchor);
  joint->localAnchorB = b3Body_GetLocalPoint(joint->bodyB, anchor);
  joint->referenceRotation =
      quat_mul(quat_conjugate(b3Body_GetOrientation(joint->bodyA)),
               b3Body_GetOrientation(joint->bodyB));
}

