void b3Joint_SetLength(b3Joint *joint, scalar length) {
  if (joint != NULL) {
    scalar clamped = scalar_max(0.0f, length);
    if (joint->type == e_springJoint) {
      joint->length = clamped;
      return;
    }
    if (joint->length != clamped) {
      joint_mark_bodies_awake(joint);
      joint->springImpulse = 0.0f;
    }
    joint->length = clamped;
  }
}

