b3Quat b3Joint_GetReferenceRotation(const b3Joint *joint) {
  return joint != NULL ? joint->referenceRotation : b3Quat_Identity();
}

void b3Joint_SetReferenceRotation(b3Joint *joint, b3Quat referenceRotation) {
  if (joint != NULL) {
    b3Quat normalized = quat_normalize(referenceRotation);
    if (joint->type == e_weldJoint) {
      joint->referenceRotation = normalized;
      return;
    }
    if (fabsf(joint->referenceRotation.v.x - normalized.v.x) > B3_EPSILON ||
        fabsf(joint->referenceRotation.v.y - normalized.v.y) > B3_EPSILON ||
        fabsf(joint->referenceRotation.v.z - normalized.v.z) > B3_EPSILON ||
        fabsf(joint->referenceRotation.s - normalized.s) > B3_EPSILON) {
      joint_mark_bodies_awake(joint);
      joint->angularImpulse = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    }
    joint->referenceRotation = normalized;
  }
}

