    b3Quat normalized = quat_normalize(angularOffset);
    if (fabsf(joint->angularOffset.v.x - normalized.v.x) > B3_EPSILON ||
        fabsf(joint->angularOffset.v.y - normalized.v.y) > B3_EPSILON ||
        fabsf(joint->angularOffset.v.z - normalized.v.z) > B3_EPSILON ||
        fabsf(joint->angularOffset.s - normalized.s) > B3_EPSILON) {
      joint_mark_bodies_awake(joint);
    }
    joint->angularOffset = normalized;
