scalar b3Joint_GetJointAngularSpeed(const b3Joint *joint) {
  if (joint == NULL || joint->bodyA == NULL || joint->bodyB == NULL) {
    return 0.0f;
  }
  b3Vec3 axis =
      joint->type == e_wheelJoint ? joint_world_axis_b(joint)
                                  : joint_hinge_axis_a(joint);
  b3Vec3 relativeAngularVelocity =
      vec3_sub(joint->bodyB->angularVelocity, joint->bodyA->angularVelocity);
  return vec3_dot(relativeAngularVelocity, axis);
}

