b3BodyType b3Body_GetType(const b3Body *body) {
  return body != NULL ? body->type : e_staticBody;
}

void b3Body_SetType(b3Body *body, b3BodyType type) {
  if (body == NULL) {
    return;
  }
  if (body->type == type) {
    return;
  }
  body->type = type;
  body_reset_mass(body);
  if (body->type == e_staticBody) {
    body->linearVelocity = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    body->angularVelocity = b3Vec3_Make(0.0f, 0.0f, 0.0f);
    body_reset_sweep(body);
    body_sync_fixtures(body, b3Vec3_Make(0.0f, 0.0f, 0.0f));
  }
  body_mark_awake(body);
  body->force = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  body->torque = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  world_remove_contacts(body->world, body, NULL, true);
  if (body->world != NULL && body->world->broadPhase != NULL) {
    bool touchedProxy = false;
    for (b3Fixture *fixture = body->fixtures; fixture != NULL;
         fixture = fixture->next) {
      if (fixture->proxyId != B3_NULL_DYNAMIC_NODE) {
        b3BroadPhase_TouchProxy(body->world->broadPhase, fixture->proxyId);
        touchedProxy = true;
      }
    }
    if (touchedProxy) {
      body->world->newContacts = true;
    }
  }
}

