b3Sweep b3Body_GetSweep(const b3Body *body) {
  b3Sweep sweep;
  sweep.localCenter = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  sweep.orientation0 = b3Quat_Identity();
  sweep.worldCenter0 = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  sweep.t0 = 0.0f;
  sweep.orientation = b3Quat_Identity();
  sweep.worldCenter = b3Vec3_Make(0.0f, 0.0f, 0.0f);
  if (body == NULL) {
    return sweep;
  }

  sweep.localCenter = body->localCenter;
  sweep.orientation0 = body->orientation0;
  sweep.worldCenter0 = body->worldCenter0;
  sweep.t0 = body->sweepT0;
  sweep.orientation = body->orientation;
  sweep.worldCenter = body_current_world_center(body);
  return sweep;
}

