void b3Body_SetTransform(b3Body *body, b3Vec3 position, b3Quat orientation) {
  if (body == NULL) {
    return;
  }
  body->position = position;
  body->orientation = quat_normalize(orientation);
  body_invalidate_world_aabb(body);
  body_update_world_center(body);
  body_invalidate_contact_world_manifolds(body);
  body_update_world_inv_inertia(body);
  body_reset_sweep(body);
  b3Transform newTransform = body_transform(body);
  body_sync_fixtures_between(body, newTransform, newTransform);
  if (body->world != NULL) {
    body->world->newContacts = true;
  }
}

void b3Body_SetTransformMatrix(b3Body *body, b3Vec3 position,
                               b3Mat33 orientation) {
  b3Body_SetTransform(body, position, b3Quat_FromMat33(orientation));
}

