scalar b3Body_GetLinearEnergy(const b3Body *body) {
  if (body == NULL) {
    return 0.0f;
  }
  return body->mass * vec3_dot(body->linearVelocity, body->linearVelocity);
}

scalar b3Body_GetAngularEnergy(const b3Body *body) {
  if (body == NULL) {
    return 0.0f;
  }
  b3Mat33 worldInertia = mat33_rotate_to_frame(body->inertia, body->orientation);
  b3Vec3 angularMomentum = mat33_mul_vec3(worldInertia, body->angularVelocity);
  return vec3_dot(angularMomentum, body->angularVelocity);
}

scalar b3Body_GetEnergy(const b3Body *body) {
  if (body == NULL) {
    return 0.0f;
  }
  return 0.5f *
         (b3Body_GetLinearEnergy(body) + b3Body_GetAngularEnergy(body));
}

void b3Body_GetMassData(const b3Body *body, b3MassData *out) {
  if (out == NULL) {
    return;
  }
  out->center = b3Body_GetLocalCenter(body);
  out->mass = body != NULL ? body->mass : 0.0f;
  out->I = b3Body_GetInertia(body);
}

void b3Body_SetMassData(b3Body *body, const b3MassData *massData) {
  if (body == NULL || massData == NULL || body->type != e_dynamicBody) {
    return;
  }
  b3Vec3 oldCenter = body_current_world_center(body);
  body->mass = massData->mass > 0.0f ? massData->mass : 1.0f;
  body->invMass = 1.0f / body->mass;
  body->localCenter = massData->center;
  body_update_world_center(body);
  body->inertia = mat33_zero();
  body->invInertia = mat33_zero();
  body->worldInvInertia = mat33_zero();
  if (massData->mass > 0.0f) {
    body->inertia = mat33_sub(
        massData->I,
        mat33_mul_scalar(mat33_steiner(massData->center), body->mass));
    body->invInertia = mat33_inverse(body->inertia);
    body_update_world_inv_inertia(body);
    body_apply_fixed_rotation_masks(body);
  }
  b3Vec3 newCenter = body_current_world_center(body);
  body_reset_sweep(body);
  body->linearVelocity = vec3_add(
      body->linearVelocity,
      vec3_cross(body->angularVelocity, vec3_sub(newCenter, oldCenter)));
}

