#if !defined(_WIN32) && !defined(__APPLE__) && !defined(_POSIX_C_SOURCE)
#define _POSIX_C_SOURCE 199309L
#endif


#include <stdlib.h>

#if defined(_WIN32)
#define WIN32_LEAN_AND_MEAN
#include <windows.h>
#elif defined(__APPLE__)
#include <mach/mach_time.h>
#else
#include <time.h>
#endif

struct b3Time {
#if defined(_WIN32)
  LARGE_INTEGER counter;
#elif defined(__APPLE__)
  uint64_t counter;
#else
  struct timespec counter;
#endif
  double previousMillis;
  double currentMillis;
};

struct b3ProfilerStatistic {
  const char *name;
  double minElapsed;
  double maxElapsed;
  b3ProfilerStatistic *next;
};

struct b3ProfilerNode {
  const char *name;
  double elapsed;
  uint32 callCount;
  uint32 recursionCount;
  double t1;
  double t2;
  b3ProfilerNode *parent;
  b3ProfilerNode *childList;
  uint32 childCount;
  b3ProfilerNode *childNext;
  b3ProfilerStatistic *statistic;
};

struct b3Profiler {
  b3Time time;
  b3ProfilerNode *root;
  b3ProfilerNode *top;
  b3ProfilerStatistic *statisticList;
  uint32 statisticCount;
};

static void time_init(b3Time *time) {
  if (time == NULL) {
    return;
  }
#if defined(_WIN32)
  QueryPerformanceCounter(&time->counter);
#elif defined(__APPLE__)
  time->counter = mach_absolute_time();
#else
  clock_gettime(CLOCK_MONOTONIC, &time->counter);
#endif
  time->previousMillis = 0.0;
  time->currentMillis = 0.0;
}

static void time_add(b3Time *time, double dt) {
  time->previousMillis = time->currentMillis;
  time->currentMillis += dt;
}

static void time_update(b3Time *time) {
  if (time == NULL) {
    return;
  }
#if defined(_WIN32)
  static double millisPerCounter = 0.0;
  if (millisPerCounter == 0.0) {
    LARGE_INTEGER frequency;
    QueryPerformanceFrequency(&frequency);
    millisPerCounter = 1000.0 / (double)frequency.QuadPart;
  }
  LARGE_INTEGER counter;
  QueryPerformanceCounter(&counter);
  double dt = millisPerCounter * (double)(counter.QuadPart -
                                          time->counter.QuadPart);
  time->counter = counter;
#elif defined(__APPLE__)
  static double millisPerCounter = 0.0;
  if (millisPerCounter == 0.0) {
    mach_timebase_info_data_t info;
    mach_timebase_info(&info);
    millisPerCounter = (double)info.numer / ((double)info.denom * 1.0e6);
  }
  uint64_t counter = mach_absolute_time();
  double dt = millisPerCounter * (double)(counter - time->counter);
  time->counter = counter;
#else
  struct timespec counter;
  clock_gettime(CLOCK_MONOTONIC, &counter);
  double dt = 1000.0 * (double)(counter.tv_sec - time->counter.tv_sec) +
              1.0e-6 * (double)(counter.tv_nsec - time->counter.tv_nsec);
  time->counter = counter;
#endif
  time_add(time, dt);
}

static double time_get_current_millis(const b3Time *time) {
  return time != NULL ? time->currentMillis : 0.0;
}

static double time_get_elapsed_millis(const b3Time *time) {
  return time != NULL ? time->currentMillis - time->previousMillis : 0.0;
}

b3Time *b3Time_Create(void) {
  b3Time *time = (b3Time *)calloc(1u, sizeof(*time));
  if (time == NULL) {
    return NULL;
  }
  time_init(time);
  return time;
}

void b3Time_Destroy(b3Time *time) {
  free(time);
}

double b3Time_GetCurrentMilis(const b3Time *time) {
  return time_get_current_millis(time);
}

double b3Time_GetElapsedMilis(const b3Time *time) {
  return time_get_elapsed_millis(time);
}

void b3Time_Update(b3Time *time) {
  time_update(time);
}

void b3Time_Add(b3Time *time, double dt) {
  if (time != NULL) {
    time_add(time, dt);
  }
}

static b3ProfilerNode *profiler_node_find_child(b3ProfilerNode *node,
                                                const char *name) {
  if (node == NULL) {
    return NULL;
  }
  for (b3ProfilerNode *child = node->childList; child != NULL;
       child = child->childNext) {
    if (child->name == name) {
      return child;
    }
  }
  return NULL;
}

static b3ProfilerStatistic *profiler_find_statistic(b3Profiler *profiler,
                                                    const char *name) {
  if (profiler == NULL) {
    return NULL;
  }
  for (b3ProfilerStatistic *statistic = profiler->statisticList;
       statistic != NULL; statistic = statistic->next) {
    if (statistic->name == name) {
      return statistic;
    }
  }
  return NULL;
}

static void profiler_destroy_node(b3ProfilerNode *node) {
  if (node == NULL) {
    return;
  }
  b3ProfilerNode *child = node->childList;
  while (child != NULL) {
    b3ProfilerNode *next = child->childNext;
    profiler_destroy_node(child);
    child = next;
  }
  free(node);
}

static void profiler_destroy_statistics(b3Profiler *profiler) {
  if (profiler == NULL) {
    return;
  }
  b3ProfilerStatistic *statistic = profiler->statisticList;
  while (statistic != NULL) {
    b3ProfilerStatistic *next = statistic->next;
    free(statistic);
    statistic = next;
  }
  profiler->statisticList = NULL;
  profiler->statisticCount = 0u;
}

b3Profiler *b3Profiler_Create(void) {
  b3Profiler *profiler = (b3Profiler *)calloc(1u, sizeof(*profiler));
  if (profiler == NULL) {
    return NULL;
  }
  time_init(&profiler->time);
  return profiler;
}

void b3Profiler_Destroy(b3Profiler *profiler) {
  if (profiler == NULL) {
    return;
  }
  profiler_destroy_node(profiler->root);
  profiler_destroy_statistics(profiler);
  free(profiler);
}

void b3Profiler_Clear(b3Profiler *profiler) {
  if (profiler == NULL) {
    return;
  }
  profiler_destroy_node(profiler->root);
  profiler->root = NULL;
  profiler->top = NULL;
}

void b3Profiler_OpenScope(b3Profiler *profiler, const char *name) {
  if (profiler == NULL || name == NULL) {
    return;
  }

  if (profiler->top != NULL) {
    b3ProfilerNode *topChild =
        profiler_node_find_child(profiler->top, name);
    if (topChild != NULL) {
      profiler->top = topChild;
      ++topChild->callCount;
      if (topChild->recursionCount == 0u) {
        time_update(&profiler->time);
        topChild->t1 = time_get_current_millis(&profiler->time);
      }
      ++topChild->recursionCount;
      return;
    }
  }

  time_update(&profiler->time);

  b3ProfilerNode *newNode = (b3ProfilerNode *)calloc(1u, sizeof(*newNode));
  if (newNode == NULL) {
    return;
  }
  newNode->name = name;
  newNode->t1 = time_get_current_millis(&profiler->time);
  newNode->callCount = 1u;
  newNode->recursionCount = 1u;
  newNode->parent = profiler->top;

  if (profiler->root == NULL) {
    profiler->root = newNode;
    profiler->top = newNode;
    return;
  }

  if (profiler->top != NULL) {
    newNode->childNext = profiler->top->childList;
    profiler->top->childList = newNode;
    ++profiler->top->childCount;
  }

  profiler->top = newNode;
}

void b3Profiler_CloseScope(b3Profiler *profiler) {
  if (profiler == NULL || profiler->top == NULL) {
    return;
  }

  if (profiler->top->recursionCount > 0u) {
    --profiler->top->recursionCount;
  }
  if (profiler->top->recursionCount > 0u) {
    return;
  }

  time_update(&profiler->time);
  profiler->top->t2 = time_get_current_millis(&profiler->time);
  double elapsed = profiler->top->t2 - profiler->top->t1;
  profiler->top->elapsed += elapsed;

  b3ProfilerStatistic *statistic =
      profiler_find_statistic(profiler, profiler->top->name);
  if (statistic == NULL) {
    statistic = (b3ProfilerStatistic *)calloc(1u, sizeof(*statistic));
    if (statistic != NULL) {
      statistic->name = profiler->top->name;
      statistic->minElapsed = elapsed;
      statistic->maxElapsed = elapsed;
      statistic->next = profiler->statisticList;
      profiler->statisticList = statistic;
      ++profiler->statisticCount;
    }
  } else {
    if (elapsed < statistic->minElapsed) {
      statistic->minElapsed = elapsed;
    }
    if (elapsed > statistic->maxElapsed) {
      statistic->maxElapsed = elapsed;
    }
  }

  profiler->top->statistic = statistic;
  profiler->top = profiler->top->parent;
}

