static b3SpInertia sp_transform_mul_t_inertia(b3SpTransform X, b3SpInertia I) {
  b3Mat33 E = X.E;
  b3Mat33 ET = mat33_transpose(X.E);
  b3Mat33 rx = mat33_skew(X.r);
  b3Mat33 IABrx = mat33_sub(I.A, mat33_mul(I.B, rx));

  b3SpInertia out;
  out.A = mat33_mul(mat33_mul(ET, IABrx), E);
  out.B = mat33_mul(mat33_mul(ET, I.B), E);
  out.C = mat33_mul(
      mat33_mul(ET,
                mat33_add(mat33_sub(mat33_mul(rx, IABrx),
                                    mat33_mul(mat33_transpose(I.A), rx)),
                          I.C)),
      E);
  return out;
}

